const gprecStartDemoSession = (role) => {
  const demo = GPREC_DEMO_SESSIONS[role];
  if (!demo) return null;
  [
    "gprecStudentId",
    "gprecAdminRole",
    "gprecAdminEmail",
    "gprecAdminDepartment",
    "gprecParentStudentId",
    "gprecNonTeachingEmail",
    "gprecAlumniEmail",
    "gprecAlumniName",
    "gprecAlumniBatch",
    "gprecDemoMode"
  ].forEach((key) => localStorage.removeItem(key));
  localStorage.setItem("gprecSessionToken", `demo-${role}-session`);
  localStorage.setItem("gprecActiveRole", demo.activeRole);
  Object.entries(demo.entries).forEach(([key, value]) => localStorage.setItem(key, value));
  localStorage.setItem("gprecDemoMode", role);
  return demo;
};

const gprecDemoRole = new URLSearchParams(window.location.search).get("demo");
const gprecDemoSession = gprecDemoRole ? gprecStartDemoSession(gprecDemoRole.toLowerCase()) : null;
if (gprecDemoSession) {
  const currentDemoRequiredRole = GPREC_DASHBOARD_ROLE[GPREC_CURRENT_ROUTE_FILE];
  const currentDemoRequiredRoles = Array.isArray(currentDemoRequiredRole)
    ? currentDemoRequiredRole
    : [currentDemoRequiredRole].filter(Boolean);
  if (!currentDemoRequiredRoles.includes(gprecDemoSession.activeRole)) {
    window.location.replace(gprecPageUrl(gprecDemoSession.dashboard));
  }
}

// Runs before any dashboard content renders, on every dashboard page. This is UX-only (avoids a
// flash of a dashboard that's about to redirect away) - the real boundary is the backend
// rejecting unauthenticated/mismatched requests with 401, not this check.
const gprecRequiredDashboardRole = GPREC_DASHBOARD_ROLE[GPREC_CURRENT_ROUTE_FILE];
const gprecAllowAlumniDashboardPreview = gprecIsAlumniDashboardPreviewRoute;
if (gprecRequiredDashboardRole && !gprecAllowAlumniDashboardPreview) {
  const requiredRoles = Array.isArray(gprecRequiredDashboardRole) ? gprecRequiredDashboardRole : [gprecRequiredDashboardRole];
  const preferredLoginRole = requiredRoles[0];
  const hasValidSession = Boolean(localStorage.getItem("gprecSessionToken")) && requiredRoles.includes(localStorage.getItem("gprecActiveRole"));
  if (!hasValidSession) {
    // Preserves where the visitor was trying to go (e.g. a hostel-gate-scan.html QR link with its
    // ?type/id/t params) across the login detour, so signing in returns them to that exact page
    // instead of the generic dashboard.
    const returnTo = window.location.pathname.replace(/^.*\//, "") + window.location.search;
    const loginUrl = gprecPageUrl(GPREC_ROLE_LOGIN_PAGE[preferredLoginRole]);
    const separator = loginUrl.includes("?") ? "&" : "?";
    window.location.replace(`${loginUrl}${separator}next=${encodeURIComponent(returnTo)}`);
  }
}

// Called whenever any API call comes back 401 (missing/expired/revoked token) - clears this
// role's identity + the shared session keys and bounces to login with a flag the login page can
// read to show "session expired" instead of a blank form.
const gprecHandleSessionExpired = () => {
  if (gprecIsAlumniDashboardPreviewRoute) return;
  const role = localStorage.getItem("gprecActiveRole");
  // Falls back to *this page's own* required role when there's no active role to key off of -
  // location.replace() doesn't halt script execution, so the rest of this file can still run (and
  // hit a second 401) after the guard above already queued a redirect. Without this fallback that
  // second redirect could race a hardcoded student-login.html ahead of the correct login page.
  const requiredRoles = Array.isArray(gprecRequiredDashboardRole) ? gprecRequiredDashboardRole : [gprecRequiredDashboardRole];
  const loginPage = GPREC_ROLE_LOGIN_PAGE[role] || GPREC_ROLE_LOGIN_PAGE[requiredRoles[0]] || "student-login.html";
  clearGprecianChatHistory();
  (gprecLogoutKeysByLoginPage[loginPage] || []).forEach((key) => localStorage.removeItem(key));
  localStorage.removeItem("gprecSessionToken");
  localStorage.removeItem("gprecActiveRole");
  window.location.replace(`${gprecPageUrl(loginPage)}?expired=1`);
};

document.querySelectorAll(".student-user-dropdown a").forEach((link) => {
  const hrefWithoutQuery = (link.getAttribute("href") || "").split("?")[0];
  const loginPage = Object.keys(gprecLogoutKeysByLoginPage).find((page) =>
    hrefWithoutQuery.endsWith(page)
  );
  if (!loginPage) return;
  link.addEventListener("click", () => {
    clearGprecianChatHistory();
    const token = localStorage.getItem("gprecSessionToken");
    if (token) {
      try {
        const xhr = new XMLHttpRequest();
        xhr.open("POST", `${gprecApiBaseUrl()}/auth/logout`, false);
        xhr.setRequestHeader("Authorization", `Bearer ${token}`);
        xhr.setRequestHeader("Content-Type", "application/json");
        xhr.send("{}");
      } catch {
        // best-effort - still clear local state below even if the server call fails
      }
    }
    gprecLogoutKeysByLoginPage[loginPage].forEach((key) => localStorage.removeItem(key));
    localStorage.removeItem("gprecSessionToken");
    localStorage.removeItem("gprecActiveRole");
  });
});

// Local dev servers (VS Code Live Server, python -m http.server, etc.) serve exact filenames only,
// with no rewrite rule to resolve a cleaned URL back to a .html file - any reload there would 404.
// Only clean the address bar on a real host, where the deployed server has that rewrite configured.
const gprecIsLocalDevHost = ["localhost", "127.0.0.1", ""].includes(window.location.hostname);
const cleanHtmlFromAddressBar = () => {
  if (gprecIsLocalDevHost) return;
  const { pathname, search, hash } = window.location;
  if (!pathname.endsWith(".html")) return;
  const cleanedPath = pathname.endsWith("/index.html")
    ? pathname.slice(0, -"index.html".length)
    : pathname.slice(0, -".html".length);
  try {
    window.history.replaceState(null, "", `${cleanedPath || "/"}${search}${hash}`);
  } catch (error) {
    // Some non-server preview modes disallow address-bar rewriting.
  }
};

// Site maintenance: per-section admin-panel toggles (public website, each dashboard) that block
// visitors with a maintenance screen, except for whoever is already signed in as an admin (any
// admin role, not just the main one), so the admin can keep browsing around to check changes.
// Login pages stay open so an admin can still sign in during maintenance.
const gprecMaintenanceKey = "gprecMaintenanceMode";
const gprecMaintenanceZoneKeys = ["publicSite", "student", "faculty", "parent", "alumni", "placement", "examCell", "hostel", "department"];
const gprecMaintenanceZoneFiles = {
  student: "student-dashboard.html",
  faculty: "faculty-dashboard.html",
  parent: "parent-dashboard.html",
  alumni: "alumni-dashboard.html",
  placement: "placement-dashboard.html",
  examCell: "exam-cell-dashboard.html",
  hostel: "hostel-dashboard.html",
  department: "department-dashboard.html"
};
const defaultMaintenanceMode = () => ({
  zones: Object.fromEntries(gprecMaintenanceZoneKeys.map((zone) => [zone, false])),
  message: "",
  notice: { message: "", zones: Object.fromEntries(gprecMaintenanceZoneKeys.map((zone) => [zone, false])) }
});
const getMaintenanceMode = () => {
  const defaults = defaultMaintenanceMode();
  try {
    const stored = JSON.parse(localStorage.getItem(gprecMaintenanceKey));
    if (!stored || typeof stored !== "object") return defaults;
    if (!stored.zones && typeof stored.enabled === "boolean") {
      // Migrate the old single all-or-nothing toggle to the per-zone shape.
      return {
        zones: Object.fromEntries(gprecMaintenanceZoneKeys.map((zone) => [zone, stored.enabled])),
        message: stored.message || "",
        notice: defaults.notice
      };
    }
    const storedNotice = stored.notice || {};
    const noticeZones = storedNotice.zones
      || (typeof storedNotice.enabled === "boolean"
        // Migrate the old single notice on/off toggle to the per-zone shape.
        ? Object.fromEntries(gprecMaintenanceZoneKeys.map((zone) => [zone, storedNotice.enabled]))
        : defaults.notice.zones);
    return {
      zones: { ...defaults.zones, ...(stored.zones || {}) },
      message: stored.message || "",
      notice: {
        message: storedNotice.message || "",
        zones: { ...defaults.notice.zones, ...noticeZones }
      }
    };
  } catch {
    return defaults;
  }
};
const saveMaintenanceMode = (mode) => localStorage.setItem(gprecMaintenanceKey, JSON.stringify(mode));
const gprecIsAdminSession = () => Boolean(localStorage.getItem("gprecAdminEmail") && localStorage.getItem("gprecAdminRole"));
const gprecMaintenanceLoginPages = [
  "admin-login.html",
  "student-login.html",
  "faculty-login.html",
  "parent-login.html",
  "alumni-login.html"
];
const gprecCurrentMaintenanceZone = () => {
  const currentFile = window.location.pathname.split("/").pop() || "index.html";
  const matchedZone = Object.keys(gprecMaintenanceZoneFiles).find((zone) => gprecMaintenanceZoneFiles[zone] === currentFile);
  return matchedZone || "publicSite";
};
(() => {
  const currentFile = window.location.pathname.split("/").pop() || "index.html";
  if (gprecMaintenanceLoginPages.includes(currentFile) || currentFile === "admin-dashboard.html") return;
  const maintenance = getMaintenanceMode();
  if (!gprecIsAdminSession() && maintenance.zones[gprecCurrentMaintenanceZone()]) {
    const overlay = document.createElement("div");
    overlay.id = "gprecMaintenanceOverlay";
    const box = document.createElement("div");
    box.className = "maintenance-box";
    const icon = document.createElement("div");
    icon.className = "maintenance-icon";
    icon.innerHTML = '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><path d="m4 6 8-3 8 3-8 3zM7 8v3M17 8v3M9 12a3 3 0 1 0 6 0M5 21c.7-3.2 3.4-5 7-5s6.3 1.8 7 5"/></svg>';
    const heading = document.createElement("h1");
    heading.textContent = "Under Maintenance";
    const message = document.createElement("p");
    message.textContent = maintenance.message || "We're temporarily offline for maintenance. We'll be back online shortly.";
    box.append(icon, heading, message);
    overlay.append(box);
    document.body.appendChild(overlay);
    document.documentElement.style.overflow = "hidden";
    return;
  }
  if (!maintenance.notice.message || !maintenance.notice.zones[gprecCurrentMaintenanceZone()]) return;
  const notice = document.createElement("div");
  notice.id = "gprecMaintenanceNotice";
  const noticeIcon = document.createElement("span");
  noticeIcon.className = "maintenance-notice-icon";
  noticeIcon.innerHTML = '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><path d="M4 10a2 2 0 0 1 2-2h1l8-4v16l-8-4H6a2 2 0 0 1-2-2v-4z"/><path d="M8 16v3a2 2 0 0 0 2 2h1"/><path d="M17 9a3 3 0 0 1 0 6"/><path d="M19.5 6.5a7 7 0 0 1 0 11"/></svg>';
  const noticeText = document.createElement("span");
  noticeText.textContent = maintenance.notice.message;
  const dismissButton = document.createElement("button");
  dismissButton.type = "button";
  dismissButton.setAttribute("aria-label", "Dismiss notice");
  dismissButton.textContent = "×";
  dismissButton.addEventListener("click", () => {
    notice.remove();
  });
  notice.append(noticeIcon, noticeText, dismissButton);
  document.body.prepend(notice);
})();

// Remembers which dropdown/sub-tab views were open inside a dashboard panel (Media section,
// Web Page Content page + subtab + funded-project view, ...) so a refresh lands back where the
// admin left off instead of resetting to each control's HTML-authored default. Keyed per-page
// since admin-dashboard.html and department-dashboard.html etc. share this same script.
const gprecAdminUiStateKey = `gprecAdminUiState_${GPREC_CURRENT_FOLDER}_${window.location.pathname.split("/").pop()}`;
const getAdminUiState = () => {
  try {
    return JSON.parse(localStorage.getItem(gprecAdminUiStateKey) || "{}");
  } catch {
    return {};
  }
};
const saveAdminUiState = (partial) => {
  localStorage.setItem(gprecAdminUiStateKey, JSON.stringify({ ...getAdminUiState(), ...partial }));
};



