// Action-busy indicator (see #gprecLoader in styles.css). Injected once here so it exists on
// every page without editing each HTML file. Call showGprecLoader() right before an async
// operation - uploading a file, generating a download, redirecting after login/logout - and
// hideGprecLoader() when it finishes. Reference-counted so nested/overlapping calls (e.g. two
// uploads in flight) don't hide the icon until all of them are done.
const gprecLoaderEl = document.createElement("div");
gprecLoaderEl.id = "gprecLoader";
gprecLoaderEl.setAttribute("aria-hidden", "true");
gprecLoaderEl.innerHTML =
  '<svg viewBox="0 0 24 24"><path d="m4 6 8-3 8 3-8 3zM7 8v3M17 8v3M9 12a3 3 0 1 0 6 0M5 21c.7-3.2 3.4-5 7-5s6.3 1.8 7 5"/></svg>';
document.body.appendChild(gprecLoaderEl);

let gprecLoaderCount = 0;
let gprecLoaderShownAt = 0;
const GPREC_LOADER_MIN_MS = 500;

const showGprecLoader = () => {
  if (gprecLoaderCount === 0) gprecLoaderShownAt = Date.now();
  gprecLoaderCount += 1;
  document.body.classList.add("gprec-loading");
};
const hideGprecLoader = () => {
  gprecLoaderCount = Math.max(0, gprecLoaderCount - 1);
  if (gprecLoaderCount > 0) return;
  // Fast operations (e.g. reading a small file) can finish in a few milliseconds - hold the
  // icon visible for a minimum stretch so it's actually perceptible, not just correct.
  const remaining = GPREC_LOADER_MIN_MS - (Date.now() - gprecLoaderShownAt);
  if (remaining > 0) {
    setTimeout(() => {
      if (gprecLoaderCount === 0) document.body.classList.remove("gprec-loading");
    }, remaining);
  } else {
    document.body.classList.remove("gprec-loading");
  }
};

// Also show briefly on every page load/reload, not just during async actions.
showGprecLoader();
window.addEventListener("load", () => {
  setTimeout(hideGprecLoader, 500);
});

// Generic toast for confirmations that need to be visible regardless of which section/modal
// is currently open (e.g. Share) - safer than writing into a page-specific feedback paragraph
// that may be hidden at the moment the action runs.
let gprecToastTimer = null;
const showFeedToast = (message) => {
  let toast = document.querySelector("#gprecToast");
  if (!toast) {
    toast = document.createElement("div");
    toast.id = "gprecToast";
    document.body.appendChild(toast);
  }
  toast.textContent = message;
  toast.classList.add("is-visible");
  clearTimeout(gprecToastTimer);
  gprecToastTimer = setTimeout(() => toast.classList.remove("is-visible"), 3200);
};

// .detail-back-link has a hardcoded href as a safe fallback (direct link, no-JS, new tab), but
// when the visitor actually navigated here from another page on this site, prefer real browser
// history so "Back" returns to wherever they came from instead of a fixed destination.
document.querySelectorAll(".detail-back-link").forEach((link) => {
  link.addEventListener("click", (event) => {
    const referrer = document.referrer;
    const cameFromThisSite = referrer && new URL(referrer).origin === window.location.origin;
    if (cameFromThisSite && window.history.length > 1) {
      event.preventDefault();
      window.history.back();
    }
  });
});

