let gprecDbBootstrap = null;
let gprecDbBootstrapTried = false;
const gprecApiBaseUrl = () => {
  const configured = defaultAdminConfig.databaseApiConfig?.baseUrl || defaultAdminConfig.libraryApiConfig?.baseUrl || "";
  if (configured) return configured.replace(/\/$/, "");
  // When running the portal locally, the API server lives on port 8766, on whatever host the page
  // itself was loaded from - a hardcoded 127.0.0.1 only works when browsing from the same machine
  // the server runs on, which breaks phone/LAN testing (the phone's own 127.0.0.1 isn't the Mac).
  // Still avoid using the current page's PORT because static preview servers such as Live Server
  // on 127.0.0.1:5500 do not host the API routes. Protocol matches the current page so this isn't
  // blocked as mixed content if the site ends up served over https without databaseApiConfig.baseUrl
  // being set - see PRODUCTION.md.
  return `${window.location.protocol}//${window.location.hostname}:8766/api`;
};
const gprecDbRequest = (path, options = {}) => {
  if (localStorage.getItem("gprecDemoMode")) return null;
  const baseUrl = gprecApiBaseUrl();
  if (!baseUrl) return null;
  const xhr = new XMLHttpRequest();
  xhr.open(options.method || "GET", `${baseUrl}${path}`, false);
  xhr.setRequestHeader("Accept", "application/json");
  if (options.body !== undefined) xhr.setRequestHeader("Content-Type", "application/json");
  const sessionToken = localStorage.getItem("gprecSessionToken");
  if (sessionToken) xhr.setRequestHeader("Authorization", `Bearer ${sessionToken}`);
  try {
    xhr.send(options.body !== undefined ? JSON.stringify(options.body) : null);
    if (xhr.status === 401) {
      gprecHandleSessionExpired();
      return null;
    }
    if (xhr.status >= 200 && xhr.status < 300) return xhr.responseText ? JSON.parse(xhr.responseText) : null;
  } catch {
    return null;
  }
  return null;
};
const getGprecDbBootstrap = () => {
  if (gprecDbBootstrapTried) return gprecDbBootstrap;
  gprecDbBootstrap = gprecDbRequest("/bootstrap") || null;
  // Only cache a successful fetch. If the API server was mid-restart (e.g. after a Live Server
  // reload) this call fails once, but leaving gprecDbBootstrapTried false means the next call
  // retries instead of the app staying stuck believing the backend is unreachable until a
  // full page refresh.
  if (gprecDbBootstrap) gprecDbBootstrapTried = true;
  return gprecDbBootstrap;
};
const fetchGprecDbBootstrap = async () => {
  const baseUrl = gprecApiBaseUrl();
  if (!baseUrl) return null;
  try {
    const response = await fetch(`${baseUrl}/bootstrap`, { mode: "cors" });
    if (!response.ok) return null;
    return await response.json();
  } catch {
    return null;
  }
};
const refreshGprecDbBootstrap = () => {
  gprecDbBootstrapTried = false;
  return getGprecDbBootstrap();
};
const gprecDbPost = (path, body) => {
  const response = gprecDbRequest(path, { method: "POST", body });
  if (response) refreshGprecDbBootstrap();
  return response;
};
// Credential endpoints never touch the bootstrap cache - they're never included in it.
const gprecAuthPost = (path, body) => gprecDbRequest(`/auth${path}`, { method: "POST", body });
const gprecAuthGet = (path) => gprecDbRequest(`/auth${path}`);

