  const seeded = [
    { id: "complaint-seed-1", studentId: "20X51A0501", studentName: "Sai Chandan", category: "Hostel", department: "CSE", hostel: "Boys Hostel", room: "B-204", subject: "Fan repair", description: "Ceiling fan in the room is not working.", status: "Pending" },
    { id: "complaint-seed-2", studentId: "20X51A0488", studentName: "S. Ananya", category: "Hostel", department: "CSE", hostel: "Girls Hostel", room: "G-310", subject: "Water supply", description: "Low water pressure in the washroom.", status: "Pending" }
  ];
  localStorage.setItem("gprecComplaints", JSON.stringify(seeded));
