// Personal app-drawer shortcuts - each signed-in identity (see gprecChatIdentityKey, same
// per-account keying the chat history uses) gets their own list, stored client-side since
// these are just personal bookmarks, not data other users or devices need to see.
const gprecAppDrawerLinksKey = () => `gprecAppDrawerLinks:${gprecChatScopeKey()}:${gprecChatIdentityKey()}`;
const getAppDrawerLinks = () => {
  try {
    return JSON.parse(localStorage.getItem(gprecAppDrawerLinksKey()) || "[]");
  } catch {
    return [];
  }
};
const saveAppDrawerLinks = (links) => localStorage.setItem(gprecAppDrawerLinksKey(), JSON.stringify(links));

const appDrawerCustomLinksList = document.querySelector("#appDrawerCustomLinks");
const appDrawerAddToggle = document.querySelector("#appDrawerAddToggle");
const appDrawerAddLinkForm = document.querySelector("#appDrawerAddLinkForm");

// Generic "link" glyph, used only if a link's real favicon fails to load.
const appDrawerFallbackIconSvg = `<svg viewBox="0 0 24 24" aria-hidden="true"><path d="M10 14 21 3M21 3h-6M21 3v6M12 5H7a2 2 0 0 0-2 2v10a2 2 0 0 0 2 2h10a2 2 0 0 0 2-2v-5"/></svg>`;

const renderAppDrawerCustomLinks = () => {
  if (!appDrawerCustomLinksList) return;
  appDrawerCustomLinksList.innerHTML = "";
  getAppDrawerLinks().forEach((link, index) => {
    const tile = document.createElement("a");
    tile.className = "app-drawer-tile";
    tile.href = link.url;
    tile.target = "_blank";
    tile.rel = "noopener";

    // Real site favicon (same idea as a browser's "Add to Home Screen") instead of a generic
    // glyph, so each personal link looks like its actual app/site rather than a stand-in icon.
    const iconWrap = document.createElement("span");
    iconWrap.className = "app-drawer-tile-icon app-drawer-tile-icon-favicon";
    let hostname = "";
    try { hostname = new URL(link.url).hostname; } catch {}
    if (hostname) {
      const favicon = document.createElement("img");
      favicon.alt = "";
      favicon.loading = "lazy";
      favicon.src = `https://www.google.com/s2/favicons?sz=64&domain=${encodeURIComponent(hostname)}`;
      favicon.addEventListener("error", () => {
        iconWrap.classList.remove("app-drawer-tile-icon-favicon");
        iconWrap.innerHTML = appDrawerFallbackIconSvg;
      });
      iconWrap.appendChild(favicon);
    } else {
      iconWrap.innerHTML = appDrawerFallbackIconSvg;
    }
    tile.appendChild(iconWrap);

    const label = document.createElement("span");
    label.className = "app-drawer-tile-label";
    // textContent (not innerHTML) for the user-supplied name - safe against a pasted name
    // like "<img onerror=...>" ending up interpreted as markup.
    label.textContent = link.name;
    tile.appendChild(label);

    const editButton = document.createElement("button");
    editButton.type = "button";
    editButton.className = "app-drawer-tile-edit";
    editButton.setAttribute("aria-label", `Edit ${link.name}`);
    editButton.innerHTML = `<svg viewBox="0 0 24 24" aria-hidden="true"><path d="M12 20h9M16.5 3.5a2.121 2.121 0 0 1 3 3L7 19l-4 1 1-4Z"/></svg>`;
    editButton.addEventListener("click", (event) => {
      event.preventDefault();
      event.stopPropagation();
      openAppDrawerAddForm(index, link);
    });
    tile.appendChild(editButton);

    const removeButton = document.createElement("button");
    removeButton.type = "button";
    removeButton.className = "app-drawer-tile-remove";
    removeButton.setAttribute("aria-label", `Remove ${link.name}`);
    removeButton.textContent = "×";
    removeButton.addEventListener("click", (event) => {
      event.preventDefault();
      event.stopPropagation();
      saveAppDrawerLinks(getAppDrawerLinks().filter((_, i) => i !== index));
      renderAppDrawerCustomLinks();
    });
    tile.appendChild(removeButton);

    appDrawerCustomLinksList.appendChild(tile);
  });
};

// null while adding a brand-new link; the link's index while editing an existing one, so the
// form's submit handler below knows whether to push a new entry or overwrite one in place.
let appDrawerEditingIndex = null;

const openAppDrawerAddForm = (editingIndex = null, existingLink = null) => {
  if (!appDrawerAddLinkForm) return;
  appDrawerEditingIndex = editingIndex;
  const nameInput = document.querySelector("#appDrawerLinkName");
  const urlInput = document.querySelector("#appDrawerLinkUrl");
  if (nameInput) nameInput.value = existingLink?.name || "";
  if (urlInput) urlInput.value = existingLink?.url || "";
  const submitButton = appDrawerAddLinkForm.querySelector("button[type=submit]");
  if (submitButton) submitButton.textContent = editingIndex === null ? "Save" : "Save changes";
  appDrawerAddLinkForm.classList.remove("is-hidden");
  appDrawerAddToggle?.setAttribute("aria-expanded", "true");
  nameInput?.focus();
};

appDrawerAddToggle?.addEventListener("click", (event) => {
  event.stopPropagation();
  if (appDrawerAddLinkForm?.classList.contains("is-hidden")) {
    openAppDrawerAddForm();
  } else {
    appDrawerAddLinkForm?.classList.add("is-hidden");
    appDrawerAddToggle.setAttribute("aria-expanded", "false");
  }
});

appDrawerAddLinkForm?.addEventListener("submit", (event) => {
  event.preventDefault();
  const nameInput = document.querySelector("#appDrawerLinkName");
  const urlInput = document.querySelector("#appDrawerLinkUrl");
  const name = nameInput.value.trim();
  let url = urlInput.value.trim();
  if (!name || !url) return;
  if (!/^https?:\/\//i.test(url)) url = `https://${url}`;
  const links = getAppDrawerLinks();
  if (appDrawerEditingIndex !== null && links[appDrawerEditingIndex]) {
    links[appDrawerEditingIndex] = { name, url };
  } else {
    links.push({ name, url });
  }
  saveAppDrawerLinks(links);
  appDrawerEditingIndex = null;
  nameInput.value = "";
  urlInput.value = "";
  appDrawerAddLinkForm.classList.add("is-hidden");
  appDrawerAddToggle?.setAttribute("aria-expanded", "false");
  renderAppDrawerCustomLinks();
});

renderAppDrawerCustomLinks();

const bindGprecTap = (element, handler) => {
  if (!element) return;
  let handledPointer = false;
  if (window.PointerEvent) {
    element.addEventListener("pointerup", (event) => {
      handledPointer = true;
      window.setTimeout(() => {
        handledPointer = false;
      }, 0);
      handler(event);
    });
  }
  element.addEventListener("click", (event) => {
    if (handledPointer) return;
    handler(event);
  });
};

// The clear-all button re-renders with whatever legacy items were last passed in, since only the
// persisted feed is clearable server-side - the hand-built pending-action strings aren't stored
// rows, so clearing can't (and shouldn't) touch them.
let lastRenderedNotificationItems = [];

// Plays the collapse-and-fade exit transition (see .notification-item.is-clearing in styles.css)
// on the given tiles, staggered by staggerMs apart, then runs onSettled once the slowest tile's
// transition would have finished - a plain setTimeout rather than transitionend listeners, since
// each tile animates several properties at once and transitionend fires once per property.
const COLLAPSE_TRANSITION_MS = 240;
const animateNotificationTilesOut = (tiles, staggerMs, onSettled) => {
  if (tiles.length === 0) {
    onSettled();
    return;
  }
  tiles.forEach((tile, index) => {
    tile.style.transitionDelay = `${index * staggerMs}ms`;
    tile.classList.add("is-clearing");
  });
  const totalMs = (tiles.length - 1) * staggerMs + COLLAPSE_TRANSITION_MS;
  setTimeout(onSettled, totalMs);
};

const notificationDropdownHead = document.querySelector(".notification-dropdown-head");
if (notificationDropdownHead && !notificationDropdownHead.querySelector("#notificationClearAll")) {
  const clearAllButton = document.createElement("button");
  clearAllButton.type = "button";
  clearAllButton.id = "notificationClearAll";
  clearAllButton.className = "notification-clear-all";
  clearAllButton.innerHTML = clearAllIconSvg;
  clearAllButton.setAttribute("aria-label", "Clear all notifications");
  clearAllButton.addEventListener("click", (event) => {
    event.stopPropagation();
    const tiles = [...document.querySelectorAll("#notificationList [data-notification-id]")];
    animateNotificationTilesOut(tiles, 45, () => {
      gprecDbRequest("/notifications/clear", { method: "POST", body: {} });
      renderNotificationList(lastRenderedNotificationItems);
    });
  });
  notificationDropdownHead.appendChild(clearAllButton);
}

// items is the page's own hand-built list of pending-action strings (unread by nature, no
// persistence). Merged here with the real, persisted notification feed (any feature can add to
// it via create_notification()/create_notifications_bulk() in portal_db_server.py) so both show
// up in the one bell dropdown every dashboard already has, instead of building a second widget.
// Two unrelated nav systems exist on this site: student/faculty/parent-style dashboards use
// <a data-dashboard-link>, admin-family dashboards use <div class="admin-nav" data-admin-target>
// instead - try both before falling back to just setting location.hash.
const gprecNavigateToNotificationTarget = (targetLink) => {
  if (!targetLink) return;
  const targetNavLink = document.querySelector(`[data-dashboard-link][href="${targetLink}"]`)
    || document.querySelector(`.admin-nav[data-admin-target="${targetLink}"]`);
  if (targetNavLink) {
    targetNavLink.click();
  } else {
    window.location.hash = targetLink;
  }
  document.querySelector("#notificationDropdown")?.classList.add("is-hidden");
};

const renderNotificationList = (items) => {
  lastRenderedNotificationItems = items;
  const notificationBadge = document.querySelector("#notificationBadge");
  const notificationList = document.querySelector("#notificationList");
  if (!notificationList) return;
  const persisted = gprecDbRequest("/notifications/mine", { method: "POST", body: {} })?.notifications || [];
  const unreadPersistedCount = persisted.filter((notification) => !notification.isRead).length;
  const totalCount = items.length + unreadPersistedCount;
  if (notificationBadge) {
    if (totalCount > 0) {
      notificationBadge.textContent = String(totalCount);
      notificationBadge.classList.remove("is-hidden");
    } else {
      notificationBadge.classList.add("is-hidden");
    }
  }
  const persistedHtml = persisted
    .map(
      (notification) => `
        <div class="notification-item${notification.isRead ? "" : " notification-unread"}${notification.link ? " notification-clickable" : ""}" data-notification-id="${notification.id}" data-notification-link="${notification.link || ""}">
          <button type="button" class="notification-dismiss" data-dismiss-notification aria-label="Dismiss notification">${deleteIconSvg}</button>
          <strong>${notification.title}${notification.isRead ? "" : "<em>NEW</em>"}</strong>
          <p>${notification.message}</p>
          <small>${notification.createdAt}</small>
        </div>
      `
    )
    .join("");
  // Legacy items are usually a bare string (no navigation), but some callers (e.g. the hostel
  // warden's "N outing requests awaiting approval") pass {text, link} instead so the notification
  // can jump straight to the relevant section - these are computed fresh from live data on every
  // render rather than persisted/dismissible, so they don't get the id-based mark-read/dismiss
  // machinery the persisted ones above do, just a click-to-navigate.
  const legacyHtml = items
    .map((item) => {
      const isLinked = typeof item === "object" && item !== null;
      const text = isLinked ? item.text : item;
      return isLinked
        ? `<div class="notification-item notification-clickable" data-notification-link="${item.link}">${text}</div>`
        : `<div class="notification-item">${text}</div>`;
    })
    .join("");
  notificationList.innerHTML = persistedHtml + legacyHtml || `<div class="notification-empty">No new notifications.</div>`;
  notificationList.querySelectorAll("[data-dismiss-notification]").forEach((dismissButton) => {
    dismissButton.addEventListener("click", (event) => {
      event.stopPropagation();
      const item = dismissButton.closest("[data-notification-id]");
      if (!item) return;
      animateNotificationTilesOut([item], 0, () => {
        gprecDbRequest("/notifications/clear", { method: "POST", body: { id: item.dataset.notificationId } });
        renderNotificationList(lastRenderedNotificationItems);
      });
    });
  });
  notificationList.querySelectorAll("[data-notification-id]").forEach((item) => {
    item.addEventListener("click", () => {
      if (item.classList.contains("notification-unread")) {
        gprecDbRequest("/notifications/mark-read", { method: "POST", body: { id: item.dataset.notificationId } });
        item.classList.remove("notification-unread");
        const remaining = notificationList.querySelectorAll(".notification-unread").length + items.length;
        if (notificationBadge) {
          if (remaining > 0) {
            notificationBadge.textContent = String(remaining);
          } else {
            notificationBadge.classList.add("is-hidden");
          }
        }
      }
      gprecNavigateToNotificationTarget(item.dataset.notificationLink);
    });
  });
  notificationList.querySelectorAll("[data-notification-link]:not([data-notification-id])").forEach((item) => {
    item.addEventListener("click", () => gprecNavigateToNotificationTarget(item.dataset.notificationLink));
  });
};

