const applicationCards = document.querySelectorAll(".application-card");

// Certificate-style forms have several stacked, mutually-exclusive field groups, each with their
// own `required` inputs. The inactive-state CSS sets display:none, but a plain `required`
// attribute still blocks submission even while hidden. Mark every field that started out required,
// then re-sync `required` to actual visibility (offsetParent is null under display:none) on toggle.
document.querySelectorAll(".service-request-card [required]").forEach((field) => {
  field.dataset.wasRequired = "true";
});

const syncRequiredByVisibility = (root) => {
  root.querySelectorAll("[data-was-required]").forEach((field) => {
    field.required = field.offsetParent !== null;
  });
};

// Also sync on initial load - the default-active application/service type never fires a click,
// so without this the very first submit attempt (no card switching at all) would still hit the
// same stale-required bug for every non-default application/service type's hidden fields.
document.querySelectorAll(".service-request-card").forEach((form) => syncRequiredByVisibility(form));

const selectApplication = (card) => {
  const group = card.closest(".service-fields");
  if (!group) return;
  group.querySelectorAll(".application-card").forEach((otherCard) => {
    otherCard.classList.toggle("active", otherCard === card);
  });
  group.querySelectorAll(".application-fields").forEach((fields) => {
    fields.classList.toggle("is-active", fields.dataset.applicationFields === card.dataset.application);
  });
  const amountDisplay = group.querySelector("[data-amount-display]");
  if (amountDisplay) {
    amountDisplay.textContent = `₹${Number(card.dataset.amount).toLocaleString("en-IN")}`;
  }
  group.querySelectorAll("[data-shared-fields]").forEach((sharedFields) => {
    sharedFields.classList.toggle("is-hidden", card.dataset.application === "bonafide");
  });
  syncRequiredByVisibility(group.closest("form") || group);
};

// Apply admin-set base amounts before the form's first render, so the default-active card's
// price already reflects them.
if (applicationCards.length > 0) {
  const feeAmountOverrides = getFeeAmountOverrides();
  applicationCards.forEach((card) => {
    const appId = card.dataset.application;
    if (feeAmountOverrides[appId] !== undefined) {
      card.dataset.amount = String(feeAmountOverrides[appId]);
    }
  });

  // A per-student CSV-uploaded pending fee (Fee Management > Bulk Update Due Fees) is what THIS
  // student actually still owes for that application - e.g. a partially-paid Semester Tuition due
  // of Rs. 28,500, not the flat Rs. 48,500 default/base override above, which is the same for
  // every student. Wins over both when present and not already paid, so what's charged at
  // checkout always matches the "Pending Fees" notice shown elsewhere on this dashboard.
  const currentStudentId = getCurrentStudentId();
  const studentPendingFees = currentStudentId ? getStudentPendingFeeOverrides()[currentStudentId] || [] : [];
  studentPendingFees
    .filter((fee) => !isPendingFeePaid(fee))
    .forEach((fee) => {
      const card = [...applicationCards].find((item) => item.dataset.application === fee.application);
      if (card) card.dataset.amount = String(fee.amount);
    });
}

applicationCards.forEach((card) => {
  card.addEventListener("click", () => selectApplication(card));
});

if (serviceTypeButtons.length > 0 && serviceFieldGroups.length > 0) {
  const showServiceType = (service) => {
    serviceTypeButtons.forEach((button) => {
      button.classList.toggle("active", button.dataset.service === service);
    });
    serviceFieldGroups.forEach((group) => {
      const isActive = group.dataset.serviceFields === service;
      group.classList.toggle("is-active", isActive);
      if (isActive) {
        const firstCard = group.querySelector(".application-card");
        if (firstCard) selectApplication(firstCard);
      }
    });
    const anyGroup = serviceFieldGroups[0]?.closest("form");
    if (anyGroup) syncRequiredByVisibility(anyGroup);
  };

  serviceTypeButtons.forEach((button) => {
    button.addEventListener("click", () => showServiceType(button.dataset.service));
  });

  const availableServices = [...serviceTypeButtons].map((button) => button.dataset.service);
  const requestedService = new URLSearchParams(window.location.search).get("service");
  showServiceType(availableServices.includes(requestedService) ? requestedService : availableServices[0]);
}

const studentBacklogSubjects = [];
const BACKLOG_FEE_PER_SUBJECT = 1500;
const backlogSubjectField = document.querySelector("#backlogSubjectField");
const backlogFeeCard = document.querySelector('.application-card[data-application="backlog-fee"]');

if (backlogSubjectField) {
  if (studentBacklogSubjects.length === 0) {
    backlogSubjectField.innerHTML = '<p class="portal-note">No backlog subjects found in your academic record. Backlog fee payment is not applicable.</p>';
    if (backlogFeeCard) {
      backlogFeeCard.disabled = true;
      backlogFeeCard.dataset.amount = "0";
    }
  } else {
    backlogSubjectField.innerHTML = `
      <span class="field-label">Backlog Subjects</span>
      <div class="backlog-subject-checks">
        ${studentBacklogSubjects
          .map((subject) => `<label class="backlog-subject-check"><input type="checkbox" value="${subject}" checked><span>${subject}</span></label>`)
          .join("")}
      </div>
    `;
    const updateBacklogAmount = () => {
      const checkedCount = backlogSubjectField.querySelectorAll('input[type="checkbox"]:checked').length;
      const amount = checkedCount * BACKLOG_FEE_PER_SUBJECT;
      if (backlogFeeCard) backlogFeeCard.dataset.amount = String(amount);
      if (backlogFeeCard?.classList.contains("active")) {
        const amountDisplay = backlogFeeCard.closest(".service-fields")?.querySelector("[data-amount-display]");
        if (amountDisplay) amountDisplay.textContent = `₹${amount.toLocaleString("en-IN")}`;
      }
    };
    backlogSubjectField.querySelectorAll('input[type="checkbox"]').forEach((checkbox) => {
      checkbox.addEventListener("change", updateBacklogAmount);
    });
    updateBacklogAmount();
  }
}

