const syncMaintenanceZoneAllState = () => {
  if (!maintenanceZoneAll) return;
  const allChecked = [...maintenanceZoneCheckboxes].every((checkbox) => checkbox.checked);
  const noneChecked = [...maintenanceZoneCheckboxes].every((checkbox) => !checkbox.checked);
  maintenanceZoneAll.checked = allChecked;
  maintenanceZoneAll.indeterminate = !allChecked && !noneChecked;
};
