const getAllExamCellData = () => {
  const databaseExamData = getGprecDbBootstrap()?.examCellData;
  if (databaseExamData && Object.keys(databaseExamData).length) return { ...defaultExamCellData, ...databaseExamData };
  try {
    const stored = JSON.parse(localStorage.getItem("gprecExamCellData") || "null");
    if (stored) {
      const patched = Array.isArray(stored)
        ? { ...defaultExamCellData, CSE: stored }
        : { ...defaultExamCellData, ...stored };
      if (JSON.stringify(patched) !== JSON.stringify(stored)) {
        localStorage.setItem("gprecExamCellData", JSON.stringify(patched));
      }
      return patched;
    }
  } catch {
    // fall through to default data
  }
  localStorage.setItem("gprecExamCellData", JSON.stringify(defaultExamCellData));
  return defaultExamCellData;
};

const getExamCellData = (branch = "CSE") => getAllExamCellData()[branch] || [];

const saveExamCellData = (branch, data) => {
  const all = getAllExamCellData();
  all[branch] = data;
  const saved = gprecDbPost("/exam-schedules", all);
  if (saved) {
    localStorage.setItem("gprecExamCellUpdatedAt", String(Date.now()));
    return;
  }
  localStorage.setItem("gprecExamCellData", JSON.stringify(all));
  localStorage.setItem("gprecExamCellUpdatedAt", String(Date.now()));
};

const defaultHallTicketRelease = { enabled: false, releaseAt: "", updatedAt: 0 };

const getHallTicketRelease = () => {
  const databaseSettings = getSiteContent("hallTicketRelease", null);
  if (databaseSettings) return { ...defaultHallTicketRelease, ...databaseSettings };
  try {
    return { ...defaultHallTicketRelease, ...(JSON.parse(localStorage.getItem("gprecHallTicketRelease") || "null") || {}) };
  } catch {
    return defaultHallTicketRelease;
  }
};

const saveHallTicketRelease = (settings) => {
  const nextSettings = { ...getHallTicketRelease(), ...settings, updatedAt: Date.now() };
  const saved = saveSiteContent("hallTicketRelease", nextSettings);
  localStorage.setItem("gprecHallTicketRelease", JSON.stringify(nextSettings));
  return saved;
};

const formatHallTicketReleaseAt = (value) => {
  if (!value) return "";
  const date = new Date(value);
  if (Number.isNaN(date.getTime())) return "";
  return date.toLocaleString("en-IN", { day: "2-digit", month: "short", year: "numeric", hour: "2-digit", minute: "2-digit" });
};

const getHallTicketReleaseState = () => {
  const settings = getHallTicketRelease();
  if (!settings.enabled) {
    return { released: false, settings, message: "Hall ticket is not released yet by the Exam Cell." };
  }
  if (settings.releaseAt) {
    const releaseTime = new Date(settings.releaseAt).getTime();
    if (Number.isFinite(releaseTime) && Date.now() < releaseTime) {
      return { released: false, settings, message: `Hall ticket will be available from ${formatHallTicketReleaseAt(settings.releaseAt)}.` };
    }
  }
  return { released: true, settings, message: "Hall ticket is available for viewing." };
};

const formatExamDate = (isoDate) =>
  new Date(isoDate).toLocaleDateString("en-IN", { day: "2-digit", month: "short", year: "numeric" });

const parseRollSuffix = (roll) => {
  const match = String(roll || "").match(/(\d+)$/);
  return match ? parseInt(match[1], 10) : null;
};

const findSeatForRoll = (subjectRows, roll) => {
  const rollNum = parseRollSuffix(roll);
  const block = subjectRows.find((row) => {
    const from = parseRollSuffix(row.rollFrom);
    const to = parseRollSuffix(row.rollTo);
    return rollNum !== null && from !== null && to !== null && rollNum >= from && rollNum <= to;
  });
  if (!block) return null;
  const from = parseRollSuffix(block.rollFrom);
  const seatNumber = Number(block.startSeat || 1) + (rollNum - from);
  return { seat: `${block.room}-${seatNumber}`, location: block.location };
};

const getExamScheduleForStudent = (branch, roll) => {
  const rows = getExamCellData(branch);
  const subjectCodes = [...new Set(rows.map((row) => row.code))];
  return subjectCodes.map((code) => {
    const subjectRows = rows.filter((row) => row.code === code);
    const base = subjectRows[0];
    const seatInfo = findSeatForRoll(subjectRows, roll);
    return {
      code: base.code,
      subject: base.subject,
      date: base.date,
      time: base.time,
      seat: seatInfo ? seatInfo.seat : "Not allotted",
      location: seatInfo ? seatInfo.location : "Contact exam cell"
    };
  });
};

