const commitExamCellEdits = (feedbackMessage) => {
  const branch = currentExamCellBranch();
  const data = getExamCellData(branch);
  examCellBody?.querySelectorAll("input").forEach((input) => {
    const index = Number(input.dataset.examIndex);
    const field = input.dataset.field;
    if (data[index]) data[index][field] = field === "startSeat" ? Number(input.value) : input.value;
  });
  saveExamCellData(branch, data);
  logExamCellActivity(branch, "Saved exam center details");
  renderExamCellStats();
  renderExamCellActivity();
  if (examCellFeedback && feedbackMessage) {
    examCellFeedback.textContent = feedbackMessage;
    examCellFeedback.classList.add("success");
  }
};
