// Real per-student placement-eligibility profile - branch from the student directory, CGPA/backlogs
// from their most recent grades term on file. Previously a single hardcoded object shown to every
// logged-in student regardless of who they actually were.
const getStudentPlacementProfile = (studentId) => {
  const id = studentId || getCurrentStudentId();
  // Reads straight from the raw bootstrap response rather than the module-level
  // defaultStudentDirectory/defaultStudentProfiles - those are only hydrated later in this file,
  // but renderPlacementDrives() below calls this synchronously at page load, before that
  // hydration code runs (a TDZ ReferenceError otherwise).
  const bootstrap = getGprecDbBootstrap();
  const branch = bootstrap?.studentDirectory?.find((student) => student.studentId === id)?.branch
    || bootstrap?.studentProfiles?.[id]?.branch
    || "";
  const terms = bootstrap?.studentGrades?.[id] || [];
  const latestTerm = terms[terms.length - 1];
  return {
    cgpa: Number(latestTerm?.gpa) || 0,
    backlogs: Number(latestTerm?.backlogs) || 0,
    branch
  };
};

const getPlacementDrives = () => getGprecDbBootstrap()?.placementDrives || [];

// Targeted single-row create/remove, not a full-array replace - a TRUNCATE+reinsert approach would
// wipe every student's applications (and interview_schedules) on every add/remove, since TRUNCATE
// CASCADE empties the whole child table regardless of which drive changed.
const createPlacementDrive = (fields) => gprecDbPost("/placement-drives/create", fields);
const removePlacementDriveById = (id) => gprecDbPost("/placement-drives/remove", { id });

const getPlacementApplications = () => getGprecDbBootstrap()?.placementApplications?.[getCurrentStudentId()] || [];

const applyToPlacementDrive = (driveId) => gprecDbPost("/placement-applications", { studentId: getCurrentStudentId(), driveId });

const checkDriveEligibility = (drive) => {
  const studentPlacementProfile = getStudentPlacementProfile();
  const reasons = [];
  if (studentPlacementProfile.cgpa < drive.minCgpa) {
    reasons.push(`Requires minimum CGPA ${drive.minCgpa} (yours: ${studentPlacementProfile.cgpa})`);
  }
  if (studentPlacementProfile.backlogs > drive.maxBacklogs) {
    reasons.push(`Allows up to ${drive.maxBacklogs} backlog(s) (yours: ${studentPlacementProfile.backlogs})`);
  }
  if (drive.branches.length && !drive.branches.includes(studentPlacementProfile.branch)) {
    reasons.push(`Not open to ${studentPlacementProfile.branch} branch`);
  }
  return { eligible: reasons.length === 0, reasons };
};

