const spotlightPosterGrid = document.querySelector("#spotlightPosterGrid");
const spotlightPosterGrids = [...document.querySelectorAll("[data-spotlight-poster-grid]")];


const refreshSpotlightNewTag = () => {
  if (!spotlightGrid) return;
  const registrationCard = spotlightGrid.querySelector("[data-registration-notice]");
  if (registrationCard && spotlightGrid.firstElementChild !== registrationCard) {
    spotlightGrid.prepend(registrationCard);
  }
  const normalizeNewBadge = (strong) => {
    const badges = [...strong.querySelectorAll("em, .notice-board-new")];
    badges.forEach((badge, index) => {
      if (index > 0) badge.remove();
    });
    return badges[0] || null;
  };
  let hasTaggedNewItem = false;
  Array.from(spotlightGrid.children).forEach((article, index) => {
    if (article.matches("[data-registration-notice]")) return;
    const strong = article.querySelector(".spotlight-card-body > strong") || article.querySelector(".notice-board-body h3") || article.querySelector(":scope > strong") || article.querySelector("strong");
    if (!strong) return;
    const existingEm = normalizeNewBadge(strong);
    if (!hasTaggedNewItem && !article.matches("[data-spotlight-event], [data-registration-notice]")) {
      hasTaggedNewItem = true;
      article.classList.add("is-new");
      if (!existingEm) {
        const em = document.createElement(strong.matches(".notice-board-body h3") ? "span" : "em");
        if (strong.matches(".notice-board-body h3")) em.className = "notice-board-new";
        em.textContent = "New";
        strong.appendChild(em);
      }
    } else {
      article.classList.remove("is-new");
      existingEm?.remove();
    }
  });
};

const renderPlacementSpotlight = () => {
  if (!spotlightGrid) return;
  spotlightGrid.querySelectorAll("[data-spotlight-placement]").forEach((article) => article.remove());
  const today = new Date(new Date().toDateString());
  const upcomingDrives = getPlacementDrives()
    .filter((drive) => new Date(drive.date) >= today)
    .sort((a, b) => (b.addedAt || 0) - (a.addedAt || 0));

  const spotlightCopyByType = {
    Placement: (drive) => `<strong>Placement</strong><span>${drive.company} is hiring for ${drive.role} (${drive.ctc}) on ${formatExamDate(drive.date)}. Open Placement Drives to check eligibility and apply.</span>`,
    Internship: (drive) => `<strong>Internship</strong><span>${drive.company} is hiring for ${drive.role} (${drive.ctc}) on ${formatExamDate(drive.date)}. Open Internship Drives to check eligibility and apply.</span>`,
    "Mock Interview": (drive) => `<strong>Mock Interview</strong><span>${drive.company} on ${formatExamDate(drive.date)}. Open Mock Interviews to register.</span>`,
    "Aptitude Test": (drive) => `<strong>Aptitude Test</strong><span>${drive.company} on ${formatExamDate(drive.date)}. Open Aptitude Tests to register.</span>`,
    "Job Recommendation": (drive) => `<strong>Job Recommendation</strong><span>${drive.company} is hiring for ${drive.role}. Open Job Recommendations to view and apply.</span>`
  };
  const articles = upcomingDrives.map((drive) => {
    const article = document.createElement("article");
    article.setAttribute("data-spotlight-placement", drive.id);
    const buildCopy = spotlightCopyByType[drive.driveType || "Placement"] || spotlightCopyByType.Placement;
    article.innerHTML = buildCopy(drive);
    return article;
  });
  if (articles.length) spotlightGrid.prepend(...articles);

  refreshSpotlightNewTag();
};

// Spotlight Posters: admin-published promotional images (event posters, college posters, general
// ads) shown in the same Spotlight feed as notices/placement drives - reuses the exact
// data-spotlight-{x}/remove-then-reinsert-then-refreshSpotlightNewTag pattern already established
// by renderPlacementSpotlight/renderAdminNoticesInto above, just with a poster thumbnail image.
const getSpotlightPosters = () => getSiteContent("spotlightPosters", []);
const saveSpotlightPosters = (posters) => saveSiteContent("spotlightPosters", posters);
