const credentialStatusBody = document.querySelector("#credentialStatusBody");
const setCredentialButton = document.querySelector("#setCredentialButton");
if (credentialStatusBody || setCredentialButton) {
  const credentialAddFeedback = document.querySelector("#credentialAddFeedback");
  const roleTypeLabels = { admin: "Admin", faculty: "Faculty", non_teaching: "Non-Teaching Staff" };

  const renderCredentialStatus = () => {
    if (!credentialStatusBody) return;
    const rows = gprecAuthGet("/credentials") || [];
    credentialStatusBody.innerHTML = rows.length
      ? rows
          .map((row) => `<tr><td>${row.email}</td><td>${roleTypeLabels[row.roleType] || row.roleType}</td><td><span class="${row.mustChangePassword ? "warn" : "ok"}">${row.mustChangePassword ? "Must change on next login" : "Active"}</span></td><td>${row.passwordSetAt || "-"}</td></tr>`)
          .join("")
      : `<tr><td colspan="4">No login credentials set yet.</td></tr>`;
  };

  renderCredentialStatus();

  setCredentialButton?.addEventListener("click", () => {
    const roleType = document.querySelector("#credentialRoleType")?.value || "admin";
    const email = document.querySelector("#credentialEmail")?.value.trim().toLowerCase() || "";
    const recoveryMobile = document.querySelector("#credentialMobile")?.value.trim() || "";
    if (!email || !recoveryMobile) {
      if (credentialAddFeedback) {
        credentialAddFeedback.textContent = "Enter an email and recovery mobile before generating a password.";
        credentialAddFeedback.classList.remove("success");
      }
      return;
    }
    const result = gprecAuthPost("/set-password", { email, roleType, recoveryMobile });
    if (!result?.ok) {
      if (credentialAddFeedback) {
        credentialAddFeedback.textContent = "Could not reach the login server. Make sure the portal API is running.";
        credentialAddFeedback.classList.remove("success");
      }
      return;
    }
    if (credentialAddFeedback) {
      credentialAddFeedback.textContent = `Password for ${email}: ${result.generatedPassword} (shown once - share it securely, they'll be asked to change it on first login).`;
      credentialAddFeedback.classList.add("success");
    }
    recordActivity(`Set login credentials for ${email} (${roleType})`, "Users & Access");
    renderCredentialStatus();
  });
}

// Mirrors the .application-card ids/amounts hardcoded in student-dashboard.html and
// certificate-request.html - admin overrides here are picked up wherever that "application" id
// is used. Dynamic per-unit fees (backlog fee per subject, mess advance per plan) aren't listed
// here since they're computed, not flat amounts.
const feeAmountDefaults = [
  { feeType: "Exam Fee", application: "regular-exam", label: "Regular Examination", defaultAmount: 850 },
  { feeType: "Exam Fee", application: "supplementary-exam", label: "Supplementary Examination", defaultAmount: 1200 },
  { feeType: "Exam Fee", application: "revaluation", label: "Revaluation", defaultAmount: 500 },
  { feeType: "Certificate Fee", application: "bonafide", label: "Bona fide Certificate", defaultAmount: 100 },
  { feeType: "Certificate Fee", application: "cmm", label: "CMM", defaultAmount: 200 },
  { feeType: "Certificate Fee", application: "study-conduct", label: "Study and Conduct", defaultAmount: 100 },
  { feeType: "Certificate Fee", application: "tc", label: "Transfer Certificate", defaultAmount: 300 },
  { feeType: "Certificate Fee", application: "provisional", label: "Provisional Certificate", defaultAmount: 500 },
  { feeType: "Condonation Fee", application: "condonation-standard", label: "Condonation (65% - 74%)", defaultAmount: 500 },
  { feeType: "Condonation Fee", application: "condonation-committee", label: "Condonation (Below 65%)", defaultAmount: 1000 },
  { feeType: "Lost ID Card", application: "lost-id", label: "Lost ID Card", defaultAmount: 150 },
  { feeType: "T&P Fee", application: "tp-fee", label: "Training & Placement Fee", defaultAmount: 2500 },
  { feeType: "Transportation Fee", application: "transportation-fee", label: "Bus Service Fee", defaultAmount: 3000 }
];

const feeAmountBody = document.querySelector("#feeAmountBody");
if (feeAmountBody) {
  const renderFeeAmountTable = () => {
    const overrides = getFeeAmountOverrides();
    feeAmountBody.innerHTML = feeAmountDefaults
      .map((fee) => {
        const currentAmount = overrides[fee.application] !== undefined ? overrides[fee.application] : fee.defaultAmount;
        return `
          <tr>
            <td>${fee.feeType}</td>
            <td>${fee.label}</td>
            <td><input type="number" min="0" data-fee-amount-input="${fee.application}" value="${currentAmount}"></td>
            <td><button type="button" data-fee-amount-save="${fee.application}">Save</button></td>
          </tr>
        `;
      })
      .join("");

    feeAmountBody.querySelectorAll("[data-fee-amount-save]").forEach((button) => {
      button.addEventListener("click", () => {
        const appId = button.dataset.feeAmountSave;
        const amountInput = feeAmountBody.querySelector(`[data-fee-amount-input="${appId}"]`);
        const value = Number(amountInput?.value);
        if (!value || value < 0) return;
        const result = setFeeAmountOverride(appId, value);
        if (!result?.ok) {
          showFeedToast("Could not reach the portal API to save this fee amount.");
          return;
        }
        const fee = feeAmountDefaults.find((entry) => entry.application === appId);
        showFeedToast(`${fee?.label || appId} amount updated to Rs. ${value.toLocaleString("en-IN")}.`);
      });
    });
  };
  renderFeeAmountTable();
}

const pendingFeeOverrideBody = document.querySelector("#pendingFeeOverrideBody");
const pendingFeeOverrideEmpty = document.querySelector("#pendingFeeOverrideEmpty");
const pendingFeeCsvInput = document.querySelector("#pendingFeeCsvInput");
const pendingFeeCsvDueDate = document.querySelector("#pendingFeeCsvDueDate");
const pendingFeeCsvUploadButton = document.querySelector("#pendingFeeCsvUploadButton");
const pendingFeeCsvSampleButton = document.querySelector("#pendingFeeCsvSampleButton");
const pendingFeeCsvFeedback = document.querySelector("#pendingFeeCsvFeedback");

if (pendingFeeOverrideBody) {
  const renderPendingFeeOverrideTable = () => {
    const overrides = getStudentPendingFeeOverrides();
    const rows = [];
    Object.entries(overrides).forEach(([roll, fees]) => {
      fees.forEach((fee, index) => rows.push({ roll, index, ...fee }));
    });
    pendingFeeOverrideEmpty?.classList.toggle("is-hidden", rows.length > 0);
    pendingFeeOverrideBody.innerHTML = rows
      .map(
        (row) => `
          <tr>
            <td>${row.roll}</td>
            <td>${row.feeType}</td>
            <td>${row.detail || "-"}</td>
            <td>Rs. ${Number(row.totalFee || 0).toLocaleString("en-IN")}</td>
            <td>Rs. ${Number(row.paidAmount || 0).toLocaleString("en-IN")}</td>
            <td>Rs. ${Number(row.amount).toLocaleString("en-IN")}</td>
            <td>${formatExamDate(row.dueDate)}</td>
            <td><button type="button" class="icon-btn-delete" data-remove-pending-fee="${row.roll}|${row.index}" aria-label="Remove" title="Remove">${deleteIconSvg}</button></td>
          </tr>
        `
      )
      .join("");

    pendingFeeOverrideBody.querySelectorAll("[data-remove-pending-fee]").forEach((button) => {
      button.addEventListener("click", () => {
        const [roll, index] = button.dataset.removePendingFee.split("|");
        const current = getStudentPendingFeeOverrides();
        if (current[roll]) {
          current[roll].splice(Number(index), 1);
          if (current[roll].length === 0) delete current[roll];
        }
        saveStudentPendingFeeOverrides(current);
        renderPendingFeeOverrideTable();
        showFeedToast(`Removed a pending fee row for ${roll}.`);
      });
    });
  };

  renderPendingFeeOverrideTable();

  // Deliberately simple comma-split parsing (no quoted-field support) - fine for a plain
  // Roll Number / Fee Type / amounts CSV exported from Excel, and avoids pulling in a full CSV
  // parsing library for this one admin-only upload form. Due date isn't a column here - the
  // admin picks one due date that applies to the whole uploaded file, via the date field above.
  const parsePendingFeeCsv = (text, dueDate) => {
    const lines = text.split(/\r?\n/).map((line) => line.trim()).filter(Boolean);
    const dataLines = /roll\s*number/i.test(lines[0] || "") ? lines.slice(1) : lines;
    const overrides = {};
    let skippedRows = 0;
    let appliedRows = 0;
    dataLines.forEach((line) => {
      const [rollRaw, feeTypeRaw, detailRaw, totalFeeRaw, paidAmountRaw, applicationRaw] = line
        .split(",")
        .map((cell) => cell.trim());
      const roll = (rollRaw || "").toUpperCase();
      const totalFee = Number(totalFeeRaw) || 0;
      const paidAmount = Number(paidAmountRaw) || 0;
      const pendingAmount = totalFee - paidAmount;
      if (!roll || !feeTypeRaw || pendingAmount <= 0) {
        skippedRows += 1;
        return;
      }
      if (!overrides[roll]) overrides[roll] = [];
      overrides[roll].push({
        feeType: feeTypeRaw,
        detail: detailRaw || feeTypeRaw,
        totalFee,
        paidAmount,
        amount: pendingAmount,
        dueDate,
        application: applicationRaw || feeTypeRaw.toLowerCase().replace(/\s+/g, "-")
      });
      appliedRows += 1;
    });
    return { overrides, appliedRows, skippedRows };
  };

  pendingFeeCsvUploadButton?.addEventListener("click", () => {
    const file = pendingFeeCsvInput?.files?.[0];
    const dueDate = pendingFeeCsvDueDate?.value;
    if (!dueDate) {
      if (pendingFeeCsvFeedback) {
        pendingFeeCsvFeedback.textContent = "Select a due date for this upload first.";
        pendingFeeCsvFeedback.classList.remove("success");
      }
      return;
    }
    if (!file) {
      if (pendingFeeCsvFeedback) {
        pendingFeeCsvFeedback.textContent = "Choose a CSV file first.";
        pendingFeeCsvFeedback.classList.remove("success");
      }
      return;
    }
    const reader = new FileReader();
    reader.onload = () => {
      const { overrides: newOverrides, appliedRows, skippedRows } = parsePendingFeeCsv(String(reader.result || ""), dueDate);
      if (appliedRows === 0) {
        if (pendingFeeCsvFeedback) {
          pendingFeeCsvFeedback.textContent = "No valid rows found. Check the column order and that Paid Amount is less than Total Fee.";
          pendingFeeCsvFeedback.classList.remove("success");
        }
        return;
      }
      const current = getStudentPendingFeeOverrides();
      Object.entries(newOverrides).forEach(([roll, fees]) => {
        current[roll] = fees;
      });
      saveStudentPendingFeeOverrides(current);
      renderPendingFeeOverrideTable();
      if (pendingFeeCsvFeedback) {
        pendingFeeCsvFeedback.textContent = `Applied ${appliedRows} row(s) across ${Object.keys(newOverrides).length} student(s), due ${dueDate}.${skippedRows ? ` Skipped ${skippedRows} invalid or fully-paid row(s).` : ""}`;
        pendingFeeCsvFeedback.classList.add("success");
      }
      if (pendingFeeCsvInput) pendingFeeCsvInput.value = "";
    };
    reader.readAsText(file);
  });

  pendingFeeCsvSampleButton?.addEventListener("click", () => {
    const sampleCsv = [
      "Roll Number,Fee Type,Detail,Total Fee,Paid Amount,Application",
      "20X51A0501,Tuition Fee,Semester Tuition,48500,20000,semester-tuition",
      "20X51A0502,Tuition Fee,Semester Tuition,48500,48500,semester-tuition",
      "20X51A0503,Exam Fee,Regular Examination,850,0,regular-exam",
      "20X51A0504,Hostel Fee,Room Rent,18000,0,room-rent"
    ].join("\n");
    const blob = new Blob([sampleCsv], { type: "text/csv" });
    const link = document.createElement("a");
    link.href = URL.createObjectURL(blob);
    link.download = "gprec-pending-fee-upload-sample.csv";
    link.click();
  });
}

const gradesCsvInput = document.querySelector("#gradesCsvInput");
const gradesCsvUploadButton = document.querySelector("#gradesCsvUploadButton");
const gradesCsvSampleButton = document.querySelector("#gradesCsvSampleButton");
const gradesCsvFeedback = document.querySelector("#gradesCsvFeedback");
const gradesPreviewRollInput = document.querySelector("#gradesPreviewRollInput");
const gradesPreviewBody = document.querySelector("#gradesPreviewBody");
const gradesPreviewEmpty = document.querySelector("#gradesPreviewEmpty");
const gradesPreviewRollResults = document.querySelector("#gradesPreviewRollResults");
const gradesNotifyButton = document.querySelector("#gradesNotifyButton");
const gradesNotifyFeedback = document.querySelector("#gradesNotifyFeedback");

if (gradesCsvUploadButton) {
  const renderGradesPreview = () => {
    if (!gradesPreviewBody) return;
    const rollNo = gradesPreviewRollInput?.value.trim().toUpperCase() || "";
    const grades = rollNo ? getGprecDbBootstrap()?.studentGrades?.[rollNo] || [] : [];
    gradesPreviewEmpty?.classList.toggle("is-hidden", grades.length > 0);
    if (gradesPreviewEmpty) {
      gradesPreviewEmpty.textContent = !rollNo
        ? "Enter a roll number to preview its grades."
        : "No grades on file for this roll number.";
    }
    gradesPreviewBody.innerHTML = grades
      .map((row) => `<tr><td>${row.term}</td><td>${row.gpa}</td><td>${row.backlogs}</td></tr>`)
      .join("");
    gradesNotifyButton?.classList.toggle("is-hidden", grades.length === 0);
    if (gradesNotifyButton) {
      gradesNotifyButton.dataset.rollNo = rollNo;
      gradesNotifyButton.disabled = false;
      gradesNotifyButton.textContent = "Notify Parent via SMS";
    }
    if (gradesNotifyFeedback) gradesNotifyFeedback.textContent = "";
  };

  // Same search-by-roll-number pattern as the student Project form's teammate picker: type to
  // see real matches, click one to select it - instead of a free-text field or a giant dropdown
  // listing every student.
  gradesPreviewRollInput?.addEventListener("input", () => {
    const query = gradesPreviewRollInput.value.trim().toLowerCase();
    if (!query) {
      gradesPreviewRollResults?.classList.add("is-hidden");
      renderGradesPreview();
      return;
    }
    const matches = (getGprecDbBootstrap()?.studentDirectory || []).filter((student) =>
      student.studentId.toLowerCase().includes(query)
    );
    if (gradesPreviewRollResults) {
      gradesPreviewRollResults.innerHTML = matches.length
        ? matches
            .slice(0, 20)
            .map((student) => `<button type="button" data-pick-grades-roll="${student.studentId}">${student.name} (${student.studentId})</button>`)
            .join("")
        : `<p class="portal-note">No matching students.</p>`;
      gradesPreviewRollResults.classList.remove("is-hidden");
    }
  });

  gradesPreviewRollResults?.addEventListener("click", (event) => {
    const button = event.target.closest("[data-pick-grades-roll]");
    if (!button) return;
    if (gradesPreviewRollInput) gradesPreviewRollInput.value = button.dataset.pickGradesRoll;
    gradesPreviewRollResults.classList.add("is-hidden");
    renderGradesPreview();
  });

  renderGradesPreview();

  gradesNotifyButton?.addEventListener("click", () => {
    const rollNo = gradesNotifyButton.dataset.rollNo || "";
    const grades = rollNo ? getGprecDbBootstrap()?.studentGrades?.[rollNo] || [] : [];
    const latest = grades[grades.length - 1];
    if (!rollNo || !latest) return;
    const student = (getGprecDbBootstrap()?.studentDirectory || []).find((item) => item.studentId === rollNo);
    const message = `your ward ${student?.name || rollNo}'s result for ${latest.term} is out - GPA ${latest.gpa}, Backlogs: ${latest.backlogs}`;
    gradesNotifyButton.disabled = true;
    gradesNotifyButton.textContent = "Sending...";
    const result = gprecDbRequest("/notify/parent", { method: "POST", body: { rollNo, kind: "grades", message } });
    if (result?.ok) {
      if (gradesNotifyFeedback) {
        gradesNotifyFeedback.textContent = `Sent successfully via ${result.channel === "whatsapp" ? "WhatsApp" : "SMS"}.`;
        gradesNotifyFeedback.classList.add("success");
      }
      gradesNotifyButton.textContent = "Notify Parent via SMS";
      gradesNotifyButton.disabled = false;
    } else {
      if (gradesNotifyFeedback) {
        gradesNotifyFeedback.textContent = result?.reason === "no-guardian-mobile"
          ? "No parent mobile number on file for this student."
          : `Could not send: ${result?.error || "gateway not reachable"}.`;
        gradesNotifyFeedback.classList.remove("success");
      }
      gradesNotifyButton.textContent = "Notify Parent via SMS";
      gradesNotifyButton.disabled = false;
    }
  });

  // Deliberately simple comma-split parsing, consistent with the other admin CSV upload forms
  // (Curriculum, Timetable, Pending Fees).
  const parseGradesCsv = (text) => {
    const lines = text.split(/\r?\n/).map((line) => line.trim()).filter(Boolean);
    const dataLines = /roll\s*number/i.test(lines[0] || "") ? lines.slice(1) : lines;
    const rows = [];
    dataLines.forEach((line) => {
      const [rollNo, term, gpa, backlogs] = line.split(",").map((cell) => cell.trim());
      if (!rollNo || !term || !gpa) return;
      rows.push({ rollNo: rollNo.toUpperCase(), term, gpa, backlogs: backlogs || "NIL" });
    });
    return rows;
  };

  gradesCsvUploadButton.addEventListener("click", () => {
    const file = gradesCsvInput?.files?.[0];
    if (!file) {
      if (gradesCsvFeedback) {
        gradesCsvFeedback.textContent = "Choose a CSV file first.";
        gradesCsvFeedback.classList.remove("success");
      }
      return;
    }
    const reader = new FileReader();
    reader.onload = () => {
      const rows = parseGradesCsv(String(reader.result || ""));
      if (rows.length === 0) {
        if (gradesCsvFeedback) {
          gradesCsvFeedback.textContent = "No valid rows found. Check the column order.";
          gradesCsvFeedback.classList.remove("success");
        }
        return;
      }
      const result = gprecDbPost("/grades", { rows });
      if (!result?.ok) {
        if (gradesCsvFeedback) {
          gradesCsvFeedback.textContent = "Could not reach the portal API to save grades. Check that every Roll Number exists.";
          gradesCsvFeedback.classList.remove("success");
        }
        return;
      }
      renderGradesPreview();
      if (gradesCsvFeedback) {
        gradesCsvFeedback.textContent = `Applied ${rows.length} grade record(s).`;
        gradesCsvFeedback.classList.add("success");
      }
      if (gradesCsvInput) gradesCsvInput.value = "";
    };
    reader.readAsText(file);
  });

  gradesCsvSampleButton?.addEventListener("click", () => {
    const sampleCsv = [
      "Roll Number,Term,GPA,Backlogs",
      "20X51A0501,I - I,8.32,NIL",
      "20X51A0501,I - II,8.58,NIL",
      "20X51A0502,I - I,7.64,NIL"
    ].join("\n");
    const blob = new Blob([sampleCsv], { type: "text/csv" });
    const link = document.createElement("a");
    link.href = URL.createObjectURL(blob);
    link.download = "gprec-grades-upload-sample.csv";
    link.click();
  });
}

// Shared by the Academic/Financial report exports below - CSV field quoting per RFC 4180 (only
// wrap in quotes when the value actually needs it, doubling any embedded quotes).
const csvField = (value) => {
  const text = String(value ?? "");
  return /[",\n]/.test(text) ? `"${text.replace(/"/g, '""')}"` : text;
};
const downloadCsv = (filename, headers, rows) => {
  const csv = [headers, ...rows].map((row) => row.map(csvField).join(",")).join("\r\n");
  const blob = new Blob([csv], { type: "text/csv" });
  const link = document.createElement("a");
  link.href = URL.createObjectURL(blob);
  link.download = filename;
  link.click();
};

const generateAcademicReportButton = document.querySelector("#generateAcademicReportButton");
generateAcademicReportButton?.addEventListener("click", () => {
  const reportType = document.querySelector("#academicReportType")?.value || "attendance";
  const bootstrap = getGprecDbBootstrap() || {};

  if (reportType === "attendance") {
    const rows = (bootstrap.attendanceRecords || []).flatMap((record) =>
      (record.entries || []).map((entry) => [record.date, record.subject, record.section, entry.studentId, entry.present ? "Present" : "Absent"])
    );
    downloadCsv("gprec-attendance-report.csv", ["Date", "Subject", "Section", "Roll Number", "Status"], rows);
  } else if (reportType === "assignments") {
    const rows = (bootstrap.assignments || []).map((item) => [item.department, item.subjectCode, item.title, item.dueDate, item.createdAt]);
    downloadCsv("gprec-assignments-report.csv", ["Department", "Subject Code", "Title", "Due Date", "Created At"], rows);
  } else if (reportType === "results") {
    const rows = Object.entries(bootstrap.studentGrades || {}).flatMap(([rollNo, terms]) =>
      terms.map((term) => [rollNo, term.term, term.gpa, term.backlogs])
    );
    downloadCsv("gprec-results-report.csv", ["Roll Number", "Term", "GPA", "Backlogs"], rows);
  } else if (reportType === "timetable") {
    const rows = Object.entries(bootstrap.classTimetable || {}).flatMap(([department, slots]) =>
      slots.map((slot) => [department, slot.section, slot.day, slot.time, slot.code, slot.subject, slot.facultyEmail])
    );
    downloadCsv("gprec-timetable-report.csv", ["Department", "Section", "Day", "Time", "Subject Code", "Subject", "Faculty Email"], rows);
  }
});

const openFinanceExportButton = document.querySelector("#openFinanceExportButton");
