// Data Retention Policy panel - read-only classification (which table falls under which
// retention behavior/period/disposal action) plus an on-demand "Check Retention Status" dry-run
// that reports how many rows in each table are past their cutoff. Deliberately never deletes or
// archives anything itself - purge/archival stays a manual, reviewed action for an admin to take
// after reading this report.
const dataRetentionBody = document.querySelector("#dataRetentionBody");
if (dataRetentionBody) {
  const checkRetentionStatusButton = document.querySelector("#checkRetentionStatusButton");
  const dataRetentionCheckFeedback = document.querySelector("#dataRetentionCheckFeedback");
  const dataRetentionResultsCard = document.querySelector("#dataRetentionResultsCard");
  const dataRetentionResultsBody = document.querySelector("#dataRetentionResultsBody");
  const dataRetentionResultsEmpty = document.querySelector("#dataRetentionResultsEmpty");

  const policiesByCode = Object.fromEntries(
    (getGprecDbBootstrap()?.dataRetentionPolicies || []).map((policy) => [policy.policyCode, policy])
  );
  const tablePolicies = getGprecDbBootstrap()?.dataRetentionTablePolicies || [];

  const formatRetention = (policy) =>
    policy?.retentionMonths == null
      ? "Indefinite"
      : policy.retentionMonths % 12 === 0
        ? `${policy.retentionMonths / 12} year${policy.retentionMonths / 12 > 1 ? "s" : ""}`
        : `${policy.retentionMonths} months`;

  dataRetentionBody.innerHTML = tablePolicies
    .map((row) => {
      const policy = policiesByCode[row.policyCode];
      return `
        <tr>
          <td>${row.tableName}</td>
          <td>${row.ownerModule}</td>
          <td>${policy?.behavior || row.policyCode}</td>
          <td>${formatRetention(policy)}</td>
          <td>${row.containsPii ? "Yes" : "No"}</td>
          <td>${policy?.disposalAction || "-"}</td>
        </tr>
      `;
    })
    .join("");

  checkRetentionStatusButton?.addEventListener("click", () => {
    checkRetentionStatusButton.disabled = true;
    if (dataRetentionCheckFeedback) {
      dataRetentionCheckFeedback.textContent = "Checking...";
      dataRetentionCheckFeedback.classList.remove("success");
    }
    const response = gprecDbRequest("/data-retention/check");
    checkRetentionStatusButton.disabled = false;
    if (!response?.ok) {
      if (dataRetentionCheckFeedback) {
        dataRetentionCheckFeedback.textContent = "Could not reach the database server - try again.";
        dataRetentionCheckFeedback.classList.remove("success");
      }
      return;
    }
    const eligible = (response.results || []).filter((row) => row.eligibleCount > 0);
    dataRetentionResultsCard?.classList.remove("is-hidden");
    dataRetentionResultsEmpty?.classList.toggle("is-hidden", eligible.length > 0);
    if (dataRetentionResultsBody) {
      dataRetentionResultsBody.innerHTML = eligible
        .map((row) => {
          const policy = policiesByCode[row.policyCode];
          return `<tr><td>${row.tableName}</td><td>${formatRetention(policy)}</td><td>${row.eligibleCount}</td></tr>`;
        })
        .join("");
    }
    if (dataRetentionCheckFeedback) {
      dataRetentionCheckFeedback.textContent = `Checked ${response.results.length} tables as of ${new Date(response.checkedAt * 1000).toLocaleString("en-IN", { day: "2-digit", month: "short", hour: "2-digit", minute: "2-digit" })}.`;
      dataRetentionCheckFeedback.classList.add("success");
    }
  });
}

const libraryApiBaseUrl = document.querySelector("#libraryApiBaseUrl");
const libraryApiKey = document.querySelector("#libraryApiKey");
const libraryApiSaveButton = document.querySelector("#libraryApiSaveButton");
const libraryApiTestButton = document.querySelector("#libraryApiTestButton");
const libraryApiClearButton = document.querySelector("#libraryApiClearButton");
const libraryApiFeedback = document.querySelector("#libraryApiFeedback");
const libraryApiStatus = document.querySelector("#libraryApiStatus");

if (libraryApiStatus) {
  const renderLibraryApiStatus = () => {
    const config = getLibraryApiConfig();
    if (config?.baseUrl) {
      libraryApiStatus.innerHTML = `<span class="ok">Connected</span> to ${config.baseUrl}`;
      if (libraryApiBaseUrl) libraryApiBaseUrl.value = config.baseUrl;
      if (libraryApiKey) libraryApiKey.value = config.apiKey || "";
    } else {
      libraryApiStatus.innerHTML = `<span class="warn">Not connected</span> - enter the library system's API details above`;
    }
  };

  renderLibraryApiStatus();
  onAdminConfigLoaded(renderLibraryApiStatus);

  libraryApiSaveButton?.addEventListener("click", () => {
    const baseUrl = libraryApiBaseUrl?.value.trim().replace(/\/$/, "") || "";
    const apiKey = libraryApiKey?.value.trim() || "";
    if (!baseUrl) {
      if (libraryApiFeedback) {
        libraryApiFeedback.textContent = "Enter the API Base URL.";
        libraryApiFeedback.classList.remove("success");
      }
      return;
    }
    saveLibraryApiConfig({ baseUrl, apiKey });
    renderLibraryApiStatus();
    if (libraryApiFeedback) {
      libraryApiFeedback.textContent = `Saved. Book scans will now try ${baseUrl} first.`;
      libraryApiFeedback.classList.add("success");
    }
    persistIntegrationSettings(libraryApiFeedback, "Library API settings saved.");
  });

  libraryApiTestButton?.addEventListener("click", async () => {
    const baseUrl = libraryApiBaseUrl?.value.trim().replace(/\/$/, "") || "";
    if (!baseUrl) {
      if (libraryApiFeedback) {
        libraryApiFeedback.textContent = "Enter the API Base URL first.";
        libraryApiFeedback.classList.remove("success");
      }
      return;
    }
    if (libraryApiFeedback) {
      libraryApiFeedback.textContent = "Testing connection...";
      libraryApiFeedback.classList.remove("success");
    }
    try {
      const response = await fetch(`${baseUrl}/catalog`, {
        headers: libraryApiHeaders({ apiKey: libraryApiKey?.value.trim() }, false)
      });
      if (libraryApiFeedback) {
        libraryApiFeedback.textContent = response.ok
          ? `Connected successfully (HTTP ${response.status}).`
          : `Reached the server but got HTTP ${response.status}. Check the URL and API key.`;
        libraryApiFeedback.classList.toggle("success", response.ok);
      }
    } catch (err) {
      if (libraryApiFeedback) {
        libraryApiFeedback.textContent = `Could not reach ${baseUrl}: ${err.message}. Check the URL and that the API is reachable from this browser.`;
        libraryApiFeedback.classList.remove("success");
      }
    }
  });

  libraryApiClearButton?.addEventListener("click", () => {
    clearLibraryApiConfig();
    if (libraryApiBaseUrl) libraryApiBaseUrl.value = "";
    if (libraryApiKey) libraryApiKey.value = "";
    renderLibraryApiStatus();
    if (libraryApiFeedback) {
      libraryApiFeedback.textContent = "Disconnected from the library API.";
      libraryApiFeedback.classList.add("success");
    }
    persistIntegrationSettings(libraryApiFeedback, "Library API settings cleared.");
  });
}

const smsAuthKeyInput = document.querySelector("#smsAuthKeyInput");
