const smsSettingsFeedback = document.querySelector("#smsSettingsFeedback");
const smsSettingsStatus = document.querySelector("#smsSettingsStatus");
const smsTestMobileInput = document.querySelector("#smsTestMobileInput");
const smsTestButton = document.querySelector("#smsTestButton");
const smsTestFeedback = document.querySelector("#smsTestFeedback");
const smsWhatsappNumberInput = document.querySelector("#smsWhatsappNumberInput");
const smsWhatsappTemplateInput = document.querySelector("#smsWhatsappTemplateInput");
const smsWhatsappBodyVarInput = document.querySelector("#smsWhatsappBodyVarInput");
const smsGradesTemplateIdInput = document.querySelector("#smsGradesTemplateIdInput");
const smsGradesTemplateVariableInput = document.querySelector("#smsGradesTemplateVariableInput");
const smsGradesWhatsappTemplateInput = document.querySelector("#smsGradesWhatsappTemplateInput");
const smsAttendanceTemplateIdInput = document.querySelector("#smsAttendanceTemplateIdInput");
const smsAttendanceTemplateVariableInput = document.querySelector("#smsAttendanceTemplateVariableInput");
const smsAttendanceWhatsappTemplateInput = document.querySelector("#smsAttendanceWhatsappTemplateInput");
const smsSettingsSaveButtonBottom = document.querySelector("#smsSettingsSaveButtonBottom");
const smsSettingsFeedbackBottom = document.querySelector("#smsSettingsFeedbackBottom");

if (smsSettingsStatus) {
  const renderSmsSettingsStatus = () => {
    const settings = getSmsSettings();
    const smsReady = Boolean(settings?.authKey && settings?.templateId);
    const waReady = Boolean(settings?.authKey && settings?.whatsappIntegratedNumber && settings?.whatsappTemplateName);
    if (smsReady) {
      smsSettingsStatus.innerHTML = `<span class="ok">SMS configured</span> - template ${settings.templateId}${waReady ? " (WhatsApp fallback ready)" : ""}`;
    } else if (waReady) {
      smsSettingsStatus.innerHTML = `<span class="ok">WhatsApp configured</span> - SMS not set up, OTPs deliver over WhatsApp`;
    } else {
      smsSettingsStatus.innerHTML = `<span class="warn">Not configured</span> - parent OTPs will only show on-screen`;
    }
    if (smsAuthKeyInput) smsAuthKeyInput.value = settings?.authKey || "";
    if (smsSenderIdInput) smsSenderIdInput.value = settings?.senderId || "";
    if (smsTemplateIdInput) smsTemplateIdInput.value = settings?.templateId || "";
    if (smsTemplateVariableInput) smsTemplateVariableInput.value = settings?.templateVariable || "OTP";
    if (smsWhatsappNumberInput) smsWhatsappNumberInput.value = settings?.whatsappIntegratedNumber || "";
    if (smsWhatsappTemplateInput) smsWhatsappTemplateInput.value = settings?.whatsappTemplateName || "";
    if (smsWhatsappBodyVarInput) smsWhatsappBodyVarInput.value = settings?.whatsappBodyVariable || "body_1";
    const notifications = { ...defaultSmsNotifications, ...(settings?.notifications || {}) };
    if (smsGradesTemplateIdInput) smsGradesTemplateIdInput.value = notifications.gradesTemplateId;
    if (smsGradesTemplateVariableInput) smsGradesTemplateVariableInput.value = notifications.gradesTemplateVariable;
    if (smsGradesWhatsappTemplateInput) smsGradesWhatsappTemplateInput.value = notifications.whatsappGradesTemplateName;
    if (smsAttendanceTemplateIdInput) smsAttendanceTemplateIdInput.value = notifications.attendanceTemplateId;
    if (smsAttendanceTemplateVariableInput) smsAttendanceTemplateVariableInput.value = notifications.attendanceTemplateVariable;
    if (smsAttendanceWhatsappTemplateInput) smsAttendanceWhatsappTemplateInput.value = notifications.whatsappAttendanceTemplateName;
  };
  renderSmsSettingsStatus();
  onAdminConfigLoaded(renderSmsSettingsStatus);

  // Every field in this card (OTP, WhatsApp fallback, Grades/Attendance notification templates)
  // lives in the one smsSettings object, so either Save button - the one near the top by the OTP
  // fields, or this one at the bottom by the Grades/Attendance fields - saves everything at once.
  const saveAllSmsSettings = (feedbackEl) => {
    saveSmsSettings({
      provider: "msg91",
      authKey: smsAuthKeyInput?.value.trim() || "",
      senderId: smsSenderIdInput?.value.trim() || "",
      templateId: smsTemplateIdInput?.value.trim() || "",
      templateVariable: smsTemplateVariableInput?.value.trim() || "OTP",
      whatsappIntegratedNumber: smsWhatsappNumberInput?.value.trim() || "",
      whatsappTemplateName: smsWhatsappTemplateInput?.value.trim() || "",
      whatsappBodyVariable: smsWhatsappBodyVarInput?.value.trim() || "body_1",
      notifications: {
        gradesTemplateId: smsGradesTemplateIdInput?.value.trim() || "",
        gradesTemplateVariable: smsGradesTemplateVariableInput?.value.trim() || "MESSAGE",
        whatsappGradesTemplateName: smsGradesWhatsappTemplateInput?.value.trim() || "",
        attendanceTemplateId: smsAttendanceTemplateIdInput?.value.trim() || "",
        attendanceTemplateVariable: smsAttendanceTemplateVariableInput?.value.trim() || "MESSAGE",
        whatsappAttendanceTemplateName: smsAttendanceWhatsappTemplateInput?.value.trim() || ""
      }
    });
    renderSmsSettingsStatus();
    persistIntegrationSettings(feedbackEl, "SMS settings saved.");
  };

  smsSettingsSaveButton?.addEventListener("click", () => saveAllSmsSettings(smsSettingsFeedback));
  smsSettingsSaveButtonBottom?.addEventListener("click", () => saveAllSmsSettings(smsSettingsFeedbackBottom));

  smsTestButton?.addEventListener("click", () => {
    const mobile = smsTestMobileInput?.value.trim() || "";
    if (!mobile) {
      if (smsTestFeedback) {
        smsTestFeedback.textContent = "Enter a mobile number first.";
        smsTestFeedback.classList.remove("success");
      }
      return;
    }
    if (smsTestFeedback) {
      smsTestFeedback.textContent = "Sending test OTP...";
      smsTestFeedback.classList.remove("success");
    }
    const result = gprecDbRequest("/sms/test", { method: "POST", body: { mobile } });
    if (smsTestFeedback) {
      if (result?.ok) {
        smsTestFeedback.textContent = `Sent successfully via ${result.channel === "whatsapp" ? "WhatsApp" : "SMS"}.`;
        smsTestFeedback.classList.add("success");
      } else {
        smsTestFeedback.textContent = `Could not send: ${result?.error || "gateway not reachable"}.`;
        smsTestFeedback.classList.remove("success");
      }
    }
  });
}

