const databaseTypeInput = document.querySelector("#databaseTypeInput");
const databaseApiBaseUrl = document.querySelector("#databaseApiBaseUrl");
const databaseApiKey = document.querySelector("#databaseApiKey");
const phpBaseUrlInput = document.querySelector("#phpBaseUrlInput");
const phpUsernameInput = document.querySelector("#phpUsernameInput");
const phpPasswordInput = document.querySelector("#phpPasswordInput");
const mysqlHostInput = document.querySelector("#mysqlHostInput");
const mysqlPortInput = document.querySelector("#mysqlPortInput");
const mysqlDatabaseInput = document.querySelector("#mysqlDatabaseInput");
const mysqlUserInput = document.querySelector("#mysqlUserInput");
const mysqlPasswordInput = document.querySelector("#mysqlPasswordInput");
const mysqlJdbcPreview = document.querySelector("#mysqlJdbcPreview");
const postgresHostInput = document.querySelector("#postgresHostInput");
const postgresPortInput = document.querySelector("#postgresPortInput");
const postgresDatabaseInput = document.querySelector("#postgresDatabaseInput");
const postgresUserInput = document.querySelector("#postgresUserInput");
const postgresPasswordInput = document.querySelector("#postgresPasswordInput");
const postgresJdbcPreview = document.querySelector("#postgresJdbcPreview");
const databaseApiSaveButton = document.querySelector("#databaseApiSaveButton");
const databaseApiTestButton = document.querySelector("#databaseApiTestButton");
const databaseApiClearButton = document.querySelector("#databaseApiClearButton");
const databaseApiFeedback = document.querySelector("#databaseApiFeedback");
const databaseApiStatus = document.querySelector("#databaseApiStatus");
const databaseFieldGroups = document.querySelectorAll("[data-database-fields]");

if (databaseApiStatus) {
  const buildJdbcUrl = (jdbcDriver, host, port, database) =>
    `jdbc:${jdbcDriver}://${host || "host"}:${port || (jdbcDriver === "mysql" ? "3306" : "5432")}/${database || "database"}`;

  const updateJdbcPreviews = () => {
    if (mysqlJdbcPreview) {
      mysqlJdbcPreview.textContent = buildJdbcUrl("mysql", mysqlHostInput?.value.trim(), mysqlPortInput?.value.trim(), mysqlDatabaseInput?.value.trim());
    }
    if (postgresJdbcPreview) {
      postgresJdbcPreview.textContent = buildJdbcUrl("postgresql", postgresHostInput?.value.trim(), postgresPortInput?.value.trim(), postgresDatabaseInput?.value.trim());
    }
  };

  const showDatabaseFields = (type) => {
    databaseFieldGroups.forEach((group) => {
      group.classList.toggle("is-hidden", !group.dataset.databaseFields.split(",").includes(type));
    });
  };

  const renderDatabaseApiStatus = () => {
    const config = getDatabaseApiConfig();
    if (!config?.type) {
      databaseApiStatus.innerHTML = `<span class="warn">Not connected</span> - configure PostgreSQL or a backend API before launch`;
      return;
    }
    if (config.type === "rest") {
      databaseApiStatus.innerHTML = `<span class="ok">Connected</span> to ${config.baseUrl}`;
      if (databaseApiBaseUrl) databaseApiBaseUrl.value = config.baseUrl || "";
      if (databaseApiKey) databaseApiKey.value = config.apiKey || "";
    } else if (config.type === "php") {
      databaseApiStatus.innerHTML = `<span class="ok">Connected</span> to ${config.baseUrl} (HTTP Basic Auth)`;
      if (phpBaseUrlInput) phpBaseUrlInput.value = config.baseUrl || "";
      if (phpUsernameInput) phpUsernameInput.value = config.username || "";
      if (phpPasswordInput) phpPasswordInput.value = config.password || "";
    } else {
      const jdbcUrl = buildJdbcUrl(config.type === "mysql" ? "mysql" : "postgresql", config.host, config.port, config.database);
      databaseApiStatus.innerHTML = `<span class="ok">Recorded</span> - ${jdbcUrl} (JDBC connections can't be verified from a browser)`;
      if (config.type === "mysql") {
        if (mysqlHostInput) mysqlHostInput.value = config.host || "";
        if (mysqlPortInput) mysqlPortInput.value = config.port || "";
        if (mysqlDatabaseInput) mysqlDatabaseInput.value = config.database || "";
        if (mysqlUserInput) mysqlUserInput.value = config.username || "";
        if (mysqlPasswordInput) mysqlPasswordInput.value = config.password || "";
      } else {
        if (postgresHostInput) postgresHostInput.value = config.host || "";
        if (postgresPortInput) postgresPortInput.value = config.port || "";
        if (postgresDatabaseInput) postgresDatabaseInput.value = config.database || "";
        if (postgresUserInput) postgresUserInput.value = config.username || "";
        if (postgresPasswordInput) postgresPasswordInput.value = config.password || "";
      }
    }
    if (databaseTypeInput) databaseTypeInput.value = config.type;
    showDatabaseFields(config.type);
    updateJdbcPreviews();
  };

  renderDatabaseApiStatus();
  onAdminConfigLoaded(renderDatabaseApiStatus);
  updateJdbcPreviews();
  showDatabaseFields(databaseTypeInput?.value || "rest");

  databaseTypeInput?.addEventListener("change", () => {
    showDatabaseFields(databaseTypeInput.value);
    updateJdbcPreviews();
  });

  [mysqlHostInput, mysqlPortInput, mysqlDatabaseInput, postgresHostInput, postgresPortInput, postgresDatabaseInput].forEach((input) => {
    input?.addEventListener("input", updateJdbcPreviews);
  });

  databaseApiSaveButton?.addEventListener("click", () => {
    const type = databaseTypeInput?.value || "rest";
    if (type === "rest") {
      const baseUrl = databaseApiBaseUrl?.value.trim().replace(/\/$/, "") || "";
      const apiKey = databaseApiKey?.value.trim() || "";
      if (!baseUrl) {
        if (databaseApiFeedback) {
          databaseApiFeedback.textContent = "Enter the API Base URL.";
          databaseApiFeedback.classList.remove("success");
        }
        return;
      }
      saveDatabaseApiConfig({ type, baseUrl, apiKey });
    } else if (type === "php") {
      const baseUrl = phpBaseUrlInput?.value.trim().replace(/\/$/, "") || "";
      const username = phpUsernameInput?.value.trim() || "";
      const password = phpPasswordInput?.value || "";
      if (!baseUrl) {
        if (databaseApiFeedback) {
          databaseApiFeedback.textContent = "Enter the PHP Endpoint URL.";
          databaseApiFeedback.classList.remove("success");
        }
        return;
      }
      saveDatabaseApiConfig({ type, baseUrl, username, password });
    } else {
      const isMysql = type === "mysql";
      const host = (isMysql ? mysqlHostInput : postgresHostInput)?.value.trim() || "";
      const port = (isMysql ? mysqlPortInput : postgresPortInput)?.value.trim() || "";
      const database = (isMysql ? mysqlDatabaseInput : postgresDatabaseInput)?.value.trim() || "";
      const username = (isMysql ? mysqlUserInput : postgresUserInput)?.value.trim() || "";
      const password = (isMysql ? mysqlPasswordInput : postgresPasswordInput)?.value || "";
      if (!host || !database) {
        if (databaseApiFeedback) {
          databaseApiFeedback.textContent = "Enter at least the Host and Database Name.";
          databaseApiFeedback.classList.remove("success");
        }
        return;
      }
      saveDatabaseApiConfig({ type, host, port, database, username, password });
    }
    renderDatabaseApiStatus();
    if (databaseApiFeedback) {
      databaseApiFeedback.textContent = "Database settings saved. Connect these credentials from the backend service before launch.";
      databaseApiFeedback.classList.add("success");
    }
    persistIntegrationSettings(databaseApiFeedback, "Database settings saved.");
  });

  databaseApiTestButton?.addEventListener("click", async () => {
    const type = databaseTypeInput?.value || "rest";
    if (type === "mysql" || type === "postgres") {
      // A browser can't open this raw connection itself (no JDBC/wire-protocol support in
      // fetch()/XHR), so this asks the portal's own backend server - which can - to try
      // connecting with exactly what's currently typed in these fields, not just whatever was
      // last saved. That's the only way to answer "is this specific host/user/password combo
      // actually reachable?" before committing to it.
      const isMysql = type === "mysql";
      const host = (isMysql ? mysqlHostInput : postgresHostInput)?.value.trim() || "";
      const port = (isMysql ? mysqlPortInput : postgresPortInput)?.value.trim() || "";
      const database = (isMysql ? mysqlDatabaseInput : postgresDatabaseInput)?.value.trim() || "";
      const username = (isMysql ? mysqlUserInput : postgresUserInput)?.value.trim() || "";
      const password = (isMysql ? mysqlPasswordInput : postgresPasswordInput)?.value || "";
      if (!host || !database) {
        if (databaseApiFeedback) {
          databaseApiFeedback.textContent = "Enter at least the Host and Database Name before testing.";
          databaseApiFeedback.classList.remove("success");
        }
        return;
      }
      if (databaseApiFeedback) {
        databaseApiFeedback.textContent = "Testing connection...";
        databaseApiFeedback.classList.remove("success");
      }
      const result = gprecDbRequest("/test-db-connection", { method: "POST", body: { type, host, port, database, username, password } });
      if (databaseApiFeedback) {
        if (!result) {
          databaseApiFeedback.textContent = "Could not reach the portal API server. Make sure tools/portal_db_server.py is running.";
          databaseApiFeedback.classList.remove("success");
        } else if (result.ok) {
          databaseApiFeedback.textContent = `Connected successfully (${result.latencyMs} ms).`;
          databaseApiFeedback.classList.add("success");
        } else {
          databaseApiFeedback.textContent = `Connection failed: ${result.error || "unknown error"}`;
          databaseApiFeedback.classList.remove("success");
        }
      }
      return;
    }
    const isPhp = type === "php";
    const baseUrl = (isPhp ? phpBaseUrlInput : databaseApiBaseUrl)?.value.trim().replace(/\/$/, "") || "";
    if (!baseUrl) {
      if (databaseApiFeedback) {
        databaseApiFeedback.textContent = isPhp ? "Enter the PHP Endpoint URL first." : "Enter the API Base URL first.";
        databaseApiFeedback.classList.remove("success");
      }
      return;
    }
    if (databaseApiFeedback) {
      databaseApiFeedback.textContent = "Testing connection...";
      databaseApiFeedback.classList.remove("success");
    }
    try {
      const headers = isPhp
        ? basicAuthHeaders(phpUsernameInput?.value.trim(), phpPasswordInput?.value)
        : libraryApiHeaders({ apiKey: databaseApiKey?.value.trim() }, false);
      const response = await fetch(baseUrl, { headers });
      if (databaseApiFeedback) {
        databaseApiFeedback.textContent = response.ok
          ? `Connected successfully (HTTP ${response.status}).`
          : `Reached the server but got HTTP ${response.status}. Check the URL and ${isPhp ? "username/password" : "API key"}.`;
        databaseApiFeedback.classList.toggle("success", response.ok);
      }
    } catch (err) {
      if (databaseApiFeedback) {
        databaseApiFeedback.textContent = `Could not reach ${baseUrl}: ${err.message}. Check the URL and that the server is reachable from this browser.`;
        databaseApiFeedback.classList.remove("success");
      }
    }
  });

  databaseApiClearButton?.addEventListener("click", () => {
    clearDatabaseApiConfig();
    if (databaseApiBaseUrl) databaseApiBaseUrl.value = "";
    if (databaseApiKey) databaseApiKey.value = "";
    [phpBaseUrlInput, phpUsernameInput, phpPasswordInput,
      mysqlHostInput, mysqlPortInput, mysqlDatabaseInput, mysqlUserInput, mysqlPasswordInput,
      postgresHostInput, postgresPortInput, postgresDatabaseInput, postgresUserInput, postgresPasswordInput
    ].forEach((input) => { if (input) input.value = ""; });
    updateJdbcPreviews();
    renderDatabaseApiStatus();
    if (databaseApiFeedback) {
      databaseApiFeedback.textContent = "Disconnected.";
      databaseApiFeedback.classList.add("success");
    }
    persistIntegrationSettings(databaseApiFeedback, "Database settings cleared.");
  });
}

const dbHealthCheckButton = document.querySelector("#dbHealthCheckButton");
if (dbHealthCheckButton) {
  // Matches the plain "<span class='ok/warn'>...</span> - detail" status-line pattern already
  // used by #databaseApiStatus/#googleClientIdStatus right above this card, instead of a raw
  // sentence of connection internals in a feedback box.
  const dbHealthStatus = document.querySelector("#dbHealthStatus");
  const dbHealthTableBody = document.querySelector("#dbHealthTableBody");

  const checkDbHealth = () => {
    dbHealthCheckButton.disabled = true;
    if (dbHealthStatus) dbHealthStatus.innerHTML = "Checking...";
    const result = gprecDbRequest("/health");
    dbHealthCheckButton.disabled = false;
    if (!result) {
      if (dbHealthStatus) {
        dbHealthStatus.innerHTML = `<span class="warn">Not connected</span> - make sure the portal API server is running`;
      }
      if (dbHealthTableBody) dbHealthTableBody.innerHTML = "";
      return;
    }
    if (!result.ok) {
      if (dbHealthStatus) {
        dbHealthStatus.innerHTML = `<span class="warn">Not connected</span> - ${result.error || "unknown error"}`;
      }
      if (dbHealthTableBody) dbHealthTableBody.innerHTML = "";
      return;
    }
    if (dbHealthStatus) {
      const checkedTime = new Date(result.checkedAt).toLocaleTimeString("en-IN", { hour: "numeric", minute: "2-digit" });
      dbHealthStatus.innerHTML = `<span class="ok">Connected</span> - ${result.latencyMs} ms - checked ${checkedTime}`;
    }
    if (dbHealthTableBody) {
      const counts = result.tableCounts || {};
      dbHealthTableBody.innerHTML = Object.entries(counts)
        .map(([table, count]) => `<tr><td>${table}</td><td>${count}</td></tr>`)
        .join("") || `<tr><td colspan="2">No tables reported.</td></tr>`;
    }
  };

  dbHealthCheckButton.addEventListener("click", checkDbHealth);
  checkDbHealth();
}

// Live-updating mini charts (Server Sessions, Transactions/sec, Block IO/sec) for the same
// "Live Database Health" card, styled with this app's own navy/orange palette instead of a
// generic monitoring-tool look. xact_commit/xact_rollback/blks_read/blks_hit from Postgres are
// cumulative since server start, not point-in-time rates, so the rate charts are computed here
// as a delta between this poll and the previous one.
const dbHealthCard = document.querySelector("#dbHealthCard");
if (dbHealthCard) {
  const DB_CHART_MAX_POINTS = 20;
  const DB_CHART_POLL_MS = 3000;

  const drawLineChart = (canvas, seriesA, seriesB) => {
    if (!canvas) return;
    const rect = canvas.getBoundingClientRect();
    if (!rect.width || !rect.height) return;
    const dpr = window.devicePixelRatio || 1;
    const targetWidth = Math.round(rect.width * dpr);
    const targetHeight = Math.round(rect.height * dpr);
    if (canvas.width !== targetWidth || canvas.height !== targetHeight) {
      canvas.width = targetWidth;
      canvas.height = targetHeight;
    }
    const ctx = canvas.getContext("2d");
    ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
    ctx.clearRect(0, 0, rect.width, rect.height);
    const maxValue = Math.max(...seriesA, ...seriesB, 1);
    const padding = 6;
    const plotWidth = rect.width - padding * 2;
    const plotHeight = rect.height - padding * 2;
    const pointCount = Math.max(seriesA.length, 2);
    const toX = (index) => padding + (plotWidth * index) / (pointCount - 1);
    const toY = (value) => padding + plotHeight - (plotHeight * value) / maxValue;
    const drawSeries = (series, color) => {
      if (series.length < 2) return;
      ctx.beginPath();
      series.forEach((value, index) => {
        const x = toX(index);
        const y = toY(value);
        if (index === 0) ctx.moveTo(x, y);
        else ctx.lineTo(x, y);
      });
      ctx.strokeStyle = color;
      ctx.lineWidth = 2;
      ctx.stroke();
    };
    drawSeries(seriesB, "#d7ecff");
    drawSeries(seriesA, "#ff8100");
  };

  const pushHistory = (history, value) => {
    history.push(value);
    if (history.length > DB_CHART_MAX_POINTS) history.shift();
  };

  const dbChartSessionsCanvas = document.querySelector("#dbChartSessions");
  const dbChartTransactionsCanvas = document.querySelector("#dbChartTransactions");
  const dbChartBlockIoCanvas = document.querySelector("#dbChartBlockIo");

  const sessionsActive = [];
  const sessionsIdle = [];
  const txCommitRate = [];
  const txRollbackRate = [];
  const ioReadRate = [];
  const ioHitRate = [];
  let dbStatsPrevSample = null;

  const pollDbStats = () => {
    if (dbHealthCard.classList.contains("is-hidden")) return;
    const result = gprecDbRequest("/db-stats");
    if (!result?.ok) return;

    pushHistory(sessionsActive, result.sessions?.active || 0);
    pushHistory(sessionsIdle, result.sessions?.idle || 0);

    if (dbStatsPrevSample) {
      const elapsedSeconds = Math.max(result.sampledAt - dbStatsPrevSample.sampledAt, 1);
      pushHistory(txCommitRate, Math.max((result.transactions.commit - dbStatsPrevSample.transactions.commit) / elapsedSeconds, 0));
      pushHistory(txRollbackRate, Math.max((result.transactions.rollback - dbStatsPrevSample.transactions.rollback) / elapsedSeconds, 0));
      pushHistory(ioReadRate, Math.max((result.blockIo.read - dbStatsPrevSample.blockIo.read) / elapsedSeconds, 0));
      pushHistory(ioHitRate, Math.max((result.blockIo.hit - dbStatsPrevSample.blockIo.hit) / elapsedSeconds, 0));
    }
    dbStatsPrevSample = result;

    drawLineChart(dbChartSessionsCanvas, sessionsActive, sessionsIdle);
    drawLineChart(dbChartTransactionsCanvas, txCommitRate, txRollbackRate);
    drawLineChart(dbChartBlockIoCanvas, ioReadRate, ioHitRate);
  };

  pollDbStats();
  setInterval(pollDbStats, DB_CHART_POLL_MS);
}

