const hydratePortalDataFromDatabase = () => {
  const databaseData = getGprecDbBootstrap();
  if (!databaseData) return;
  if (Array.isArray(databaseData.studentDirectory) && databaseData.studentDirectory.length) {
    defaultStudentDirectory.splice(0, defaultStudentDirectory.length, ...databaseData.studentDirectory);
  }
  if (databaseData.studentProfiles && Object.keys(databaseData.studentProfiles).length) {
    Object.keys(defaultStudentProfiles).forEach((key) => delete defaultStudentProfiles[key]);
    Object.assign(defaultStudentProfiles, databaseData.studentProfiles);
  }
  if (databaseData.hostelStudentData && Object.keys(databaseData.hostelStudentData).length) {
    Object.keys(hostelStudentData).forEach((key) => delete hostelStudentData[key]);
    Object.assign(hostelStudentData, databaseData.hostelStudentData);
  }
};
hydratePortalDataFromDatabase();

const studentProfileView = document.querySelector("#studentProfileView");

const hydratePortalDataFromDatabaseAsync = async () => {
  const databaseData = await fetchGprecDbBootstrap();
  if (!databaseData) return;
  if (Array.isArray(databaseData.studentDirectory) && databaseData.studentDirectory.length) {
    defaultStudentDirectory.splice(0, defaultStudentDirectory.length, ...databaseData.studentDirectory);
  }
  if (databaseData.studentProfiles && Object.keys(databaseData.studentProfiles).length) {
    Object.keys(defaultStudentProfiles).forEach((key) => delete defaultStudentProfiles[key]);
    Object.assign(defaultStudentProfiles, databaseData.studentProfiles);
  }
  if (databaseData.hostelStudentData && Object.keys(databaseData.hostelStudentData).length) {
    Object.keys(hostelStudentData).forEach((key) => delete hostelStudentData[key]);
    Object.assign(hostelStudentData, databaseData.hostelStudentData);
  }

  const storedStudentId = getCurrentStudentId();
  if (studentProfileView) {
    renderStudentProfileInto(studentProfileView, storedStudentId);
    renderStudentTopbarAvatar(storedStudentId);
    renderHostelSectionInfo(storedStudentId);
  }
};
hydratePortalDataFromDatabaseAsync();

// Shared everywhere an avatar falls back to initials (students and faculty). Strips honorifics
// (Dr./Mr./Mrs./Ms./Prof./Miss) so they never count as part of the initials, and splits on both
// whitespace AND periods so a name written without spaces after an initial (e.g. "N.Kasiviswanath")
// still yields two letters ("NK") instead of collapsing to a single "N".
const NAME_TITLE_WORDS = /^(dr|mr|mrs|ms|miss|prof)$/i;
const getInitialsFromName = (name, fallback = "Student") => {
  const words = String(name || fallback)
    .split(/[\s.]+/)
    .filter(Boolean)
    .filter((word) => !NAME_TITLE_WORDS.test(word));
  return words
    .slice(0, 2)
    .map((word) => word[0].toUpperCase())
    .join("")
    .slice(0, 2);
};

// Used for the greeting line only, not for initials - unlike getInitialsFromName, this keeps
// titles (Dr./Prof./etc.) intact rather than splitting on periods too (which would chop an
// initial-style name like "N.Kasiviswanath" down to just "N"). Despite the name, this doesn't
// shorten to a casual first name - it only strips a trailing "(HOD)"-style parenthetical, so the
// greeting always matches the full name shown in the topbar (names are stored in inconsistent
// orders with no reliable way to pick out a single "first" word).
const getFirstName = (name, fallback = "") => {
  const cleaned = String(name || fallback)
    .replace(/\([^)]*\)/g, "")
    .trim();
  return cleaned || fallback;
};

// Shown once per dashboard load as a personal welcome line, matching what time of day it is on
// the visitor's own device (there's no server-side session to key a "once per login" flag off of
// in this static app, so "every fresh login" in practice means "every time the dashboard loads").
const getTimeBasedGreeting = (name) => {
  const hour = new Date().getHours();
  const timeLabel = hour < 12 ? "Good morning" : hour < 17 ? "Good afternoon" : "Good evening";
  return name ? `${timeLabel}, ${name}` : timeLabel;
};

// Fills in the GPRECian welcome screen's personalized greeting line ("Good morning, Chandan").
// The capability-list subtext right below it is static per-page HTML - not touched here.
const applyGprecianBotGreeting = (name) => {
  const el = document.querySelector("#gprecianWelcomeGreeting");
  if (el && !el.dataset.greeted) {
    el.textContent = getTimeBasedGreeting(name);
    el.dataset.greeted = "true";
  }
};
// Admin/department dashboards resolve their "name" as a role (e.g. "College Admin"), set way
// earlier in this file (before this function even existed) - so this is a small self-contained
// pass rather than reusing that earlier block, run once here instead. Gated on an actual
// admin-page element (not just the gprecAdminRole localStorage key, which persists across every
// page on this origin once someone has ever logged into admin - checking only the key made this
// misfire with a stale "College Admin" greeting on the faculty/other dashboards too).
if ((adminRoleName || adminRoleBadge) && localStorage.getItem("gprecAdminRole")) {
  applyGprecianBotGreeting(localStorage.getItem("gprecAdminRole"));
}

const getFallbackInitialsSvg = (name, backgroundColor = "ff8100", textColor = "ffffff") => {
  const initials = getInitialsFromName(name);
  return `https://api.dicebear.com/9.x/initials/svg?seed=${encodeURIComponent(initials)}&backgroundColor=${backgroundColor}&textColor=${textColor}`;
};

const normalizeProfilePhotoUrl = (value) => {
  if (!value) return "";
  const url = String(value).trim();
  if (!url) return "";
  if (/^(data:|https?:|\/)/i.test(url)) return url;

  const cleanUrl = url.replace(/^\/+/, "");
  try {
    return new URL(`${gprecRootPrefix}${cleanUrl}`, window.location.href).href;
  } catch {
    return `${gprecRootPrefix}${cleanUrl}`;
  }
};

const getStudentPhotoSrc = (profile) => {
  const rawPhoto = profile?.profilePhoto || profile?.photo || profile?.profile_photo_url || "";
  const photo = normalizeProfilePhotoUrl(rawPhoto);
  if (photo) return photo;
  return getFallbackInitialsSvg(profile?.name || profile?.full_name || "Student");
};

const getExplicitProfilePhotoSrc = (profile) => {
  const rawPhoto = profile?.profilePhoto || profile?.photo || profile?.profile_photo_url || "";
  return normalizeProfilePhotoUrl(rawPhoto);
};

// Several request records (outing, hostel leave, visiting) snapshot a "studentName" at the time
// they were created/seeded - which can go stale or, for the seed data, was always just a short
// display name ("Sai Chandan") rather than the real full name on file ("Lakkavaram Sai Chandan").
// Anywhere a PDF prints a student's name, resolve it fresh from the current DB-backed profile
// instead of trusting that snapshot, falling back to it only if no profile is found.
const resolveStudentDisplayName = (studentId, fallbackName) =>
  defaultStudentProfiles[studentId]?.name || hostelStudentData[studentId]?.name || fallbackName || "Student";

// Same reasoning as resolveStudentDisplayName, for the other DB-backed fields these passes print:
// prefer the student's current record over whatever was snapshotted onto the request at the time
// it was created (hostel allocation especially can change after a request is on file).
const resolveStudentRoomHostel = (studentId, fallbackRoom, fallbackHostel) => {
  const student = hostelStudentData[studentId];
  return { room: student?.room || fallbackRoom || "-", hostel: student?.hostel || fallbackHostel || "-" };
};
const resolveStudentMobile = (studentId, fallbackMobile) =>
  defaultStudentProfiles[studentId]?.mobile || fallbackMobile || "-";
const resolveParentMobile = (studentId, fallbackMobile) =>
  defaultStudentProfiles[studentId]?.parentMobile || hostelStudentData[studentId]?.parentMobile || fallbackMobile || "-";

const getNameInitials = (name) => getInitialsFromName(name);

const renderStudentTopbarAvatar = (studentId) => {
  const profile = defaultStudentProfiles[studentId];
  if (!profile) return;
  document.querySelectorAll(".student-user-name-block strong").forEach((nameEl) => {
    nameEl.textContent = profile.name || studentId || "Student";
  });
  const explicitPhoto = getExplicitProfilePhotoSrc(profile);
  if (!explicitPhoto) {
    document.querySelectorAll(".student-user-menu .student-user-avatar").forEach((avatarEl) => {
      avatarEl.textContent = getNameInitials(profile.name);
    });
    return;
  }
  document.querySelectorAll(".student-user-menu .student-user-avatar").forEach((avatarEl) => {
    const img = document.createElement("img");
    img.src = explicitPhoto;
    img.alt = `${profile.name || "Student"} profile photo`;
    img.className = avatarEl.className;
    avatarEl.replaceWith(img);
  });
};

