// hostelStudentData only has an entry for actual hostel residents (see BOOTSTRAP_SQL's
// hostel_rows, joined from hostel_allocations), so its absence is exactly how a day scholar is
// identified here.
const renderHostelSectionInfo = (studentId) => {
  const subtitle = document.querySelector("#hostelSectionSubtitle");
  const grid = document.querySelector("#hostelInfoGrid");
  const notApplicable = document.querySelector("#hostelNotApplicable");
  if (!subtitle && !grid && !notApplicable) return;
  const student = hostelStudentData[studentId];
  if (!student) {
    if (subtitle) subtitle.textContent = "Day scholar";
    grid?.classList.add("is-hidden");
    notApplicable?.classList.remove("is-hidden");
    return;
  }
  if (subtitle) subtitle.textContent = "Active hosteler";
  grid?.classList.remove("is-hidden");
  notApplicable?.classList.add("is-hidden");
  const allocationText = document.querySelector("#hostelAllocationText");
  if (allocationText) allocationText.textContent = `${student.hostel}, ${student.block}, Room ${student.room}, Bed ${student.bed}`;
  const messText = document.querySelector("#hostelMessText");
  if (messText) messText.textContent = student.mess || "-";
};

// Current Day Timetable (faculty "Current Day Timetable" and student "Current Day Timetable" -
// both share this exact .current-day-panel/.today-slider markup and this same time-passed logic,
// so a class tile disappears once its end time has passed, on both dashboards identically).
const parseTimeToMinutes = (timeStr) => {
  const match = /(\d{1,2}):(\d{2})\s*(AM|PM)/i.exec(timeStr || "");
  if (!match) return null;
  let hours = Number(match[1]) % 12;
  if (/PM/i.test(match[3])) hours += 12;
  return hours * 60 + Number(match[2]);
};
const classHasEnded = (timeRange, nowMinutes) => {
  const parts = (timeRange || "").split("-").map((part) => part.trim());
  const endMinutes = parseTimeToMinutes(parts[1] || parts[0]);
  return endMinutes != null && endMinutes < nowMinutes;
};
const currentDayLabel = (now) => now.toLocaleDateString("en-IN", { weekday: "long", day: "2-digit", month: "short", year: "numeric" });

// class_timetable.section ("CSE III-A") and students.class_name ("CSE III A") format the same
// section differently - normalize both sides (strip hyphens/extra spaces, uppercase) before
// comparing, instead of an exact match that would silently return an empty roster/schedule.
const normalizeSectionLabel = (value) => (value || "").replace(/[-\s]+/g, " ").trim().toUpperCase();

// Internal Marks: labs are modeled as sibling curriculum rows (e.g. code "DBMS" + "DBMS-L"), not
// a structured has-lab flag - this is a best-effort match against that naming convention, not a
// guaranteed relationship. Falls back to no match (no Lab Marks column) rather than guessing wrong.
const findAssociatedLabSubject = (theorySubject, departmentCurriculum) => {
  if (!theorySubject?.code || !Array.isArray(departmentCurriculum)) return null;
  const labs = departmentCurriculum.filter(
    (subject) => subject.type === "Lab" && subject.semester === theorySubject.semester && subject.code !== theorySubject.code
  );
  if (!labs.length) return null;
  const theoryCode = theorySubject.code.toUpperCase();
  const suffixMatch = labs.find((lab) => {
    const code = (lab.code || "").toUpperCase();
    return code === `${theoryCode}-L` || code === `${theoryCode}-LAB` || code === `${theoryCode}L`;
  });
  if (suffixMatch) return suffixMatch;
  const prefixMatch = labs.find((lab) => {
    const code = (lab.code || "").toUpperCase();
    return code.startsWith(theoryCode) && code.length > theoryCode.length && !/[A-Z0-9]/.test(code[theoryCode.length]);
  });
  if (prefixMatch) return prefixMatch;
  const theoryName = (theorySubject.name || "").toLowerCase();
  return (
    labs.find((lab) => {
      const labName = (lab.name || "").toLowerCase().replace(/laboratory|lab/g, "").trim();
      return labName && (theoryName.includes(labName) || (lab.name || "").toLowerCase().includes(theoryCode.toLowerCase()));
    }) || null
  );
};

// Mid-1 + Mid-2 (averaged, out of 20) + Assignment (out of 10) = total out of 30. Returns null
// (not 0) when nothing has been entered yet, so the UI can show "-" instead of implying a zero
// score for marks that just haven't been graded.
const computeInternalTotal = (mid1, mid2, assignment) => {
  if (mid1 == null && mid2 == null && assignment == null) return null;
  const midAverage = Math.round(((Number(mid1) || 0) + (Number(mid2) || 0)) / 2);
  return Math.min(30, Math.max(0, midAverage + (Number(assignment) || 0)));
};

if (studentProfileView) {
  const storedStudentId = getCurrentStudentId();
  renderStudentProfileInto(studentProfileView, storedStudentId);
  renderStudentTopbarAvatar(storedStudentId);
  renderHostelSectionInfo(storedStudentId);
  const studentGreetingEl = document.querySelector("#dashboardGreeting");
  if (studentGreetingEl) {
    studentGreetingEl.textContent = getTimeBasedGreeting(getFirstName(resolveStudentDisplayName(storedStudentId)));
  }
  applyGprecianBotGreeting(getFirstName(resolveStudentDisplayName(storedStudentId)));

  // Grades panel - real per-student data (student_grades table), not the same fixed 4 rows shown
  // to every student regardless of who's logged in. No fallback to demo numbers on purpose: a
  // student with nothing on file yet sees an honest empty state instead of someone else's grades.
  const gradesLatestSgpaEl = document.querySelector("#gradesLatestSgpa");
  if (gradesLatestSgpaEl) {
    const setGradesText = (selector, value) => {
      const node = document.querySelector(selector);
      if (node) node.textContent = value;
    };
    const grades = getGprecDbBootstrap()?.studentGrades?.[storedStudentId] || [];
    const latest = grades[grades.length - 1];
    const cgpa = grades.length
      ? (grades.reduce((sum, row) => sum + Number(row.gpa || 0), 0) / grades.length).toFixed(2)
      : null;
    setGradesText("#gradesLatestSgpa", latest?.gpa || "-");
    setGradesText("#gradesLatestTermLabel", latest?.term || "No results on file yet");
    setGradesText("#gradesCgpa", cgpa || "-");
    const gradesStudentProfile = defaultStudentProfiles[storedStudentId];
    setGradesText(
      "#gradesHeadSummary",
      gradesStudentProfile?.branch
        ? `B.Tech ${gradesStudentProfile.branch}${gradesStudentProfile.className ? ` | ${gradesStudentProfile.className}` : ""}`
        : "-"
    );
    // Credits Earned - computed from real curriculum records (subject credits per semester),
    // summed for semesters on file with no backlogs. There's no per-subject grade table yet
    // (student_grades is per-semester GPA only), so this is a semester-level completion proxy,
    // not an exact per-subject ledger - it only counts semesters where curriculum data actually
    // exists, rather than guessing credits for semesters with no curriculum record on file.
    const TERM_TO_SEMESTER_NUMERAL = {
      "I - I": "I", "I - II": "II", "II - I": "III", "II - II": "IV",
      "III - I": "V", "III - II": "VI", "IV - I": "VII", "IV - II": "VIII"
    };
    const creditsCurriculum = getGprecDbBootstrap()?.curriculum?.[gradesStudentProfile?.branch] || [];
    let creditsEarned = 0;
    let semestersOnFile = 0;
    grades.forEach((row) => {
      const numeral = TERM_TO_SEMESTER_NUMERAL[row.term];
      const semesterSubjects = numeral ? creditsCurriculum.filter((subject) => subject.semester === numeral) : [];
      if (!semesterSubjects.length) return;
      semestersOnFile += 1;
      const backlogValue = String(row.backlogs || "").trim().toUpperCase();
      if (backlogValue === "NIL" || backlogValue === "0" || backlogValue === "") {
        creditsEarned += semesterSubjects.reduce((sum, subject) => sum + (Number(subject.credits) || 0), 0);
      }
    });
    setGradesText("#gradesCreditsEarned", semestersOnFile ? String(creditsEarned) : "-");
    setGradesText(
      "#gradesCreditsEarnedNote",
      semestersOnFile
        ? `From ${semestersOnFile} semester${semestersOnFile > 1 ? "s" : ""} with curriculum data on file`
        : "Curriculum records not yet on file for your semesters"
    );
    const resultTableBody = document.querySelector("#resultTableBody");
    if (resultTableBody) {
      resultTableBody.innerHTML = grades.length
        ? grades.map((row) => `<div><span>${row.term}</span><span>${row.gpa}</span><span>${row.backlogs}</span></div>`).join("")
        : `<div><span colspan="3">No results on file yet.</span></div>`;
    }
    const lastUpdatedEl = document.querySelector("#resultLastUpdated");
    const lastUpdatedWrap = document.querySelector("#resultLastUpdatedWrap");
    if (lastUpdatedEl) {
      const latestUpdate = grades.reduce((max, row) => Math.max(max, Number(row.updatedAt) || 0), 0);
      lastUpdatedWrap?.classList.toggle("is-hidden", !latestUpdate);
      if (latestUpdate) {
        lastUpdatedEl.textContent = new Date(latestUpdate).toLocaleDateString("en-IN", { day: "2-digit", month: "short", year: "numeric" });
      }
    }
    // Period of Study is derived from the roll number's admission-year prefix (e.g. "20X51A0501"
    // -> 2020) plus the standard 4-year B.Tech duration - real data, not stored separately.
    // Scheme has no fabricated fallback: it only shows once an admin actually sets it on the
    // student record.
    setGradesText("#resultPeriodOfStudy", (() => {
      const admissionYear = Number(`20${storedStudentId.slice(0, 2)}`);
      return Number.isFinite(admissionYear) && admissionYear > 2000 ? `${admissionYear}-${admissionYear + 4}` : "-";
    })());
    setGradesText("#resultScheme", defaultStudentProfiles[storedStudentId]?.admissionScheme || "-");

    // Inspirational / career-boost message, always framed positively (never as criticism, even
    // when backlogs exist) per explicit product requirement. Rule-based off real GPA/backlog data
    // rather than a live AI call, so it's instant and doesn't depend on an AI provider being
    // configured by the admin.
    const inspirationCard = document.querySelector("#gradesInspirationCard");
    if (inspirationCard) {
      let title = "";
      let text = "";
      if (grades.length) {
        const backlogSemesters = grades.filter((row) => {
          const value = String(row.backlogs || "").trim().toUpperCase();
          return value && value !== "NIL" && value !== "0";
        });
        const cgpaNum = Number(cgpa) || 0;
        if (backlogSemesters.length) {
          title = "You've got this - a focused push clears the path";
          text = `Clearing your pending backlog${backlogSemesters.length > 1 ? "s" : ""} early keeps every placement and higher-studies option open. A focused revision plan for the next supplementary exam can put you right back on track - many students clear theirs in a single attempt.`;
        } else if (cgpaNum && cgpaNum < 7.5) {
          title = "Aim higher - you're closer than you think";
          text = "Zero backlogs is a great foundation. Pushing your CGPA past 7.5 opens up more placement drives and higher-studies options - even a small lift next semester makes a real difference. Target: 7.5+ CGPA.";
        } else if (cgpaNum && cgpaNum < 8.5) {
          title = "Solid, backlog-free progress - keep the momentum";
          text = "You're on a strong track with no backlogs. Stay consistent and aim for 8.5+ CGPA to be in contention for top recruiters and postgraduate admissions.";
        } else if (cgpaNum) {
          title = "Excellent work - you're in the top bracket";
          text = "An outstanding, backlog-free record like this puts you in strong contention for top recruiters, scholarships, and postgraduate programs. Keep this consistency going into your final semesters.";
        }
      }
      inspirationCard.classList.toggle("is-hidden", !title);
      if (title) {
        setGradesText("#gradesInspirationTitle", title);
        setGradesText("#gradesInspirationText", text);
      }
    }

    // Internal Marks - real data via /api/internal-marks/mine, same honest-empty-state convention
    // as the rest of this Grades panel (no fallback to demo numbers).
    const internalMarksDisplayBody = document.querySelector("#internalMarksDisplayBody");
    if (internalMarksDisplayBody) {
      const marks = gprecDbRequest("/internal-marks/mine")?.marks || [];
      document.querySelector("#internalMarksDisplayEmpty")?.classList.toggle("is-hidden", marks.length > 0);
      internalMarksDisplayBody.innerHTML = marks
        .map((row) => {
          const total = computeInternalTotal(row.mid1, row.mid2, row.assignment);
          return `
            <tr>
              <td>${row.subjectName}</td>
              <td>${row.mid1 ?? "-"}</td>
              <td>${row.mid2 ?? "-"}</td>
              <td>${row.assignment ?? "-"}</td>
              <td>${total ?? "-"}</td>
              <td>${row.labMarks ?? "-"}</td>
            </tr>
          `;
        })
        .join("");
    }
  }
}

const currentDayTimetableBody = document.querySelector("#currentDayTimetableBody");
