// Hall ticket: a student's room/seat for each exam is worked out from which uploaded
// roll-number range (rollFrom-rollTo) they fall into. No hall ticket exists until the exam cell
// has uploaded a schedule covering this roll number - that's an honest "not released yet" state,
// not an error. Opens in the browser's own PDF viewer, which already has save/print controls.
const viewHallTicketButton = document.querySelector("#viewHallTicketButton");
const hallTicketStatus = document.querySelector("#hallTicketStatus");
let hallTicketAvailabilityTimer = null;

const renderHallTicketAvailability = () => {
  if (!hallTicketStatus && !viewHallTicketButton) return;
  const releaseState = getHallTicketReleaseState();
  clearTimeout(hallTicketAvailabilityTimer);
  if (hallTicketStatus) {
    hallTicketStatus.textContent = releaseState.released
      ? "Available for viewing after exam cell schedule allocation."
      : releaseState.message;
  }
  if (viewHallTicketButton) {
    viewHallTicketButton.disabled = !releaseState.released;
    viewHallTicketButton.setAttribute("aria-disabled", String(!releaseState.released));
  }
  const releaseTime = releaseState.settings.releaseAt ? new Date(releaseState.settings.releaseAt).getTime() : 0;
  if (!releaseState.released && Number.isFinite(releaseTime) && releaseTime > Date.now()) {
    hallTicketAvailabilityTimer = setTimeout(renderHallTicketAvailability, Math.min(releaseTime - Date.now() + 250, 2147483647));
  }
};

const buildHallTicketPdf = async () => {
  const releaseState = getHallTicketReleaseState();
  if (!releaseState.released) {
    if (hallTicketStatus) hallTicketStatus.textContent = releaseState.message;
    return null;
  }
  const studentId = getCurrentStudentId();
  const profile = defaultStudentProfiles[studentId];
  const statusEl = hallTicketStatus;
  const branch = profile?.branch || "CSE";
  const examSchedule = getExamCellData(branch).filter(
    (exam) => exam.rollFrom && exam.rollTo && studentId >= exam.rollFrom && studentId <= exam.rollTo
  );
  if (!examSchedule.length) {
    if (statusEl) statusEl.textContent = "Hall ticket not available yet - the exam cell hasn't published a schedule covering your roll number.";
    return null;
  }
  const name = profile?.name || "Student";
  const seatFor = (exam) => {
    const rangeStart = exam.rollFrom.slice(-2);
    const studentSuffix = studentId.slice(-2);
    const offset = Number(studentSuffix) - Number(rangeStart);
    return exam.startSeat + (Number.isFinite(offset) && offset >= 0 ? offset : 0);
  };
  const examCentreFor = (exam) => exam.location || exam.examCentre || exam.examCenter || "-";
  const schedule = examSchedule.map((exam) => ({
    subject: `${exam.code} - ${exam.subject}`,
    date: formatExamDate(exam.date),
    time: exam.time,
    room: exam.room,
    seat: String(seatFor(exam)),
    centre: examCentreFor(exam)
  }));
  const photoUrl = getExplicitProfilePhotoSrc(profile);
  const pdf = await buildHallTicketImage({
    ticketNo: makeShortPassId("HT", [studentId, branch]),
    name,
    rollNumber: studentId,
    branch,
    className: profile?.className,
    dob: profile?.dob,
    schedule,
    photoUrl
  });
  return { pdf, statusEl };
};

renderHallTicketAvailability();

viewHallTicketButton?.addEventListener("click", async () => {
  const result = await buildHallTicketPdf();
  if (!result) return;
  window.open(URL.createObjectURL(result.pdf), "_blank");
  if (result.statusEl) result.statusEl.textContent = "Hall ticket opened for viewing - use your browser's PDF viewer to save or print it.";
});

