const renderHostelStudent = (studentId) => {
  if (!hostelStudentResult) return;
  const normalizedStudentId = studentId.toUpperCase();
  const student = hostelStudentData[normalizedStudentId];
  if (!student) {
    // Search is by exact roll number only (not name or year) - list available hostler IDs.
    const sampleIds = Object.keys(hostelStudentData).join(", ");
    hostelStudentResult.innerHTML = `
      <p class="lookup-empty">No hostel record found for <strong>${studentId || "this student ID"}</strong>. Search matches the exact roll number only (not name or year).</p>
      <p class="portal-note">Try one of the available hostler IDs: ${sampleIds}</p>
    `;
    return;
  }
  const roommates = Object.entries(hostelStudentData)
    .filter(([id, item]) => id !== normalizedStudentId && item.room === student.room && item.hostel === student.hostel)
    .map(([id, item]) => `<li><strong>${item.name}</strong><span>${id} | Bed ${item.bed} | ${item.branch} | ${item.parentMobile}</span></li>`)
    .join("");
  hostelStudentResult.innerHTML = `
    <div class="hostel-student-head">
      <div><strong>${student.name}</strong><span>${normalizedStudentId} | ${student.branch} | ${student.className}</span></div>
      <em>${student.status}</em>
    </div>
    <div class="hostel-student-grid">
      <p><strong>Hostel</strong><span>${student.hostel}</span></p>
      <p><strong>Room / Bed</strong><span>${student.block}, ${student.room}, Bed ${student.bed}</span></p>
      <p><strong>Warden</strong><span>${student.warden}</span></p>
      <p><strong>Parent</strong><span>${student.parent} | ${student.parentMobile}</span></p>
      <p><strong>Mess</strong><span>${student.mess}</span></p>
      <p><strong>Outing</strong><span>${student.outing}</span></p>
      <p><strong>Complaints</strong><span>${student.complaints}</span></p>
    </div>
    <div class="roommate-list">
      <strong>Students sharing same room</strong>
      ${roommates ? `<ul>${roommates}</ul>` : "<p>No other student is assigned to this room.</p>"}
    </div>
  `;
};

