const adminOutingBody = document.querySelector("#adminOutingBody");

const renderAdminOutingRequests = () => {
  if (!adminOutingBody) return;
  const requests = getOutingRequests();
  adminOutingBody.innerHTML = requests
    .map((request) => {
      let actionCell = "-";
      if (request.status === "Pending") {
        actionCell = `<div class="action-cell"><button type="button" data-outing-approve="${request.id}">Approve</button><button type="button" class="btn-reject" data-outing-reject="${request.id}">Reject</button></div>`;
      }
      const { room } = resolveStudentRoomHostel(request.studentId, request.room, request.hostel);
      return `
        <details class="request-card">
          <summary class="hostel-student-head">
            <strong>${request.studentId} (${room})</strong>
            <span class="${outingStatusClass(request.status)}">${request.status}</span>
          </summary>
          <div class="hostel-student-grid">
            <p><strong>Requested By</strong><span>${request.requestedBy || "Student"}</span></p>
            <p><strong>Outing Type</strong><span>${request.outingType || "-"}</span></p>
            <p><strong>Purpose of Visit</strong><span>${request.reason}</span></p>
            <p><strong>Place of Visit</strong><span>${request.place || "-"}</span></p>
            <p><strong>Parent Mobile</strong><span>${resolveParentMobile(request.studentId, request.parentMobile)}</span></p>
            <p><strong>Out Time</strong><span>${request.outTime}</span></p>
            <p><strong>Return Time</strong><span>${request.returnTime}</span></p>
          </div>
          <div class="request-card-actions">${actionCell}</div>
        </details>
      `;
    })
    .join("");

  adminOutingBody.querySelectorAll("[data-outing-approve]").forEach((button) => {
    button.addEventListener("click", () => {
      const currentRequests = getOutingRequests();
      const request = currentRequests.find((item) => item.id === button.dataset.outingApprove);
      if (!request) return;
      request.status = "Approved";
      request.approvedBy = localStorage.getItem("gprecAdminRole") || "Hostel Warden";
      request.approvedOn = new Date().toLocaleDateString("en-IN", { day: "2-digit", month: "short", year: "numeric" });
      saveOutingRequests(currentRequests);
      recordActivity(`Approved outing request for ${request.studentId}`, "Hostel");
      renderAdminOutingRequests();
    });
  });

  adminOutingBody.querySelectorAll("[data-outing-reject]").forEach((button) => {
    button.addEventListener("click", () => {
      const currentRequests = getOutingRequests();
      const request = currentRequests.find((item) => item.id === button.dataset.outingReject);
      if (!request) return;
      request.status = "Rejected";
      saveOutingRequests(currentRequests);
      recordActivity(`Rejected outing request for ${request.studentId}`, "Hostel");
      renderAdminOutingRequests();
    });
  });
};

