const downloadVisitPass = async (request) => {
  const { room, hostel } = resolveStudentRoomHostel(request.studentId, request.room, request.hostel);
  const table = {
    columns: [
      { label: "Field", width: 150 },
      { label: "Details", width: 320 }
    ],
    rows: [
      ["Student Name", resolveStudentDisplayName(request.studentId, request.studentName)],
      ["Roll Number", request.studentId],
      ["Room / Hostel", `${room} | ${hostel}`],
      ["Visitor Name", request.visitorName],
      ["Relationship", request.relationship],
      ["Visitor Mobile", request.visitorMobile || "-"],
      ["Purpose of Visit", request.purpose],
      ["Visit Date & Time", formatOutingDateTime(request.visitDateTime)],
      ["Approved By", request.approvedBy || "-"],
      ["Approved On", request.approvedOn || "-"],
      ["Status", "Approved"]
    ]
  };
  const visitPassFooterLines = ["Visitors must carry a valid photo ID and report to the hostel gate security."];
  const gateToken = ensureHostelGateToken(getVisitingRequests, saveVisitingRequests, request.id);
  const qrText = gateToken ? hostelGateScanUrl("visit", request.id, gateToken) : null;
  const pdf = await makeSimplePdf(
    "GPREC Hostel Visit Pass", [], table, visitPassFooterLines, "Notes",
    estimatePdfHeight({ table, footerLines: visitPassFooterLines, hasQr: Boolean(qrText) }),
    qrText
  );
  const link = document.createElement("a");
  link.href = URL.createObjectURL(pdf);
  link.download = `gprec-visit-pass-${request.studentId}.pdf`;
  link.click();
};

