const busRouteManagerBody = document.querySelector("#busRouteManagerBody");
if (busRouteManagerBody) {
  const busRouteSelectInput = document.querySelector("#busRouteSelectInput");
  const busManagerBody = document.querySelector("#busManagerBody");
  const busRequestsAdminBody = document.querySelector("#busRequestsAdminBody");
  const vehiclePassesAdminBody = document.querySelector("#vehiclePassesAdminBody");

  const renderBusRouteManager = () => {
    const routes = getGprecDbBootstrap()?.busRoutes || [];
    busRouteManagerBody.innerHTML = routes.length
      ? routes
          .map(
            (route) => `
              <tr>
                <td>${route.routeName}</td>
                <td>${route.stops}</td>
                <td>${route.pickupTime || "-"}</td>
                <td>${route.dropTime || "-"}</td>
                <td><button type="button" class="icon-btn-delete" data-bus-route-remove="${route.id}" aria-label="Remove route">${deleteIconSvg}</button></td>
              </tr>
            `
          )
          .join("")
      : `<tr><td colspan="5">No bus routes added yet.</td></tr>`;
    if (busRouteSelectInput) {
      const currentValue = busRouteSelectInput.value;
      busRouteSelectInput.innerHTML =
        `<option value="">Select a route</option>` +
        routes.map((route) => `<option value="${route.id}">${route.routeName}</option>`).join("");
      busRouteSelectInput.value = currentValue;
    }
    busRouteManagerBody.querySelectorAll("[data-bus-route-remove]").forEach((button) => {
      button.addEventListener("click", () => {
        gprecDbRequest("/bus-routes/remove", { method: "POST", body: { id: button.dataset.busRouteRemove } });
        gprecDbBootstrapTried = false;
        renderBusRouteManager();
        renderBusManager();
      });
    });
  };

  const renderBusManager = () => {
    if (!busManagerBody) return;
    const buses = getGprecDbBootstrap()?.buses || [];
    busManagerBody.innerHTML = buses.length
      ? buses
          .map(
            (bus) => `
              <tr>
                <td>${bus.busNumber}</td>
                <td>${bus.routeName}</td>
                <td>${bus.driverName}</td>
                <td>${bus.driverMobile || "-"}</td>
                <td><button type="button" class="icon-btn-delete" data-bus-remove="${bus.id}" aria-label="Remove bus">${deleteIconSvg}</button></td>
              </tr>
            `
          )
          .join("")
      : `<tr><td colspan="5">No buses added yet.</td></tr>`;
    busManagerBody.querySelectorAll("[data-bus-remove]").forEach((button) => {
      button.addEventListener("click", () => {
        gprecDbRequest("/buses/remove", { method: "POST", body: { id: button.dataset.busRemove } });
        gprecDbBootstrapTried = false;
        renderBusManager();
      });
    });
  };

  const renderBusRequestsAdmin = () => {
    if (!busRequestsAdminBody) return;
    const requests = gprecDbRequest("/bus-requests/all", { method: "POST", body: {} })?.requests || [];
    busRequestsAdminBody.innerHTML = requests.length
      ? requests
          .map((item) => {
            // Students must pay the Transportation Fee before their request can be approved -
            // faculty have no fee, so this gate only ever applies to student rows.
            const feeBlocked = item.requesterType === "student" && !item.feePaid;
            const actionCell =
              item.status === "Cancellation Requested"
                ? `<button type="button" class="btn-reject" data-bus-request-confirm-cancel="${item.id}">Confirm Cancellation</button>`
                : item.status !== "Pending"
                  ? "-"
                  : feeBlocked
                    ? `<div class="action-cell"><button type="button" class="btn-reject" data-bus-request-reject="${item.id}">No</button></div>`
                    : `<div class="action-cell"><button type="button" data-bus-request-approve="${item.id}">Yes</button><button type="button" class="btn-reject" data-bus-request-reject="${item.id}">No</button></div>`;
            const feeCell =
              item.requesterType === "faculty" ? "-" : item.feePaid ? `<span class="ok">Paid</span>` : `<span class="warn">Unpaid</span>`;
            return `
              <tr>
                <td>${item.requesterName}</td>
                <td>${item.requesterType}</td>
                <td>${item.busNumber}</td>
                <td>${item.routeName}</td>
                <td>${item.pickupPoint || "-"} / ${item.dropPoint || "-"}</td>
                <td>${feeCell}</td>
                <td>${item.requestedAt}</td>
                <td><span class="${requestStatusClass(item.status)}">${item.status}</span></td>
                <td>${actionCell}</td>
              </tr>
            `;
          })
          .join("")
      : `<tr><td colspan="9">No bus requests yet.</td></tr>`;
    busRequestsAdminBody.querySelectorAll("[data-bus-request-approve]").forEach((button) => {
      button.addEventListener("click", () => {
        gprecDbRequest("/bus-requests/decide", { method: "POST", body: { id: button.dataset.busRequestApprove, status: "Approved" } });
        renderBusRequestsAdmin();
      });
    });
    busRequestsAdminBody.querySelectorAll("[data-bus-request-reject]").forEach((button) => {
      button.addEventListener("click", () => {
        gprecDbRequest("/bus-requests/decide", { method: "POST", body: { id: button.dataset.busRequestReject, status: "Rejected" } });
        renderBusRequestsAdmin();
      });
    });
    busRequestsAdminBody.querySelectorAll("[data-bus-request-confirm-cancel]").forEach((button) => {
      button.addEventListener("click", () => {
        gprecDbRequest("/bus-requests/decide", { method: "POST", body: { id: button.dataset.busRequestConfirmCancel, status: "Cancelled" } });
        renderBusRequestsAdmin();
      });
    });
  };

  const verificationBadge = (result) => {
    if (result === "verified") return `<span class="ok">Verified</span>`;
    if (result === "failed") return `<span class="warn">Failed</span>`;
    if (result === "error") return `<span class="warn">Error</span>`;
    return `<span class="warn">Not configured</span>`;
  };

  const renderVehiclePassesAdmin = () => {
    if (!vehiclePassesAdminBody) return;
    const passes = gprecDbRequest("/vehicle-passes/all", { method: "POST", body: {} })?.passes || [];
    vehiclePassesAdminBody.innerHTML = passes.length
      ? passes
          .map((item) => {
            const actionCell =
              item.status === "Pending"
                ? `<div class="action-cell"><button type="button" data-vehicle-pass-approve="${item.id}">Yes</button><button type="button" class="btn-reject" data-vehicle-pass-reject="${item.id}">No</button></div>`
                : "-";
            const docsCell = `<a href="${item.licenseDocUrl}" target="_blank" rel="noopener">License</a> / <a href="${item.rcDocUrl}" target="_blank" rel="noopener">RC</a>`;
            const verificationCell = `
              ${verificationBadge(item.verificationResult)}
              ${item.verificationNotes ? `<p class="portal-note">${item.verificationNotes}</p>` : ""}
              <button type="button" class="link-button" data-vehicle-pass-verify="${item.id}">Verify</button>
            `;
            return `
              <tr>
                <td>${item.requesterName}</td>
                <td>${item.requesterType}</td>
                <td>${item.vehicleType} - ${item.vehicleNumber}</td>
                <td>${item.licenseNumber}</td>
                <td>${docsCell}</td>
                <td>${verificationCell}</td>
                <td><span class="${requestStatusClass(item.status)}">${item.status}</span></td>
                <td>${actionCell}</td>
              </tr>
            `;
          })
          .join("")
      : `<tr><td colspan="8">No vehicle pass applications yet.</td></tr>`;
    vehiclePassesAdminBody.querySelectorAll("[data-vehicle-pass-approve]").forEach((button) => {
      button.addEventListener("click", () => {
        gprecDbRequest("/vehicle-passes/decide", { method: "POST", body: { id: button.dataset.vehiclePassApprove, status: "Approved" } });
        renderVehiclePassesAdmin();
      });
    });
    vehiclePassesAdminBody.querySelectorAll("[data-vehicle-pass-reject]").forEach((button) => {
      button.addEventListener("click", () => {
        gprecDbRequest("/vehicle-passes/decide", { method: "POST", body: { id: button.dataset.vehiclePassReject, status: "Rejected" } });
        renderVehiclePassesAdmin();
      });
    });
    vehiclePassesAdminBody.querySelectorAll("[data-vehicle-pass-verify]").forEach((button) => {
      button.addEventListener("click", () => {
        button.disabled = true;
        button.textContent = "Checking...";
        gprecDbRequest("/vehicle-passes/verify", { method: "POST", body: { id: button.dataset.vehiclePassVerify } });
        renderVehiclePassesAdmin();
      });
    });
  };

  document.querySelector("#addBusRouteButton")?.addEventListener("click", () => {
    const routeName = document.querySelector("#busRouteNameInput")?.value.trim() || "";
    const stops = document.querySelector("#busRouteStopsInput")?.value.trim() || "";
    const pickupTime = document.querySelector("#busRoutePickupTimeInput")?.value.trim() || "";
    const dropTime = document.querySelector("#busRouteDropTimeInput")?.value.trim() || "";
    const feedback = document.querySelector("#busRouteAddFeedback");
    if (!routeName || !stops) {
      if (feedback) {
        feedback.textContent = "Enter a route name and stops.";
        feedback.classList.remove("success");
      }
      return;
    }
    const result = gprecDbRequest("/bus-routes", { method: "POST", body: { routeName, stops, pickupTime, dropTime } });
    if (result?.ok) {
      gprecDbBootstrapTried = false;
      document.querySelector("#busRouteNameInput").value = "";
      document.querySelector("#busRouteStopsInput").value = "";
      document.querySelector("#busRoutePickupTimeInput").value = "";
      document.querySelector("#busRouteDropTimeInput").value = "";
      if (feedback) {
        feedback.textContent = "Route added.";
        feedback.classList.add("success");
      }
      renderBusRouteManager();
    } else if (feedback) {
      feedback.textContent = result?.error || "Could not add route.";
      feedback.classList.remove("success");
    }
  });

  document.querySelector("#addBusButton")?.addEventListener("click", () => {
    const busNumber = document.querySelector("#busNumberInput")?.value.trim() || "";
    const routeId = busRouteSelectInput?.value || "";
    const driverName = document.querySelector("#busDriverNameInput")?.value.trim() || "";
    const driverMobile = document.querySelector("#busDriverMobileInput")?.value.trim() || "";
    const feedback = document.querySelector("#busAddFeedback");
    if (!busNumber || !routeId || !driverName) {
      if (feedback) {
        feedback.textContent = "Bus number, route, and driver name are required.";
        feedback.classList.remove("success");
      }
      return;
    }
    const result = gprecDbRequest("/buses", { method: "POST", body: { busNumber, routeId, driverName, driverMobile } });
    if (result?.ok) {
      gprecDbBootstrapTried = false;
      document.querySelector("#busNumberInput").value = "";
      document.querySelector("#busDriverNameInput").value = "";
      document.querySelector("#busDriverMobileInput").value = "";
      if (feedback) {
        feedback.textContent = "Bus added.";
        feedback.classList.add("success");
      }
      renderBusManager();
    } else if (feedback) {
      feedback.textContent = result?.error || "Could not add bus.";
      feedback.classList.remove("success");
    }
  });

  renderBusRouteManager();
  renderBusManager();
  renderBusRequestsAdmin();
  renderVehiclePassesAdmin();
}

if (document.querySelector("#notificationList")) {
  const notifyAdminRole = localStorage.getItem("gprecAdminRole") || "College Admin";
  const adminNotifications = [];

  if (notifyAdminRole === "Boys Hostel Warden" || notifyAdminRole === "Girls Hostel Warden") {
    // Scoped to this warden's own hostel - these used to count every pending request site-wide,
    // so a Boys Hostel Warden's badge included Girls Hostel requests they can't even act on (and
    // vice versa). Also now clickable straight to the relevant section (see
    // gprecNavigateToNotificationTarget) instead of being plain unclickable text.
    const wardenHostel = notifyAdminRole === "Boys Hostel Warden" ? "Boys Hostel" : "Girls Hostel";
    const pendingOutings = getOutingRequests().filter((request) => request.hostel === wardenHostel && request.status === "Pending").length;
    const pendingVisits = getVisitingRequests().filter((request) => request.hostel === wardenHostel && request.status === "Pending").length;
    if (pendingOutings > 0) adminNotifications.push({ text: `${pendingOutings} outing request(s) awaiting your approval.`, link: "#hostel-outings" });
    if (pendingVisits > 0) adminNotifications.push({ text: `${pendingVisits} visiting request(s) awaiting your approval.`, link: "#hostel-visiting-requests" });
  }

  if (notifyAdminRole === "College Admin") {
    const pendingHodLeaves = getLeaveRequests().filter((request) => request.isHod && request.status === "Pending").length;
    if (pendingHodLeaves > 0) adminNotifications.push(`${pendingHodLeaves} HOD leave request(s) awaiting your approval.`);
  }

  renderNotificationList(adminNotifications);
}

{
  // Slides/dots are re-queried every tick, and the active index is read straight off the DOM
  // rather than tracked in a separate counter - renderHomeHeroSlides() can re-render #homeHeroSlides
  // at any time (e.g. once the bootstrap fetch lands), which would desync a separate counter.
  setInterval(() => {
    const currentHeroSlides = document.querySelectorAll(".hero-slide");
    const currentHeroDots = document.querySelectorAll(".hero-dots span");
    if (currentHeroSlides.length <= 1) return;
    let activeSlide = Array.prototype.findIndex.call(currentHeroSlides, (slide) => slide.classList.contains("active"));
    if (activeSlide === -1) activeSlide = 0;
    currentHeroSlides[activeSlide]?.classList.remove("active");
    currentHeroDots[activeSlide]?.classList.remove("active");
    activeSlide = (activeSlide + 1) % currentHeroSlides.length;
    currentHeroSlides[activeSlide]?.classList.add("active");
    currentHeroDots[activeSlide]?.classList.add("active");
    // .hero-dots caps itself to ~4 dots wide and scrolls (see styles.css) so a long slide list
    // doesn't stretch the pill - without this, the active (orange) dot rotates past the edge of
    // that window and disappears from view once its slide is more than ~4 slides in.
    currentHeroDots[activeSlide]?.scrollIntoView({ inline: "nearest", block: "nearest", behavior: "smooth" });
  }, 4200);
}

if (voiceTrack) {
  let voiceIndex = 0;

  const getVisibleVoices = () => {
    if (window.matchMedia("(max-width: 680px)").matches) return 1;
    if (window.matchMedia("(max-width: 1080px)").matches) return 2;
    return 3;
  };

  const updateVoices = () => {
    // re-queried fresh (voice-grid content is admin-managed and rendered dynamically)
    const currentVoiceCards = voiceTrack.querySelectorAll("article");
    if (!currentVoiceCards.length) return;
    const visible = getVisibleVoices();
    const maxIndex = Math.max(0, currentVoiceCards.length - visible);
    voiceIndex = Math.min(voiceIndex, maxIndex);
    const cardWidth = currentVoiceCards[0].getBoundingClientRect().width;
    const gap = parseFloat(getComputedStyle(voiceTrack).gap) || 0;
    voiceTrack.style.transform = `translateX(-${voiceIndex * (cardWidth + gap)}px)`;
    voicePrev?.toggleAttribute("disabled", voiceIndex === 0);
    voiceNext?.toggleAttribute("disabled", voiceIndex === maxIndex);
  };

  voicePrev?.addEventListener("click", () => {
    voiceIndex = Math.max(0, voiceIndex - 1);
    updateVoices();
  });

  voiceNext?.addEventListener("click", () => {
    voiceIndex += 1;
    updateVoices();
  });

  window.addEventListener("resize", updateVoices);
  updateVoices();
}

if (courseTrack && courseCards.length > 0) {
  let courseIndex = 0;

  const getVisibleCourses = () => window.matchMedia("(max-width: 680px)").matches ? 1 : 2;

  const updateCourses = () => {
    const visible = getVisibleCourses();
    const maxIndex = Math.max(0, courseCards.length - visible);
    courseIndex = Math.min(courseIndex, maxIndex);
    const cardWidth = courseCards[0].getBoundingClientRect().width;
    const gap = parseFloat(getComputedStyle(courseTrack).gap) || 0;
    courseTrack.style.transform = `translateX(-${courseIndex * (cardWidth + gap)}px)`;
    coursePrev?.toggleAttribute("disabled", courseIndex === 0);
    courseNext?.toggleAttribute("disabled", courseIndex === maxIndex);
  };

  coursePrev?.addEventListener("click", () => {
    courseIndex = Math.max(0, courseIndex - 1);
    updateCourses();
  });

  courseNext?.addEventListener("click", () => {
    courseIndex += 1;
    updateCourses();
  });

  window.addEventListener("resize", updateCourses);
  updateCourses();
}

