const studentIcon =
  '<svg viewBox="0 0 24 24" aria-hidden="true" focusable="false"><path d="m4 6 8-3 8 3-8 3zM7 8v3M17 8v3M9 12a3 3 0 1 0 6 0M5 21c.7-3.2 3.4-5 7-5s6.3 1.8 7 5"/></svg>';
const gprecianUserIcon =
  '<svg viewBox="0 0 24 24" aria-hidden="true" focusable="false"><circle cx="12" cy="8" r="4"/><path d="M4 20c0-4 3.5-7 8-7s8 3 8 7"/></svg>';

const saveGprecianHistory = () => {
  if (!gprecianMessages) return;
  const history = Array.from(gprecianMessages.querySelectorAll(".chat-row")).map((row) => ({
    type: row.classList.contains("user-row") ? "user" : "bot",
    text: row.classList.contains("user-row")
      ? row.querySelector("p")?.textContent || ""
      : row.querySelector(".bot-message")?.dataset.rawText || "",
    links: Array.from(row.querySelectorAll(".chat-links a")).map((a) => ({
      url: a.getAttribute("href") || "",
      // Download links render as "Download: {label}" (added at render time in addGprecianMessage) -
      // read the raw label back from the download attribute's value instead of the rendered
      // textContent, so restoring history doesn't double up the "Download:" prefix.
      label: a.hasAttribute("download") ? a.getAttribute("download") || "" : a.textContent || "",
      download: a.hasAttribute("download")
    }))
  }));
  const serialized = JSON.stringify(history);
  localStorage.setItem(gprecianChatStorageKey(), serialized);
  sessionStorage.setItem(gprecianChatStorageKey(), serialized);
};

// Bot answers are plain text with markdown-ish conventions (blank line = new paragraph, "- " =
// list item, "Label: value" = a labelled fact) rather than real markdown. This turns that into
// real structured HTML (paragraphs, bulleted lists, bolded labels). Uses a local escapeHtml
// duplicate rather than the shared one (declared much later in this file) since restoring saved
// chat history calls into this synchronously on page load, before the shared const exists (TDZ).
const formatBotMessageEscapeHtml = (value) =>
  String(value)
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;")
    .replace(/'/g, "&#39;");

const formatBotMessageLine = (line) => {
  const match = line.match(/^([A-Za-z][A-Za-z0-9 /&']{1,32}):\s*(.*)$/);
  if (!match || !match[2]) return formatBotMessageEscapeHtml(line);
  return `<strong>${formatBotMessageEscapeHtml(match[1])}:</strong> ${formatBotMessageEscapeHtml(match[2])}`;
};

const formatBotMessageHtml = (text) =>
  String(text || "")
    .split(/\n{2,}/)
    .map((block) => {
      const lines = block.split("\n").map((line) => line.trim()).filter(Boolean);
      if (!lines.length) return "";
      // A block can mix a lead-in sentence with a run of "- " bullets (e.g. "Here's how to
      // reach us:" followed by address/phone/email lines) - group consecutive lines of the same
      // kind instead of requiring the whole block to be uniformly bulleted or not.
      const groups = [];
      lines.forEach((line) => {
        const kind = /^[-*]\s+/.test(line) ? "list" : "text";
        const last = groups[groups.length - 1];
        if (last?.kind === kind) last.lines.push(line);
        else groups.push({ kind, lines: [line] });
      });
      return groups
        .map((group) => {
          if (group.kind === "list") {
            const items = group.lines
              .map((line, index) => `<li style="--i:${index}">${formatBotMessageLine(line.replace(/^[-*]\s+/, ""))}</li>`)
              .join("");
            return `<ul class="bot-message-list">${items}</ul>`;
          }
          return `<p>${group.lines.map(formatBotMessageLine).join("<br>")}</p>`;
        })
        .join("");
    })
    .filter(Boolean)
    .join("");

// Bot replies can suggest real links instead of saying "go to this page" - either a page on this
// site (opened in a new tab so the chat stays open) or a document to download right there in the
// chat. Always built from data this code controls (keyword-answer metadata, notice attachments,
// knowledge-base chunk sources), never from raw AI text, so there's no HTML/URL injection risk.
const addGprecianMessage = (text, type = "bot", links = [], question = null) => {
  if (!gprecianMessages) return;
  const row = document.createElement("div");
  row.className = type === "user" ? "chat-row user-row" : "chat-row bot-row";

  const avatar = document.createElement("span");
  avatar.className = type === "user" ? "chat-avatar user-avatar" : "chat-avatar bot-avatar";
  avatar.innerHTML = type === "user" ? gprecianUserIcon : studentIcon;

  if (type === "user") {
    const message = document.createElement("p");
    message.className = "user-message";
    message.textContent = text;
    row.append(message, avatar);
  } else {
    // A single bordered bubble (div.bot-message, styled the same as the old <p class="bot-message">)
    // containing the text and, if any, the suggested links - so a link/download button renders
    // inside the same message bubble instead of floating off as a separate flex sibling.
    const bubble = document.createElement("div");
    bubble.className = "bot-message";
    bubble.dataset.rawText = text;
    const textEl = document.createElement("div");
    textEl.className = "bot-message-body";
    textEl.innerHTML = formatBotMessageHtml(text);
    bubble.append(textEl);
    if (links?.length) {
      const linksWrap = document.createElement("div");
      linksWrap.className = "chat-links";
      links.forEach((link) => {
        const a = document.createElement("a");
        a.href = link.url;
        a.textContent = link.download ? "Download Attachment" : link.label;
        a.target = "_blank";
        a.rel = "noreferrer";
        if (link.download) a.setAttribute("download", link.label);
        linksWrap.appendChild(a);
      });
      bubble.append(linksWrap);
    }
    // The actual feedback-loop entry point (see bot_feedback in portal_db_server.py) - only shown
    // when the question that produced this answer is known (live chat, not restored history),
    // since flagging needs both sides of the exchange to be useful to whoever reviews it.
    if (question) {
      const flagButton = document.createElement("button");
      flagButton.type = "button";
      flagButton.className = "gprecian-flag-answer";
      flagButton.textContent = "Report inaccurate answer";
      flagButton.addEventListener("click", () => {
        gprecDbRequest("/bot-feedback", { method: "POST", body: { question, botAnswer: text } });
        flagButton.textContent = "Reported - thanks, we'll review it";
        flagButton.disabled = true;
      });
      bubble.append(flagButton);
    }
    row.append(avatar, bubble);
  }

  gprecianMessages.appendChild(row);
  if (type !== "user") {
    const meta = document.createElement("span");
    meta.className = "chat-meta";
    meta.textContent = `GPRECian Bot · AI Assistant · ${new Date().toLocaleTimeString("en-IN", { hour: "numeric", minute: "2-digit" })}`;
    gprecianMessages.appendChild(meta);
  }
  gprecianMessages.scrollTop = gprecianMessages.scrollHeight;
  saveGprecianHistory();
};

const addGprecianBotReply = async (replyPromise, question = null) => {
  if (!gprecianMessages) return;
  const typingRow = document.createElement("div");
  typingRow.className = "chat-row bot-row";
  typingRow.innerHTML = `<span class="chat-avatar bot-avatar">${studentIcon}</span><p class="bot-message gprecian-typing"><span></span><span></span><span></span></p>`;
  gprecianMessages.appendChild(typingRow);
  gprecianMessages.scrollTop = gprecianMessages.scrollHeight;

  const [rawReply] = await Promise.all([replyPromise, new Promise((resolve) => setTimeout(resolve, 450))]);
  typingRow.remove();
  const reply = typeof rawReply === "string" ? { text: rawReply, links: [] } : rawReply;
  addGprecianMessage(reply.text, "bot", reply.links, question);
};

const restoreGprecianHistory = () => {
  if (!gprecianMessages) return;
  try {
    const key = gprecianChatStorageKey();
    const serialized = localStorage.getItem(key) || sessionStorage.getItem(key);
    const history = JSON.parse(serialized || "null");
    if (!history || !history.length) return;
    gprecianMessages.innerHTML = "";
    // Skip the welcome screen when there's already a conversation to resume - reaching for
    // revealGprecianConversation() here would be a TDZ error, since it's declared much later in
    // this file (after the chat form's submit handler), so this duplicates its two lines directly.
    document.querySelector(".gprecian-welcome")?.classList.add("is-hidden");
    gprecianMessages.classList.remove("is-hidden");
    history.forEach((item) => addGprecianMessage(item.text, item.type, item.links));
    localStorage.setItem(key, JSON.stringify(history));
  } catch {
    // keep the default greeting already in the markup on parse failure
  }
};

restoreGprecianHistory();

const getNoticeAnswer = () => {
  const notices = getNotices()
    .filter((notice) => publicNoticeAudiences.includes(notice.audience))
    .slice(-3)
    .reverse();
  if (!notices.length) {
    return {
      text: "There are no public notices posted right now. Check the Notice Board section on the homepage for updates.",
      links: []
    };
  }
  return {
    text: `Latest notices: ${notices.map((notice) => `"${notice.title}"`).join(", ")}. See the Notice Board section on the homepage for full details.`,
    links: notices
      .filter((notice) => notice.attachment)
      .map((notice) => ({ url: notice.attachment.dataUrl, label: notice.attachment.name, download: true }))
  };
};

