// Vehicle Pass: gated behind admin approval (see #vehicle-pass in student/faculty dashboards),
// not payment, unlike most other PDFs in this file - so it's downloaded straight from the
// approved pass record rather than via recordPayment()'s tempIdCardName-style flow.
// Code 128 (Set C - numeric pairs) symbol bar-width table, transcribed verbatim from the
// widely-used python-barcode library (barcode.charsets.code128.CODES) and cross-checked
// byte-for-byte against that library's own output before use - see the comment where this is
// called in makeChallanPdfs for why that verification mattered here.
const CODE128_PATTERNS = [
  "11011001100", "11001101100", "11001100110", "10010011000", "10010001100", "10001001100",
  "10011001000", "10011000100", "10001100100", "11001001000", "11001000100", "11000100100",
  "10110011100", "10011011100", "10011001110", "10111001100", "10011101100", "10011100110",
  "11001110010", "11001011100", "11001001110", "11011100100", "11001110100", "11101101110",
  "11101001100", "11100101100", "11100100110", "11101100100", "11100110100", "11100110010",
  "11011011000", "11011000110", "11000110110", "10100011000", "10001011000", "10001000110",
  "10110001000", "10001101000", "10001100010", "11010001000", "11000101000", "11000100010",
  "10110111000", "10110001110", "10001101110", "10111011000", "10111000110", "10001110110",
  "11101110110", "11010001110", "11000101110", "11011101000", "11011100010", "11011101110",
  "11101011000", "11101000110", "11100010110", "11101101000", "11101100010", "11100011010",
  "11101111010", "11001000010", "11110001010", "10100110000", "10100001100", "10010110000",
  "10010000110", "10000101100", "10000100110", "10110010000", "10110000100", "10011010000",
  "10011000010", "10000110100", "10000110010", "11000010010", "11001010000", "11110111010",
  "11000010100", "10001111010", "10100111100", "10010111100", "10010011110", "10111100100",
  "10011110100", "10011110010", "11110100100", "11110010100", "11110010010", "11011011110",
  "11011110110", "11110110110", "10101111000", "10100011110", "10001011110", "10111101000",
  "10111100010", "11110101000", "11110100010", "10111011110", "10111101110", "11101011110",
  "11110101110", "11010000100", "11010010000", "11010011100"
];
const CODE128_STOP = "11000111010";
const CODE128_START_C = 105;

// Encodes an even-length digit string as Code 128 Set C (two digits per symbol - the standard,
// most compact mode for numeric data). Returns the raw bar/space bit string ("1" = black module,
// "0" = white module), ready to be drawn as a series of filled rectangles.
const encodeCode128C = (digits) => {
  const values = [CODE128_START_C];
  for (let i = 0; i < digits.length; i += 2) {
    values.push(Number(digits.slice(i, i + 2)));
  }
  const checksum = values.reduce((sum, value, i) => sum + (i === 0 ? value : i * value), 0) % 103;
  values.push(checksum);
  return values.map((value) => CODE128_PATTERNS[value]).join("") + CODE128_STOP + "11";
};

// Renders a QR code as raw PDF content-stream operators (filled rectangles), the same "draw black
// bars at computed positions" technique as the Code 128 barcode above, just over a 2D module grid
// instead of a 1D bar pattern. Adjacent dark modules in the same row are merged into one wide
// rectangle (same run-length approach as encodeCode128C's bars) so a ~40x40-module code produces
// a few hundred `re` ops instead of up to 1600 single-module ones. Relies on the `qrcode` global
// from the vendored qrcode-generator.js (see that file's header for provenance/license) - only
// pages that actually build a QR-bearing PDF load that extra script.
const buildQrPdfOps = (text, x, yTop, size) => {
  // "H" (30% error-correction budget) rather than "M" (15%) - leaves enough recoverable headroom
  // to draw a small seal stamp over the center of the code (see makePdfWithPhoto) without breaking
  // the scan.
  const qr = qrcode(0, "H");
  qr.addData(text);
  qr.make();
  const moduleCount = qr.getModuleCount();
  const moduleSize = size / moduleCount;
  const ops = ["q", "0 0 0 rg"];
  for (let row = 0; row < moduleCount; row++) {
    let runStart = null;
    for (let col = 0; col <= moduleCount; col++) {
      const dark = col < moduleCount && qr.isDark(row, col);
      if (dark) {
        if (runStart === null) runStart = col;
      } else if (runStart !== null) {
        const rectX = x + runStart * moduleSize;
        const rectY = yTop - (row + 1) * moduleSize;
        const rectWidth = (col - runStart) * moduleSize;
        ops.push(`${rectX} ${rectY} ${rectWidth} ${moduleSize} re`, "f");
        runStart = null;
      }
    }
  }
  ops.push("Q");
  return ops;
};

// Single-page raw PDF assembler - same branded header band, seal watermark, and diagonal
// "OFFICIAL DOCUMENT" stamp other documents get via makePdfWithPhoto, but built independently so
// this document's custom per-line positioning can't affect any other PDF in this app. `images`
// are the already-loaded logo/seal/stamp byte buffers (loaded once by the caller and reused
// across all three copies, not re-fetched per page).
const buildSinglePagePdf = (contentBytes, images = {}, pageWidth = 595, pageHeight = 842) => {
  const { logoBytes, logoPixelWidth, logoPixelHeight, sealBytes, sealPixelWidth, sealPixelHeight, stampBytes, stampSize } = images;
  const chunks = [];
  let position = 0;
  const offsets = [0];
  const pushText = (str) => {
    const bytes = new TextEncoder().encode(str);
    chunks.push(bytes);
    position += bytes.length;
  };
  const pushBytes = (bytes) => {
    chunks.push(bytes);
    position += bytes.length;
  };
  const beginObj = (num) => {
    offsets.push(position);
    pushText(`${num} 0 obj\n`);
  };

  // Object numbers: 1 Catalog, 2 Pages, 3 Page, 4/5 fonts, 6 content stream, then optional
  // image/ExtGState objects only for whichever assets actually loaded - same sequential-allocation
  // pattern makePdfWithPhoto uses, so a failed image fetch just means fewer objects, not gaps.
  let nextObjNum = 7;
  const logoObjNum = logoBytes ? nextObjNum++ : null;
  const sealObjNum = sealBytes ? nextObjNum++ : null;
  const sealGsObjNum = sealBytes ? nextObjNum++ : null;
  const stampObjNum = stampBytes ? nextObjNum++ : null;
  const stampGsObjNum = stampBytes ? nextObjNum++ : null;
  const xObjectEntries = [
    logoObjNum ? `/ImLogo ${logoObjNum} 0 R` : "",
    sealObjNum ? `/ImSeal ${sealObjNum} 0 R` : "",
    stampObjNum ? `/ImStamp ${stampObjNum} 0 R` : ""
  ].filter(Boolean).join(" ");
  const extGStateEntries = [
    sealGsObjNum ? `/GS1 ${sealGsObjNum} 0 R` : "",
    stampGsObjNum ? `/GS2 ${stampGsObjNum} 0 R` : ""
  ].filter(Boolean).join(" ");

  pushText("%PDF-1.4\n");
  beginObj(1);
  pushText("<< /Type /Catalog /Pages 2 0 R >>\nendobj\n");
  beginObj(2);
  pushText("<< /Type /Pages /Kids [3 0 R] /Count 1 >>\nendobj\n");
  beginObj(3);
  pushText(
    `<< /Type /Page /Parent 2 0 R /MediaBox [0 0 ${pageWidth} ${pageHeight}] /Resources << /Font << /F1 4 0 R /F2 5 0 R >> /XObject << ${xObjectEntries} >> /ExtGState << ${extGStateEntries} >> >> /Contents 6 0 R >>\nendobj\n`
  );
  beginObj(4);
  pushText("<< /Type /Font /Subtype /Type1 /BaseFont /Helvetica >>\nendobj\n");
  beginObj(5);
  pushText("<< /Type /Font /Subtype /Type1 /BaseFont /Helvetica-Bold >>\nendobj\n");
  beginObj(6);
  pushText(`<< /Length ${contentBytes.length} >>\nstream\n`);
  pushBytes(contentBytes);
  pushText("\nendstream\nendobj\n");

  if (logoBytes) {
    beginObj(logoObjNum);
    pushText(`<< /Type /XObject /Subtype /Image /Width ${logoPixelWidth} /Height ${logoPixelHeight} /ColorSpace /DeviceRGB /BitsPerComponent 8 /Filter /DCTDecode /Length ${logoBytes.length} >>\nstream\n`);
    pushBytes(logoBytes);
    pushText("\nendstream\nendobj\n");
  }
  if (sealBytes) {
    beginObj(sealObjNum);
    pushText(`<< /Type /XObject /Subtype /Image /Width ${sealPixelWidth} /Height ${sealPixelHeight} /ColorSpace /DeviceRGB /BitsPerComponent 8 /Filter /DCTDecode /Length ${sealBytes.length} >>\nstream\n`);
    pushBytes(sealBytes);
    pushText("\nendstream\nendobj\n");
    beginObj(sealGsObjNum);
    pushText("<< /Type /ExtGState /ca 0.06 >>\nendobj\n");
  }
  if (stampBytes) {
    beginObj(stampObjNum);
    pushText(`<< /Type /XObject /Subtype /Image /Width ${stampSize} /Height ${stampSize} /ColorSpace /DeviceRGB /BitsPerComponent 8 /Filter /DCTDecode /Length ${stampBytes.length} >>\nstream\n`);
    pushBytes(stampBytes);
    pushText("\nendstream\nendobj\n");
    beginObj(stampGsObjNum);
    pushText("<< /Type /ExtGState /ca 0.05 >>\nendobj\n");
  }

  const objectCount = nextObjNum - 1;
  const xrefStart = position;
  pushText(`xref\n0 ${objectCount + 1}\n0000000000 65535 f \n`);
  offsets.slice(1).forEach((offset) => {
    pushText(`${String(offset).padStart(10, "0")} 00000 n \n`);
  });
  pushText(`trailer\n<< /Size ${objectCount + 1} /Root 1 0 R >>\nstartxref\n${xrefStart}\n%%EOF`);

  return new Blob(chunks, { type: "application/pdf" });
};

// Matches the real Andhra Bank/GPREC challan's exact layout - centered headers, left/right paired
// fields, and underlined fill-in-the-blank style for the Rs./towards lines (their own PDF leaves
// these two blank; ours fills them in). Returns THREE separate single-page PDFs (College/Student/
// Bank Copy), matching how the real system issues them as three distinct documents.
//
// No barcode bars are drawn - Code 128/39 need an exact standard bit-for-bit symbol table, and
// getting even one character subtly wrong produces bars that LOOK like a barcode but decode to
// garbage, which is worse than not having one. Instead each copy shows a generated reference
// number as plain text (same YYMMDDHHMMSS shape as the real SNO) - it is NOT looked up in the
// college's own system, since it was never submitted there.
const makeChallanPdfs = async (name, rollNo, purposeLabel, amountNumber, amountWords) => {
  const pad2 = (n) => String(n).padStart(2, "0");
  const now = new Date();
  const refNumber = `${pad2(now.getFullYear() % 100)}${pad2(now.getMonth() + 1)}${pad2(now.getDate())}${pad2(now.getHours())}${pad2(now.getMinutes())}${pad2(now.getSeconds())}`;
  const today = now.toLocaleDateString("en-IN", { day: "2-digit", month: "short", year: "numeric" });

  const renderCopy = (copyLabel) =>
    buildFeeChallanImage({ copyLabel, refNumber, name, rollNo, purposeLabel, amountNumber, amountWords, today });

  return [
    { label: "College Copy", fileSuffix: "college-copy", blob: await renderCopy("COLLEGE COPY") },
    { label: "Student Copy", fileSuffix: "student-copy", blob: await renderCopy("STUDENT COPY") },
    { label: "Bank Copy", fileSuffix: "bank-copy", blob: await renderCopy("BANK COPY") }
  ];
};

// PNG, not a PDF - matches "24_vehicle_pass.html" exactly, same treatment as buildBusPassImage
