// Student-uploaded records (SSC/inter/admission/ID proof) - real files persisted to server
// storage (department-folder pattern, same as profile photos/assignments), not just a filename.
const getStudentDocuments = (studentId) => getGprecDbBootstrap()?.studentDocuments?.[studentId] || [];
const createStudentDocument = (doc) => gprecDbPost("/student-documents", doc);
const removeStudentDocument = (id) => gprecDbPost("/student-documents/remove", { id });

// Same reasoning as gprecApiBaseUrl() above: a hardcoded 127.0.0.1 only resolves on the machine
// admin_config_server.py itself runs on - every other visitor's browser (LAN testing, or any real
// deployment) would try to reach their own loopback interface and silently fail every upload.
// Protocol matches the current page (not hardcoded http:) so this doesn't get blocked as mixed
// content once the site is actually served over https - see PRODUCTION.md for exposing this port.
const GPREC_UPLOAD_ENDPOINT = `${window.location.protocol}//${window.location.hostname}:8765/upload`;

const uploadDataUrlToServerStorage = async (file, dataUrl, section = "general") => {
  try {
    const response = await fetch(GPREC_UPLOAD_ENDPOINT, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        section,
        filename: file.name,
        dataUrl
      })
    });
    if (!response.ok) {
      showFeedToast("Upload server unreachable - this file is only saved in this browser, not on the server.");
      return null;
    }
    return await response.json();
  } catch {
    showFeedToast("Upload server unreachable - this file is only saved in this browser, not on the server.");
    return null;
  }
};

const readFileAsDataUrl = (file, section = "general") =>
  new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = async () => {
      const saved = await uploadDataUrlToServerStorage(file, reader.result, section);
      resolve({
        name: saved?.name || file.name,
        dataUrl: saved?.url || reader.result,
        storagePath: saved?.path || "",
        mime: saved?.mime || file.type || "",
        size: saved?.size || file.size || 0
      });
    };
    reader.onerror = reject;
    reader.readAsDataURL(file);
  });

// Student Documents panel (SSC/inter/admission/ID proof uploads) - real files persisted via the
// upload server, unlike course materials which only stores a filename. Lives here (after
// readFileAsDataUrl/getStudentDocuments are declared) rather than in the early studentProfileView
// block to avoid referencing those consts before their declarations run.
const documentListBody = document.querySelector("#documentListBody");
if (documentListBody) {
  const documentListEmpty = document.querySelector("#documentListEmpty");
  const uploadDocumentForm = document.querySelector("#uploadDocumentForm");
  const documentUploadFeedback = document.querySelector("#documentUploadFeedback");
  const documentStudentId = getCurrentStudentId();

  const renderDocumentList = () => {
    const documents = getStudentDocuments(documentStudentId);
    documentListEmpty?.classList.toggle("is-hidden", documents.length > 0);
    documentListBody.innerHTML = documents
      .map(
        (doc) => `
          <tr>
            <td>${doc.docType}</td>
            <td><a href="${doc.fileUrl}" target="_blank" rel="noopener">${doc.fileName}</a></td>
            <td>${doc.uploadedAt}</td>
            <td><button type="button" class="icon-btn-delete" data-remove-document="${doc.id}" aria-label="Remove" title="Remove">${deleteIconSvg}</button></td>
          </tr>
        `
      )
      .join("");

    documentListBody.querySelectorAll("[data-remove-document]").forEach((button) => {
      button.addEventListener("click", () => {
        removeStudentDocument(button.dataset.removeDocument);
        renderDocumentList();
      });
    });
  };

  uploadDocumentForm?.addEventListener("submit", async (event) => {
    event.preventDefault();
    const docType = document.querySelector("#documentTypeInput").value;
    const fileInput = document.querySelector("#documentFileInput");
    const file = fileInput.files?.[0];
    if (!docType || !file) return;

    const department = defaultStudentDirectory.find((student) => student.studentId === documentStudentId)?.branch || "unassigned";
    const saved = await readFileAsDataUrl(file, `documents/student/${department}`);

    createStudentDocument({
      studentId: documentStudentId,
      docType,
      fileName: saved.name,
      fileUrl: saved.dataUrl,
      fileMime: saved.mime
    });

    if (documentUploadFeedback) {
      documentUploadFeedback.textContent = `${docType} uploaded successfully.`;
      documentUploadFeedback.classList.remove("is-hidden");
      documentUploadFeedback.classList.add("success");
    }
    uploadDocumentForm.reset();
    renderDocumentList();
  });

  renderDocumentList();
}

// Transportation: Bus Service + Vehicle Pass, shared by student-dashboard.html and
// faculty-dashboard.html (same element IDs on both pages). Day-scholar gating only applies to
// students - faculty have no hostel-resident concept in this app so their sections render
// unconditionally.
const transportationRequesterInfo = () => {
  // Checks the active role first, not just "does a gprecStudentId key exist" - localStorage is
  // shared across every tab on this origin, so a stale gprecStudentId left over from an earlier
  // student login (in another tab) would otherwise misidentify a faculty session as a student one.
  const activeRole = localStorage.getItem("gprecActiveRole");
  if (activeRole === "student") {
    const studentId = getCurrentStudentId();
    if (studentId) return { type: "student", id: studentId, name: defaultStudentProfiles[studentId]?.name || "Student" };
  }
  if (activeRole === "faculty") {
    const facultyEmail = (localStorage.getItem("gprecFacultyEmail") || "").trim();
    if (facultyEmail) return { type: "faculty", id: facultyEmail, name: lookupFacultyRecordByEmail(facultyEmail)?.name || "Faculty" };
  }
  return null;
};

const busServiceListBody = document.querySelector("#busServiceListBody");
if (busServiceListBody) {
  const requester = transportationRequesterInfo();
  const busServiceListEmpty = document.querySelector("#busServiceListEmpty");
  const myBusRequestStatus = document.querySelector("#myBusRequestStatus");
  const myBusRequestNote = document.querySelector("#myBusRequestNote");
  const busServiceContent = document.querySelector("#busServiceContent");
  const busServiceNotApplicable = document.querySelector("#busServiceNotApplicable");
  const downloadBusPassButton = document.querySelector("#downloadBusPassButton");
  const requestBusCancellationButton = document.querySelector("#requestBusCancellationButton");
  const busCancellationFeedback = document.querySelector("#busCancellationFeedback");

  let busServiceBlocked = false;
  if (requester?.type === "student") {
    busServiceBlocked = Boolean(hostelStudentData[requester.id]);
    busServiceContent?.classList.toggle("is-hidden", busServiceBlocked);
    busServiceNotApplicable?.classList.toggle("is-hidden", !busServiceBlocked);
  }

  let currentBusRequest = null;

  const renderMyBusRequest = () => {
    if (!requester) return;
    const result = gprecDbRequest("/bus-requests/mine", { method: "POST", body: {} });
    const request = result?.request;
    currentBusRequest = request;
    if (!request) {
      if (myBusRequestStatus) myBusRequestStatus.textContent = "No request yet";
      myBusRequestNote?.classList.add("is-hidden");
      downloadBusPassButton?.classList.add("is-hidden");
      requestBusCancellationButton?.classList.add("is-hidden");
      return;
    }
    if (myBusRequestStatus) {
      myBusRequestStatus.innerHTML = `<span class="${requestStatusClass(request.status)}">${request.status}</span> - ${request.busNumber} (${request.routeName})`;
    }
    if (myBusRequestNote) {
      myBusRequestNote.classList.remove("success");
      if (request.status === "Rejected" && request.decisionNote) {
        myBusRequestNote.textContent = `Reason: ${request.decisionNote}`;
        myBusRequestNote.classList.remove("is-hidden");
      } else if (requester.type === "student" && request.status === "Pending" && !request.feePaid) {
        myBusRequestNote.textContent = `Pickup: ${request.pickupPoint || "-"} - Drop: ${request.dropPoint || "-"}. Pay the Transportation Fee under Online Payments to send this for admin approval.`;
        myBusRequestNote.classList.remove("is-hidden");
      } else if (request.status === "Pending") {
        myBusRequestNote.textContent = `Pickup: ${request.pickupPoint || "-"} - Drop: ${request.dropPoint || "-"}. Awaiting admin approval.`;
        myBusRequestNote.classList.remove("is-hidden");
      } else if (request.status === "Cancellation Requested") {
        myBusRequestNote.textContent = "Your cancellation request is awaiting admin confirmation.";
        myBusRequestNote.classList.remove("is-hidden");
      } else if (request.status === "Cancelled") {
        myBusRequestNote.textContent = "This bus pass has been cancelled. Request a new bus above if you need one again.";
        myBusRequestNote.classList.remove("is-hidden");
      } else if (request.status === "Approved") {
        myBusRequestNote.textContent = `Pickup: ${request.pickupPoint || "-"} - Drop: ${request.dropPoint || "-"}. Valid until ${request.validUntil || "-"}.`;
        myBusRequestNote.classList.add("success");
        myBusRequestNote.classList.remove("is-hidden");
      } else {
        myBusRequestNote.classList.add("is-hidden");
      }
    }
    downloadBusPassButton?.classList.toggle("is-hidden", request.status !== "Approved");
    // Self-service surrender of an Approved pass - for faculty there's no fee to refund, just the
    // pass to give back; for students this is also how they switch routes (cancel, then submit a
    // fresh request from Available Buses - which starts unpaid again, same as any new request).
    requestBusCancellationButton?.classList.toggle("is-hidden", request.status !== "Approved");
  };

  downloadBusPassButton?.addEventListener("click", async () => {
    if (!currentBusRequest || !requester) return;
    const photoUrl =
      requester.type === "student"
        ? getExplicitProfilePhotoSrc(defaultStudentProfiles[requester.id])
        : normalizeProfilePhotoUrl(lookupFacultyRecordByEmail(requester.id)?.photoUrl);
    const image = await buildBusPassImage(requester.name, photoUrl, currentBusRequest, requester);
    const link = document.createElement("a");
    link.href = URL.createObjectURL(image);
    link.download = `gprec-bus-pass-${requester.id}.png`;
    link.click();
    URL.revokeObjectURL(link.href);
  });

  requestBusCancellationButton?.addEventListener("click", () => {
    requestBusCancellationButton.disabled = true;
    const result = gprecDbRequest("/bus-requests/request-cancellation", { method: "POST", body: {} });
    requestBusCancellationButton.disabled = false;
    if (busCancellationFeedback) {
      busCancellationFeedback.textContent = result?.ok
        ? "Cancellation requested. Awaiting admin confirmation."
        : result?.error || "Could not request cancellation.";
      busCancellationFeedback.classList.remove("is-hidden");
      busCancellationFeedback.classList.toggle("success", Boolean(result?.ok));
    }
    if (result?.ok) renderMyBusRequest();
  });

  const renderBusServiceList = () => {
    const buses = getGprecDbBootstrap()?.buses || [];
    busServiceListEmpty?.classList.toggle("is-hidden", buses.length > 0);
    // Rendered as cards, not a table - a bus route carries too much per-item info (route, full
    // stop list, driver, two point pickers) to fit cleanly into table columns without every cell
    // wrapping onto several lines.
    busServiceListBody.innerHTML = buses
      .map((bus) => {
        // Pickup/drop point is a dropdown of the route's own published stops (not free text),
        // so a student can't request a point that isn't actually on the route.
        const stopOptions = (bus.stops || "")
          .split(",")
          .map((stop) => stop.trim())
          .filter(Boolean)
          .map((stop) => `<option value="${stop}">${stop}</option>`)
          .join("");
        return `
          <article class="bus-service-card">
            <div class="bus-service-card-head">
              <strong>${bus.busNumber}</strong>
              <span>${bus.routeName}</span>
            </div>
            <p class="bus-service-stops"><strong>Stops:</strong> ${bus.stops}</p>
            <div class="bus-service-meta">
              <span><strong>Driver:</strong> ${bus.driverName}${bus.driverMobile ? ` (${bus.driverMobile})` : ""}</span>
              <span><strong>Pickup:</strong> ${bus.pickupTime || "-"}</span>
              <span><strong>Drop:</strong> ${bus.dropTime || "-"}</span>
            </div>
            <div class="bus-service-request-row">
              <label>Your Pickup Point
                <select data-pickup-point="${bus.id}"><option value="">Select a stop</option>${stopOptions}</select>
              </label>
              <label>Your Drop Point
                <select data-drop-point="${bus.id}"><option value="">Select a stop</option>${stopOptions}</select>
              </label>
              <button type="button" data-request-bus="${bus.id}">Request</button>
            </div>
          </article>
        `;
      })
      .join("");
    const busServiceListFeedback = document.querySelector("#busServiceListFeedback");
    busServiceListBody.querySelectorAll("[data-request-bus]").forEach((button) => {
      button.addEventListener("click", () => {
        if (!requester) return;
        const busId = button.dataset.requestBus;
        const pickupPoint = busServiceListBody.querySelector(`[data-pickup-point="${busId}"]`)?.value.trim() || "";
        const dropPoint = busServiceListBody.querySelector(`[data-drop-point="${busId}"]`)?.value.trim() || "";
        if (busServiceListFeedback) busServiceListFeedback.classList.remove("success");
        if (!pickupPoint || !dropPoint) {
          if (busServiceListFeedback) {
            busServiceListFeedback.textContent = "Select your pickup point and drop point before requesting this bus.";
            busServiceListFeedback.classList.remove("is-hidden");
          }
          return;
        }
        button.disabled = true;
        button.textContent = "Requesting...";
        const result = gprecDbRequest("/bus-requests", {
          method: "POST",
          body: { busId, requesterName: requester.name, pickupPoint, dropPoint }
        });
        button.disabled = false;
        button.textContent = "Request";
        if (result?.ok) {
          if (busServiceListFeedback) busServiceListFeedback.classList.add("is-hidden");
          renderMyBusRequest();
        } else if (busServiceListFeedback) {
          busServiceListFeedback.textContent = result?.error || "Could not submit request.";
          busServiceListFeedback.classList.remove("is-hidden");
        }
      });
    });
  };

  if (!busServiceBlocked) renderBusServiceList();
  renderMyBusRequest();
}

// Shared in-dashboard viewer for lesson resources (YouTube links, uploaded documents, other
// links) - injected once into <body> on first use rather than duplicated in every dashboard
// HTML file, since both faculty and student Online Courses screens need the same viewer.
const getYouTubeEmbedUrl = (url) => {
  const match = (url || "").match(/(?:youtube\.com\/watch\?v=|youtu\.be\/|youtube\.com\/embed\/)([\w-]{11})/);
  return match ? `https://www.youtube.com/embed/${match[1]}` : null;
};

// Generic "N watching now" facepile + count, shared by the webinar card and the resource
// viewer modal - avatars are always the plain gprecianUserIcon silhouette (no real photos), the
// viewer's name is only used as a hover tooltip.
const renderWebinarWatchingRow = (webinar) => {
  if (!webinar?.watchingCount) return "";
  const names = (webinar.watchingViewers || []).map((viewer) => viewer.name).join(", ");
  return `
    <span class="webinar-viewer-avatar" title="${names}">${gprecianUserIcon}</span>
    <span class="webinar-watching-count">${webinar.watchingCount} watching now</span>
  `;
};

let activeWebinarPingInterval = null;
const stopWebinarPing = () => {
  if (activeWebinarPingInterval) {
    clearInterval(activeWebinarPingInterval);
    activeWebinarPingInterval = null;
  }
};

// watchRefreshFn, if given, is called immediately and every 20s while the modal stays open; it
// should ping presence server-side and return fresh watching-row HTML - used by both Webinars
// and Online Classes, kept generic here so this modal doesn't need to know which feature it's showing.
const openResourceModal = (url, title, watchRefreshFn) => {
  let overlay = document.querySelector("#resourceViewerOverlay");
  if (!overlay) {
    overlay = document.createElement("div");
    overlay.id = "resourceViewerOverlay";
    overlay.className = "resource-viewer-overlay is-hidden";
    overlay.innerHTML = `
      <div class="resource-viewer-modal">
        <button type="button" class="resource-viewer-close" aria-label="Close">&times;</button>
        <h3 id="resourceViewerTitle"></h3>
        <div id="resourceViewerWatching" class="webinar-watching-row is-hidden"></div>
        <div class="resource-viewer-frame-wrap"><iframe id="resourceViewerFrame" allow="autoplay; encrypted-media; picture-in-picture" allowfullscreen></iframe></div>
        <a id="resourceViewerFallbackLink" href="#" target="_blank" rel="noreferrer">Can't view it here? Open in a new tab</a>
      </div>
    `;
    document.body.appendChild(overlay);
    const closeModal = () => {
      overlay.classList.add("is-hidden");
      document.querySelector("#resourceViewerFrame").src = "about:blank";
      stopWebinarPing();
    };
    overlay.addEventListener("click", (event) => {
      if (event.target === overlay) closeModal();
    });
    overlay.querySelector(".resource-viewer-close").addEventListener("click", closeModal);
  }
  document.querySelector("#resourceViewerTitle").textContent = title || "Resource";
  document.querySelector("#resourceViewerFrame").src = getYouTubeEmbedUrl(url) || url;
  document.querySelector("#resourceViewerFallbackLink").href = url;
  stopWebinarPing();
  const watchingRow = document.querySelector("#resourceViewerWatching");
  watchingRow.classList.add("is-hidden");
  watchingRow.innerHTML = "";
  if (watchRefreshFn) {
    const refresh = () => {
      const rowHtml = watchRefreshFn() || "";
      if (rowHtml !== watchingRow.innerHTML) {
        watchingRow.innerHTML = rowHtml;
        watchingRow.classList.toggle("is-hidden", !rowHtml);
      }
    };
    refresh();
    activeWebinarPingInterval = setInterval(refresh, 20000);
  }
  overlay.classList.remove("is-hidden");
};

// Webinars - shared between student and faculty dashboards, both of which have a
// #webinarsListBody element; admin-created, visible to everyone, no enrollment step.
// Shared by Webinars and Online Classes - both have the same scheduledAtRaw/watchingCount shape.
// No explicit end time is stored, so "Live" is treated as within a couple of hours of the
// scheduled start, generous enough for any real session without needing a duration field.
const LIVE_WINDOW_MS = 2 * 60 * 60 * 1000;
const getLiveStatusBadge = (item) => {
  const now = Date.now();
  const start = item.scheduledAtRaw;
  if (now < start) return `<span class="warn">Upcoming</span>`;
  if (now <= start + LIVE_WINDOW_MS) return `<span class="live-badge">Live</span>`;
  return `<span class="not-marked">Ended</span>`;
};

const webinarsListBody = document.querySelector("#webinarsListBody");
if (webinarsListBody) {
  const webinarsEmpty = document.querySelector("#webinarsEmpty");
  let webinarsById = {};
  // Rebuilding innerHTML every 20s (even when nothing changed) flickers the whole list and drops
  // focus/scroll position - skip the DOM write entirely when the fetched data is byte-identical
  // to what's already on screen.
  let lastWebinarsSnapshot = "";

  const renderWebinars = () => {
    const webinars = gprecDbRequest("/webinars/all", { method: "POST", body: {} })?.webinars || [];
    const snapshot = JSON.stringify(webinars);
    if (snapshot === lastWebinarsSnapshot) return;
    lastWebinarsSnapshot = snapshot;
    webinarsById = {};
    webinars.forEach((webinar) => { webinarsById[webinar.id] = webinar; });
    webinarsEmpty?.classList.toggle("is-hidden", webinars.length > 0);
    webinarsListBody.innerHTML = webinars
      .map(
        (webinar) => `
          <article class="bus-service-card">
            <div class="bus-service-card-head">
              <strong>${webinar.title}</strong>
              <span class="webinar-card-meta"><span>${webinar.scheduledAt}</span>${getLiveStatusBadge(webinar)}</span>
            </div>
            ${
              webinar.watchingCount > 0
                ? `<div class="webinar-watching-row">${renderWebinarWatchingRow(webinar)}</div>`
                : ""
            }
            <p class="bus-service-stops">${webinar.description}</p>
            <p class="course-summary-faculty"><span class="course-assigned-by-label">Hosted by</span> ${webinar.createdByName}</p>
            <a href="${webinar.liveLink}" class="pass-action-button" data-open-resource="${webinar.id}">Join Webinar</a>
          </article>
        `
      )
      .join("");
    webinarsListBody.querySelectorAll("[data-open-resource]").forEach((link) => {
      link.addEventListener("click", (event) => {
        event.preventDefault();
        const webinar = webinarsById[link.dataset.openResource];
        if (!webinar) return;
        openResourceModal(webinar.liveLink, webinar.title, () => {
          gprecDbRequest("/webinars/view-ping", { method: "POST", body: { webinarId: webinar.id } });
          const fresh = (gprecDbRequest("/webinars/all", { method: "POST", body: {} })?.webinars || []).find(
            (item) => item.id === webinar.id
          );
          return renderWebinarWatchingRow(fresh);
        });
      });
    });
  };
  renderWebinars();
  // Refresh periodically so the "N watching now" count updates for people just looking at the
  // list (not just the person whose own ping triggered the change).
  setInterval(renderWebinars, 20000);
}

// Online Classes (student side) - faculty-scheduled live classes for the student's own section.
// Faculty's own "My Online Classes" create/manage UI lives further down, near the course builder.
const onlineClassesListBody = document.querySelector("#onlineClassesListBody");
if (onlineClassesListBody) {
  const onlineClassesEmpty = document.querySelector("#onlineClassesEmpty");
  let onlineClassesById = {};
  let lastOnlineClassesSnapshot = "";

  const renderOnlineClasses = () => {
    const classes = gprecDbRequest("/online-classes/all", { method: "POST", body: {} })?.classes || [];
    const snapshot = JSON.stringify(classes);
    if (snapshot === lastOnlineClassesSnapshot) return;
    lastOnlineClassesSnapshot = snapshot;
    onlineClassesById = {};
    classes.forEach((item) => { onlineClassesById[item.id] = item; });
    onlineClassesEmpty?.classList.toggle("is-hidden", classes.length > 0);
    onlineClassesListBody.innerHTML = classes
      .map(
        (item) => `
          <article class="bus-service-card">
            <div class="bus-service-card-head">
              <strong>${item.title}</strong>
              <span class="webinar-card-meta"><span>${item.scheduledAt}</span>${getLiveStatusBadge(item)}</span>
            </div>
            ${
              item.watchingCount > 0
                ? `<div class="webinar-watching-row">${renderWebinarWatchingRow(item)}</div>`
                : ""
            }
            <p class="bus-service-stops">${item.description}</p>
            <p class="course-summary-faculty"><span class="course-assigned-by-label">Faculty</span> ${item.facultyName}</p>
            <a href="${item.liveLink}" class="pass-action-button" data-open-resource="${item.id}">Join Class</a>
          </article>
        `
      )
      .join("");
    onlineClassesListBody.querySelectorAll("[data-open-resource]").forEach((link) => {
      link.addEventListener("click", (event) => {
        event.preventDefault();
        const item = onlineClassesById[link.dataset.openResource];
        if (!item) return;
        openResourceModal(item.liveLink, item.title, () => {
          gprecDbRequest("/online-classes/view-ping", { method: "POST", body: { classId: item.id } });
          const fresh = (gprecDbRequest("/online-classes/all", { method: "POST", body: {} })?.classes || []).find(
            (c) => c.id === item.id
          );
          return renderWebinarWatchingRow(fresh);
        });
      });
    });
  };
  renderOnlineClasses();
  setInterval(renderOnlineClasses, 20000);
}

const availableCoursesListBody = document.querySelector("#availableCoursesListBody");
if (availableCoursesListBody) {
  const availableCoursesEmpty = document.querySelector("#availableCoursesEmpty");
  const myEnrolledCoursesListBody = document.querySelector("#myEnrolledCoursesListBody");
  const myEnrolledCoursesEmpty = document.querySelector("#myEnrolledCoursesEmpty");

  const renderCourses = () => {
    const openAvailableIds = new Set(
      [...availableCoursesListBody.querySelectorAll("details[open]")].map((d) => d.dataset.courseId)
    );
    const openEnrolledIds = new Set(
      [...myEnrolledCoursesListBody.querySelectorAll("details[open]")].map((d) => d.dataset.courseId)
    );

    const allCourses = gprecDbRequest("/courses/all", { method: "POST", body: {} })?.courses || [];
    const enrollments = gprecDbRequest("/course-enrollments/mine", { method: "POST", body: {} })?.enrollments || [];
    const enrolledCourseIds = new Set(enrollments.map((enrollment) => enrollment.courseId));
    const lessonsById = {};
    allCourses.forEach((course) => (course.lessons || []).forEach((lesson) => { lessonsById[lesson.id] = lesson; }));

    const available = allCourses.filter((course) => !enrolledCourseIds.has(course.id));
    availableCoursesEmpty?.classList.toggle("is-hidden", available.length > 0);
    availableCoursesListBody.innerHTML = `<div class="profile-accordion">${available
      .map(
        (course) => `
          <details class="profile-accordion-item" data-course-id="${course.id}">
            <summary>
              <span>${course.title}</span>
              <span class="course-summary-faculty"><span class="course-assigned-by-label">Assigned by</span> ${course.facultyName}</span>
            </summary>
            <div class="profile-accordion-body">
              <p class="bus-service-stops">${course.description}</p>
              <div class="bus-service-meta">
                <span>${(course.lessons || []).length} lesson${(course.lessons || []).length === 1 ? "" : "s"}</span>
              </div>
              <button type="button" class="pass-action-button" data-enroll-course="${course.id}">Enroll</button>
            </div>
          </details>
        `
      )
      .join("")}</div>`;
    availableCoursesListBody.querySelectorAll("details").forEach((d) => {
      if (openAvailableIds.has(d.dataset.courseId)) d.open = true;
    });
    availableCoursesListBody.querySelectorAll("[data-enroll-course]").forEach((button) => {
      button.addEventListener("click", () => {
        button.disabled = true;
        button.textContent = "Enrolling...";
        gprecDbRequest("/course-enrollments", { method: "POST", body: { courseId: button.dataset.enrollCourse } });
        renderCourses();
      });
    });

    myEnrolledCoursesEmpty?.classList.toggle("is-hidden", enrollments.length > 0);
    myEnrolledCoursesListBody.innerHTML = `<div class="profile-accordion">${enrollments
      .map((enrollment) => {
        const course = allCourses.find((item) => item.id === enrollment.courseId);
        const completedLessonIds = new Set(enrollment.completedLessonIds || []);
        const totalLessons = enrollment.totalLessons || 0;
        const progressPercent = totalLessons ? Math.round((completedLessonIds.size / totalLessons) * 100) : 0;
        const lessonRows = (course?.lessons || [])
          .map((lesson) => {
            const done = completedLessonIds.has(lesson.id);
            return `
              <div class="course-lesson-display-row">
                <strong>${lesson.title}</strong>
                <div class="course-lesson-actions">
                  <a href="${lesson.resourceUrl}" data-open-resource="${lesson.id}">Open resource</a>
                  <label class="toggle-switch">
                    <input type="checkbox" data-toggle-lesson="${lesson.id}" data-toggle-course="${enrollment.courseId}" ${done ? "checked" : ""}>
                    <span class="toggle-slider"></span>
                    <span class="toggle-label-text">${done ? "Done" : "Mark Done"}</span>
                  </label>
                </div>
              </div>
            `;
          })
          .join("");
        return `
          <details class="profile-accordion-item" data-course-id="${enrollment.courseId}">
            <summary>
              <span class="course-summary-title">
                <span>${enrollment.title}</span>
                <span class="${enrollment.status === "Completed" ? "ok" : "warn"}">${enrollment.status}</span>
              </span>
            </summary>
            <div class="profile-accordion-body">
              <p class="bus-service-stops">${enrollment.description}</p>
              <div class="funding-progress-track"><div class="funding-progress-fill" style="width:${progressPercent}%"></div></div>
              <p class="funding-progress-label">${completedLessonIds.size} of ${totalLessons} lessons done (${progressPercent}%)</p>
              <div class="course-lesson-list">${lessonRows}</div>
            </div>
          </details>
        `;
      })
      .join("")}</div>`;
    myEnrolledCoursesListBody.querySelectorAll("details").forEach((d) => {
      if (openEnrolledIds.has(d.dataset.courseId)) d.open = true;
    });
    myEnrolledCoursesListBody.querySelectorAll("[data-open-resource]").forEach((button) => {
      button.addEventListener("click", (event) => {
        event.preventDefault();
        const lesson = lessonsById[button.dataset.openResource];
        if (lesson) openResourceModal(lesson.resourceUrl, lesson.title);
      });
    });
    myEnrolledCoursesListBody.querySelectorAll("[data-toggle-lesson]").forEach((checkbox) => {
      checkbox.addEventListener("change", () => {
        const markingDone = checkbox.checked;
        checkbox.disabled = true;
        gprecDbRequest(markingDone ? "/course-lessons/complete" : "/course-lessons/uncomplete", {
          method: "POST",
          body: { courseId: checkbox.dataset.toggleCourse, lessonId: checkbox.dataset.toggleLesson }
        });
        renderCourses();
      });
    });
  };

  renderCourses();
}

const vehiclePassForm = document.querySelector("#vehiclePassForm");
if (vehiclePassForm) {
  const requester = transportationRequesterInfo();
  const myVehiclePassStatus = document.querySelector("#myVehiclePassStatus");
  const myVehiclePassNote = document.querySelector("#myVehiclePassNote");
  const downloadVehiclePassButton = document.querySelector("#downloadVehiclePassButton");
  const vehiclePassFeedback = document.querySelector("#vehiclePassFeedback");
  const vehiclePassContent = document.querySelector("#vehiclePassContent");
  const vehiclePassNotApplicable = document.querySelector("#vehiclePassNotApplicable");

  if (requester?.type === "student") {
    const blocked = Boolean(hostelStudentData[requester.id]);
    vehiclePassContent?.classList.toggle("is-hidden", blocked);
    vehiclePassNotApplicable?.classList.toggle("is-hidden", !blocked);
  }

  let currentPass = null;

  const renderMyVehiclePass = () => {
    if (!requester) return;
    const result = gprecDbRequest("/vehicle-passes/mine", { method: "POST", body: {} });
    currentPass = result?.pass || null;
    if (!currentPass) {
      if (myVehiclePassStatus) myVehiclePassStatus.textContent = "No application yet";
      myVehiclePassNote?.classList.add("is-hidden");
      downloadVehiclePassButton?.classList.add("is-hidden");
      return;
    }
    if (myVehiclePassStatus) {
      myVehiclePassStatus.innerHTML = `<span class="${requestStatusClass(currentPass.status)}">${currentPass.status}</span> - ${currentPass.vehicleType} ${currentPass.vehicleNumber}`;
    }
    if (myVehiclePassNote) {
      myVehiclePassNote.classList.remove("success");
      if (currentPass.status === "Rejected" && currentPass.decisionNote) {
        myVehiclePassNote.textContent = `Reason: ${currentPass.decisionNote}`;
        myVehiclePassNote.classList.remove("is-hidden");
      } else if (currentPass.status === "Pending") {
        myVehiclePassNote.textContent =
          currentPass.verificationResult === "verified"
            ? "Documents auto-verified. Awaiting admin approval."
            : "Awaiting admin review and approval.";
        myVehiclePassNote.classList.remove("is-hidden");
      } else if (currentPass.status === "Approved") {
        myVehiclePassNote.textContent = `Valid until ${currentPass.validUntil || "-"}.`;
        myVehiclePassNote.classList.add("success");
        myVehiclePassNote.classList.remove("is-hidden");
      } else {
        myVehiclePassNote.classList.add("is-hidden");
      }
    }
    downloadVehiclePassButton?.classList.toggle("is-hidden", currentPass.status !== "Approved");
  };

  vehiclePassForm.addEventListener("submit", async (event) => {
    event.preventDefault();
    if (!requester) return;
    const vehicleType = document.querySelector("#vehiclePassTypeInput")?.value || "";
    const vehicleNumber = document.querySelector("#vehiclePassNumberInput")?.value.trim() || "";
    const licenseNumber = document.querySelector("#vehiclePassLicenseInput")?.value.trim() || "";
    const licenseFile = document.querySelector("#vehiclePassLicenseDocInput")?.files?.[0];
    const rcFile = document.querySelector("#vehiclePassRcDocInput")?.files?.[0];
    if (!vehicleType || !vehicleNumber || !licenseNumber || !licenseFile || !rcFile) {
      if (vehiclePassFeedback) {
        vehiclePassFeedback.textContent = "All fields, including License and RC photos, are required.";
        vehiclePassFeedback.classList.remove("is-hidden", "success");
      }
      return;
    }
    if (vehiclePassFeedback) {
      vehiclePassFeedback.textContent = "Uploading documents...";
      vehiclePassFeedback.classList.remove("is-hidden", "success");
    }
    try {
      const [licenseDoc, rcDoc] = await Promise.all([
        readFileAsDataUrl(licenseFile, `documents/vehicle-pass/${requester.id}`),
        readFileAsDataUrl(rcFile, `documents/vehicle-pass/${requester.id}`)
      ]);
      const result = gprecDbRequest("/vehicle-passes", {
        method: "POST",
        body: {
          requesterName: requester.name,
          vehicleType,
          vehicleNumber,
          licenseNumber,
          licenseDocUrl: licenseDoc.dataUrl,
          rcDocUrl: rcDoc.dataUrl
        }
      });
      if (result?.ok) {
        vehiclePassFeedback.textContent = "Application submitted. Awaiting admin approval.";
        vehiclePassFeedback.classList.add("success");
        vehiclePassForm.reset();
        renderMyVehiclePass();
      } else {
        vehiclePassFeedback.textContent = result?.error || "Could not submit application.";
        vehiclePassFeedback.classList.remove("success");
      }
    } catch {
      vehiclePassFeedback.textContent = "Could not upload documents. Please try again.";
      vehiclePassFeedback.classList.remove("success");
    }
  });

  downloadVehiclePassButton?.addEventListener("click", async () => {
    if (!currentPass || !requester) return;
    const photoUrl =
      requester.type === "student"
        ? getExplicitProfilePhotoSrc(defaultStudentProfiles[requester.id])
        : normalizeProfilePhotoUrl(lookupFacultyRecordByEmail(requester.id)?.photoUrl);
    const image = await buildVehiclePassImage(requester.name, photoUrl, currentPass, requester);
    const link = document.createElement("a");
    link.href = URL.createObjectURL(image);
    link.download = `gprec-vehicle-pass-${requester.id}.png`;
    link.click();
    URL.revokeObjectURL(link.href);
  });

  renderMyVehiclePass();
}

// General-purpose registry of uploadable photo slots on the public website (not dashboards).
// To add a new slot: add an entry here, then put a matching data-photo-slot="key" attribute
// on an <img> (hydrated via .src) or a container element (hydrated via background-image) on
// the target page. The admin's Notices & Content > Website Photo Manager panel lists every
// entry here automatically, so no other admin-side change is needed.
// defaultUrl is whatever's hardcoded as that <img>'s own src on the public page - shown as the
// current photo until an admin uploads a custom one, instead of the table just saying "No custom
// photo uploaded" while the page itself is clearly showing something.
const sitePhotoSlots = [
  { key: "about-founder", page: "About Us", section: "Founder Portrait", recommendedSize: "220 x 260px, portrait, JPG/PNG", defaultUrl: "https://www.gprec.ac.in/wp-content/uploads/2019/04/G.-Pulla-Reddy-Garu.jpg", orientation: "portrait" },
  { key: "admin-principal", page: "About Us", section: "Principal Photo", recommendedSize: "200 x 300px, portrait, JPG/PNG", defaultUrl: "https://www.gprec.ac.in/wp-content/uploads/2019/04/principal-01-201x300.png", orientation: "portrait" },
  { key: "admin-vice-principal", page: "About Us", section: "Vice Principal Photo", recommendedSize: "200 x 300px, portrait, JPG/PNG", defaultUrl: "https://www.gprec.ac.in/wp-content/uploads/2026/03/VBR-240x300.jpeg", orientation: "portrait" }
];

const getSitePhotos = () => getSiteContent("sitePhotos", {});
const saveSitePhotos = (photos) => saveSiteContent("sitePhotos", photos);

const sitePhotoManagerBody = document.querySelector("#sitePhotoManagerBody");

const renderSitePhotoManager = () => {
  if (!sitePhotoManagerBody) return;
  const photos = getSitePhotos();
  sitePhotoManagerBody.innerHTML = sitePhotoSlots
    .map((slot) => {
      const photo = photos[slot.key];
      return `
        <tr>
          <td>${slot.page} - ${slot.section}</td>
          <td>${slot.recommendedSize}</td>
          <td>${photo ? `<img src="${photo.dataUrl}" alt="" class="site-photo-thumb">` : "No custom photo uploaded"}</td>
          <td><input type="file" accept="image/*" data-photo-upload="${slot.key}"></td>
          <td>${photo ? `<button type="button" class="icon-btn-delete" data-photo-remove="${slot.key}" aria-label="Remove photo">${deleteIconSvg}</button>` : ""}</td>
        </tr>
      `;
    })
    .join("");
};

renderSitePhotoManager();

sitePhotoManagerBody?.addEventListener("change", async (event) => {
  const input = event.target.closest("[data-photo-upload]");
  if (!input || !input.files[0]) return;
  try {
    const uploaded = await readFileAsDataUrl(input.files[0], `site-photos/${input.dataset.photoUpload || "general"}`);
    const photos = getSitePhotos();
    photos[input.dataset.photoUpload] = { ...uploaded, uploadedAt: Date.now() };
    saveSitePhotos(photos);
    renderSitePhotoManager();
  } catch {
    input.value = "";
  }
});

sitePhotoManagerBody?.addEventListener("click", (event) => {
  const removeButton = event.target.closest("[data-photo-remove]");
  if (!removeButton) return;
  const photos = getSitePhotos();
  delete photos[removeButton.dataset.photoRemove];
  saveSitePhotos(photos);
  renderSitePhotoManager();
});

// Public-page hydration: fills in any admin-uploaded photo for slots present on the current page.
document.querySelectorAll("[data-photo-slot]").forEach((el) => {
  const photo = getSitePhotos()[el.dataset.photoSlot];
  if (!photo) return;
  if (el.tagName === "IMG") {
    el.src = photo.dataUrl;
    // a properly-sized admin upload shouldn't need the zoom/crop tuned for the old default photo
    el.style.transform = "none";
    el.style.objectPosition = "center";
  } else {
    el.classList.remove("about-gallery-placeholder");
    el.style.backgroundImage = `url(${photo.dataUrl})`;
    el.style.backgroundSize = "cover";
    el.style.backgroundPosition = "center";
    el.innerHTML = "";
  }
});

// Home page hero slider: fully admin-managed slide list (add/remove).
const getHomeHeroSlides = () => getSiteContent("homeHeroSlides", []);
const saveHomeHeroSlides = (slides) => saveSiteContent("homeHeroSlides", slides);

const regenerateHeroDots = () => {
  const dotsContainer = document.querySelector(".hero-dots");
  if (!dotsContainer) return;
  const totalSlides = document.querySelectorAll(".hero-slide").length;
  dotsContainer.innerHTML = Array.from({ length: totalSlides }, (_, i) => `<span${i === 0 ? ' class="active"' : ""}></span>`).join("");
}

const homeHeroSlidesContainer = document.querySelector("#homeHeroSlides");

const renderHomeHeroSlides = () => {
  if (!homeHeroSlidesContainer) return;
  homeHeroSlidesContainer.innerHTML = getHomeHeroSlides()
    .map(
      (slide, index) => `<img class="hero-slide${slide.poster ? " poster-slide" : ""}${index === 0 ? " active" : ""}" src="${slide.photoDataUrl}" alt="${slide.alt || "GPREC campus photo"}">`
    )
    .join("");
  regenerateHeroDots();
};

renderHomeHeroSlides();

const homeHeroManagerBody = document.querySelector("#homeHeroManagerBody");
const homeHeroAltInput = document.querySelector("#homeHeroAltInput");
const homeHeroPhotoInput = document.querySelector("#homeHeroPhotoInput");
const addHomeHeroSlideButton = document.querySelector("#addHomeHeroSlideButton");
const homeHeroFeedback = document.querySelector("#homeHeroFeedback");

const renderHomeHeroManager = () => {
  if (!homeHeroManagerBody) return;
  const slides = getHomeHeroSlides();
  homeHeroManagerBody.innerHTML = slides.length
    ? slides
        .map(
          (slide, index) => `
        <tr>
          <td><img src="${slide.photoDataUrl}" alt="" class="site-photo-thumb"></td>
          <td>${slide.alt || "-"}</td>
          <td>
            <div class="action-cell">
              <button type="button" class="btn-set-first" data-home-hero-first="${slide.id}"${index === 0 ? " disabled" : ""}>${index === 0 ? "First" : "Set First"}</button>
              <button type="button" class="icon-btn-delete" data-home-hero-remove="${slide.id}" aria-label="Remove slide">${deleteIconSvg}</button>
            </div>
          </td>
        </tr>
      `
        )
        .join("")
    : `<tr><td colspan="3">No slides yet. Add one above.</td></tr>`;
};

renderHomeHeroManager();

homeHeroManagerBody?.addEventListener("click", (event) => {
  const firstButton = event.target.closest("[data-home-hero-first]");
  if (firstButton) {
    const slides = getHomeHeroSlides();
    const index = slides.findIndex((slide) => slide.id === firstButton.dataset.homeHeroFirst);
    if (index > 0) {
      const [slide] = slides.splice(index, 1);
      slides.unshift(slide);
      saveHomeHeroSlides(slides);
      renderHomeHeroManager();
      renderHomeHeroSlides();
    }
    return;
  }
  const removeButton = event.target.closest("[data-home-hero-remove]");
  if (!removeButton) return;
  const slides = getHomeHeroSlides().filter((slide) => slide.id !== removeButton.dataset.homeHeroRemove);
  saveHomeHeroSlides(slides);
  renderHomeHeroManager();
});

addHomeHeroSlideButton?.addEventListener("click", async () => {
  const alt = homeHeroAltInput?.value.trim();
  const file = homeHeroPhotoInput?.files[0];
  if (!file) {
    if (homeHeroFeedback) {
      homeHeroFeedback.textContent = "Choose a photo before adding a slide.";
      homeHeroFeedback.classList.remove("success");
    }
    return;
  }
  try {
    const uploaded = await readFileAsDataUrl(file, "media/home-hero");
    const slides = getHomeHeroSlides();
    slides.push({ id: `hero-${Date.now()}`, alt, photoDataUrl: uploaded.dataUrl });
    saveHomeHeroSlides(slides);
    renderHomeHeroManager();
    if (homeHeroAltInput) homeHeroAltInput.value = "";
    if (homeHeroPhotoInput) homeHeroPhotoInput.value = "";
    if (homeHeroFeedback) {
      homeHeroFeedback.textContent = "Slide added. It will appear in the homepage hero rotation.";
      homeHeroFeedback.classList.add("success");
    }
  } catch {
    if (homeHeroFeedback) {
      homeHeroFeedback.textContent = "Could not read that photo file. Try a different image.";
      homeHeroFeedback.classList.remove("success");
    }
  }
});

