const renderAboutHistoryManager = () => {
  if (!aboutHistoryManagerBody) return;
  const slides = getAboutHistorySlides();
  aboutHistoryManagerBody.innerHTML = slides.length
    ? slides
        .map(
          (slide, index) => `
        <tr>
          <td><img src="${slide.photoDataUrl}" alt="" class="site-photo-thumb"></td>
          <td>${slide.caption || "-"}</td>
          <td>
            <div class="action-cell">
              <button type="button" class="btn-set-first" data-about-history-first="${slide.id}"${index === 0 ? " disabled" : ""}>${index === 0 ? "First" : "Set First"}</button>
              <button type="button" class="icon-btn-delete" data-about-history-remove="${slide.id}" aria-label="Remove slide">${deleteIconSvg}</button>
            </div>
          </td>
        </tr>
      `
        )
        .join("")
    : `<tr><td colspan="3">No slides yet. Add one above.</td></tr>`;
};

renderAboutHistoryManager();

aboutHistoryManagerBody?.addEventListener("click", (event) => {
  const firstButton = event.target.closest("[data-about-history-first]");
  if (firstButton) {
    const slides = getAboutHistorySlides();
    const index = slides.findIndex((slide) => slide.id === firstButton.dataset.aboutHistoryFirst);
    if (index > 0) {
      const [slide] = slides.splice(index, 1);
      slides.unshift(slide);
      saveAboutHistorySlides(slides);
      renderAboutHistoryManager();
      renderAboutHistoryGallery();
    }
    return;
  }
  const removeButton = event.target.closest("[data-about-history-remove]");
  if (!removeButton) return;
  const slides = getAboutHistorySlides().filter((slide) => slide.id !== removeButton.dataset.aboutHistoryRemove);
  saveAboutHistorySlides(slides);
  renderAboutHistoryManager();
});

addAboutHistorySlideButton?.addEventListener("click", async () => {
  const caption = aboutHistoryCaptionInput?.value.trim();
  const file = aboutHistoryPhotoInput?.files[0];
  if (!file) {
    if (aboutHistoryFeedback) {
      aboutHistoryFeedback.textContent = "Choose a photo before adding a slide.";
      aboutHistoryFeedback.classList.remove("success");
    }
    return;
  }
  try {
    const uploaded = await readFileAsDataUrl(file, "media/about-history");
    const slides = getAboutHistorySlides();
    slides.push({ id: `hist-${Date.now()}`, caption, photoDataUrl: uploaded.dataUrl });
    saveAboutHistorySlides(slides);
    renderAboutHistoryManager();
    if (aboutHistoryCaptionInput) aboutHistoryCaptionInput.value = "";
    if (aboutHistoryPhotoInput) aboutHistoryPhotoInput.value = "";
    if (aboutHistoryFeedback) {
      aboutHistoryFeedback.textContent = "Slide added. It will appear on the About Us History gallery.";
      aboutHistoryFeedback.classList.add("success");
    }
  } catch {
    if (aboutHistoryFeedback) {
      aboutHistoryFeedback.textContent = "Could not read that photo file. Try a different image.";
      aboutHistoryFeedback.classList.remove("success");
    }
  }
});

