// Video Gallery: admin-managed list of YouTube videos shown on the homepage.
const extractYoutubeId = (url) => {
  const match = String(url || "").match(/(?:youtu\.be\/|youtube\.com\/(?:watch\?v=|embed\/))([a-zA-Z0-9_-]{11})/);
  return match ? match[1] : null;
};

const getVideoGallery = () => getSiteContent("videoGallery", []);
const saveVideoGallery = (videos) => saveSiteContent("videoGallery", videos);

const homeVideoGrid = document.querySelector(".video-grid");

const renderHomeVideoGrid = () => {
  if (!homeVideoGrid) return;
  homeVideoGrid.innerHTML = getVideoGallery()
    .map((video) => {
      const youtubeId = extractYoutubeId(video.url);
      return `
        <a href="${video.url}" target="_blank" rel="noreferrer">
          <img src="https://i.ytimg.com/vi/${youtubeId}/hqdefault.jpg" alt="${video.title}">
          <span><svg viewBox="0 0 24 24" aria-hidden="true"><path d="M8 5v14l11-7Z"/></svg></span>
          <strong>${video.title}</strong>
        </a>
      `;
    })
    .join("");
};

renderHomeVideoGrid();

// Video Gallery prev/next: re-queries fresh each call since the list is admin-managed and can
// grow/shrink at runtime (see the hero-slide rotation fix above for the same reasoning).
const videoPrevButton = document.querySelector(".video-prev");
const videoNextButton = document.querySelector(".video-next");
let videoCarouselIndex = 0;

const getVisibleVideoCount = () => {
  if (window.matchMedia("(max-width: 680px)").matches) return 1;
  if (window.matchMedia("(max-width: 1080px)").matches) return 2;
  return 4;
};

const updateVideoCarousel = () => {
  if (!homeVideoGrid) return;
  const cards = homeVideoGrid.querySelectorAll("a");
  const visible = getVisibleVideoCount();
  const maxIndex = Math.max(0, cards.length - visible);
  videoCarouselIndex = Math.min(videoCarouselIndex, maxIndex);
  const showArrows = cards.length > visible;
  videoPrevButton?.classList.toggle("is-hidden", !showArrows);
  videoNextButton?.classList.toggle("is-hidden", !showArrows);
  if (!showArrows || !cards.length) {
    homeVideoGrid.style.transform = "translateX(0)";
    return;
  }
  const cardWidth = cards[0].getBoundingClientRect().width;
  const gap = parseFloat(getComputedStyle(homeVideoGrid).gap) || 0;
  homeVideoGrid.style.transform = `translateX(-${videoCarouselIndex * (cardWidth + gap)}px)`;
  videoPrevButton?.toggleAttribute("disabled", videoCarouselIndex === 0);
  videoNextButton?.toggleAttribute("disabled", videoCarouselIndex === maxIndex);
};

videoPrevButton?.addEventListener("click", () => {
  videoCarouselIndex = Math.max(0, videoCarouselIndex - 1);
  updateVideoCarousel();
});

videoNextButton?.addEventListener("click", () => {
  videoCarouselIndex += 1;
  updateVideoCarousel();
});

window.addEventListener("resize", updateVideoCarousel);
updateVideoCarousel();

