const getPhotoGallery = () => getSiteContent("photoGallery", [
  { id: "demo-photo-campus", caption: "GPREC Campus", photoDataUrl: "https://www.gprec.ac.in/wp-content/uploads/2019/07/gprec-banner4.jpg" },
  { id: "demo-photo-library", caption: "Library", photoDataUrl: "https://www.gprec.ac.in/wp-content/uploads/2019/04/library.jpg" },
  { id: "demo-photo-hostel", caption: "Hostels", photoDataUrl: "https://www.gprec.ac.in/wp-content/uploads/2019/04/hostels.jpg" },
  { id: "demo-photo-sports", caption: "Sports Facilities", photoDataUrl: "https://www.gprec.ac.in/wp-content/uploads/2019/07/sports.jpg" }
]);
const savePhotoGallery = (photos) => saveSiteContent("photoGallery", photos);

const photoGalleryTrack = document.querySelector("#photoGalleryTrack");
const photoLightbox = document.querySelector("#photoLightbox");
const photoLightboxImage = document.querySelector("#photoLightboxImage");
const photoLightboxCaption = document.querySelector("#photoLightboxCaption");
const photoLightboxClose = document.querySelector("#photoLightboxClose");
const photoLightboxPrev = document.querySelector("#photoLightboxPrev");
const photoLightboxNext = document.querySelector("#photoLightboxNext");
let photoLightboxIndex = 0;

const showPhotoAt = (index) => {
  const photos = getPhotoGallery();
  if (!photos.length) return;
  photoLightboxIndex = (index + photos.length) % photos.length;
  const photo = photos[photoLightboxIndex];
  if (photoLightboxImage) photoLightboxImage.src = photo.photoDataUrl;
  if (photoLightboxCaption) photoLightboxCaption.textContent = photo.caption || "";
};

const openPhotoLightbox = (index) => {
  showPhotoAt(index);
  photoLightbox?.classList.remove("is-hidden");
};

const closePhotoLightbox = () => {
  photoLightbox?.classList.add("is-hidden");
};

const renderPhotoGalleryTrack = () => {
  if (!photoGalleryTrack) return;
  const photos = getPhotoGallery();
  if (!photos.length) {
    photoGalleryTrack.innerHTML = `<p class="photo-gallery-empty">No photos yet. Add some from the admin Media panel.</p>`;
    return;
  }
  // the list is duplicated so the CSS marquee (translateX 0 to -50%) loops seamlessly
  const slideMarkup = photos
    .map(
      (photo, index) => `
        <figure data-photo-index="${index}">
          <img src="${photo.photoDataUrl}" alt="${photo.caption || "GPREC campus photo"}">
          ${photo.caption ? `<figcaption>${photo.caption}</figcaption>` : ""}
        </figure>
      `
    )
    .join("");
  photoGalleryTrack.innerHTML = slideMarkup + slideMarkup;
};

renderPhotoGalleryTrack();

photoGalleryTrack?.addEventListener("click", (event) => {
  const figure = event.target.closest("[data-photo-index]");
  if (!figure) return;
  openPhotoLightbox(Number(figure.dataset.photoIndex));
});

photoLightboxClose?.addEventListener("click", closePhotoLightbox);
photoLightboxPrev?.addEventListener("click", () => showPhotoAt(photoLightboxIndex - 1));
photoLightboxNext?.addEventListener("click", () => showPhotoAt(photoLightboxIndex + 1));

photoLightbox?.addEventListener("click", (event) => {
  if (event.target === photoLightbox) closePhotoLightbox();
});

document.addEventListener("keydown", (event) => {
  if (!photoLightbox || photoLightbox.classList.contains("is-hidden")) return;
  if (event.key === "Escape") closePhotoLightbox();
  if (event.key === "ArrowLeft") showPhotoAt(photoLightboxIndex - 1);
  if (event.key === "ArrowRight") showPhotoAt(photoLightboxIndex + 1);
});

