const getPlacementLogos = () => getSiteContent("placementLogos", []);
const savePlacementLogos = (logos) => saveSiteContent("placementLogos", logos);

const placementLogoGrid = document.querySelector("#placementLogoGrid");
const placementLogoTrackWrap = document.querySelector(".logo-grid-track-wrap");

const renderPlacementLogos = () => {
  if (!placementLogoGrid) return;
  const logos = getPlacementLogos();
  const logoMarkup = logos.map((logo) => `<img src="${logo.logoDataUrl}" alt="${logo.name}">`).join("");
  const shouldScroll = logos.length > 9;
  placementLogoGrid.classList.toggle("is-scrolling", shouldScroll);
  placementLogoGrid.innerHTML = shouldScroll ? logoMarkup + logoMarkup : logoMarkup;
  if (placementLogoTrackWrap) placementLogoTrackWrap.scrollLeft = 0;
};

renderPlacementLogos();

// Auto-scrolls right-to-left through the (doubled) logo strip by nudging native scrollLeft, so a
// visitor can swipe/drag left or right at any time to browse manually - the same gesture that
// pauses the autoplay, instead of a CSS transform animation fighting the user's own touch scroll.
if (placementLogoTrackWrap && placementLogoGrid) {
  let autoScrollTimer = null;
  let resumeTimer = null;

  const stopAutoScroll = () => {
    clearInterval(autoScrollTimer);
    autoScrollTimer = null;
  };

  const startAutoScroll = () => {
    stopAutoScroll();
    autoScrollTimer = setInterval(() => {
      if (!placementLogoGrid.classList.contains("is-scrolling")) return;
      const halfWidth = placementLogoGrid.scrollWidth / 2;
      placementLogoTrackWrap.scrollLeft += 1;
      if (placementLogoTrackWrap.scrollLeft >= halfWidth) {
        placementLogoTrackWrap.scrollLeft -= halfWidth;
      }
    }, 30);
  };

  const pauseThenResume = () => {
    stopAutoScroll();
    clearTimeout(resumeTimer);
    resumeTimer = setTimeout(startAutoScroll, 2500);
  };

  ["pointerdown", "touchstart", "wheel"].forEach((eventName) => {
    placementLogoTrackWrap.addEventListener(eventName, pauseThenResume, { passive: true });
  });
  placementLogoTrackWrap.addEventListener("mouseenter", stopAutoScroll);
  placementLogoTrackWrap.addEventListener("mouseleave", startAutoScroll);

  startAutoScroll();
}

