// 360° Campus View: admin-editable media settings shown on pages/campus-360.html.
const getCampus360Note = () => getSiteContent("campus360Note", "Tap play for a real 360° look around this location - drag, use the on-screen controls, or view in fullscreen.");
const saveCampus360Note = (note) => saveSiteContent("campus360Note", note);
const defaultCampus360Settings = {
  previewSize: "large",
  backgroundStrength: "subtle",
  tileLabel: "overlay",
  tileCrop: "crop",
  audioVolume: "medium",
  audioUrl: "../uploads/media/campus-360-audio/music.mp3"
};
// Maps the admin's named volume levels to the actual <audio>.volume value used when fading in.
const campus360AudioVolumeLevels = { off: 0, quiet: 0.15, medium: 0.25, full: 0.4 };
const getCampus360Settings = () => ({ ...defaultCampus360Settings, ...(getSiteContent("campus360Settings", {}) || {}) });
const saveCampus360Settings = (settings) => saveSiteContent("campus360Settings", settings);

const campus360NoteInput = document.querySelector("#campus360NoteInput");
const campus360PreviewSizeInput = document.querySelector("#campus360PreviewSizeInput");
const campus360BackgroundStrengthInput = document.querySelector("#campus360BackgroundStrengthInput");
const campus360TileLabelInput = document.querySelector("#campus360TileLabelInput");
const campus360TileCropInput = document.querySelector("#campus360TileCropInput");
const campus360AudioVolumeInput = document.querySelector("#campus360AudioVolumeInput");
const campus360AudioFileInput = document.querySelector("#campus360AudioFileInput");
const saveCampus360NoteButton = document.querySelector("#saveCampus360NoteButton");
const campus360NoteFeedback = document.querySelector("#campus360NoteFeedback");

if (campus360NoteInput) {
  const settings = getCampus360Settings();
  campus360NoteInput.value = getCampus360Note();
  if (campus360PreviewSizeInput) campus360PreviewSizeInput.value = settings.previewSize;
  if (campus360BackgroundStrengthInput) campus360BackgroundStrengthInput.value = settings.backgroundStrength;
  if (campus360TileLabelInput) campus360TileLabelInput.value = settings.tileLabel;
  if (campus360TileCropInput) campus360TileCropInput.value = settings.tileCrop;
  if (campus360AudioVolumeInput) campus360AudioVolumeInput.value = settings.audioVolume;
}

saveCampus360NoteButton?.addEventListener("click", async () => {
  saveCampus360Note(campus360NoteInput.value.trim());
  const audioFile = campus360AudioFileInput?.files[0];
  let audioUrl = getCampus360Settings().audioUrl || defaultCampus360Settings.audioUrl;
  if (audioFile) {
    const uploaded = await readFileAsDataUrl(audioFile, "media/campus-360-audio");
    if (uploaded?.dataUrl) audioUrl = uploaded.dataUrl;
  }
  saveCampus360Settings({
    previewSize: campus360PreviewSizeInput?.value || defaultCampus360Settings.previewSize,
    backgroundStrength: campus360BackgroundStrengthInput?.value || defaultCampus360Settings.backgroundStrength,
    tileLabel: campus360TileLabelInput?.value || defaultCampus360Settings.tileLabel,
    tileCrop: campus360TileCropInput?.value || defaultCampus360Settings.tileCrop,
    audioVolume: campus360AudioVolumeInput?.value || defaultCampus360Settings.audioVolume,
    audioUrl
  });
  if (campus360AudioFileInput) campus360AudioFileInput.value = "";
  if (campus360NoteFeedback) {
    campus360NoteFeedback.textContent = "360° Campus View settings saved. They will appear on the public page.";
    campus360NoteFeedback.classList.add("success");
  }
});

// Real 360° cube photography (each location has 6 real face photos: front/right/back/left/up/
// down), fully admin-managed - see the admin dashboard's Media > 360° Campus View section. Both
// the category tab list and each tab's location list are admin-editable independently - e.g.
// replacing a photo under Central Facilities never touches Campus View's copy, even if they
// started out as the same real place, so each tab is free to diverge once an admin edits it.
const campus360RealLocationFaces = (slug) =>
  Object.fromEntries(["front", "right", "back", "left", "up", "down"].map((face) => [face, `../uploads/media/campus-360/${slug}/${face}.jpg`]));
const campus360RealLocationEntry = (slug, title) => ({ slug, title, faces: campus360RealLocationFaces(slug) });
const defaultCampus360CategorySections = {
  "Campus View": [
    ["temple-complex-health-center", "Temple Complex & Health Center"],
    ["campus-view-1", "Campus View - 1"],
    ["campus-view-2", "Campus View - 2"],
    ["administrative-block-exterior", "Administrative Block - Exterior"],
    ["administrative-block-lobby", "Administrative Block - Lobby"],
    ["silver-jubilee-block", "Silver Jubilee Block"],
    ["principals-chamber", "Principal's Chamber"],
    ["departments-exterior", "Departments - Exterior"],
    ["entrance-transport", "Entrance / Transport"],
    ["aerial-view-1", "Aerial View - 1"],
    ["aerial-view-2", "Aerial View - 2"]
  ].map(([slug, title]) => campus360RealLocationEntry(slug, title)),
  // These 4 tabs have no dedicated photography of their own, so they start out reusing whichever
  // real Campus View photos are the closest match - but as independent copies an admin can freely
  // replace or remove without affecting Campus View.
  "Central Facilities": [
    ["silver-jubilee-block", "Silver Jubilee Block"],
    ["administrative-block-lobby", "Administrative Block - Lobby"],
    ["campus-view-1", "Campus View - 1"],
    ["entrance-transport", "Entrance / Transport"]
  ].map(([slug, title]) => campus360RealLocationEntry(slug, title)),
  Departments: [
    ["departments-exterior", "Departments - Exterior"],
    ["campus-view-2", "Campus View - 2"],
    ["administrative-block-exterior", "Administrative Block - Exterior"],
    ["administrative-block-lobby", "Administrative Block - Lobby"]
  ].map(([slug, title]) => campus360RealLocationEntry(slug, title)),
  "Training & Placement": [
    ["principals-chamber", "Principal's Chamber"],
    ["administrative-block-lobby", "Administrative Block - Lobby"],
    ["silver-jubilee-block", "Silver Jubilee Block"],
    ["administrative-block-exterior", "Administrative Block - Exterior"]
  ].map(([slug, title]) => campus360RealLocationEntry(slug, title)),
  "Sports & Games": [
    ["aerial-view-1", "Aerial View - 1"],
    ["administrative-block-lobby", "Administrative Block - Lobby"],
    ["aerial-view-2", "Aerial View - 2"],
    ["entrance-transport", "Entrance / Transport"]
  ].map(([slug, title]) => campus360RealLocationEntry(slug, title))
};
const getCampus360CategorySections = () => getSiteContent("campus360CategorySections", defaultCampus360CategorySections);
const saveCampus360CategorySections = (sections) => saveSiteContent("campus360CategorySections", sections);

// The list of category tabs itself is admin-editable too (add/remove a whole tab, not just
// locations within one) - this drives both the admin category picker and the public page's tab
// buttons, so a newly-added category shows up in both places automatically.
const defaultCampus360Categories = ["Campus View", "Central Facilities", "Departments", "Training & Placement", "Sports & Games"];
const getCampus360Categories = () => getSiteContent("campus360Categories", defaultCampus360Categories);
const saveCampus360Categories = (categories) => saveSiteContent("campus360Categories", categories);
const campus360CategorySlug = (name) =>
  name
    .toLowerCase()
    .trim()
    .replace(/[^a-z0-9]+/g, "-")
    .replace(/(^-|-$)/g, "") || `category-${Date.now()}`;

// Admin: the list of 360° category tabs is itself editable (add/remove a whole tab, not just
// locations within one), so this uses the same "one dropdown drives one shared form" pattern as
// the Departments admin panel (see #departmentEditSelect above) rather than a fixed form per tab.
const slugifyCampus360Title = (title) =>
  title
    .toLowerCase()
    .trim()
    .replace(/[^a-z0-9]+/g, "-")
    .replace(/(^-|-$)/g, "") || `location-${Date.now()}`;

const campus360CategorySelect = document.querySelector("#campus360CategorySelect");
const campus360NewCategoryCard = document.querySelector("#campus360NewCategoryCard");
const campus360NewCategoryNameInput = document.querySelector("#campus360NewCategoryNameInput");
const addCampus360CategoryButton = document.querySelector("#addCampus360CategoryButton");
const campus360CategoryFeedback = document.querySelector("#campus360CategoryFeedback");
const campus360LocationFormCard = document.querySelector("#campus360LocationFormCard");
const campus360LocationTableCard = document.querySelector("#campus360LocationTableCard");
const campus360LocTitleInput = document.querySelector("#campus360LocTitleInput");
const campus360LocFaceInputs = {
  front: document.querySelector("#campus360LocFrontInput"),
  right: document.querySelector("#campus360LocRightInput"),
  back: document.querySelector("#campus360LocBackInput"),
  left: document.querySelector("#campus360LocLeftInput"),
  up: document.querySelector("#campus360LocUpInput"),
  down: document.querySelector("#campus360LocDownInput")
};
const campus360LocFormHeading = document.querySelector("#campus360LocFormHeading");
const campus360LocFormHint = document.querySelector("#campus360LocFormHint");
const campus360LocSaveButton = document.querySelector("#campus360LocSaveButton");
const campus360LocCancelButton = document.querySelector("#campus360LocCancelButton");
const campus360RemoveCategoryButton = document.querySelector("#campus360RemoveCategoryButton");
const campus360LocFeedback = document.querySelector("#campus360LocFeedback");
const campus360LocManagerBody = document.querySelector("#campus360LocManagerBody");

if (campus360CategorySelect) {
  let currentCampus360Category = null;
  let editingCampus360Slug = null;

  const getCampus360Entries = () => getCampus360CategorySections()[currentCampus360Category] || [];
  const saveCampus360Entries = (entries) => {
    const sections = getCampus360CategorySections();
    sections[currentCampus360Category] = entries;
    saveCampus360CategorySections(sections);
  };

  const resetCampus360LocationForm = () => {
    editingCampus360Slug = null;
    if (campus360LocTitleInput) campus360LocTitleInput.value = "";
    Object.values(campus360LocFaceInputs).forEach((input) => {
      if (input) input.value = "";
    });
    if (campus360LocFormHeading) campus360LocFormHeading.textContent = `${currentCampus360Category} - Add Location`;
    if (campus360LocFormHint) {
      campus360LocFormHint.textContent = "Upload all 6 directional photos (front, right, back, left, up, down) to add a new location.";
    }
    if (campus360LocSaveButton) campus360LocSaveButton.textContent = "Add Location";
    campus360LocCancelButton?.classList.add("is-hidden");
  };

  const renderCampus360LocationManager = () => {
    if (!campus360LocManagerBody) return;
    const entries = getCampus360Entries();
    campus360LocManagerBody.innerHTML = entries.length
      ? entries
          .map(
            (entry) => `
          <tr>
            <td><img src="${entry.faces.front || ""}" alt="" class="site-photo-thumb"></td>
            <td>${escapeHtml(entry.title)}</td>
            <td>
              <div class="action-cell">
                <button type="button" class="btn-set-first" data-edit="${entry.slug}">Replace Photos</button>
                <button type="button" class="icon-btn-delete" data-remove="${entry.slug}" aria-label="Remove location">${deleteIconSvg}</button>
              </div>
            </td>
          </tr>
        `
          )
          .join("")
      : `<tr><td colspan="3">No locations yet. Add one above.</td></tr>`;
  };

  const renderCampus360CategorySelect = () => {
    const categories = getCampus360Categories();
    const currentValue = campus360CategorySelect.value;
    campus360CategorySelect.innerHTML =
      `<option value="">+ Add New Category</option>` +
      categories.map((name) => `<option value="${escapeHtml(name)}">${escapeHtml(name)}</option>`).join("");
    // Falls back to the first real category (not blank) when there's no valid current selection -
    // covers both first page load and re-rendering right after the selected category got removed,
    // so the admin lands on a useful view instead of an empty "add new" form both times.
    campus360CategorySelect.value = categories.includes(currentValue) ? currentValue : categories[0] || "";
  };

  const showCampus360Category = (name) => {
    currentCampus360Category = name;
    campus360NewCategoryCard?.classList.add("is-hidden");
    campus360LocationFormCard?.classList.remove("is-hidden");
    campus360LocationTableCard?.classList.remove("is-hidden");
    resetCampus360LocationForm();
    renderCampus360LocationManager();
  };

  const showCampus360AddCategoryForm = () => {
    currentCampus360Category = null;
    campus360NewCategoryCard?.classList.remove("is-hidden");
    campus360LocationFormCard?.classList.add("is-hidden");
    campus360LocationTableCard?.classList.add("is-hidden");
    if (campus360NewCategoryNameInput) campus360NewCategoryNameInput.value = "";
  };

  renderCampus360CategorySelect();
  if (campus360CategorySelect.value) showCampus360Category(campus360CategorySelect.value);
  else showCampus360AddCategoryForm();

  campus360CategorySelect.addEventListener("change", () => {
    if (campus360CategorySelect.value) showCampus360Category(campus360CategorySelect.value);
    else showCampus360AddCategoryForm();
  });

  addCampus360CategoryButton?.addEventListener("click", () => {
    const name = campus360NewCategoryNameInput?.value.trim();
    if (!name) {
      if (campus360CategoryFeedback) {
        campus360CategoryFeedback.textContent = "Enter a category name.";
        campus360CategoryFeedback.classList.remove("success");
      }
      return;
    }
    const categories = getCampus360Categories();
    if (categories.some((existing) => existing.toLowerCase() === name.toLowerCase())) {
      if (campus360CategoryFeedback) {
        campus360CategoryFeedback.textContent = "A category with that name already exists.";
        campus360CategoryFeedback.classList.remove("success");
      }
      return;
    }
    saveCampus360Categories([...categories, name]);
    const sections = getCampus360CategorySections();
    sections[name] = [];
    saveCampus360CategorySections(sections);
    renderCampus360CategorySelect();
    campus360CategorySelect.value = name;
    showCampus360Category(name);
    if (campus360CategoryFeedback) {
      campus360CategoryFeedback.textContent = "Category added. It will appear as a new tab on the public page.";
      campus360CategoryFeedback.classList.add("success");
    }
  });

  campus360RemoveCategoryButton?.addEventListener("click", () => {
    if (!currentCampus360Category) return;
    saveCampus360Categories(getCampus360Categories().filter((name) => name !== currentCampus360Category));
    const sections = getCampus360CategorySections();
    delete sections[currentCampus360Category];
    saveCampus360CategorySections(sections);
    renderCampus360CategorySelect();
    if (campus360CategorySelect.value) showCampus360Category(campus360CategorySelect.value);
    else showCampus360AddCategoryForm();
  });

  campus360LocManagerBody?.addEventListener("click", (event) => {
    const editButton = event.target.closest("[data-edit]");
    if (editButton) {
      const slug = editButton.dataset.edit;
      const entry = getCampus360Entries().find((e) => e.slug === slug);
      if (!entry) return;
      editingCampus360Slug = slug;
      if (campus360LocTitleInput) campus360LocTitleInput.value = entry.title;
      Object.values(campus360LocFaceInputs).forEach((input) => {
        if (input) input.value = "";
      });
      if (campus360LocFormHeading) campus360LocFormHeading.textContent = `${currentCampus360Category} - Replace Photos - ${entry.title}`;
      if (campus360LocFormHint) {
        campus360LocFormHint.textContent = "Only choose the directions you want to replace - anything left empty keeps its current photo.";
      }
      if (campus360LocSaveButton) campus360LocSaveButton.textContent = "Save Changes";
      campus360LocCancelButton?.classList.remove("is-hidden");
      campus360LocTitleInput?.scrollIntoView({ behavior: "smooth", block: "center" });
      return;
    }
    const removeButton = event.target.closest("[data-remove]");
    if (!removeButton) return;
    const slug = removeButton.dataset.remove;
    saveCampus360Entries(getCampus360Entries().filter((e) => e.slug !== slug));
    renderCampus360LocationManager();
    if (editingCampus360Slug === slug) resetCampus360LocationForm();
  });

  campus360LocCancelButton?.addEventListener("click", resetCampus360LocationForm);

  campus360LocSaveButton?.addEventListener("click", async () => {
    const title = campus360LocTitleInput?.value.trim();
    if (!title) {
      if (campus360LocFeedback) {
        campus360LocFeedback.textContent = "Enter a location title.";
        campus360LocFeedback.classList.remove("success");
      }
      return;
    }
    const entries = getCampus360Entries();
    const isEditing = !!editingCampus360Slug;
    const existing = isEditing ? entries.find((e) => e.slug === editingCampus360Slug) : null;
    if (!isEditing) {
      const allFacesChosen = Object.values(campus360LocFaceInputs).every((input) => input?.files[0]);
      if (!allFacesChosen) {
        if (campus360LocFeedback) {
          campus360LocFeedback.textContent = "Choose all 6 directional photos (front, right, back, left, up, down).";
          campus360LocFeedback.classList.remove("success");
        }
        return;
      }
    }
    const slug = existing?.slug || slugifyCampus360Title(title);
    const faces = { ...(existing?.faces || {}) };
    const originalButtonText = campus360LocSaveButton.textContent;
    campus360LocSaveButton.disabled = true;
    campus360LocSaveButton.textContent = "Saving...";
    try {
      for (const [face, input] of Object.entries(campus360LocFaceInputs)) {
        const file = input?.files[0];
        if (!file) continue;
        const uploaded = await readFileAsDataUrl(file, `media/campus-360/${campus360CategorySlug(currentCampus360Category)}-${slug}`);
        if (uploaded?.dataUrl) faces[face] = uploaded.dataUrl;
      }
      const entry = { slug, title, faces };
      const nextEntries = existing ? entries.map((e) => (e.slug === slug ? entry : e)) : [...entries, entry];
      saveCampus360Entries(nextEntries);
      renderCampus360LocationManager();
      resetCampus360LocationForm();
      if (campus360LocFeedback) {
        campus360LocFeedback.textContent = isEditing
          ? "Location updated. Changes will appear on the public page."
          : `Location added. It will appear under ${currentCampus360Category} on the public page.`;
        campus360LocFeedback.classList.add("success");
      }
    } catch {
      campus360LocSaveButton.textContent = originalButtonText;
      if (campus360LocFeedback) {
        campus360LocFeedback.textContent = "Could not upload one or more photos. Try again.";
        campus360LocFeedback.classList.remove("success");
      }
    } finally {
      campus360LocSaveButton.disabled = false;
    }
  });
}

// Public pages/campus-360.html: hydrate the shared status note from the admin setting, and render
// the coming-soon 360° locations as a media-player stage with a horizontal tile strip per section.
const campus360StageNote = document.querySelector("#campus360StageNote");
if (campus360StageNote) {
  campus360StageNote.textContent = getCampus360Note();
}
const campus360StageImage = document.querySelector("#campus360StageImage");
const campus360StageTitle = document.querySelector("#campus360StageTitle");
const campus360StageSection = document.querySelector("#campus360StageSection");
const campus360StatusPanel = document.querySelector(".campus-360-status");
const campus360Viewer = document.querySelector(".campus-360-viewer");
const campus360Filmstrip = document.querySelector("#campus360Filmstrip");
// Declared here (rather than down by the rest of the pano viewer logic) because selectCampus360Tile
// below needs to check campus360PanoViewer's visibility at page-load time, when the initial scene
// tab is auto-selected synchronously - a later `const` for the same name would leave it in the
// temporal dead zone at that point and throw.
const campus360PanoViewer = document.querySelector("#campus360PanoViewer");
const campus360PanoFrame = document.querySelector(".campus-360-pano-frame");
const campus360CubeViewport = document.querySelector("#campus360CubeViewport");
const campus360Cube = document.querySelector("#campus360Cube");
if (campus360Viewer) {
  const settings = getCampus360Settings();
  campus360Viewer.dataset.previewSize = settings.previewSize;
  campus360Viewer.dataset.backgroundStrength = settings.backgroundStrength;
  campus360Viewer.dataset.tileLabel = settings.tileLabel;
  campus360Viewer.dataset.tileCrop = settings.tileCrop;
  const campus360AudioEl = document.querySelector("#campus360Audio");
  if (campus360AudioEl && settings.audioUrl) {
    campus360AudioEl.querySelector("source").src = settings.audioUrl;
    campus360AudioEl.load();
  }
}
// Each tab's location list is independent (see getCampus360CategorySections above), so tiles carry
// their own faces map directly rather than looking one up from a single cross-tab slug index - two
// tabs can otherwise have entries that started out with the same slug but have since been edited
// apart. The tab list itself is admin-editable too (see getCampus360Categories), so the tab
// buttons below are generated rather than hardcoded.
const campus360CategoryNames = getCampus360Categories();
const campus360CategorySectionsData = getCampus360CategorySections();
const campus360Scenes = Object.fromEntries(
  campus360CategoryNames.map((sceneName) => [
    sceneName,
    (campus360CategorySectionsData[sceneName] || []).map((entry) => [entry.title, entry.slug, entry.faces])
  ])
);
const campus360FaceThumb = (faces) => faces?.front || "";
// "Campus View" is just the conventional first tab, not guaranteed to exist once an admin can
// rename/remove categories - fall back to whichever tab actually comes first instead of assuming.
const campus360FallbackScene = campus360Scenes[campus360CategoryNames[0]] || [];
let campus360CurrentSlug = null;
let campus360CurrentFaces = null;
const selectCampus360Tile = (sceneName, itemIndex) => {
  const item = campus360Scenes[sceneName]?.[itemIndex] || campus360FallbackScene[0];
  if (!item) return;
  const [title, slug, faces] = item;
  campus360CurrentSlug = slug;
  campus360CurrentFaces = faces;
  if (campus360StageImage) {
    campus360StageImage.src = campus360FaceThumb(faces);
    campus360StageImage.alt = title;
  }
  if (campus360StageTitle) campus360StageTitle.textContent = title;
  if (campus360StageSection) campus360StageSection.textContent = sceneName;
  if (campus360StatusPanel) {
    campus360StatusPanel.classList.remove("is-playing");
    requestAnimationFrame(() => campus360StatusPanel.classList.add("is-playing"));
  }
  campus360Filmstrip?.querySelectorAll(".campus-360-tile").forEach((tile) => {
    tile.classList.toggle("is-active", Number(tile.dataset.tileIndex) === itemIndex);
  });
  // If the panorama viewer is already open, switch it to the newly picked location live instead
  // of requiring the visitor to close and reopen it.
  if (campus360PanoViewer && !campus360PanoViewer.classList.contains("is-hidden")) {
    openCampus360Pano(slug, faces);
  }
};
const renderCampus360Filmstrip = (sceneName) => {
  if (!campus360Filmstrip) return;
  const items = campus360Scenes[sceneName] || campus360FallbackScene;
  campus360Filmstrip.innerHTML = items
    .map(
      ([title, slug, faces], index) => `
        <button type="button" class="campus-360-tile" data-tile-index="${index}" aria-label="Play ${escapeHtml(title)}">
          <img src="${campus360FaceThumb(faces)}" alt="" loading="lazy">
          <span>${escapeHtml(title)}</span>
        </button>
      `
    )
    .join("");
  campus360Filmstrip.querySelectorAll(".campus-360-tile").forEach((tile) => {
    tile.addEventListener("click", () => selectCampus360Tile(sceneName, Number(tile.dataset.tileIndex)));
  });
  selectCampus360Tile(sceneName, 0);
};
const selectCampus360Scene = (button) => {
  document.querySelectorAll(".campus-360-scene").forEach((b) => b.classList.remove("is-active"));
  button.classList.add("is-active");
  renderCampus360Filmstrip(button.dataset.scene);
};
const campus360SceneTabs = document.querySelector("#campus360SceneTabs");
if (campus360SceneTabs) {
  campus360SceneTabs.innerHTML = campus360CategoryNames
    .map(
      (name, index) => `<button type="button" class="campus-360-scene${index === 0 ? " is-active" : ""}" data-scene="${escapeHtml(name)}">${escapeHtml(name)}</button>`
    )
    .join("");
  campus360SceneTabs.querySelectorAll(".campus-360-scene").forEach((button) => {
    button.addEventListener("click", () => selectCampus360Scene(button));
  });
  const campus360InitialScene = campus360SceneTabs.querySelector(".campus-360-scene.is-active");
  if (campus360InitialScene) selectCampus360Scene(campus360InitialScene);
}

// Real 360° cube viewer - pure CSS 3D (transform-style: preserve-3d), no external library, no
// WebGL, no video. 6 real photo faces (front/right/back/left/up/down) form an inward-facing cube;
// "looking around" is done by rotating the whole cube opposite to the drag/nudge direction.
// (campus360PanoViewer/PanoFrame/CubeViewport/Cube are declared earlier, alongside the other
// campus-360 DOM refs - see the comment there.)
const campus360CubeFaceOrder = ["front", "right", "back", "left", "up", "down"];
let campus360Yaw = 0;
let campus360Pitch = 0;
let campus360PanoDragging = false;
let campus360PanoStartX = 0;
let campus360PanoStartY = 0;
let campus360StartYaw = 0;
let campus360StartPitch = 0;

const CAMPUS_360_ZOOM_MIN = 0.6;
const CAMPUS_360_ZOOM_MAX = 2.5;
const CAMPUS_360_ZOOM_STEP = 0.25;
const CAMPUS_360_PITCH_LIMIT = 85;
const CAMPUS_360_DRAG_SENSITIVITY = 0.25;
// Views open fully zoomed out (widest field of view) by default.
let campus360Zoom = CAMPUS_360_ZOOM_MIN;
let campus360BasePerspective = 900;

const loadCampus360CubeFaces = (faces) => {
  if (!campus360Cube || !faces) return;
  campus360CubeFaceOrder.forEach((face) => {
    const img = campus360Cube.querySelector(`.campus-360-cube-${face} img`);
    if (img && faces[face]) img.src = faces[face];
  });
};

const applyCampus360CubeTransform = () => {
  if (!campus360Cube) return;
  campus360Pitch = Math.max(-CAMPUS_360_PITCH_LIMIT, Math.min(CAMPUS_360_PITCH_LIMIT, campus360Pitch));
  campus360Cube.style.transform = `rotateX(${campus360Pitch}deg) rotateY(${campus360Yaw}deg)`;
};

// Sizes the cube to comfortably overfill the frame in every rotation and sets the perspective
// (camera distance) that gives the faces a natural, undistorted field of view. Re-run whenever the
// frame size changes (fullscreen toggle) - current yaw/pitch are untouched, so the look direction
// carries over.
const measureCampus360Cube = () => {
  if (!campus360CubeViewport || !campus360PanoFrame) return;
  const rect = campus360PanoFrame.getBoundingClientRect();
  // +30% safety margin against corner gaps while rotating. Source photos are the real full-res
  // cube faces extracted from the site's original Flash tour (~1780-2734px per face), so there's
  // enough headroom for this margin without visible upscaling blur at normal zoom.
  const size = Math.max(rect.width, rect.height, 1) * 1.4;
  campus360CubeViewport.style.setProperty("--cube-size", `${size}px`);
  campus360BasePerspective = size * 0.9;
  campus360CubeViewport.style.perspective = `${campus360BasePerspective / campus360Zoom}px`;
};

// Zoom is done via perspective (camera distance), not scale - narrowing the field of view like a
// real lens rather than stretching/blurring the image. A *smaller* CSS perspective value moves the
// effective camera closer to the cube face, which magnifies it - so zooming in means dividing, not
// multiplying, the base perspective by the zoom level.
const setCampus360Zoom = (zoom) => {
  campus360Zoom = Math.max(CAMPUS_360_ZOOM_MIN, Math.min(CAMPUS_360_ZOOM_MAX, zoom));
  if (campus360CubeViewport) campus360CubeViewport.style.perspective = `${campus360BasePerspective / campus360Zoom}px`;
};

let campus360AudioFadeId = null;
const fadeCampus360Audio = (target, onDone) => {
  const audio = document.querySelector("#campus360Audio");
  if (!audio) return;
  if (campus360AudioFadeId) cancelAnimationFrame(campus360AudioFadeId);
  const start = audio.volume;
  const startTime = performance.now();
  const duration = 700;
  const step = (now) => {
    // Clamped on both ends - rAF's timestamp can land fractionally before the synchronous
    // startTime read above, which would otherwise make t (and briefly the resulting volume)
    // negative and throw, since HTMLMediaElement.volume only accepts [0, 1].
    const t = Math.max(0, Math.min(1, (now - startTime) / duration));
    audio.volume = Math.max(0, Math.min(1, start + (target - start) * t));
    if (t < 1) {
      campus360AudioFadeId = requestAnimationFrame(step);
    } else {
      campus360AudioFadeId = null;
      onDone?.();
    }
  };
  campus360AudioFadeId = requestAnimationFrame(step);
};

const openCampus360Pano = (overrideSlug, overrideFaces) => {
  const slug = overrideSlug || campus360CurrentSlug;
  const faces = overrideFaces || campus360CurrentFaces;
  if (!slug || !faces || !campus360Cube || !campus360PanoViewer) return;
  campus360CurrentSlug = slug;
  campus360CurrentFaces = faces;
  // Must remove is-hidden (display:none) BEFORE measuring - getBoundingClientRect() would
  // otherwise capture a 0x0 frame while the viewer is still display:none.
  campus360PanoViewer.classList.remove("is-hidden");
  loadCampus360CubeFaces(faces);
  campus360Yaw = 0;
  campus360Pitch = 0;
  campus360Zoom = CAMPUS_360_ZOOM_MIN;
  measureCampus360Cube();
  applyCampus360CubeTransform();
  // Background music only while the viewer is open - triggered by the same click that opened it,
  // so this satisfies browsers' autoplay-requires-a-user-gesture policy. Fades in/out smoothly
  // rather than snapping straight to volume.
  const audio = document.querySelector("#campus360Audio");
  const targetVolume = campus360AudioVolumeLevels[getCampus360Settings().audioVolume] ?? campus360AudioVolumeLevels.medium;
  if (audio && targetVolume > 0) {
    audio.volume = 0;
    audio.currentTime = 0;
    audio.play().catch(() => {});
    fadeCampus360Audio(targetVolume);
  }
};

const closeCampus360Pano = () => {
  if (document.fullscreenElement) document.exitFullscreen?.();
  campus360PanoViewer?.classList.add("is-hidden");
  const audio = document.querySelector("#campus360Audio");
  if (audio) {
    fadeCampus360Audio(0, () => {
      audio.pause();
      audio.currentTime = 0;
    });
  }
};

document.querySelector("#campus360PlayButton")?.addEventListener("click", () => openCampus360Pano());

document.querySelector("#campus360FullscreenButton")?.addEventListener("click", () => {
  if (document.fullscreenElement) {
    document.exitFullscreen?.();
  } else {
    campus360PanoFrame?.requestFullscreen?.();
  }
});
// Frame dimensions change when entering/exiting fullscreen, so re-measure the cube size/perspective.
document.addEventListener("fullscreenchange", () => {
  if (campus360PanoViewer && !campus360PanoViewer.classList.contains("is-hidden")) measureCampus360Cube();
});
document.querySelector("#campus360PanoClose")?.addEventListener("click", closeCampus360Pano);

const campus360UnmutedIconSvg = '<path d="M11 5 6 9H3v6h3l5 4z"/><path d="M15.5 8.5a5 5 0 0 1 0 7M18.5 5.5a9 9 0 0 1 0 13"/>';
const campus360MutedIconSvg = '<path d="M11 5 6 9H3v6h3l5 4z"/><path d="m16 9 5 6M21 9l-5 6"/>';
document.querySelector("#campus360MuteButton")?.addEventListener("click", (event) => {
  const audio = document.querySelector("#campus360Audio");
  if (!audio) return;
  audio.muted = !audio.muted;
  const button = event.currentTarget;
  button.classList.toggle("is-muted", audio.muted);
  button.setAttribute("aria-label", audio.muted ? "Unmute background music" : "Mute background music");
  const svg = button.querySelector("svg");
  if (svg) svg.innerHTML = audio.muted ? campus360MutedIconSvg : campus360UnmutedIconSvg;
});

document.querySelector("#campus360ZoomInButton")?.addEventListener("click", () => {
  setCampus360Zoom(campus360Zoom + CAMPUS_360_ZOOM_STEP);
});
document.querySelector("#campus360ZoomOutButton")?.addEventListener("click", () => {
  setCampus360Zoom(campus360Zoom - CAMPUS_360_ZOOM_STEP);
});

// Directional pad - click-and-hold nudges the view that way, an explicit alternative to dragging.
// [dYaw, dPitch] signs match what dragging in the equivalent screen direction already does (see
// the drag handler below - e.g. dragging down reveals more sky, so the "up" button decreases pitch
// the same way an upward look does).
const campus360PanStepDeg = { up: [0, -6], down: [0, 6], left: [6, 0], right: [-6, 0] };
let campus360DirPanIntervalId = null;
const nudgeCampus360Pano = (dir) => {
  const [dYaw, dPitch] = campus360PanStepDeg[dir] || [0, 0];
  campus360Yaw += dYaw;
  campus360Pitch += dPitch;
  applyCampus360CubeTransform();
};
const stopCampus360DirPan = () => {
  if (campus360DirPanIntervalId) {
    clearInterval(campus360DirPanIntervalId);
    campus360DirPanIntervalId = null;
  }
};
document.querySelectorAll(".campus-360-dir-btn[data-pan-dir]").forEach((button) => {
  const dir = button.dataset.panDir;
  button.addEventListener("pointerdown", (event) => {
    event.preventDefault();
    nudgeCampus360Pano(dir);
    stopCampus360DirPan();
    campus360DirPanIntervalId = setInterval(() => nudgeCampus360Pano(dir), 120);
  });
  button.addEventListener("pointerup", stopCampus360DirPan);
  button.addEventListener("pointerleave", stopCampus360DirPan);
});

// Recenter - back to the same fully-zoomed-out, forward-facing starting view as a fresh open.
document.querySelector("#campus360RecenterButton")?.addEventListener("click", () => {
  campus360Yaw = 0;
  campus360Pitch = 0;
  setCampus360Zoom(CAMPUS_360_ZOOM_MIN);
  applyCampus360CubeTransform();
});

campus360PanoViewer?.addEventListener("pointerdown", (event) => {
  if (event.target.closest("#campus360PanoClose, #campus360FullscreenButton, #campus360MuteButton, .campus-360-dir-btn, .campus-360-zoom-btn")) return;
  campus360PanoDragging = true;
  campus360PanoStartX = event.clientX;
  campus360PanoStartY = event.clientY;
  campus360StartYaw = campus360Yaw;
  campus360StartPitch = campus360Pitch;
  campus360PanoViewer.classList.add("is-dragging");
  campus360PanoViewer.setPointerCapture(event.pointerId);
});
campus360PanoViewer?.addEventListener("pointermove", (event) => {
  if (!campus360PanoDragging) return;
  campus360Yaw = campus360StartYaw + (event.clientX - campus360PanoStartX) * CAMPUS_360_DRAG_SENSITIVITY;
  campus360Pitch = campus360StartPitch - (event.clientY - campus360PanoStartY) * CAMPUS_360_DRAG_SENSITIVITY;
  applyCampus360CubeTransform();
});
const stopCampus360PanoDrag = () => {
  campus360PanoDragging = false;
  campus360PanoViewer?.classList.remove("is-dragging");
};
campus360PanoViewer?.addEventListener("pointerup", stopCampus360PanoDrag);
campus360PanoViewer?.addEventListener("pointerleave", stopCampus360PanoDrag);

if (attendanceTableBody) {
  const renderAttendance = () => {
    const semesterStart = new Date(attendanceSemesterStart);
    const semesterEnd = new Date(attendanceSemesterEnd);
    const asOnDate = attendanceAsOnDate?.value ? new Date(attendanceAsOnDate.value) : semesterEnd;

    let totalHeld = 0;
    let totalAttended = 0;
    attendanceTableBody.innerHTML = defaultAttendanceSubjects
      .map((subject) => {
        const { held, attended } = computeAttendanceForRange(subject, semesterStart, semesterEnd, asOnDate);
        totalHeld += held;
        totalAttended += attended;
        const percent = held > 0 ? Math.round((attended / held) * 100) : 0;
        return `
          <tr>
            <td>${subject.code} - ${subject.name}</td>
            <td>${held}</td>
            <td>${attended}</td>
            <td><span class="${percent >= 75 ? "ok" : "warn"}">${percent}%</span></td>
          </tr>
        `;
      })
      .join("");

    if (attendanceOverall) {
      const overallPercent = totalHeld > 0 ? Math.round((totalAttended / totalHeld) * 100) : 0;
      attendanceOverall.textContent = `${overallPercent}% (${totalAttended} / ${totalHeld} classes)`;
    }
  };

  attendanceApplyButton?.addEventListener("click", renderAttendance);
  renderAttendance();
}

