renderCampusEvents();

// Shared by the Campus Events grid's own "Apply Now" buttons and every shortcut into the same
// flow (spotlight cards' "Register Now" for a public campus event, the Fest's own promo card) -
// one place that opens #eventApplyForm against a given {id, name, fee, date, venue, capacity} so
// every entry point produces an identical registration record and downloadable Event Pass.
const openCampusEventApply = (eventLike) => {
  if (!eventLike || !eventApplyForm) return false;
  activeEvent = { id: eventLike.id, name: eventLike.name, fee: Number(eventLike.fee) || 0, date: eventLike.date, venue: eventLike.venue, capacity: eventLike.capacity || null };
  const hasFee = activeEvent.fee > 0;
  if (eventApplyTitle) eventApplyTitle.textContent = activeEvent.name;
  eventFeeRow?.classList.toggle("is-hidden", !hasFee);
  if (eventFeeAmount) eventFeeAmount.textContent = `₹${activeEvent.fee.toLocaleString("en-IN")}`;
  if (eventSubmitButton) eventSubmitButton.textContent = hasFee ? "Pay & Register" : "Submit Registration";
  eventReceiptDownload?.classList.remove("ready");
  eventReceiptDownload?.classList.add("is-hidden");
  eventFeedback?.classList.add("is-hidden");
  eventApplyForm?.classList.remove("is-hidden");
  eventApplyForm?.scrollIntoView({ behavior: "smooth", block: "start" });
  return true;
};

document.querySelector("#campusEventGrid")?.addEventListener("click", (event) => {
  const button = event.target.closest("[data-campus-event-id]");
  if (!button) return;
  const selected = getCampusEvents().find((item) => item.id === button.dataset.campusEventId);
  if (!selected) return;
  openCampusEventApply({ id: selected.id, name: selected.title, fee: selected.fee, date: selected.date, venue: selected.venue, capacity: selected.capacity });
});

// Spotlight grid's own "Register Now" shortcuts (a public campus event's card, or the Fest's own
// promo card) should not require signing into the external Fest visitor portal, a separate
// signed-out account system meant for outside guests. On a page with its own #eventApplyForm
// (student dashboard), route through the exact same in-account flow #campusEventGrid's "Apply Now"
// uses instead. Pages without that form fall through to the link's own href unchanged.
spotlightGrid?.addEventListener("click", (event) => {
  const link = event.target.closest("[data-spotlight-apply-event], [data-spotlight-apply-fest]");
  if (!link || !eventApplyForm) return;
  event.preventDefault();
  if (link.dataset.spotlightApplyFest) {
    openCampusEventApply({ id: "gprec-fest", name: getFestName(), fee: 0, date: getFestDate(), venue: getFestVenue() });
    return;
  }
  const selected = getCampusEvents().find((item) => item.id === link.dataset.spotlightApplyEvent);
  if (selected) {
    openCampusEventApply({ id: selected.id, name: selected.title, fee: selected.fee, date: selected.date, venue: selected.venue, capacity: selected.capacity });
  }
});

// Campus Events registration (#eventApplyForm) is shared by student-dashboard.html,
// faculty-dashboard.html, and admin-dashboard.html - whichever of those a page has, the identity
// behind the registration is whoever is actually signed in, not always a student. Faculty/admin
// have no roll number, so they're keyed by their login email instead (same convention the public
// event-visitor flow already uses for outside guests - see campus_event_manual_checkin's
// roll-number-or-email lookup in portal_db_server.py, which this keeps working with unchanged).
const getCampusEventRegistrant = () => {
  const role = localStorage.getItem("gprecActiveRole");
  if (role === "faculty") {
    const email = (localStorage.getItem("gprecFacultyEmail") || "").trim().toLowerCase();
    return { key: email, rollNumber: "", email, defaultName: lookupFacultyRecordByEmail(email)?.name || "Faculty" };
  }
  if (role === "admin") {
    const email = (localStorage.getItem("gprecAdminEmail") || "").trim().toLowerCase();
    return { key: email, rollNumber: "", email, defaultName: localStorage.getItem("gprecAdminRole") || "Admin" };
  }
  const rollNumber = getCurrentStudentId();
  return { key: rollNumber, rollNumber, email: "", defaultName: resolveStudentDisplayName(rollNumber, "Student") };
};
// Outside Visitor (isExternal) vs GPREC Student (has a roll number) vs GPREC Staff (faculty/admin,
// email only) - shown in the registrant tables/CSV exports faculty event-heads and admins see.
const campusEventParticipantType = (registration) =>
  registration.isExternal ? "Outside Visitor" : registration.rollNumber ? "GPREC Student" : "GPREC Staff";

const saveCampusEventRegistration = ({ paymentType = "Free", paymentReference = "-", paymentStatus = "Registered" } = {}) => {
  if (!activeEvent) return null;
  const registrant = getCampusEventRegistrant();
  const participantName = eventParticipantName?.value.trim() || registrant.defaultName;
  const registeredAt = new Date().toISOString();
  const record = {
    id: `${activeEvent.id}:${registrant.key}`,
    eventId: activeEvent.id,
    eventName: activeEvent.name,
    participantName,
    rollNumber: registrant.rollNumber,
    email: registrant.email,
    teamMembers: eventTeamMembers?.value.trim() || "",
    fee: activeEvent.fee,
    paymentType,
    paymentReference,
    paymentStatus,
    registeredAt
  };
  // postCampusEventRegistration returns null on any non-2xx response (including a 409 capacity
  // rejection - the client-side pre-check above is only a snapshot and can race between two
  // students registering close together, so the server call here can still fail even after the
  // pre-check passed). Only report success back to the caller if the write actually went through.
  const response = postCampusEventRegistration(record);
  return response?.ok ? record : null;
};

// Assigns (once, then reuses) a random opaque gate-scan token on an event registration record -
// same technique as ensureHostelGateToken (see hostel gate passes elsewhere in this file), just
// against campus_event_registrations via postCampusEventRegistration's single-record upsert
// instead of a full-array save. Re-downloading the same ticket keeps returning the same token/QR.
const ensureEventGateToken = (registrationId) => {
  const record = getCampusEventRegistrations().find((item) => item.id === registrationId);
  if (!record) return null;
  if (record.gateToken) return record.gateToken;
  // crypto.randomUUID() throws on a plain http:// origin that isn't localhost - exactly how this
  // could be served during local testing/on a LAN, and this QR gets scanned by a phone's camera.
  const randomBytes = crypto.getRandomValues(new Uint8Array(16));
  const randomHex = Array.from(randomBytes, (b) => b.toString(16).padStart(2, "0")).join("");
  const token = `${Date.now().toString(36)}${randomHex}`;
  const response = postCampusEventRegistration({ ...record, gateToken: token });
  return response?.ok ? token : null;
};

const eventGateScanUrl = (eventId, regId, token) =>
  `${window.location.origin}/pages/event-pass-scan.html?eventId=${encodeURIComponent(eventId)}&reg=${encodeURIComponent(regId)}&t=${token}`;

const safeDownloadSlug = (value, fallback = "file") => {
  const slug = String(value || "")
    .trim()
    .toLowerCase()
    .replace(/&/g, " and ")
    .replace(/[^a-z0-9]+/g, "-")
    .replace(/^-+|-+$/g, "")
    .slice(0, 80);
  return slug || fallback;
};

const eventPassDownloadName = (registration = {}, event = {}) => {
  const eventName = event.name || event.title || registration.eventName || registration.eventId || "event";
  const attendee = registration.participantName || registration.rollNumber || registration.email || "attendee";
  return `gprec-event-pass-${safeDownloadSlug(eventName, "event")}-${safeDownloadSlug(attendee, "attendee")}.png`;
};

// Wraps text across up to `maxLines` lines within `maxWidth`, truncating the last line with an
// ellipsis if there's more text than that - used for event titles of unpredictable length on the
// ticket image below.
const wrapCanvasText = (ctx, text, x, y, maxWidth, lineHeight, maxLines = 2) => {
  const words = String(text || "").split(/\s+/).filter(Boolean);
  const lines = [];
  let line = "";
  let index = 0;
  while (index < words.length && lines.length < maxLines) {
    const test = line ? `${line} ${words[index]}` : words[index];
    if (ctx.measureText(test).width > maxWidth && line) {
      lines.push(line);
      line = "";
    } else {
      line = test;
      index += 1;
    }
  }
  if (line && lines.length < maxLines) lines.push(line);
  if (index < words.length && lines.length) {
    let last = lines[lines.length - 1];
    while (ctx.measureText(`${last}…`).width > maxWidth && last.length > 1) last = last.slice(0, -1);
    lines[lines.length - 1] = `${last}…`;
  }
  lines.forEach((lineText, lineIndex) => ctx.fillText(lineText, x, y + lineIndex * lineHeight));
};

const canvasTextLines = (ctx, text, maxWidth) => {
  const words = String(text || "").split(/\s+/).filter(Boolean);
  if (!words.length) return ["-"];
  const lines = [];
  let line = "";
  words.forEach((word) => {
    const test = line ? `${line} ${word}` : word;
    if (ctx.measureText(test).width > maxWidth && line) {
      lines.push(line);
      line = word;
    } else {
      line = test;
    }
  });
  if (line) lines.push(line);
  return lines;
};

const drawFittedCanvasText = (ctx, text, x, y, maxWidth, { maxLines = 2, maxFontSize = 20, minFontSize = 12, weight = 800, color = "#04284a" } = {}) => {
  let fontSize = maxFontSize;
  let lines = [];
  while (fontSize >= minFontSize) {
    ctx.font = `${weight} ${fontSize}px Arial, sans-serif`;
    lines = canvasTextLines(ctx, text || "-", maxWidth);
    if (lines.length <= maxLines && lines.every((line) => ctx.measureText(line).width <= maxWidth)) break;
    fontSize -= 1;
  }
  ctx.font = `${weight} ${fontSize}px Arial, sans-serif`;
  ctx.fillStyle = color;
  const lineHeight = Math.max(16, Math.round(fontSize * 1.18));
  const visibleLines = lines.slice(0, maxLines);
  visibleLines.forEach((lineText, lineIndex) => ctx.fillText(lineText, x, y + lineIndex * lineHeight));
  return { lines: visibleLines.length, lineHeight, height: visibleLines.length * lineHeight };
};

