// Draws a ticket-format pass - a downloadable PNG, not a PDF, so it can be saved straight
// to a phone's photo gallery ahead of real Apple/Google Wallet integration (which needs signing
// credentials this app doesn't have yet). Layout/colors match the "Udaan 2K26" reference design -
// see renderTicketStubCard for the shared card shape this and the other ticket-family passes use.
const buildEventTicketImage = async (registration, event) => {
  // A public/external registration's response already carries a server-generated gateToken (see
  // register_for_public_event in portal_db_server.py) - the caller has no session to look it back
  // up via getCampusEventRegistrations() the way ensureEventGateToken normally does.
  const token = registration.gateToken || ensureEventGateToken(registration.id);
  if (!token) {
    throw new Error("Could not prepare this event pass QR. Please sign in on the same app server and try downloading the pass again.");
  }
  registration.gateToken = token;
  const scanUrl = eventGateScanUrl(event.id, registration.id, token);

  const makeTicketCode = () => {
    const source = [registration.id, registration.eventId, registration.email, registration.registeredAt, token].filter(Boolean).join("|");
    let hash = 0;
    for (let i = 0; i < source.length; i += 1) {
      hash = (hash * 31 + source.charCodeAt(i)) >>> 0;
    }
    return `EV-${hash.toString(36).toUpperCase().padStart(6, "0").slice(-6)}`;
  };
  const ticketCode = makeTicketCode();
  const festName = (getFestName() || "GPREC FEST").toUpperCase();

  return renderTicketStubCard({
    eyebrow: `${festName} · EVENT PASS`,
    scanCaption: "SCAN AT ENTRY GATE",
    tag: "E-TICKET",
    tagIconPath: TICKET_ICON_PATHS.ticket,
    qrText: scanUrl,
    title: event.name || "GPREC Event",
    fields: [
      { label: "TICKET ID", value: ticketCode, mono: true },
      { label: "NAME", value: registration.participantName },
      { label: "DATE", value: formatCampusEventDate(event.date) },
      { label: "STATUS", value: registration.paymentStatus || "Registered", status: true },
      { label: "LOCATION", value: event.venue || "Venue TBA", fullWidth: true }
    ],
    footerLeft: festName,
    footerRight: "ADMIT ONE",
    showNotches: true,
    watermarkSvg: TICKET_WATERMARKS.compass,
    watermarkSize: 230,
    watermarkOpacity: 0.16
  });
};

// Builds the ticket image and reveals it as a persistent download link (same pattern as
// eventReceiptDownload above it) rather than auto-triggering the download - so a student can
// come back and re-download the same ticket without re-registering. Called from both the paid
// (recordEventPayment) and free registration paths - volunteers need to check every attendee in,
// paid or free, so both need a scannable ticket, not just the paid ones.
const showEventTicketDownload = async (record) => {
  if (!eventTicketDownload || !activeEvent) return;
  const blob = await buildEventTicketImage(record, activeEvent);
  eventTicketDownload.href = URL.createObjectURL(blob);
  eventTicketDownload.download = eventPassDownloadName(record, activeEvent);
  eventTicketDownload.classList.remove("is-hidden");
  eventTicketDownload.classList.add("ready");
  eventTicketHint?.classList.remove("is-hidden");
};

// Records a paid event registration (called once the PayU checkout tab has been opened) -
// builds the same downloadable PDF receipt and payment-history entry the old simulated
// "Confirm Payment" button used to.
const recordEventPayment = async (paymentType, paymentReference) => {
  const registrant = getCampusEventRegistrant();
  const participantName = eventParticipantName?.value.trim() || registrant.defaultName;
  const paymentDate = new Date().toLocaleDateString("en-IN", { day: "2-digit", month: "short", year: "numeric" });
  const paymentTime = new Date().toLocaleTimeString("en-IN", { hour: "2-digit", minute: "2-digit", hour12: true });

  const receiptLines = [
    `Participant Name: ${participantName}`,
    registrant.rollNumber ? `Roll Number: ${registrant.rollNumber}` : `Email: ${registrant.email}`,
    `Event: ${activeEvent.name}`,
    `Registration Fee: Rs. ${activeEvent.fee.toLocaleString("en-IN")}`,
    `Payment Type: ${paymentType}`,
    `Payment Reference: ${paymentReference}`,
    `Payment Date: ${paymentDate}`,
    `Payment Time: ${paymentTime}`,
    "Payment Status: Paid"
  ];
  const pdf = await makeReceiptPdf("GPREC Event Registration Receipt", receiptLines);
  if (eventReceiptDownload) {
    eventReceiptDownload.href = URL.createObjectURL(pdf);
    eventReceiptDownload.classList.remove("is-hidden");
    eventReceiptDownload.classList.add("ready");
  }
  const record = saveCampusEventRegistration({ paymentType, paymentReference, paymentStatus: "Paid" });
  renderCampusEventManager();
  if (record) {
    showEventFeedback(eventFeedback, "Payment received. Registration receipt is ready to download.", true);
    showEventTicketDownload(record);
  } else {
    showEventFeedback(eventFeedback, "Payment received, but the event reached capacity before your registration was saved. Contact the event organizer for a refund.", false);
  }

  // recordPayment posts against a student roll number (see /api/payments in
  // portal_db_server.py) - faculty/admin registrants have none, and neither dashboard has a
  // Payment History panel to show it in, so there's nothing to log for them here.
  if (registrant.rollNumber) {
    recordPayment({
      feeType: "Event Registration",
      detail: activeEvent.name,
      amount: `Rs. ${activeEvent.fee.toLocaleString("en-IN")}`,
      date: paymentDate,
      receiptLines
    });
  }
};

eventSubmitButton?.addEventListener("click", async () => {
  if (!activeEvent) return;
  if (eventParticipantName && !eventParticipantName.reportValidity()) return;
  const declaration = eventApplyForm?.querySelector('input[type="checkbox"]');
  if (declaration && !declaration.reportValidity()) return;

  // Client-side pre-check for immediate feedback (don't even open PayU for a full paid event) -
  // the server-side check in upsert_campus_event_registration is the authoritative one, since
  // this cached registration count can race between two students registering close together.
  // Never blocks re-registering for an event you're already registered for.
  if (activeEvent.capacity) {
    const registrant = getCampusEventRegistrant();
    const alreadyRegistered = getCampusEventRegistrations().some((item) => item.id === `${activeEvent.id}:${registrant.key}`);
    const currentCount = getCampusEventRegistrations().filter((item) => item.eventId === activeEvent.id).length;
    if (!alreadyRegistered && currentCount >= activeEvent.capacity) {
      showEventFeedback(eventFeedback, "Registration limit reached for this event.", false);
      return;
    }
  }

  if (activeEvent.fee === 0) {
    const registrant = getCampusEventRegistrant();
    const registrationDate = new Date().toLocaleDateString("en-IN", { day: "2-digit", month: "short", year: "numeric" });
    const record = saveCampusEventRegistration({ paymentType: "Free", paymentReference: "-", paymentStatus: "Registered" });
    renderCampusEventManager();
    if (!record) {
      showEventFeedback(eventFeedback, "Registration limit reached for this event.", false);
      return;
    }
    showEventFeedback(eventFeedback, `Registration confirmed for ${activeEvent.name}. No payment required.`, true);
    showEventTicketDownload(record);
    if (registrant.rollNumber) {
      recordPayment({
        feeType: "Event Registration",
        detail: activeEvent.name,
        amount: "Free",
        date: registrationDate,
        receiptLines: [
          `Participant Name: ${eventParticipantName?.value.trim() || registrant.defaultName}`,
          `Roll Number: ${registrant.rollNumber}`,
          `Event: ${activeEvent.name}`,
          "Registration Fee: Free",
          `Registration Date: ${registrationDate}`,
          "Status: Registered"
        ]
      });
    }
    return;
  }

  const payuPaymentLink = await resolvePayuPaymentLink();
  if (!payuPaymentLink) {
    showEventFeedback(eventFeedback, "Payment gateway is not linked yet.", false);
    return;
  }

  openPayuCheckoutAndRecord(payuPaymentLink, activeEvent.fee, (paymentId) => {
    recordEventPayment("Online Payment", paymentId);
  });
});

// Manual Check-In (student-dashboard.html only) - the same roll-number-or-email fallback
// event-pass-scan.html offers a volunteer whose QR camera scan won't work, but reachable
// straight from the dashboard's own nav instead of needing a scanned QR link to land on that
// page first. Same /campus-event/manual-checkin endpoint (allowed_types admin/student), so
// nothing on the backend changes for this to work.
const studentManualCheckinButton = document.querySelector("#studentManualCheckinButton");
if (studentManualCheckinButton) {
  const checkinEventSelect = document.querySelector("#studentManualCheckinEventSelect");
  const checkinRollInput = document.querySelector("#studentManualCheckinRollInput");
  const checkinEmailInput = document.querySelector("#studentManualCheckinEmailInput");
  const checkinFeedback = document.querySelector("#studentManualCheckinFeedback");
  const showCheckinFeedback = (text, isSuccess) => {
    checkinFeedback.textContent = text;
    checkinFeedback.classList.remove("is-hidden");
    checkinFeedback.classList.toggle("success", Boolean(isSuccess));
  };
  if (checkinEventSelect) {
    checkinEventSelect.innerHTML = [...getCampusEvents()]
      .sort((a, b) => String(a.date || "").localeCompare(String(b.date || "")))
      .map((event) => `<option value="${escapeHtml(event.id)}">${escapeHtml(event.title)}</option>`)
      .join("");
  }
  studentManualCheckinButton.addEventListener("click", () => {
    const eventId = checkinEventSelect?.value || "";
    const rollNumber = checkinRollInput?.value.trim().toUpperCase() || "";
    const email = checkinEmailInput?.value.trim().toLowerCase() || "";
    if (!eventId || (!rollNumber && !email)) {
      showCheckinFeedback("Select an event and enter either a GPREC roll number or an outside visitor email.", false);
      return;
    }
    if (rollNumber && email) {
      showCheckinFeedback("Use only one field: roll number for GPREC students, email for outside visitors.", false);
      return;
    }
    const response = gprecDbPost("/campus-event/manual-checkin", { eventId, rollNumber, email });
    if (response && response.ok) {
      showCheckinFeedback(`${rollNumber || email} checked in.`, true);
      if (checkinRollInput) checkinRollInput.value = "";
      if (checkinEmailInput) checkinEmailInput.value = "";
    } else {
      showCheckinFeedback((response && response.error) || "Could not check this attendee in.", false);
    }
  });
}

