const campusEventRegistrationCsvRows = (registrations) =>
  registrations.map((registration) => [
    registration.eventName || "",
    campusEventParticipantType(registration),
    registration.participantName || "",
    registration.rollNumber || "",
    registration.email || "",
    registration.college || "",
    registration.teamMembers || "",
    registration.fee ? `Rs. ${Number(registration.fee).toLocaleString("en-IN")}` : "Free",
    registration.paymentStatus || "",
    registration.paymentType || "",
    registration.paymentReference || "",
    registration.registeredAt ? new Date(registration.registeredAt).toLocaleString("en-IN") : "",
    registration.checkIn ? "Yes" : "No",
    registration.checkIn?.scannedAt ? formatOutingDateTime(registration.checkIn.scannedAt) : "",
    registration.checkIn?.scannedBy || "",
    registration.checkIn?.scannedBy || ""
  ]);
const campusEventRegistrationCsvHeaders = [
  "Event",
  "Type",
  "Participant",
  "Roll Number",
  "Email",
  "College / Organization",
  "Team Members",
  "Fee",
  "Status",
  "Payment Type",
  "Payment Reference",
  "Registered At",
  "Checked In",
  "Checked In At",
  "Checked In By",
  "Appointed To"
];

const exportCampusEventParticipants = (eventId) => {
  const event = getCampusEvents().find((item) => item.id === eventId);
  const rows = campusEventRegistrationCsvRows(getCampusEventRegistrations().filter((registration) => registration.eventId === eventId && registration.checkIn));
  if (!rows.length) {
    showFeedToast("No check-ins recorded for this event yet.");
    return;
  }
  const filenamePart = (event?.title || "campus-event").toLowerCase().replace(/[^a-z0-9]+/g, "-").replace(/^-|-$/g, "") || "campus-event";
  downloadCsv(`gprec-${filenamePart}-check-ins.csv`, campusEventRegistrationCsvHeaders, rows);
};

const renderCampusEventManager = () => {
  if (!campusEventManagerBody) return;
  const events = [...getCampusEvents()].sort((a, b) => String(a.date || "").localeCompare(String(b.date || "")));
  const registrations = getCampusEventRegistrations();
  campusEventManagerEmpty?.classList.toggle("is-hidden", events.length > 0);
  campusEventManagerBody.innerHTML = events.length
    ? events
        .map((event) => {
          const count = registrations.filter((registration) => registration.eventId === event.id).length;
          const fee = Number(event.fee) || 0;
          const managerContact = [event.managerName, event.managerPhone, event.managerEmail || event.facultyHeadEmail].filter(Boolean).join(" | ") || "-";
          return `
            <tr>
              <td>${formatCampusEventDate(event.date)}</td>
              <td>${escapeHtml(event.title)}</td>
              <td>${fee ? `₹${fee.toLocaleString("en-IN")}` : "Free"}</td>
              <td>${escapeHtml(managerContact)}</td>
              <td>${event.capacity ? `${count} / ${event.capacity}` : count}</td>
              <td><button type="button" class="icon-btn-download" data-campus-event-export="${escapeHtml(event.id)}" aria-label="Export check-ins CSV" title="Export check-ins CSV">${downloadIconSvg}</button></td>
              <td><button type="button" class="icon-btn-delete" data-campus-event-remove="${escapeHtml(event.id)}" aria-label="Remove event">${deleteIconSvg}</button></td>
            </tr>
          `;
        })
        .join("")
    : `<tr><td colspan="7">No campus events published yet.</td></tr>`;
};

renderCampusEventManager();

campusEventAddButton?.addEventListener("click", () => {
  const title = campusEventTitleInput?.value.trim() || "";
  const date = campusEventDateInput?.value || "";
  const time = campusEventTimeInput?.value || "";
  const venue = campusEventVenueInput?.value.trim() || "";
  const fee = Math.max(0, Number(campusEventFeeInput?.value) || 0);
  const facultyHeadEmail = campusEventFacultyHeadInput?.value.trim().toLowerCase() || "";
  const capacity = campusEventCapacityInput?.value ? Math.max(0, Number(campusEventCapacityInput.value)) : null;
  const managerName = campusEventManagerNameInput?.value.trim() || "";
  const managerEmail = campusEventManagerEmailInput?.value.trim().toLowerCase() || "";
  const managerPhone = campusEventManagerPhoneInput?.value.trim() || "";
  const bannerStartDate = campusEventBannerStartInput?.value || "";
  const bannerEndDate = campusEventBannerEndInput?.value || "";
  const isPublic = Boolean(campusEventPublicInput?.checked);
  const description = campusEventDescriptionInput?.value.trim() || "";
  if (!title || !date || !venue || !description) {
    if (campusEventAddFeedback) {
      campusEventAddFeedback.textContent = "Enter title, date, venue, and description before publishing.";
      campusEventAddFeedback.classList.remove("success");
    }
    return;
  }
  const events = [...getCampusEvents()];
  events.push({
    id: `campus-event-${Date.now()}`,
    title,
    date,
    time,
    venue,
    fee,
    facultyHeadEmail,
    managerName,
    managerEmail,
    managerPhone,
    capacity,
    isPublic,
    description,
    bannerStartDate,
    bannerEndDate
  });
  saveCampusEvents(events);
  renderCampusEvents();
  renderCampusEventManager();
  [campusEventTitleInput, campusEventDateInput, campusEventTimeInput, campusEventVenueInput, campusEventFacultyHeadInput, campusEventCapacityInput, campusEventManagerNameInput, campusEventManagerEmailInput, campusEventManagerPhoneInput, campusEventBannerStartInput, campusEventBannerEndInput, campusEventDescriptionInput].forEach((field) => {
    if (field) field.value = "";
  });
  if (campusEventFeeInput) campusEventFeeInput.value = "0";
  if (campusEventAddFeedback) {
    campusEventAddFeedback.textContent = `"${title}" published to student Campus Events.`;
    campusEventAddFeedback.classList.add("success");
  }
  recordActivity(`Published campus event "${title}"`, "Campus Events");
});

campusEventExportAllButton?.addEventListener("click", () => {
  const rows = campusEventRegistrationCsvRows(getCampusEventRegistrations().filter((registration) => registration.checkIn));
  if (!rows.length) {
    showFeedToast("No campus event check-ins recorded yet.");
    return;
  }
  downloadCsv("gprec-campus-event-check-ins.csv", campusEventRegistrationCsvHeaders, rows);
});

campusEventManagerBody?.addEventListener("click", (event) => {
  const exportButton = event.target.closest("[data-campus-event-export]");
  if (exportButton) {
    exportCampusEventParticipants(exportButton.dataset.campusEventExport);
    return;
  }
  const removeButton = event.target.closest("[data-campus-event-remove]");
  if (!removeButton) return;
  // Goes through a dedicated endpoint (not the generic saveCampusEvents array-filter-then-save)
  // so removal also cleans up that event's registrations and any external visitor accounts left
  // with no other remaining registration - see remove_campus_event_registrations in
  // portal_db_server.py.
  gprecDbPost("/campus-events/remove", { eventId: removeButton.dataset.campusEventRemove });
  renderCampusEvents();
  renderCampusEventManager();
  recordActivity("Removed campus event", "Campus Events");
});

