const assignmentSubmitForm = document.querySelector("#assignmentSubmitForm");
if (assignmentSubmitForm) {
  const setText = (selector, value) => {
    const node = document.querySelector(selector);
    if (node) node.textContent = value;
  };

  const requestedAssignmentId = new URLSearchParams(window.location.search).get("assignment");
  const allAssignments = getAssignments();
  const assignment = allAssignments.find((item) => item.id === requestedAssignmentId) || allAssignments[0];

  if (!assignment) {
    setText("#assignmentEyebrow", "Assignment");
    setText("#assignmentTitle", "No assignment found");
    setText("#assignmentDescription", "This assignment is not available. Go back to your subject page.");
    assignmentSubmitForm.classList.add("is-hidden");
  } else {
    const course = subjectData[assignment.subjectCode];
    const teacherName = course?.teacher.split("|")[0].trim() || "-";
    setText("#assignmentEyebrow", `${assignment.subjectCode} | Assignment`);
    setText("#assignmentTitle", assignment.title);
    setText("#assignmentDescription", assignment.description);
    setText("#assignmentTeacher", teacherName);
    setText("#assignmentDueDate", formatOutingDateTime(assignment.dueDate));
    document.title = `${assignment.title} | GPREC`;

    const assignmentAttachments = document.querySelector("#assignmentAttachments");
    const assignmentDocumentLink = document.querySelector("#assignmentDocumentLink");
    if (assignment.document && assignmentAttachments && assignmentDocumentLink) {
      assignmentAttachments.classList.remove("is-hidden");
      assignmentDocumentLink.href = assignment.document.dataUrl;
      assignmentDocumentLink.download = assignment.document.name;
      assignmentDocumentLink.textContent = assignment.document.name;
    }

    const currentStudentId = getCurrentStudentId();
    const currentStudentName = hostelStudentData[currentStudentId]?.name || "Sai Chandan";

    const suggestedFileName = `${currentStudentId}_${assignment.title.trim().replace(/\s+/g, "_")}.pdf`;
    setText("#assignmentFileNameSuggestion", `Suggested file name: ${suggestedFileName}`);

    const refreshSubmissionStatus = () => {
      const existing = getAssignmentSubmissions().find(
        (submission) => submission.assignmentId === assignment.id && submission.studentId === currentStudentId
      );
      setText("#assignmentStatus", existing ? `Submitted on ${existing.submittedAt}` : "Not submitted");
    };
    refreshSubmissionStatus();

    assignmentSubmitForm.addEventListener("submit", async (event) => {
      event.preventDefault();
      const documentsInput = document.querySelector("#assignmentDocuments");
      const photosInput = document.querySelector("#assignmentPhotos");
      const comment = document.querySelector("#assignmentComment").value.trim();
      const feedback = document.querySelector("#assignmentSubmitFeedback");
      const allFiles = [...Array.from(documentsInput?.files || []), ...Array.from(photosInput?.files || [])];

      const studentDepartment = defaultStudentDirectory.find((student) => student.studentId === currentStudentId)?.branch || "unassigned";
      let files = [];
      try {
        files = (await Promise.all(
          allFiles.map((file) => readFileAsDataUrl(file, `assignments/submissions/${studentDepartment}`))
        )).map((file) => ({
          ...file,
          name: `${currentStudentId}_${file.name}`
        }));
      } catch {
        if (feedback) {
          feedback.textContent = "Could not read one of the selected files. Please try again.";
          feedback.classList.remove("is-hidden", "success");
        }
        return;
      }

      const result = submitAssignment({
        assignmentId: assignment.id,
        studentId: currentStudentId,
        comment,
        files
      });
      if (!result?.ok) {
        if (feedback) {
          feedback.textContent = "Could not reach the portal API to save submission.";
          feedback.classList.remove("is-hidden", "success");
        }
        return;
      }

      if (feedback) {
        feedback.textContent = "Assignment submitted successfully.";
        feedback.classList.remove("is-hidden");
        feedback.classList.add("success");
      }
      refreshSubmissionStatus();
    });
  }
}

// Edit Profile accordion: reads/writes an extended "profile" object on the current alumni's
// account record in gprecAlumniAccounts (the same store used by sign up/sign in), so details
// persist across sessions on this device.
const getCurrentAlumniAccountRecord = (email) => {
  const accounts = getAlumniAccounts();
  let account = accounts.find((acc) => acc.email === email);
  if (!account) {
    account = { email, name: localStorage.getItem("gprecAlumniName") || "", batchYear: localStorage.getItem("gprecAlumniBatch") || "" };
    accounts.push(account);
  }
  if (!account.profile) account.profile = {};
  return { account, accounts };
};

const initAlumniProfileEditor = (email) => {
  const { account, accounts } = getCurrentAlumniAccountRecord(email);
  saveAlumniAccounts(accounts);
  const profile = account.profile;

  const setValue = (selector, value) => {
    const node = document.querySelector(selector);
    if (node) node.value = value || "";
  };
  const setChecked = (selector, value) => {
    const node = document.querySelector(selector);
    if (node) node.checked = Boolean(value);
  };

  const basic = profile.basic || {};
  setValue("#profileBasicName", basic.name || account.name);
  setValue("#profileBasicGender", basic.gender);
  setValue("#profileBasicDob", basic.dob);
  setValue("#profileBasicPhone", basic.phone);
  setValue("#profileBasicBio", basic.bio);
  setValue("#profileBasicWeddingDate", basic.weddingDate);

  const picturePreview = document.querySelector("#profilePicturePreview");
  const pictureDefaultIcon = document.querySelector("#profilePictureDefaultIcon");
  const setProfilePicture = (dataUrl) => {
    if (picturePreview) {
      picturePreview.src = dataUrl || "";
      picturePreview.classList.toggle("is-hidden", !dataUrl);
    }
    if (pictureDefaultIcon) pictureDefaultIcon.classList.toggle("is-hidden", Boolean(dataUrl));
  };
  setProfilePicture(profile.pictureDataUrl);

  // Profile picture editor: after choosing a file, the user can zoom, rotate, flip, and drag
  // to reposition it on a canvas before saving. Saving flattens the canvas into one image
  // (via toDataURL) so every place the picture is shown just displays a plain image - no
  // transform metadata needs to be re-applied elsewhere.
  const PICTURE_CANVAS_SIZE = 220;
  let pictureEditorState = null;

  const renderPictureEditorCanvas = () => {
    const canvas = document.querySelector("#profilePictureEditorCanvas");
    if (!canvas || !pictureEditorState) return;
    const ctx = canvas.getContext("2d");
    const { image, scale, rotation, flip, offsetX, offsetY } = pictureEditorState;
    const size = PICTURE_CANVAS_SIZE;
    ctx.clearRect(0, 0, size, size);
    ctx.save();
    ctx.beginPath();
    ctx.arc(size / 2, size / 2, size / 2, 0, Math.PI * 2);
    ctx.closePath();
    ctx.clip();
    ctx.fillStyle = "#eef2f7";
    ctx.fillRect(0, 0, size, size);
    ctx.translate(size / 2 + offsetX, size / 2 + offsetY);
    ctx.rotate((rotation * Math.PI) / 180);
    ctx.scale(flip ? -scale : scale, scale);
    const coverScale = Math.max(size / image.width, size / image.height);
    ctx.drawImage(
      image,
      (-image.width * coverScale) / 2,
      (-image.height * coverScale) / 2,
      image.width * coverScale,
      image.height * coverScale
    );
    ctx.restore();
  };

  const resetPictureEditorState = (image) => {
    pictureEditorState = { image, scale: 1, rotation: 0, flip: false, offsetX: 0, offsetY: 0 };
    const zoomInput = document.querySelector("#profilePictureZoomInput");
    if (zoomInput) zoomInput.value = "100";
    renderPictureEditorCanvas();
  };

  const handlePictureFile = (file) => {
    if (!file) return;
    readFileAsDataUrl(file, "alumni/profile").then((uploaded) => {
      const image = new Image();
      image.onload = () => {
        document.querySelector("#profilePictureDropzone")?.classList.add("is-hidden");
        document.querySelector("#profilePictureEditor")?.classList.remove("is-hidden");
        resetPictureEditorState(image);
      };
      image.src = uploaded.dataUrl;
    });
  };

  document.querySelector("#profilePictureInput")?.addEventListener("change", (event) => {
    handlePictureFile(event.target.files[0]);
  });

  document.querySelector("#profilePictureChooseButton")?.addEventListener("click", () => {
    document.querySelector("#profilePictureInput")?.click();
  });

  const pictureDropzone = document.querySelector("#profilePictureDropzone");
  pictureDropzone?.addEventListener("dragover", (event) => {
    event.preventDefault();
    pictureDropzone.classList.add("is-drag-over");
  });
  pictureDropzone?.addEventListener("dragleave", () => {
    pictureDropzone.classList.remove("is-drag-over");
  });
  pictureDropzone?.addEventListener("drop", (event) => {
    event.preventDefault();
    pictureDropzone.classList.remove("is-drag-over");
    handlePictureFile(event.dataTransfer.files[0]);
  });

  const renderPictureGallery = () => {
    const gallery = document.querySelector("#profilePictureGallery");
    if (!gallery) return;
    const { account: fresh } = getCurrentAlumniAccountRecord(email);
    const history = fresh.profile.pictureHistory || [];
    gallery.innerHTML = history.length
      ? history
          .map(
            (item) => `
        <div class="profile-picture-gallery-item">
          <img src="${item.dataUrl}" alt="Previously uploaded picture">
          <div class="profile-picture-gallery-item-actions">
            <button type="button" class="profile-picture-gallery-item-use" data-picture-use="${item.id}">Use This</button>
            <button type="button" class="icon-btn-delete profile-picture-gallery-item-delete" data-picture-delete="${item.id}" aria-label="Delete picture">${deleteIconSvg}</button>
          </div>
        </div>
      `
          )
          .join("")
      : `<p class="portal-note">No previously uploaded pictures yet.</p>`;
  };
  renderPictureGallery();

  document.querySelector("#profilePictureGallery")?.addEventListener("click", (event) => {
    const useButton = event.target.closest("[data-picture-use]");
    const deleteButton = event.target.closest("[data-picture-delete]");
    if (useButton) {
      const { account: fresh } = getCurrentAlumniAccountRecord(email);
      const item = (fresh.profile.pictureHistory || []).find((entry) => entry.id === useButton.dataset.pictureUse);
      if (!item) return;
      withAccount((p) => {
        p.pictureDataUrl = item.dataUrl;
      });
      setProfilePicture(item.dataUrl);
      showProfileFeedback("Profile picture updated.");
    } else if (deleteButton) {
      withAccount((p) => {
        p.pictureHistory = (p.pictureHistory || []).filter((entry) => entry.id !== deleteButton.dataset.pictureDelete);
      });
      renderPictureGallery();
      showProfileFeedback("Removed from previously uploaded pictures.");
    }
  });

  document.querySelector("#profilePictureZoomInput")?.addEventListener("input", (event) => {
    if (!pictureEditorState) return;
    pictureEditorState.scale = Number(event.target.value) / 100;
    renderPictureEditorCanvas();
  });

  document.querySelector("#profilePictureRotateLeftButton")?.addEventListener("click", () => {
    if (!pictureEditorState) return;
    pictureEditorState.rotation -= 90;
    renderPictureEditorCanvas();
  });

  document.querySelector("#profilePictureRotateRightButton")?.addEventListener("click", () => {
    if (!pictureEditorState) return;
    pictureEditorState.rotation += 90;
    renderPictureEditorCanvas();
  });

  document.querySelector("#profilePictureFlipButton")?.addEventListener("click", () => {
    if (!pictureEditorState) return;
    pictureEditorState.flip = !pictureEditorState.flip;
    renderPictureEditorCanvas();
  });

  document.querySelector("#profilePictureResetButton")?.addEventListener("click", () => {
    if (!pictureEditorState) return;
    resetPictureEditorState(pictureEditorState.image);
  });

  document.querySelector("#profilePictureCancelButton")?.addEventListener("click", () => {
    pictureEditorState = null;
    document.querySelector("#profilePictureEditor")?.classList.add("is-hidden");
    document.querySelector("#profilePictureDropzone")?.classList.remove("is-hidden");
    const pictureInput = document.querySelector("#profilePictureInput");
    if (pictureInput) pictureInput.value = "";
  });

  document.querySelector("#profilePictureDeleteButton")?.addEventListener("click", () => {
    withAccount((p) => {
      p.pictureDataUrl = null;
    });
    setProfilePicture(null);
    pictureEditorState = null;
    document.querySelector("#profilePictureEditor")?.classList.add("is-hidden");
    const pictureInput = document.querySelector("#profilePictureInput");
    if (pictureInput) pictureInput.value = "";
    showProfileFeedback("Profile picture removed.");
  });

  {
    const canvas = document.querySelector("#profilePictureEditorCanvas");
    let dragging = false;
    let dragStartX = 0;
    let dragStartY = 0;
    let dragOriginX = 0;
    let dragOriginY = 0;

    const startDrag = (clientX, clientY) => {
      if (!pictureEditorState) return;
      dragging = true;
      dragStartX = clientX;
      dragStartY = clientY;
      dragOriginX = pictureEditorState.offsetX;
      dragOriginY = pictureEditorState.offsetY;
    };
    const moveDrag = (clientX, clientY) => {
      if (!dragging || !pictureEditorState) return;
      pictureEditorState.offsetX = dragOriginX + (clientX - dragStartX);
      pictureEditorState.offsetY = dragOriginY + (clientY - dragStartY);
      renderPictureEditorCanvas();
    };
    const endDrag = () => {
      dragging = false;
    };

    canvas?.addEventListener("mousedown", (event) => startDrag(event.clientX, event.clientY));
    window.addEventListener("mousemove", (event) => moveDrag(event.clientX, event.clientY));
    window.addEventListener("mouseup", endDrag);

    canvas?.addEventListener("touchstart", (event) => {
      const touch = event.touches[0];
      if (touch) startDrag(touch.clientX, touch.clientY);
    });
    canvas?.addEventListener("touchmove", (event) => {
      const touch = event.touches[0];
      if (touch) moveDrag(touch.clientX, touch.clientY);
    });
    canvas?.addEventListener("touchend", endDrag);
  }

  const location = profile.location || {};
  setValue("#profileLocationCity", location.city);
  setValue("#profileLocationState", location.state);
  setValue("#profileLocationCountry", location.country);
  setValue("#profileLocationAltEmail", location.altEmail);
  setValue("#profileLocationAltPhone", location.altPhone);

  const education = profile.education || {};
  setValue("#profileEduDegree", education.degree);
  setValue("#profileEduBranch", education.branch);
  setValue("#profileEduBatch", education.batchYear || account.batchYear);
  setValue("#profileEduCgpa", education.cgpa);
  setValue("#profileEduCerts", education.certs);

  const work = profile.work || {};
  setValue("#profileWorkCompany", work.company);
  setValue("#profileWorkDesignation", work.designation);
  setValue("#profileWorkIndustry", work.industry);
  setValue("#profileWorkExperience", work.experience);
  setValue("#profileWorkLinkedin", work.linkedin);

  const renderAchievements = () => {
    const list = document.querySelector("#profileAchievementsList");
    if (!list) return;
    const achievements = profile.achievements || [];
    list.innerHTML = achievements.length
      ? achievements
          .map(
            (item, index) => `<li><span>${item}</span><button type="button" data-remove-achievement="${index}">Remove</button></li>`
          )
          .join("")
      : "<li><span>No achievements added yet.</span></li>";
  };
  renderAchievements();

  const resume = profile.resume;
  const resumeStatus = document.querySelector("#profileResumeStatus");
  if (resumeStatus) resumeStatus.textContent = resume ? `Uploaded: ${resume.name}` : "No resume uploaded yet.";

  setValue("#profileAccountEmail", account.email);

  const preferences = profile.preferences || {};
  setChecked("#profilePrefEmailNotify", preferences.emailNotify);
  setChecked("#profilePrefJobReferrals", preferences.jobReferrals);
  setValue("#profilePrefVisibility", preferences.visibility || "alumni");

  const privacy = profile.privacy || {};
  setValue("#profilePrivacyDobDay", privacy.dobDay || "all");
  setValue("#profilePrivacyDobYear", privacy.dobYear || "all");
  setValue("#profilePrivacyWeddingDay", privacy.weddingDay || "all");
  setValue("#profilePrivacyWeddingYear", privacy.weddingYear || "all");

  const additional = profile.additional || {};
  setValue("#profileAdditionalHobbies", additional.hobbies);
  setValue("#profileAdditionalNotes", additional.notes);

  const profileSaveFeedback = document.querySelector("#profileSaveFeedback");
  const refreshAlumniProfileSummary = () => {
    const { account: fresh } = getCurrentAlumniAccountRecord(email);
    const freshProfile = fresh.profile || {};
    const basic = freshProfile.basic || {};
    const location = freshProfile.location || {};
    const education = freshProfile.education || {};
    const work = freshProfile.work || {};
    const preferences = freshProfile.preferences || {};
    const additional = freshProfile.additional || {};
    const achievements = freshProfile.achievements || [];
    const resume = freshProfile.resume;

    const displayName = basic.name || fresh.name || email.split("@")[0];
    const batchYear = education.batchYear || fresh.batchYear || "";
    const initials = displayName
      .split(/\s+/)
      .map((part) => part[0])
      .join("")
      .slice(0, 2)
      .toUpperCase();

    const setText = (selector, value, fallback = "-") => {
      const node = document.querySelector(selector);
      if (node) node.textContent = value || fallback;
    };

    setText("#alumniInitials", initials, "AL");
    setText("#alumniDashboardName", displayName, "Alumni");
    setText("#alumniDashboardBatch", batchYear ? `Batch ${batchYear}` : "Batch -");
    setText("#alumniProfileName", displayName);
    setText("#alumniProfileEmail", fresh.email);
    setText("#alumniProfileBatch", batchYear);
    setText("#alumniProfileGender", basic.gender);
    setText("#alumniProfileDob", basic.dob);
    setText("#alumniProfileWeddingDate", basic.weddingDate);
    setText("#alumniProfilePhone", basic.phone);
    setText("#alumniProfileBio", basic.bio, "No bio added yet.");

    const viewPicture = document.querySelector("#alumniProfileViewPicture");
    const viewDefaultIcon = document.querySelector("#alumniProfileViewDefaultIcon");
    if (viewPicture) {
      viewPicture.src = freshProfile.pictureDataUrl || "";
      viewPicture.classList.toggle("is-hidden", !freshProfile.pictureDataUrl);
    }
    if (viewDefaultIcon) viewDefaultIcon.classList.toggle("is-hidden", Boolean(freshProfile.pictureDataUrl));

    setText("#alumniProfileCity", location.city);
    setText("#alumniProfileState", location.state);
    setText("#alumniProfileCountry", location.country);
    setText("#alumniProfileAltEmail", location.altEmail);
    setText("#alumniProfileAltPhone", location.altPhone);

    setText("#alumniProfileDegree", education.degree);
    setText("#alumniProfileBranch", education.branch);
    setText("#alumniProfileCgpa", education.cgpa);
    setText("#alumniProfileCerts", education.certs, "No certifications added yet.");

    setText("#alumniProfileCompany", work.company);
    setText("#alumniProfileDesignation", work.designation);
    setText("#alumniProfileIndustry", work.industry);
    setText("#alumniProfileExperience", work.experience ? `${work.experience} year(s)` : "");
    setText("#alumniProfileLinkedin", work.linkedin);

    const achievementsView = document.querySelector("#alumniProfileAchievementsView");
    if (achievementsView) {
      achievementsView.innerHTML = achievements.length
        ? achievements.map((item) => `<li><span>${item}</span></li>`).join("")
        : "<li><span>No achievements added yet.</span></li>";
    }

    const resumeView = document.querySelector("#alumniProfileResumeView");
    if (resumeView) {
      resumeView.innerHTML = resume
        ? `Uploaded: <a href="${resume.dataUrl}" download="${resume.name}">${resume.name}</a>`
        : "No resume uploaded yet.";
    }

    setText("#alumniProfilePrefEmail", preferences.emailNotify ? "Enabled" : "Disabled");
    setText("#alumniProfilePrefJobs", preferences.jobReferrals ? "Enabled" : "Disabled");
    setText(
      "#alumniProfilePrefVisibility",
      preferences.visibility === "public"
        ? "Public"
        : preferences.visibility === "private"
        ? "Private (only me)"
        : "Visible to Alumni Network only"
    );
    setText("#alumniProfileHobbies", additional.hobbies);
    setText("#alumniProfileNotes", additional.notes, "No additional notes added yet.");

    // Field-level accuracy: count each individual field across every section rather than
    // treating a whole section as "done" the moment any one field in it has a value.
    const profileFields = [
      basic.name,
      basic.gender,
      basic.dob,
      basic.weddingDate,
      basic.phone,
      basic.bio,
      freshProfile.pictureDataUrl,
      location.city,
      location.state,
      location.country,
      location.altEmail,
      location.altPhone,
      education.degree,
      education.branch,
      education.batchYear || fresh.batchYear,
      education.cgpa,
      education.certs,
      work.company,
      work.designation,
      work.industry,
      work.experience,
      work.linkedin,
      achievements.length > 0 ? "yes" : "",
      resume ? "yes" : "",
      preferences.visibility,
      additional.hobbies,
      additional.notes
    ];
    const filledFieldCount = profileFields.filter(
      (value) => value !== undefined && value !== null && String(value).trim() !== ""
    ).length;
    const completePercent = Math.round((filledFieldCount / profileFields.length) * 100);
    const completenessFill = document.querySelector("#profileCompletenessFill");
    const completenessPercent = document.querySelector("#profileCompletenessPercent");
    if (completenessFill) completenessFill.style.width = `${completePercent}%`;
    if (completenessPercent) completenessPercent.textContent = `${completePercent}%`;
  };

  refreshAlumniProfileSummary();

  const showProfileFeedback = (message) => {
    refreshAlumniProfileSummary();
    if (!profileSaveFeedback) return;
    profileSaveFeedback.textContent = message;
    profileSaveFeedback.classList.add("success");
  };

  const withAccount = (mutate) => {
    const { account: current, accounts: all } = getCurrentAlumniAccountRecord(email);
    mutate(current.profile, current);
    saveAlumniAccounts(all);
  };

  document.querySelectorAll("[data-profile-save]").forEach((button) => {
    button.addEventListener("click", () => {
      const section = button.dataset.profileSave;
      if (section === "basic") {
        withAccount((p) => {
          p.basic = {
            name: document.querySelector("#profileBasicName")?.value.trim(),
            gender: document.querySelector("#profileBasicGender")?.value,
            dob: document.querySelector("#profileBasicDob")?.value,
            weddingDate: document.querySelector("#profileBasicWeddingDate")?.value,
            phone: document.querySelector("#profileBasicPhone")?.value.trim(),
            bio: document.querySelector("#profileBasicBio")?.value.trim()
          };
        });
        showProfileFeedback("Basic profile saved.");
      } else if (section === "location") {
        withAccount((p) => {
          p.location = {
            city: document.querySelector("#profileLocationCity")?.value.trim(),
            state: document.querySelector("#profileLocationState")?.value.trim(),
            country: document.querySelector("#profileLocationCountry")?.value.trim(),
            altEmail: document.querySelector("#profileLocationAltEmail")?.value.trim(),
            altPhone: document.querySelector("#profileLocationAltPhone")?.value.trim()
          };
        });
        showProfileFeedback("Contact details saved.");
      } else if (section === "education") {
        withAccount((p) => {
          p.education = {
            degree: document.querySelector("#profileEduDegree")?.value.trim(),
            branch: document.querySelector("#profileEduBranch")?.value.trim(),
            batchYear: document.querySelector("#profileEduBatch")?.value.trim(),
            cgpa: document.querySelector("#profileEduCgpa")?.value.trim(),
            certs: document.querySelector("#profileEduCerts")?.value.trim()
          };
        });
        showProfileFeedback("Education details saved.");
      } else if (section === "work") {
        withAccount((p) => {
          p.work = {
            company: document.querySelector("#profileWorkCompany")?.value.trim(),
            designation: document.querySelector("#profileWorkDesignation")?.value.trim(),
            industry: document.querySelector("#profileWorkIndustry")?.value.trim(),
            experience: document.querySelector("#profileWorkExperience")?.value.trim(),
            linkedin: document.querySelector("#profileWorkLinkedin")?.value.trim()
          };
        });
        showProfileFeedback("Work details saved.");
      } else if (section === "preferences") {
        withAccount((p) => {
          p.preferences = {
            emailNotify: document.querySelector("#profilePrefEmailNotify")?.checked || false,
            jobReferrals: document.querySelector("#profilePrefJobReferrals")?.checked || false,
            visibility: document.querySelector("#profilePrefVisibility")?.value || "alumni"
          };
          p.privacy = {
            dobDay: document.querySelector("#profilePrivacyDobDay")?.value || "all",
            dobYear: document.querySelector("#profilePrivacyDobYear")?.value || "all",
            weddingDay: document.querySelector("#profilePrivacyWeddingDay")?.value || "all",
            weddingYear: document.querySelector("#profilePrivacyWeddingYear")?.value || "all"
          };
        });
        showProfileFeedback("Preferences saved.");
      } else if (section === "additional") {
        withAccount((p) => {
          p.additional = {
            hobbies: document.querySelector("#profileAdditionalHobbies")?.value.trim(),
            notes: document.querySelector("#profileAdditionalNotes")?.value.trim()
          };
        });
        showProfileFeedback("Additional details saved.");
      } else if (section === "picture") {
        if (!pictureEditorState) {
          showProfileFeedback("Choose a photo before saving.");
          return;
        }
        showGprecLoader();
        const canvas = document.querySelector("#profilePictureEditorCanvas");
        const dataUrl = canvas.toDataURL("image/png");
        withAccount((p) => {
          p.pictureDataUrl = dataUrl;
          if (!Array.isArray(p.pictureHistory)) p.pictureHistory = [];
          p.pictureHistory.push({ id: `pic-${Date.now()}`, dataUrl });
        });
        setProfilePicture(dataUrl);
        document.querySelector("#profilePictureEditor")?.classList.add("is-hidden");
        document.querySelector("#profilePictureDropzone")?.classList.remove("is-hidden");
        pictureEditorState = null;
        const pictureInput = document.querySelector("#profilePictureInput");
        if (pictureInput) pictureInput.value = "";
        renderPictureGallery();
        showProfileFeedback("Profile picture saved.");
        hideGprecLoader();
      } else if (section === "resume") {
        const file = document.querySelector("#profileResumeInput")?.files[0];
        if (!file) {
          showProfileFeedback("Choose a file before saving.");
          return;
        }
        readFileAsDataUrl(file, "alumni/profile").then((uploaded) => {
          withAccount((p) => {
            p.resume = { name: uploaded.name, dataUrl: uploaded.dataUrl };
          });
          if (resumeStatus) resumeStatus.textContent = `Uploaded: ${uploaded.name}`;
          showProfileFeedback("Resume saved.");
        });
      }
    });
  });

  document.querySelector("#addProfileAchievementButton")?.addEventListener("click", () => {
    const input = document.querySelector("#profileAchievementInput");
    const value = input?.value.trim();
    if (!value) {
      showProfileFeedback("Enter an achievement before adding.");
      return;
    }
    withAccount((p) => {
      if (!Array.isArray(p.achievements)) p.achievements = [];
      p.achievements.push(value);
    });
    profile.achievements = profile.achievements || [];
    profile.achievements.push(value);
    renderAchievements();
    if (input) input.value = "";
    showProfileFeedback("Achievement added.");
  });

  document.querySelector("#profileAchievementsList")?.addEventListener("click", (event) => {
    const button = event.target.closest("[data-remove-achievement]");
    if (!button) return;
    const index = Number(button.dataset.removeAchievement);
    withAccount((p) => {
      if (Array.isArray(p.achievements)) p.achievements.splice(index, 1);
    });
    if (Array.isArray(profile.achievements)) profile.achievements.splice(index, 1);
    renderAchievements();
    showProfileFeedback("Achievement removed.");
  });

  document.querySelector("#profileChangePasswordButton")?.addEventListener("click", () => {
    const accountFeedback = document.querySelector("#profileAccountFeedback");
    const currentPassword = document.querySelector("#profileAccountCurrentPassword")?.value || "";
    const newPassword = document.querySelector("#profileAccountNewPassword")?.value || "";
    const confirmPassword = document.querySelector("#profileAccountConfirmPassword")?.value || "";
    const { account: current, accounts: all } = getCurrentAlumniAccountRecord(email);
    if (!accountFeedback) return;
    if (current.password && current.password !== currentPassword) {
      accountFeedback.textContent = "Current password is incorrect.";
      accountFeedback.classList.remove("success");
      return;
    }
    if (!newPassword || newPassword !== confirmPassword) {
      accountFeedback.textContent = "New password and confirmation must match.";
      accountFeedback.classList.remove("success");
      return;
    }
    current.password = newPassword;
    saveAlumniAccounts(all);
    accountFeedback.textContent = "Password changed successfully.";
    accountFeedback.classList.add("success");
    document.querySelector("#profileAccountCurrentPassword").value = "";
    document.querySelector("#profileAccountNewPassword").value = "";
    document.querySelector("#profileAccountConfirmPassword").value = "";
  });
};

// Alumni Network directory: lists other registered alumni (from gprecAlumniAccounts, the same
// store built up via Edit Profile / Sign Up), surfacing batchmates (same batch year) first.
// Accounts with Profile Visibility set to "private" are excluded from both lists.
const renderAlumniDirectory = (currentEmail) => {
  const batchmatesList = document.querySelector("#alumniBatchmatesList");
  const directoryList = document.querySelector("#alumniDirectoryList");
  if (!batchmatesList && !directoryList) return;

  const { account: current } = getCurrentAlumniAccountRecord(currentEmail);
  const currentBatch = current.profile.education?.batchYear || current.batchYear || "";

  const others = getAlumniAccounts().filter(
    (account) => account.email !== currentEmail && account.profile?.preferences?.visibility !== "private"
  );

  const alumniCardMarkup = (account) => {
    const profile = account.profile || {};
    const basic = profile.basic || {};
    const work = profile.work || {};
    const education = profile.education || {};
    const name = basic.name || account.name || account.email.split("@")[0];
    const batch = education.batchYear || account.batchYear || "-";
    const roleLine = [work.designation, work.company].filter(Boolean).join(" at ") || "Details not shared yet";
    return `
      <li>
        <span><strong>${name}</strong> - Batch ${batch}<br><small>${roleLine}</small></span>
      </li>
    `;
  };

  if (batchmatesList) {
    const batchmates = currentBatch ? others.filter((account) => (account.profile?.education?.batchYear || account.batchYear) === currentBatch) : [];
    batchmatesList.innerHTML = batchmates.length
      ? batchmates.map(alumniCardMarkup).join("")
      : `<p class="portal-note">${currentBatch ? "No other batchmates registered yet." : "Add your batch year in Edit Profile to see batchmate suggestions."}</p>`;
  }

  if (directoryList) {
    directoryList.innerHTML = others.length
      ? others.map(alumniCardMarkup).join("")
      : `<p class="portal-note">No other alumni registered yet.</p>`;
  }
};

// Right-rail widgets on the All Posts feed - Upcoming Events (from getAlumniEvents) and
// Upcoming Birthdays (from each account's dob, respecting the Day of Birth privacy setting:
// "all" or "batchmates" - same batch as the viewer - are shown, "admin" is not).
const renderFeedSidebar = (currentEmail) => {
  const eventsList = document.querySelector("#feedSidebarEvents");
  if (eventsList) {
    const today = new Date();
    today.setHours(0, 0, 0, 0);
    const upcoming = getAlumniEvents()
      .filter((event) => new Date(event.date) >= today)
      .sort((a, b) => new Date(a.date) - new Date(b.date))
      .slice(0, 4);
    eventsList.innerHTML = upcoming.length
      ? upcoming
          .map(
            (event) => `
              <li><strong>${event.title}</strong><span>${new Date(event.date).toLocaleDateString("en-IN", { day: "numeric", month: "short", year: "numeric" })} - ${event.location}</span></li>
            `
          )
          .join("")
      : `<li><span>No upcoming events scheduled.</span></li>`;
  }

  const birthdaysList = document.querySelector("#feedSidebarBirthdays");
  if (birthdaysList) {
    const { account: current } = getCurrentAlumniAccountRecord(currentEmail);
    const currentBatch = current.profile.education?.batchYear || current.batchYear || "";
    const today = new Date();
    today.setHours(0, 0, 0, 0);
    const upcomingBirthdays = getAlumniAccounts()
      .filter((account) => account.profile?.preferences?.visibility !== "private")
      .map((account) => {
        const profile = account.profile || {};
        const basic = profile.basic || {};
        const privacy = profile.preferences?.privacy || {};
        const dob = basic.dob;
        if (!dob) return null;
        const accountBatch = profile.education?.batchYear || account.batchYear || "";
        const dobVisible = privacy.dobDay === "all" || (privacy.dobDay === "batchmates" && currentBatch && accountBatch === currentBatch);
        if (!dobVisible) return null;
        const [, month, day] = dob.split("-").map(Number);
        if (!month || !day) return null;
        let next = new Date(today.getFullYear(), month - 1, day);
        if (next < today) next = new Date(today.getFullYear() + 1, month - 1, day);
        return { name: basic.name || account.name || account.email.split("@")[0], next };
      })
      .filter(Boolean)
      .sort((a, b) => a.next - b.next)
      .slice(0, 4);
    birthdaysList.innerHTML = upcomingBirthdays.length
      ? upcomingBirthdays.map((item) => `<li><strong>${item.name}</strong><span>${item.next.toLocaleDateString("en-IN", { day: "numeric", month: "short" })}</span></li>`).join("")
      : `<li><span>No birthdays shared yet.</span></li>`;
  }
};

// Alumni Funding: contribution flow. Campaigns are admin-editable (added/removed via the
// Media > Alumni Funding Campaigns admin panel); contributions are stored server-side and used
// to compute each campaign's raised total live.
const getFundingCampaigns = () => getSiteContent("fundingCampaigns", []);
const saveFundingCampaigns = (campaigns) => saveSiteContent("fundingCampaigns", campaigns);

const getFundingContributions = () => getGprecDbBootstrap()?.fundingContributions || [];

const recordFundingContribution = (contribution) => gprecDbPost("/funding-contributions", contribution);

const formatInr = (amount) => `₹${Number(amount).toLocaleString("en-IN")}`;

const renderFundingCampaigns = () => {
  const container = document.querySelector("#alumniFundingCampaigns");
  const select = document.querySelector("#fundingCampaignSelect");
  if (!container && !select) return;

  const campaigns = getFundingCampaigns();
  const contributions = getFundingContributions();

  if (container) {
    container.innerHTML = campaigns
      .map((campaign) => {
        const raised = contributions
          .filter((item) => item.campaignId === campaign.id)
          .reduce((sum, item) => sum + Number(item.amount || 0), 0);
        const percent = Math.min(100, Math.round((raised / campaign.goal) * 100));
        return `
          <article class="funding-campaign-card">
            <h3>${campaign.title}</h3>
            <p>${campaign.description}</p>
            <div class="funding-progress-track"><div class="funding-progress-fill" style="width:${percent}%"></div></div>
            <p class="funding-progress-label">${formatInr(raised)} raised of ${formatInr(campaign.goal)} goal (${percent}%)</p>
          </article>
        `;
      })
      .join("");
  }

  if (select) {
    select.innerHTML = campaigns.map((campaign) => `<option value="${campaign.id}">${campaign.title}</option>`).join("");
  }
};

const renderFundingContributors = () => {
  const list = document.querySelector("#fundingContributorsList");
  if (!list) return;
  const contributions = getFundingContributions();
  const campaigns = getFundingCampaigns();
  const accounts = getAlumniAccounts();
  const recent = contributions.slice(-8).reverse();
  list.innerHTML = recent.length
    ? recent
        .map((item) => {
          const campaign = campaigns.find((c) => c.id === item.campaignId);
          const account = accounts.find((acc) => acc.email === item.email);
          const pictureUrl = account?.profile?.pictureDataUrl || "";
          const initials = item.name
            .split(/\s+/)
            .map((part) => part[0])
            .join("")
            .slice(0, 2)
            .toUpperCase();
          const avatarHtml = pictureUrl
            ? `<img src="${pictureUrl}" alt="${item.name}" class="funding-contributor-avatar">`
            : `<span class="funding-contributor-avatar funding-contributor-initials">${initials}</span>`;
          return `
            <li class="funding-contributor-row">
              ${avatarHtml}
              <span><strong>${item.name}</strong> contributed ${formatInr(item.amount)} to ${campaign?.title || "a campaign"}<br><small>${item.date ? formatRelativeDate(item.date) : ""}</small></span>
            </li>
          `;
        })
        .join("")
    : `<li><span>No contributions yet. Be the first to contribute.</span></li>`;
};

const fundingCampaignManagerBody = document.querySelector("#fundingCampaignManagerBody");
if (fundingCampaignManagerBody) {
  const fundingCampaignTitleInput = document.querySelector("#fundingCampaignTitleInput");
  const fundingCampaignGoalInput = document.querySelector("#fundingCampaignGoalInput");
  const fundingCampaignDescriptionInput = document.querySelector("#fundingCampaignDescriptionInput");
  const addFundingCampaignButton = document.querySelector("#addFundingCampaignButton");
  const fundingCampaignAddFeedback = document.querySelector("#fundingCampaignAddFeedback");
  const fundingCampaignManagerEmpty = document.querySelector("#fundingCampaignManagerEmpty");

  const renderFundingCampaignManager = () => {
    const campaigns = getFundingCampaigns();
    const contributions = getFundingContributions();
    fundingCampaignManagerBody.innerHTML = campaigns
      .map((campaign) => {
        const raised = contributions
          .filter((item) => item.campaignId === campaign.id)
          .reduce((sum, item) => sum + Number(item.amount || 0), 0);
        return `
          <tr>
            <td>${escapeHtml(campaign.title)}</td>
            <td>${formatInr(campaign.goal)}</td>
            <td>${formatInr(raised)}</td>
            <td><button type="button" class="icon-btn-delete" data-funding-campaign-remove="${campaign.id}" aria-label="Remove campaign">${deleteIconSvg}</button></td>
          </tr>`;
      })
      .join("");
    if (fundingCampaignManagerEmpty) fundingCampaignManagerEmpty.classList.toggle("is-hidden", campaigns.length > 0);
  };
  renderFundingCampaignManager();

  fundingCampaignManagerBody.addEventListener("click", (event) => {
    const removeButton = event.target.closest("[data-funding-campaign-remove]");
    if (!removeButton) return;
    const campaigns = getFundingCampaigns().filter((item) => item.id !== removeButton.dataset.fundingCampaignRemove);
    saveFundingCampaigns(campaigns);
    renderFundingCampaignManager();
    renderFundingCampaigns();
  });

  addFundingCampaignButton?.addEventListener("click", () => {
    const title = fundingCampaignTitleInput?.value.trim();
    const goal = Number(fundingCampaignGoalInput?.value);
    const description = fundingCampaignDescriptionInput?.value.trim();
    if (!title || !goal || goal <= 0 || !description) {
      if (fundingCampaignAddFeedback) {
        fundingCampaignAddFeedback.textContent = "Enter a title, description, and a goal amount above 0.";
        fundingCampaignAddFeedback.classList.remove("success");
      }
      return;
    }
    const campaigns = getFundingCampaigns();
    campaigns.push({ id: `fund-${Date.now()}`, title, description, goal });
    saveFundingCampaigns(campaigns);
    renderFundingCampaignManager();
    renderFundingCampaigns();
    if (fundingCampaignTitleInput) fundingCampaignTitleInput.value = "";
    if (fundingCampaignGoalInput) fundingCampaignGoalInput.value = "";
    if (fundingCampaignDescriptionInput) fundingCampaignDescriptionInput.value = "";
    if (fundingCampaignAddFeedback) {
      fundingCampaignAddFeedback.textContent = `"${title}" added to Alumni Funding Campaigns.`;
      fundingCampaignAddFeedback.classList.add("success");
    }
  });
}

const spotlightPosterManagerBody = document.querySelector("#spotlightPosterManagerBody");
if (spotlightPosterManagerBody) {
  const spotlightPosterTitleInput = document.querySelector("#spotlightPosterTitleInput");
  const spotlightPosterTypeInput = document.querySelector("#spotlightPosterTypeInput");
  const spotlightPosterImageInput = document.querySelector("#spotlightPosterImageInput");
  const spotlightPosterLinkInput = document.querySelector("#spotlightPosterLinkInput");
  const addSpotlightPosterButton = document.querySelector("#addSpotlightPosterButton");
  const spotlightPosterAddFeedback = document.querySelector("#spotlightPosterAddFeedback");
  const spotlightPosterManagerEmpty = document.querySelector("#spotlightPosterManagerEmpty");
  const spotlightPosterVisitorLoginInput = document.querySelector("#spotlightPosterVisitorLoginInput");
  const spotlightPosterDashboardInput = document.querySelector("#spotlightPosterDashboardInput");
  const spotlightPosterPublicInput = document.querySelector("#spotlightPosterPublicInput");
  const spotlightPosterMaxVisibleInput = document.querySelector("#spotlightPosterMaxVisibleInput");
  const saveSpotlightPosterSettingsButton = document.querySelector("#saveSpotlightPosterSettingsButton");
  const spotlightPosterSettingsFeedback = document.querySelector("#spotlightPosterSettingsFeedback");

  const renderSpotlightPosterManager = () => {
    const posters = getSpotlightPosters();
    spotlightPosterManagerEmpty?.classList.toggle("is-hidden", posters.length > 0);
    spotlightPosterManagerBody.innerHTML = posters
      .map(
        (poster) => `
          <tr>
            <td><img src="${poster.imageUrl}" alt="" class="site-photo-thumb"></td>
            <td>${escapeHtml(poster.title)}</td>
            <td>${escapeHtml(poster.type || "Poster")}</td>
            <td><button type="button" class="icon-btn-delete" data-spotlight-poster-remove="${escapeHtml(poster.id)}" aria-label="Remove poster">${deleteIconSvg}</button></td>
          </tr>`
      )
      .join("");
  };
  const renderSpotlightPosterSettings = () => {
    const settings = getSpotlightPosterSettings();
    if (spotlightPosterVisitorLoginInput) spotlightPosterVisitorLoginInput.checked = settings.showVisitorLogin;
    if (spotlightPosterDashboardInput) spotlightPosterDashboardInput.checked = settings.showDashboardSpotlight;
    if (spotlightPosterPublicInput) spotlightPosterPublicInput.checked = settings.showPublicSpotlight;
    if (spotlightPosterMaxVisibleInput) spotlightPosterMaxVisibleInput.value = settings.maxVisible;
  };
  renderSpotlightPosterManager();
  renderSpotlightPosterSettings();

  spotlightPosterManagerBody.addEventListener("click", (event) => {
    const removeButton = event.target.closest("[data-spotlight-poster-remove]");
    if (!removeButton) return;
    const posters = getSpotlightPosters().filter((item) => item.id !== removeButton.dataset.spotlightPosterRemove);
    saveSpotlightPosters(posters);
    renderSpotlightPosterManager();
    renderSpotlightPosters();
  });

  addSpotlightPosterButton?.addEventListener("click", async () => {
    if ((localStorage.getItem("gprecAdminRole") || "College Admin") !== "College Admin") {
      if (spotlightPosterAddFeedback) {
        spotlightPosterAddFeedback.textContent = "Only the College Admin role can add posters and advertisements.";
        spotlightPosterAddFeedback.classList.remove("success");
      }
      return;
    }
    const title = spotlightPosterTitleInput?.value.trim();
    const type = spotlightPosterTypeInput?.value || "Event Poster";
    const link = spotlightPosterLinkInput?.value.trim() || "";
    const file = spotlightPosterImageInput?.files[0];
    if (!title || !file) {
      if (spotlightPosterAddFeedback) {
        spotlightPosterAddFeedback.textContent = "Enter a title and choose a poster image before adding.";
        spotlightPosterAddFeedback.classList.remove("success");
      }
      return;
    }
    try {
      const uploaded = await readFileAsDataUrl(file, "media/spotlight-posters");
      const posters = getSpotlightPosters();
      posters.push({ id: `poster-${Date.now()}`, title, type, link, imageUrl: uploaded.dataUrl });
      saveSpotlightPosters(posters);
      renderSpotlightPosterManager();
      renderSpotlightPosters();
      if (spotlightPosterTitleInput) spotlightPosterTitleInput.value = "";
      if (spotlightPosterLinkInput) spotlightPosterLinkInput.value = "";
      if (spotlightPosterImageInput) spotlightPosterImageInput.value = "";
      if (spotlightPosterAddFeedback) {
        spotlightPosterAddFeedback.textContent = `"${title}" added to Spotlight.`;
        spotlightPosterAddFeedback.classList.add("success");
      }
    } catch {
      if (spotlightPosterAddFeedback) {
        spotlightPosterAddFeedback.textContent = "Could not read that image file. Try a different image.";
        spotlightPosterAddFeedback.classList.remove("success");
      }
    }
  });

  saveSpotlightPosterSettingsButton?.addEventListener("click", () => {
    if ((localStorage.getItem("gprecAdminRole") || "College Admin") !== "College Admin") {
      if (spotlightPosterSettingsFeedback) {
        spotlightPosterSettingsFeedback.textContent = "Only the College Admin role can change poster display settings.";
        spotlightPosterSettingsFeedback.classList.remove("success");
      }
      return;
    }
    const maxVisible = Number(spotlightPosterMaxVisibleInput?.value || defaultSpotlightPosterSettings.maxVisible);
    saveSpotlightPosterSettings({
      showVisitorLogin: Boolean(spotlightPosterVisitorLoginInput?.checked),
      showDashboardSpotlight: Boolean(spotlightPosterDashboardInput?.checked),
      showPublicSpotlight: Boolean(spotlightPosterPublicInput?.checked),
      maxVisible: Number.isFinite(maxVisible) ? Math.min(12, Math.max(1, Math.round(maxVisible))) : defaultSpotlightPosterSettings.maxVisible
    });
    renderSpotlightPosterSettings();
    renderSpotlightPosters();
    if (spotlightPosterSettingsFeedback) {
      spotlightPosterSettingsFeedback.textContent = "Poster display settings saved.";
      spotlightPosterSettingsFeedback.classList.add("success");
    }
  });
}

// Photo & Video Albums: a small LinkedIn-style feed - albums group "memory" posts, each post
// supports Like, Comment, and Share. Same JSONB-blob-per-record, read-all/mutate-one/save-all
// pattern as getProjects/getResearch - see replace_student_submissions in portal_db_server.py.
const getAlumniAlbums = () => getGprecDbBootstrap()?.alumniAlbums || [];
const saveAlumniAlbums = (albums) => gprecDbPost("/alumni-albums", albums);

const getAlumniMemories = () => getGprecDbBootstrap()?.alumniMemories || [];
const saveAlumniMemories = (memories) => gprecDbPost("/alumni-memories", memories);

const formatRelativeDate = (timestamp) =>
  new Date(timestamp).toLocaleDateString("en-IN", { day: "numeric", month: "short", year: "numeric" });

// Alumni Events: reunions/meetups/webinars with RSVP. Alumni can create events (like albums)
// and toggle "Going" on any event; the attendee list and count are computed from RSVPs live.
const getAlumniEvents = () => getSiteContent("alumniEvents", []);
const saveAlumniEvents = (events) => saveSiteContent("alumniEvents", events);

const getEventRsvps = () => getGprecDbBootstrap()?.alumniEventRsvps || [];
// RSVPs have no natural id of their own (keyed by eventId+email in the UI) - synthesize one here
// so they fit the same JSONB-blob-per-record save pattern as albums/memories/projects.
const saveEventRsvps = (rsvps) => gprecDbPost("/alumni-event-rsvps", rsvps.map((rsvp) => ({ id: `${rsvp.eventId}:${rsvp.email}`, ...rsvp })));

const initAlumniEvents = (currentEmail) => {
  const renderEvents = () => {
    const list = document.querySelector("#alumniEventList");
    if (!list) return;
    const events = [...getAlumniEvents()].sort((a, b) => new Date(a.date) - new Date(b.date));
    const rsvps = getEventRsvps();

    list.innerHTML = events.length
      ? events
          .map((event) => {
            const attendees = rsvps.filter((rsvp) => rsvp.eventId === event.id);
            const isGoing = attendees.some((rsvp) => rsvp.email === currentEmail);
            const dateLabel = event.date
              ? new Date(event.date).toLocaleDateString("en-IN", { day: "numeric", month: "short", year: "numeric" })
              : "Date TBA";
            return `
          <article class="alumni-event-card">
            <div class="alumni-event-head">
              <h3>${event.title}</h3>
              <span class="alumni-event-meta">${dateLabel} · ${event.location || "Location TBA"}</span>
            </div>
            <p>${event.description || ""}</p>
            <div class="alumni-event-footer">
              <span class="alumni-event-attendees">${attendees.length} going${attendees.length ? ": " + attendees.map((rsvp) => rsvp.name).join(", ") : ""}</span>
              <div class="alumni-rsvp-actions">
                ${
                  isGoing
                    ? `<span class="alumni-rsvp-button is-going" aria-hidden="true">Going ✓</span>
                <button type="button" class="alumni-rsvp-decline-button" data-rsvp-decline="${event.id}">Decline</button>`
                    : `<button type="button" class="alumni-rsvp-button" data-rsvp-event="${event.id}">RSVP - I'm Going</button>`
                }
              </div>
            </div>
          </article>
        `;
          })
          .join("")
      : `<p class="portal-note">No events yet. Create one above.</p>`;
  };

  document.querySelector("#createEventButton")?.addEventListener("click", () => {
    const title = document.querySelector("#eventTitleInput")?.value.trim();
    const date = document.querySelector("#eventDateInput")?.value;
    const location = document.querySelector("#eventLocationInput")?.value.trim();
    const description = document.querySelector("#eventDescriptionInput")?.value.trim();
    const feedback = document.querySelector("#eventFeedback");
    if (!title || !date) {
      if (feedback) {
        feedback.textContent = "Enter an event title and date.";
        feedback.classList.remove("success");
      }
      return;
    }
    const events = getAlumniEvents();
    events.push({ id: `event-${Date.now()}`, title, date, location, description, createdBy: currentEmail });
    saveAlumniEvents(events);
    renderEvents();
    ["#eventTitleInput", "#eventDateInput", "#eventLocationInput", "#eventDescriptionInput"].forEach((selector) => {
      const input = document.querySelector(selector);
      if (input) input.value = "";
    });
    if (feedback) {
      feedback.textContent = `Event "${title}" created.`;
      feedback.classList.add("success");
    }
  });

  document.querySelector("#alumniEventList")?.addEventListener("click", (event) => {
    const goingButton = event.target.closest("[data-rsvp-event]");
    const declineButton = event.target.closest("[data-rsvp-decline]");
    const button = goingButton || declineButton;
    if (!button) return;
    const eventId = goingButton ? goingButton.dataset.rsvpEvent : declineButton.dataset.rsvpDecline;
    const rsvps = getEventRsvps();
    const existingIndex = rsvps.findIndex((rsvp) => rsvp.eventId === eventId && rsvp.email === currentEmail);
    if (declineButton) {
      if (existingIndex > -1) rsvps.splice(existingIndex, 1);
    } else if (existingIndex > -1) {
      rsvps.splice(existingIndex, 1);
    } else {
      const { account } = getCurrentAlumniAccountRecord(currentEmail);
      const name = account.profile.basic?.name || account.name || currentEmail.split("@")[0];
      rsvps.push({ eventId, email: currentEmail, name });
    }
    saveEventRsvps(rsvps);
    renderEvents();
  });

  renderEvents();
};

const initAlumniGallery = (currentEmail) => {
  let activeAlbumId = null;
  let editingAlbumId = null;
  let showAddMemoryForm = false;
  let editingMemoryId = null;
  let editMemoryStagedFiles = [];
  let editMemoryRemainingUrls = [];
  let editAlbumRemainingPhotoUrls = [];
  let editAlbumRemainingVideoUrls = [];
  const albumThumbIndex = {};
  const postMediaIndex = {};

  const renderAlbumList = () => {
    const container = document.querySelector("#alumniAlbumList");
    if (!container) return;
    const albums = getAlumniAlbums();
    const memories = getAlumniMemories();
    container.innerHTML = albums.length
      ? albums
          .map((album) => {
            const albumMemories = memories.filter((memory) => memory.albumId === album.id);
            const isOwner = album.createdBy === currentEmail;

            // Counts individual photos/videos, not post records - a single post can bundle
            // several files (e.g. 2 photos added together still count as 2, not 1). Photos and
            // videos (whether YouTube links or uploaded video files) are counted separately so
            // the label can say "photos" or "videos" instead of always "photos/videos".
            const photoItems = albumMemories.flatMap((memory) =>
              memory.type === "photo" ? memory.mediaDataUrls || (memory.mediaDataUrl ? [memory.mediaDataUrl] : []) : []
            );
            const videoItems = albumMemories.flatMap((memory) =>
              memory.type === "video"
                ? (memory.videoIds || (memory.videoId ? [memory.videoId] : [])).map((videoId) => `https://img.youtube.com/vi/${videoId}/hqdefault.jpg`)
                : memory.type === "videofile"
                ? memory.mediaDataUrls || (memory.mediaDataUrl ? [memory.mediaDataUrl] : [])
                : []
            );
            const allMediaItems = [...photoItems, ...videoItems];
            // Shown as separate counts when an album has both, e.g. "2 photos, 1 video",
            // instead of a combined number with a generic "photos/videos" label.
            const countText =
              photoItems.length && videoItems.length
                ? `${photoItems.length} ${photoItems.length === 1 ? "photo" : "photos"}, ${videoItems.length} ${videoItems.length === 1 ? "video" : "videos"}`
                : videoItems.length
                ? `${videoItems.length} ${videoItems.length === 1 ? "video" : "videos"}`
                : `${photoItems.length} ${photoItems.length === 1 ? "photo" : "photos"}`;
            // Up to 5 preview thumbnails per album, browsable via dots without opening the album.
            const thumbSources = allMediaItems.slice(0, 5);
            const currentIndex = Math.min(albumThumbIndex[album.id] || 0, Math.max(thumbSources.length - 1, 0));
            const thumbUrl = thumbSources[currentIndex] || "";
            const dotsHtml =
              thumbSources.length > 1
                ? `<div class="alumni-album-thumb-dots">${thumbSources
                    .map((_, index) => `<span class="alumni-album-thumb-dot${index === currentIndex ? " is-active" : ""}" data-thumb-dot="${album.id}:${index}"></span>`)
                    .join("")}</div>`
                : "";

            return `
          <div class="alumni-album-card${album.id === activeAlbumId ? " is-active" : ""}${album.id === editingAlbumId ? " is-editing" : ""}">
            <div data-album-select="${album.id}">
              <div class="alumni-album-thumb" style="${thumbUrl ? `background-image:url('${thumbUrl}')` : ""}">${dotsHtml}</div>
              <div class="alumni-album-caption">
                <strong>${album.name}</strong>
                <small>${countText}</small>
              </div>
            </div>
            ${
              isOwner
                ? `<div class="alumni-album-actions">
                    <span class="alumni-album-action alumni-album-edit" data-edit-album="${album.id}" title="Edit album">${editIconSvg}</span>
                    <span class="alumni-album-action alumni-album-delete" data-delete-album="${album.id}" title="Delete album">${deleteIconSvg}</span>
                  </div>`
                : ""
            }
          </div>
        `;
          })
          .join("")
      : `<p class="portal-note">No albums yet. Create one above to start adding memories.</p>`;
  };

  // Builds one post card (or its inline edit form) - shared by the per-album Memories view
  // and the cross-album "All Posts" feed, so both stay in sync with one implementation.
  const renderMemoryCard = (memory, { showAlbumTag = false } = {}) => {
    const isOwner = memory.authorEmail === currentEmail;

    if (isOwner && memory.id === editingMemoryId) {
      if (memory.type === "video") {
        const links = (memory.videoIds || (memory.videoId ? [memory.videoId] : [])).map((id) => `https://youtu.be/${id}`).join("\n");
        return `
          <article class="alumni-post-card is-editing" data-memory-id="${memory.id}">
            <label>Caption<input type="text" id="editMemoryCaption-${memory.id}" value="${memory.caption.replace(/"/g, "&quot;")}"></label>
            <label>YouTube URL(s) - one per line<textarea id="editMemoryVideoInput-${memory.id}">${links}</textarea></label>
            <div class="alumni-album-actions-static">
              <button type="button" class="alumni-album-save" data-save-memory="${memory.id}">Save</button>
              <button type="button" class="alumni-album-cancel" data-cancel-memory-edit="true">Cancel</button>
            </div>
          </article>
        `;
      }

      const remainingHtml = editMemoryRemainingUrls
        .map(
          (url, index) => `
          <div class="memory-staging-item">
            ${memory.type === "videofile" ? `<video src="${url}"></video>` : `<img src="${url}">`}
            <span class="memory-staging-remove" data-remove-existing-media="${memory.id}:${index}">&times;</span>
          </div>
        `
        )
        .join("");
      const stagedHtml = editMemoryStagedFiles
        .map(
          (file, index) => `
          <div class="memory-staging-item">
            ${memory.type === "videofile" ? `<video src="${URL.createObjectURL(file)}"></video>` : `<img src="${URL.createObjectURL(file)}">`}
            <span class="memory-staging-remove" data-remove-staged-media="${index}">&times;</span>
          </div>
        `
        )
        .join("");
      return `
        <article class="alumni-post-card is-editing" data-memory-id="${memory.id}">
          <label>Caption<input type="text" id="editMemoryCaption-${memory.id}" value="${memory.caption.replace(/"/g, "&quot;")}"></label>
          <div class="memory-staging-row" id="editMemoryStaging-${memory.id}">
            ${remainingHtml}${stagedHtml}
            <button type="button" class="memory-add-tile" data-edit-add-media="${memory.id}">+<span>Add</span></button>
          </div>
          <input type="file" accept="${memory.type === "videofile" ? "video/*" : "image/*"}" id="editMemoryFileInput-${memory.id}" class="is-hidden" multiple>
          <div class="alumni-album-actions-static">
            <button type="button" class="alumni-album-save" data-save-memory="${memory.id}">Save</button>
            <button type="button" class="alumni-album-cancel" data-cancel-memory-edit="true">Cancel</button>
          </div>
        </article>
      `;
    }

    const liked = (memory.likes || []).includes(currentEmail);
    // Normalizes both the new grouped shape (mediaDataUrls/videoIds arrays - all files
    // added together in one submission) and the older single-item shape, so a post can
    // show every photo/video that belongs to it instead of splitting into separate posts.
    const mediaItems =
      memory.type === "video"
        ? (memory.videoIds || (memory.videoId ? [memory.videoId] : [])).map(
            (videoId) => `<iframe src="https://www.youtube.com/embed/${videoId}" title="${memory.caption}" allowfullscreen></iframe>`
          )
        : (memory.mediaDataUrls || (memory.mediaDataUrl ? [memory.mediaDataUrl] : [])).map((url) =>
            memory.type === "videofile" ? `<video src="${url}" controls></video>` : `<img src="${url}" alt="${memory.caption}">`
          );
    // Instagram-style: multi-photo/video posts show one item at a time with dot
    // indicators underneath, instead of a static grid of every photo at once.
    const currentMediaIndex = Math.min(postMediaIndex[memory.id] || 0, mediaItems.length - 1);
    const mediaDotsHtml =
      mediaItems.length > 1
        ? `<div class="alumni-post-media-dots">${mediaItems
            .map((_, index) => `<span class="alumni-post-media-dot${index === currentMediaIndex ? " is-active" : ""}" data-post-media-dot="${memory.id}:${index}"></span>`)
            .join("")}</div>`
        : "";
    const carouselArrowsHtml =
      mediaItems.length > 1
        ? `<span class="alumni-post-media-arrow alumni-post-media-prev" data-post-media-prev="${memory.id}">&#10094;</span>
           <span class="alumni-post-media-arrow alumni-post-media-next" data-post-media-next="${memory.id}">&#10095;</span>`
        : "";
    const mediaHtml = `<div class="alumni-post-media-carousel">${mediaItems[currentMediaIndex] || ""}${carouselArrowsHtml}${mediaDotsHtml}</div>`;
    const commentsHtml = (memory.comments || [])
      .map((comment) => `<div class="alumni-comment"><strong>${comment.author}</strong><span>${comment.text}</span></div>`)
      .join("");
    const albumTagHtml = showAlbumTag
      ? (() => {
          const album = getAlumniAlbums().find((item) => item.id === memory.albumId);
          return album ? `<span class="batchmate-tag">${album.name}</span>` : "";
        })()
      : "";
    const authorAccount = getAlumniAccounts().find((item) => item.email === memory.authorEmail);
    const authorPictureUrl = authorAccount?.profile?.pictureDataUrl || "";
    const authorInitials = memory.author
      .split(/\s+/)
      .map((part) => part[0])
      .join("")
      .slice(0, 2)
      .toUpperCase();
    const avatarHtml = authorPictureUrl
      ? `<img src="${authorPictureUrl}" alt="${memory.author}" class="alumni-post-avatar">`
      : `<span class="alumni-post-avatar">${authorInitials}</span>`;
    return `
      <article class="alumni-post-card" data-memory-id="${memory.id}">
        <div class="alumni-post-head">
          ${avatarHtml}
          <div class="alumni-post-head-info">
            <strong>${memory.author}</strong>
            <span>${
              memory.scheduledAt && memory.scheduledAt > Date.now()
                ? `Scheduled for ${new Date(memory.scheduledAt).toLocaleString("en-US", { month: "short", day: "numeric", hour: "numeric", minute: "2-digit" })}`
                : formatRelativeDate(memory.createdAt)
            }</span>
          </div>
        </div>
        ${albumTagHtml}
        <p class="alumni-post-caption">${memory.caption}</p>
        ${mediaHtml}
        <div class="alumni-post-actions">
          <button type="button" class="${liked ? "is-liked" : ""}" data-like-memory="${memory.id}">${likeIconSvg} Like${memory.likes?.length ? ` (${memory.likes.length})` : ""}</button>
          <button type="button" data-toggle-comments="${memory.id}">${commentIconSvg} Comment${memory.comments?.length ? ` (${memory.comments.length})` : ""}</button>
          <div class="alumni-share-wrap">
            <button type="button" data-toggle-share="${memory.id}">${shareIconSvg} Share</button>
            <div class="alumni-share-menu is-hidden" id="share-menu-${memory.id}">
              <button type="button" data-copy-link="${memory.id}">Copy Link</button>
              <button type="button" data-share-whatsapp="${memory.id}">Share via WhatsApp</button>
              <button type="button" data-share-email="${memory.id}">Share via Email</button>
            </div>
          </div>
          ${isOwner ? `<button type="button" data-edit-memory="${memory.id}">${editIconSvg} Edit</button>` : ""}
          ${isOwner ? `<button type="button" data-delete-memory="${memory.id}">${deleteIconSvg} Delete</button>` : ""}
        </div>
        <div class="alumni-post-comments is-hidden" id="comments-${memory.id}">
          <div class="alumni-comment-list">${commentsHtml || "<p class=\"portal-note\">No comments yet.</p>"}</div>
          <div class="alumni-comment-add">
            <input type="text" placeholder="Write a comment..." data-comment-input="${memory.id}">
            <button type="button" data-post-comment="${memory.id}">Post</button>
          </div>
        </div>
      </article>
    `;
  };

  // Post visibility ("Anyone" / "Batchmates Only" / "Only Me", set from the composer) plus
  // Schedule Post - a scheduled post stays invisible to everyone but its author until its
  // scheduled time has passed. The author always sees their own posts regardless of either.
  const isMemoryVisibleTo = (memory, viewerEmail) => {
    if (memory.authorEmail === viewerEmail) return true;
    if (memory.scheduledAt && memory.scheduledAt > Date.now()) return false;
    const visibility = memory.visibility || "all";
    if (visibility === "onlyme") return false;
    if (visibility === "batchmates") {
      const { account: viewer } = getCurrentAlumniAccountRecord(viewerEmail);
      const viewerBatch = viewer.profile.education?.batchYear || viewer.batchYear || "";
      const author = getAlumniAccounts().find((item) => item.email === memory.authorEmail);
      const authorBatch = author?.profile?.education?.batchYear || author?.batchYear || "";
      return Boolean(viewerBatch) && viewerBatch === authorBatch;
    }
    return true;
  };

  const renderAllPostsFeed = () => {
    const grid = document.querySelector("#alumniFeedGrid");
    if (!grid) return;
    const memories = getAlumniMemories()
      .filter((memory) => isMemoryVisibleTo(memory, currentEmail))
      .sort((a, b) => b.createdAt - a.createdAt);
    grid.innerHTML = memories.length
      ? memories.map((memory) => renderMemoryCard(memory, { showAlbumTag: true })).join("")
      : `<p class="portal-note">No posts yet. Add photos or videos to an album to see them here.</p>`;
  };

  const renderMemories = () => {
    const grid = document.querySelector("#alumniMemoriesGrid");
    const formWrap = document.querySelector("#alumniMemoryFormWrap");
    const heading = document.querySelector("#memoriesHeading");
    renderAllPostsFeed();
    if (!grid) return;

    if (!activeAlbumId) {
      grid.innerHTML = `<p class="portal-note">Select an album above to view its memories.</p>`;
      formWrap?.classList.add("is-hidden");
      if (heading) heading.textContent = "Memories";
      return;
    }

    // Selecting an album (clicking its tile) only opens it for viewing - the Add Memory
    // form only opens via the album's Edit button, not by clicking the album itself.
    const album = getAlumniAlbums().find((item) => item.id === activeAlbumId);
    if (heading) heading.textContent = album ? `Memories - ${album.name}` : "Memories";
    formWrap?.classList.toggle("is-hidden", !showAddMemoryForm);
    const activeAlbumName = document.querySelector("#activeAlbumName");
    if (activeAlbumName) activeAlbumName.textContent = album?.name || "-";

    const memories = getAlumniMemories()
      .filter((memory) => memory.albumId === activeAlbumId && isMemoryVisibleTo(memory, currentEmail))
      .sort((a, b) => b.createdAt - a.createdAt);

    grid.innerHTML = memories.length
      ? memories.map((memory) => renderMemoryCard(memory)).join("")
      : `<p class="portal-note">No memories in this album yet. Add the first one above.</p>`;
  };

  document.querySelector("#createAlbumButton")?.addEventListener("click", async () => {
    const name = document.querySelector("#albumNameInput")?.value.trim();
    const description = document.querySelector("#albumDescriptionInput")?.value.trim();
    const feedback = document.querySelector("#albumFeedback");
    if (!name) {
      if (feedback) {
        feedback.textContent = "Enter an album name.";
        feedback.classList.remove("success");
      }
      return;
    }

    const isEditing = Boolean(editingAlbumId);
    const albums = getAlumniAlbums();
    let album;
    if (isEditing) {
      album = albums.find((item) => item.id === editingAlbumId);
      if (!album) return;
      album.name = name;
      album.description = description;
    } else {
      album = { id: `album-${Date.now()}`, name, description, createdBy: currentEmail, createdAt: Date.now() };
      albums.push(album);
    }
    saveAlumniAlbums(albums);

    // Photos/videos on this form become (or update) the album's photo/video memory post -
    // whether creating a new album or editing an existing one uses the same save logic.
    const { account } = getCurrentAlumniAccountRecord(currentEmail);
    const authorName = account.profile.basic?.name || account.name || currentEmail.split("@")[0];
    const caption = description || name;

    const uploadStaged = async (files) => {
      const urls = [];
      for (const file of files) {
        const uploaded = await readFileAsDataUrl(file, "alumni/albums");
        urls.push(uploaded.dataUrl);
      }
      return urls;
    };

    const finalPhotoUrls = [...editAlbumRemainingPhotoUrls, ...(await uploadStaged(stagedAlbumPhotoFiles))];
    const finalVideoUrls = [...editAlbumRemainingVideoUrls, ...(await uploadStaged(stagedAlbumVideoFiles))];

    let memories = getAlumniMemories();
    const photoMemory = memories.find((item) => item.albumId === album.id && item.type === "photo");
    if (finalPhotoUrls.length) {
      if (photoMemory) photoMemory.mediaDataUrls = finalPhotoUrls;
      else
        memories.push({
          id: `memory-${Date.now()}-${Math.random().toString(36).slice(2, 7)}`,
          albumId: album.id,
          type: "photo",
          caption,
          author: authorName,
          authorEmail: currentEmail,
          createdAt: Date.now(),
          likes: [],
          comments: [],
          mediaDataUrls: finalPhotoUrls
        });
    } else if (photoMemory) {
      memories = memories.filter((item) => item.id !== photoMemory.id);
    }

    const videoMemory = memories.find((item) => item.albumId === album.id && item.type === "videofile");
    if (finalVideoUrls.length) {
      if (videoMemory) videoMemory.mediaDataUrls = finalVideoUrls;
      else
        memories.push({
          id: `memory-${Date.now()}-${Math.random().toString(36).slice(2, 7)}-v`,
          albumId: album.id,
          type: "videofile",
          caption,
          author: authorName,
          authorEmail: currentEmail,
          createdAt: Date.now(),
          likes: [],
          comments: [],
          mediaDataUrls: finalVideoUrls
        });
    } else if (videoMemory) {
      memories = memories.filter((item) => item.id !== videoMemory.id);
    }

    saveAlumniMemories(memories);

    activeAlbumId = album.id;
    showAddMemoryForm = false;
    resetAlbumForm();
    renderAlbumList();
    renderMemories();
    if (feedback) {
      feedback.textContent = isEditing ? `Album "${name}" updated.` : `Album "${name}" created.`;
      feedback.classList.add("success");
    }
  });

  document.querySelector("#cancelAlbumEditButton")?.addEventListener("click", () => {
    resetAlbumForm();
    renderAlbumList();
  });

  document.querySelector("#alumniAlbumList")?.addEventListener("click", (event) => {
    const thumbDot = event.target.closest("[data-thumb-dot]");
    if (thumbDot) {
      event.stopPropagation();
      const [albumId, index] = thumbDot.dataset.thumbDot.split(":");
      albumThumbIndex[albumId] = Number(index);
      renderAlbumList();
      return;
    }
    const editButton = event.target.closest("[data-edit-album]");
    if (editButton) {
      enterAlbumEditMode(editButton.dataset.editAlbum);
      return;
    }
    const deleteButton = event.target.closest("[data-delete-album]");
    if (deleteButton) {
      const albumId = deleteButton.dataset.deleteAlbum;
      saveAlumniAlbums(getAlumniAlbums().filter((album) => album.id !== albumId));
      saveAlumniMemories(getAlumniMemories().filter((memory) => memory.albumId !== albumId));
      if (activeAlbumId === albumId) activeAlbumId = null;
      if (editingAlbumId === albumId) resetAlbumForm();
      renderAlbumList();
      renderMemories();
      return;
    }
    const button = event.target.closest("[data-album-select]");
    if (!button) return;
    activeAlbumId = button.dataset.albumSelect;
    showAddMemoryForm = false;
    renderAlbumList();
    renderMemories();
  });

  // "Add one by one" photo/video staging: each file chosen via the "+" tile is appended to a
  // pending list shown as thumbnails (with its own remove button), rather than committed
  // immediately - "Add Memory" submits every staged file at once, one post per file.
  const stagedPhotoFiles = [];
  const stagedVideoFiles = [];

  const renderStagingRow = (containerId, files, tag) => {
    const container = document.querySelector(containerId);
    if (!container) return;
    const thumbs = files
      .map((file, index) => {
        const url = URL.createObjectURL(file);
        return `
          <div class="memory-staging-item">
            <${tag} src="${url}"></${tag}>
            <span class="memory-staging-remove" data-staging-remove="${index}">&times;</span>
          </div>
        `;
      })
      .join("");
    container.innerHTML = `${thumbs}<button type="button" class="memory-add-tile" data-staging-add="true">+<span>Add ${tag === "video" ? "Video" : "Photo"}</span></button>`;
  };

  const renderPhotoStaging = () => renderStagingRow("#memoryPhotoStaging", stagedPhotoFiles, "img");
  const renderVideoFileStaging = () => renderStagingRow("#memoryVideoFileStaging", stagedVideoFiles, "video");

  document.querySelector("#memoryPhotoStaging")?.addEventListener("click", (event) => {
    if (event.target.closest("[data-staging-add]")) {
      document.querySelector("#memoryPhotoInput")?.click();
      return;
    }
    const removeButton = event.target.closest("[data-staging-remove]");
    if (removeButton) {
      stagedPhotoFiles.splice(Number(removeButton.dataset.stagingRemove), 1);
      renderPhotoStaging();
    }
  });

  document.querySelector("#memoryPhotoInput")?.addEventListener("change", (event) => {
    stagedPhotoFiles.push(...Array.from(event.target.files || []));
    event.target.value = "";
    renderPhotoStaging();
  });

  document.querySelector("#memoryVideoFileStaging")?.addEventListener("click", (event) => {
    if (event.target.closest("[data-staging-add]")) {
      document.querySelector("#memoryVideoFileInput")?.click();
      return;
    }
    const removeButton = event.target.closest("[data-staging-remove]");
    if (removeButton) {
      stagedVideoFiles.splice(Number(removeButton.dataset.stagingRemove), 1);
      renderVideoFileStaging();
    }
  });

  document.querySelector("#memoryVideoFileInput")?.addEventListener("change", (event) => {
    stagedVideoFiles.push(...Array.from(event.target.files || []));
    event.target.value = "";
    renderVideoFileStaging();
  });

  renderPhotoStaging();
  renderVideoFileStaging();

  // Same staging pattern, but for photos/videos on the Create/Edit Album form - this form
  // doubles as both: creating an album attaches its first memory, editing an album shows its
  // existing photos/videos (editAlbumRemaining*Urls) alongside anything newly staged, and
  // removing/adding here updates that same underlying memory post on save.
  const stagedAlbumPhotoFiles = [];
  const stagedAlbumVideoFiles = [];

  const renderAlbumMediaStaging = (containerId, remainingUrls, stagedFiles, mediaType) => {
    const container = document.querySelector(containerId);
    if (!container) return;
    const tag = mediaType === "video" ? "video" : "img";
    const existingHtml = remainingUrls
      .map(
        (url, index) => `
          <div class="memory-staging-item">
            <${tag} src="${url}"></${tag}>
            <span class="memory-staging-remove" data-remove-album-existing="${mediaType}:${index}">&times;</span>
          </div>
        `
      )
      .join("");
    const stagedHtml = stagedFiles
      .map((file, index) => {
        const url = URL.createObjectURL(file);
        return `
          <div class="memory-staging-item">
            <${tag} src="${url}"></${tag}>
            <span class="memory-staging-remove" data-remove-album-staged="${mediaType}:${index}">&times;</span>
          </div>
        `;
      })
      .join("");
    container.innerHTML = `${existingHtml}${stagedHtml}<button type="button" class="memory-add-tile" data-staging-add="true">+<span>Add ${mediaType === "video" ? "Video" : "Photo"}</span></button>`;
  };

  const renderAlbumPhotoStaging = () => renderAlbumMediaStaging("#albumPhotoStaging", editAlbumRemainingPhotoUrls, stagedAlbumPhotoFiles, "photo");
  const renderAlbumVideoStaging = () => renderAlbumMediaStaging("#albumVideoFileStaging", editAlbumRemainingVideoUrls, stagedAlbumVideoFiles, "video");

  document.querySelector("#albumPhotoStaging")?.addEventListener("click", (event) => {
    if (event.target.closest("[data-staging-add]")) {
      document.querySelector("#albumPhotoInput")?.click();
      return;
    }
    const removeExisting = event.target.closest("[data-remove-album-existing]");
    if (removeExisting) {
      const [, index] = removeExisting.dataset.removeAlbumExisting.split(":");
      editAlbumRemainingPhotoUrls.splice(Number(index), 1);
      renderAlbumPhotoStaging();
      return;
    }
    const removeStaged = event.target.closest("[data-remove-album-staged]");
    if (removeStaged) {
      const [, index] = removeStaged.dataset.removeAlbumStaged.split(":");
      stagedAlbumPhotoFiles.splice(Number(index), 1);
      renderAlbumPhotoStaging();
    }
  });

  document.querySelector("#albumPhotoInput")?.addEventListener("change", (event) => {
    stagedAlbumPhotoFiles.push(...Array.from(event.target.files || []));
    event.target.value = "";
    renderAlbumPhotoStaging();
  });

  document.querySelector("#albumVideoFileStaging")?.addEventListener("click", (event) => {
    if (event.target.closest("[data-staging-add]")) {
      document.querySelector("#albumVideoFileInput")?.click();
      return;
    }
    const removeExisting = event.target.closest("[data-remove-album-existing]");
    if (removeExisting) {
      const [, index] = removeExisting.dataset.removeAlbumExisting.split(":");
      editAlbumRemainingVideoUrls.splice(Number(index), 1);
      renderAlbumVideoStaging();
      return;
    }
    const removeStaged = event.target.closest("[data-remove-album-staged]");
    if (removeStaged) {
      const [, index] = removeStaged.dataset.removeAlbumStaged.split(":");
      stagedAlbumVideoFiles.splice(Number(index), 1);
      renderAlbumVideoStaging();
    }
  });

  document.querySelector("#albumVideoFileInput")?.addEventListener("change", (event) => {
    stagedAlbumVideoFiles.push(...Array.from(event.target.files || []));
    event.target.value = "";
    renderAlbumVideoStaging();
  });

  renderAlbumPhotoStaging();
  renderAlbumVideoStaging();

  const resetAlbumForm = () => {
    editingAlbumId = null;
    editAlbumRemainingPhotoUrls = [];
    editAlbumRemainingVideoUrls = [];
    stagedAlbumPhotoFiles.length = 0;
    stagedAlbumVideoFiles.length = 0;
    if (document.querySelector("#albumNameInput")) document.querySelector("#albumNameInput").value = "";
    if (document.querySelector("#albumDescriptionInput")) document.querySelector("#albumDescriptionInput").value = "";
    if (document.querySelector("#createAlbumButton")) document.querySelector("#createAlbumButton").textContent = "Create Album";
    document.querySelector("#cancelAlbumEditButton")?.classList.add("is-hidden");
    const heading = document.querySelector("#albumFormHeading");
    if (heading) heading.textContent = "Photo & Video Albums";
    renderAlbumPhotoStaging();
    renderAlbumVideoStaging();
  };

  const enterAlbumEditMode = (albumId) => {
    const album = getAlumniAlbums().find((item) => item.id === albumId);
    if (!album) return;
    editingAlbumId = albumId;
    const albumMemories = getAlumniMemories().filter((item) => item.albumId === albumId);
    const photoMemory = albumMemories.find((item) => item.type === "photo");
    const videoMemory = albumMemories.find((item) => item.type === "videofile");
    editAlbumRemainingPhotoUrls = photoMemory ? [...(photoMemory.mediaDataUrls || [])] : [];
    editAlbumRemainingVideoUrls = videoMemory ? [...(videoMemory.mediaDataUrls || [])] : [];
    stagedAlbumPhotoFiles.length = 0;
    stagedAlbumVideoFiles.length = 0;
    const nameInput = document.querySelector("#albumNameInput");
    const descInput = document.querySelector("#albumDescriptionInput");
    if (nameInput) nameInput.value = album.name;
    if (descInput) descInput.value = album.description || "";
    if (document.querySelector("#createAlbumButton")) document.querySelector("#createAlbumButton").textContent = "Update Album";
    document.querySelector("#cancelAlbumEditButton")?.classList.remove("is-hidden");
    const heading = document.querySelector("#albumFormHeading");
    if (heading) heading.textContent = `Edit Album - ${album.name}`;
    renderAlbumPhotoStaging();
    renderAlbumVideoStaging();
    renderAlbumList();
    nameInput?.scrollIntoView({ behavior: "smooth", block: "start" });
  };

  const syncMemoryTypeFields = () => {
    const type = document.querySelector("#memoryTypeSelect")?.value;
    document.querySelector("#memoryPhotoField")?.classList.toggle("is-hidden", type !== "photo");
    document.querySelector("#memoryVideoField")?.classList.toggle("is-hidden", type !== "video");
    document.querySelector("#memoryVideoFileField")?.classList.toggle("is-hidden", type !== "videofile");
  };

  document.querySelector("#memoryTypeSelect")?.addEventListener("change", syncMemoryTypeFields);
  syncMemoryTypeFields();

  document.querySelector("#addMemoryButton")?.addEventListener("click", async () => {
    const feedback = document.querySelector("#memoryFeedback");
    if (!activeAlbumId) {
      if (feedback) {
        feedback.textContent = "Select or create an album first.";
        feedback.classList.remove("success");
      }
      return;
    }
    const type = document.querySelector("#memoryTypeSelect")?.value || "photo";
    const caption = document.querySelector("#memoryCaptionInput")?.value.trim();
    if (!caption) {
      if (feedback) {
        feedback.textContent = "Enter a caption.";
        feedback.classList.remove("success");
      }
      return;
    }

    const { account } = getCurrentAlumniAccountRecord(currentEmail);
    const authorName = account.profile.basic?.name || account.name || currentEmail.split("@")[0];
    const makeMemory = (extra) => ({
      id: `memory-${Date.now()}-${Math.random().toString(36).slice(2, 7)}`,
      albumId: activeAlbumId,
      type,
      caption,
      author: authorName,
      authorEmail: currentEmail,
      createdAt: Date.now(),
      likes: [],
      comments: [],
      ...extra
    });

    // All files added together (via the "+" staging tiles) become ONE post with multiple
    // media items, not one post per file - they belong together as a single memory.
    let newMemory = null;

    if (type === "video") {
      // One YouTube link per line - all links submitted together form one multi-video post.
      const rawUrls = (document.querySelector("#memoryVideoInput")?.value || "")
        .split(/[\n,]/)
        .map((line) => line.trim())
        .filter(Boolean);
      const videoIds = rawUrls.map(extractYoutubeId).filter(Boolean);
      if (!videoIds.length) {
        if (feedback) {
          feedback.textContent = "Enter at least one valid YouTube URL.";
          feedback.classList.remove("success");
        }
        return;
      }
      newMemory = makeMemory({ videoIds });
    } else if (type === "videofile") {
      // Uses whatever was staged via the "+ Add Video" tile - all staged files become one post.
      if (!stagedVideoFiles.length) {
        if (feedback) {
          feedback.textContent = "Add at least one video file.";
          feedback.classList.remove("success");
        }
        return;
      }
      const mediaDataUrls = [];
      for (const file of stagedVideoFiles) {
        const uploaded = await readFileAsDataUrl(file, "alumni/albums");
        mediaDataUrls.push(uploaded.dataUrl);
      }
      newMemory = makeMemory({ mediaDataUrls });
    } else {
      // Uses whatever was staged via the "+ Add Photo" tile - all staged photos become one post.
      if (!stagedPhotoFiles.length) {
        if (feedback) {
          feedback.textContent = "Add at least one photo.";
          feedback.classList.remove("success");
        }
        return;
      }
      const mediaDataUrls = [];
      for (const file of stagedPhotoFiles) {
        const uploaded = await readFileAsDataUrl(file, "alumni/albums");
        mediaDataUrls.push(uploaded.dataUrl);
      }
      newMemory = makeMemory({ mediaDataUrls });
    }

    const memories = getAlumniMemories();
    memories.push(newMemory);
    saveAlumniMemories(memories);
    renderAlbumList();
    renderMemories();
    if (document.querySelector("#memoryCaptionInput")) document.querySelector("#memoryCaptionInput").value = "";
    if (document.querySelector("#memoryVideoInput")) document.querySelector("#memoryVideoInput").value = "";
    if (document.querySelector("#memoryPhotoInput")) document.querySelector("#memoryPhotoInput").value = "";
    if (document.querySelector("#memoryVideoFileInput")) document.querySelector("#memoryVideoFileInput").value = "";
    stagedPhotoFiles.length = 0;
    stagedVideoFiles.length = 0;
    renderPhotoStaging();
    renderVideoFileStaging();
    if (feedback) {
      feedback.textContent = "Memory added.";
      feedback.classList.add("success");
    }
  });

  // Shared by both the per-album Memories grid and the cross-album All Posts feed grid -
  // both render the same post cards via renderMemoryCard, so both need the same interactions.
  const handleMemoryGridClick = async (event) => {
    const prevArrow = event.target.closest("[data-post-media-prev]");
    const nextArrow = event.target.closest("[data-post-media-next]");
    const mediaDot = event.target.closest("[data-post-media-dot]");
    if (prevArrow || nextArrow || mediaDot) {
      const memories = getAlumniMemories();
      let memoryId;
      let delta = 0;
      let explicitIndex = null;
      if (mediaDot) {
        [memoryId, explicitIndex] = mediaDot.dataset.postMediaDot.split(":");
      } else {
        memoryId = (prevArrow || nextArrow).dataset.postMediaPrev || (prevArrow || nextArrow).dataset.postMediaNext;
        delta = prevArrow ? -1 : 1;
      }
      const memory = memories.find((item) => item.id === memoryId);
      if (!memory) return;
      const total =
        memory.type === "video"
          ? (memory.videoIds || (memory.videoId ? [memory.videoId] : [])).length
          : (memory.mediaDataUrls || (memory.mediaDataUrl ? [memory.mediaDataUrl] : [])).length;
      const current = postMediaIndex[memoryId] || 0;
      postMediaIndex[memoryId] = explicitIndex !== null ? Number(explicitIndex) : (current + delta + total) % total;
      renderMemories();
      return;
    }

    const editButton = event.target.closest("[data-edit-memory]");
    if (editButton) {
      const memory = getAlumniMemories().find((item) => item.id === editButton.dataset.editMemory);
      if (!memory) return;
      editingMemoryId = memory.id;
      editMemoryRemainingUrls = [...(memory.mediaDataUrls || (memory.mediaDataUrl ? [memory.mediaDataUrl] : []))];
      editMemoryStagedFiles = [];
      renderMemories();
      return;
    }

    const cancelMemoryEdit = event.target.closest("[data-cancel-memory-edit]");
    if (cancelMemoryEdit) {
      editingMemoryId = null;
      editMemoryRemainingUrls = [];
      editMemoryStagedFiles = [];
      renderMemories();
      return;
    }

    const removeExistingMedia = event.target.closest("[data-remove-existing-media]");
    if (removeExistingMedia) {
      const [, index] = removeExistingMedia.dataset.removeExistingMedia.split(":");
      editMemoryRemainingUrls.splice(Number(index), 1);
      renderMemories();
      return;
    }

    const removeStagedMedia = event.target.closest("[data-remove-staged-media]");
    if (removeStagedMedia) {
      editMemoryStagedFiles.splice(Number(removeStagedMedia.dataset.removeStagedMedia), 1);
      renderMemories();
      return;
    }

    const editAddMedia = event.target.closest("[data-edit-add-media]");
    if (editAddMedia) {
      document.querySelector(`#editMemoryFileInput-${editAddMedia.dataset.editAddMedia}`)?.click();
      return;
    }

    const saveMemoryButton = event.target.closest("[data-save-memory]");
    if (saveMemoryButton) {
      const memoryId = saveMemoryButton.dataset.saveMemory;
      const memories = getAlumniMemories();
      const memory = memories.find((item) => item.id === memoryId);
      if (!memory) return;
      const caption = document.querySelector(`#editMemoryCaption-${memoryId}`)?.value.trim();
      if (!caption) return;
      memory.caption = caption;
      if (memory.type === "video") {
        const rawUrls = (document.querySelector(`#editMemoryVideoInput-${memoryId}`)?.value || "")
          .split(/[\n,]/)
          .map((line) => line.trim())
          .filter(Boolean);
        const videoIds = rawUrls.map(extractYoutubeId).filter(Boolean);
        if (!videoIds.length) return;
        memory.videoIds = videoIds;
        delete memory.videoId;
      } else {
        for (const file of editMemoryStagedFiles) {
          const uploaded = await readFileAsDataUrl(file, "alumni/albums");
          editMemoryRemainingUrls.push(uploaded.dataUrl);
        }
        if (!editMemoryRemainingUrls.length) return;
        memory.mediaDataUrls = editMemoryRemainingUrls;
        delete memory.mediaDataUrl;
      }
      saveAlumniMemories(memories);
      editingMemoryId = null;
      editMemoryRemainingUrls = [];
      editMemoryStagedFiles = [];
      renderAlbumList();
      renderMemories();
      return;
    }

    const likeButton = event.target.closest("[data-like-memory]");
    const commentToggle = event.target.closest("[data-toggle-comments]");
    const shareToggle = event.target.closest("[data-toggle-share]");
    const copyLinkButton = event.target.closest("[data-copy-link]");
    const shareWhatsappButton = event.target.closest("[data-share-whatsapp]");
    const shareEmailButton = event.target.closest("[data-share-email]");
    const postCommentButton = event.target.closest("[data-post-comment]");
    const deleteButton = event.target.closest("[data-delete-memory]");

    const buildShareUrl = (memoryId) => `${window.location.origin}${window.location.pathname}#alumni-gallery?memory=${memoryId}`;

    if (deleteButton) {
      const memories = getAlumniMemories().filter((item) => item.id !== deleteButton.dataset.deleteMemory);
      saveAlumniMemories(memories);
      renderAlbumList();
      renderMemories();
    } else if (likeButton) {
      const memories = getAlumniMemories();
      const memory = memories.find((item) => item.id === likeButton.dataset.likeMemory);
      if (!memory) return;
      memory.likes = memory.likes || [];
      const index = memory.likes.indexOf(currentEmail);
      if (index > -1) memory.likes.splice(index, 1);
      else memory.likes.push(currentEmail);
      saveAlumniMemories(memories);
      renderMemories();
    } else if (commentToggle) {
      document.querySelector(`#comments-${commentToggle.dataset.toggleComments}`)?.classList.toggle("is-hidden");
    } else if (shareToggle) {
      // Only one share menu open at a time - close any others before toggling this one.
      document.querySelectorAll(".alumni-share-menu").forEach((menu) => {
        if (menu.id !== `share-menu-${shareToggle.dataset.toggleShare}`) menu.classList.add("is-hidden");
      });
      document.querySelector(`#share-menu-${shareToggle.dataset.toggleShare}`)?.classList.toggle("is-hidden");
    } else if (copyLinkButton) {
      const shareUrl = buildShareUrl(copyLinkButton.dataset.copyLink);
      // A toast (rather than a page-specific feedback paragraph) works no matter which grid
      // triggered Share - the per-album Memories form's feedback line and the feed composer's
      // are both hidden most of the time, so writing into either was silently invisible.
      const showCopied = () => showFeedToast("Link copied to clipboard. Share it with your batchmates!");
      const showFallback = () => showFeedToast(`Copy this link to share: ${shareUrl}`);
      if (navigator.clipboard?.writeText) {
        navigator.clipboard.writeText(shareUrl).then(showCopied).catch(showFallback);
      } else {
        // navigator.clipboard is unavailable on file:// pages (and older browsers) - fall back
        // to the classic hidden-textarea + execCommand copy so Share still does something.
        try {
          const temp = document.createElement("textarea");
          temp.value = shareUrl;
          temp.style.position = "fixed";
          temp.style.opacity = "0";
          document.body.appendChild(temp);
          temp.select();
          document.execCommand("copy");
          document.body.removeChild(temp);
          showCopied();
        } catch {
          showFallback();
        }
      }
      document.querySelector(`#share-menu-${copyLinkButton.dataset.copyLink}`)?.classList.add("is-hidden");
    } else if (shareWhatsappButton) {
      const shareUrl = buildShareUrl(shareWhatsappButton.dataset.shareWhatsapp);
      window.open(`https://wa.me/?text=${encodeURIComponent(shareUrl)}`, "_blank", "noopener");
      document.querySelector(`#share-menu-${shareWhatsappButton.dataset.shareWhatsapp}`)?.classList.add("is-hidden");
    } else if (shareEmailButton) {
      const shareUrl = buildShareUrl(shareEmailButton.dataset.shareEmail);
      window.location.href = `mailto:?subject=${encodeURIComponent("Check this out on GPREC Alumni")}&body=${encodeURIComponent(shareUrl)}`;
      document.querySelector(`#share-menu-${shareEmailButton.dataset.shareEmail}`)?.classList.add("is-hidden");
    } else if (postCommentButton) {
      const memoryId = postCommentButton.dataset.postComment;
      const input = document.querySelector(`[data-comment-input="${memoryId}"]`);
      const text = input?.value.trim();
      if (!text) return;
      const memories = getAlumniMemories();
      const memory = memories.find((item) => item.id === memoryId);
      if (!memory) return;
      const { account } = getCurrentAlumniAccountRecord(currentEmail);
      const authorName = account.profile.basic?.name || account.name || currentEmail.split("@")[0];
      memory.comments = memory.comments || [];
      memory.comments.push({ author: authorName, text, createdAt: Date.now() });
      saveAlumniMemories(memories);
      renderMemories();
    }
  };

  const handleMemoryGridChange = (event) => {
    if (!event.target.matches('[id^="editMemoryFileInput-"]')) return;
    editMemoryStagedFiles.push(...Array.from(event.target.files || []));
    event.target.value = "";
    renderMemories();
  };

  document.querySelector("#alumniMemoriesGrid")?.addEventListener("click", handleMemoryGridClick);
  document.querySelector("#alumniMemoriesGrid")?.addEventListener("change", handleMemoryGridChange);
  document.querySelector("#alumniFeedGrid")?.addEventListener("click", handleMemoryGridClick);
  document.querySelector("#alumniFeedGrid")?.addEventListener("change", handleMemoryGridChange);

  // "Add Post" composer on the All Posts feed (Home > All Posts) - a LinkedIn-style quick-post
  // box next to the feed itself, rather than requiring a trip to the Gallery section first.
  const feedPostStagedPhotoFiles = [];
  const feedPostStagedVideoFiles = [];
  let composerScheduledAt = null;

  // Post button stays disabled (LinkedIn-style) until there's a caption or at least one
  // staged photo/video.
  const updateFeedSubmitState = () => {
    const submitButton = document.querySelector("#feedPostSubmitButton");
    if (!submitButton) return;
    const hasCaption = Boolean(document.querySelector("#feedPostCaptionInput")?.value.trim());
    submitButton.disabled = !hasCaption && !feedPostStagedPhotoFiles.length && !feedPostStagedVideoFiles.length;
  };

  const renderFeedPhotoStaging = () => {
    renderStagingRow("#feedPostPhotoStaging", feedPostStagedPhotoFiles, "img");
    document.querySelector("#feedPostPhotoStaging")?.classList.toggle("is-hidden", !feedPostStagedPhotoFiles.length);
    updateFeedSubmitState();
  };
  const renderFeedVideoStaging = () => {
    renderStagingRow("#feedPostVideoStaging", feedPostStagedVideoFiles, "video");
    document.querySelector("#feedPostVideoStaging")?.classList.toggle("is-hidden", !feedPostStagedVideoFiles.length);
    updateFeedSubmitState();
  };

  document.querySelector("#feedPostCaptionInput")?.addEventListener("input", updateFeedSubmitState);

  // Collapsed "Start a post" pill (LinkedIn-style) that opens a full-screen modal composer -
  // clicking the pill or either quick-action icon opens it; the X, or a successful post,
  // closes it again.
  const openFeedComposer = () => {
    document.querySelector("#feedComposerModalOverlay")?.classList.remove("is-hidden");
    document.querySelector("#feedPostCaptionInput")?.focus();
  };

  const closeFeedComposer = () => {
    document.querySelector("#feedComposerModalOverlay")?.classList.add("is-hidden");
  };

  const fillAvatarEl = (selector, name, pictureUrl) => {
    const el = document.querySelector(selector);
    if (!el) return;
    if (pictureUrl) {
      el.outerHTML = `<img src="${pictureUrl}" alt="${name}" class="feed-composer-avatar" id="${el.id}">`;
    } else {
      el.textContent = name
        .split(/\s+/)
        .map((part) => part[0])
        .join("")
        .slice(0, 2)
        .toUpperCase();
    }
  };

  const renderFeedComposerAvatar = () => {
    const { account } = getCurrentAlumniAccountRecord(currentEmail);
    const name = account.profile.basic?.name || account.name || currentEmail.split("@")[0];
    const pictureUrl = account.profile?.pictureDataUrl || "";
    fillAvatarEl("#feedComposerAvatar", name, pictureUrl);
    fillAvatarEl("#feedComposerModalAvatar", name, pictureUrl);
    const modalName = document.querySelector("#feedComposerModalName");
    if (modalName) modalName.textContent = name;
  };

  document.querySelector("#feedComposerStartButton")?.addEventListener("click", openFeedComposer);
  document.querySelector("#feedComposerCollapseButton")?.addEventListener("click", closeFeedComposer);
  document.querySelector("#feedComposerModalOverlay")?.addEventListener("click", (event) => {
    if (event.target.id === "feedComposerModalOverlay") closeFeedComposer();
  });
  document.querySelector("#feedComposerPhotoQuick")?.addEventListener("click", () => {
    openFeedComposer();
    document.querySelector("#feedPostPhotoInput")?.click();
  });
  document.querySelector("#feedComposerVideoQuick")?.addEventListener("click", () => {
    openFeedComposer();
    document.querySelector("#feedPostVideoInput")?.click();
  });
  document.querySelector("#feedComposerModalPhotoButton")?.addEventListener("click", () => {
    document.querySelector("#feedPostPhotoInput")?.click();
  });
  document.querySelector("#feedComposerModalVideoButton")?.addEventListener("click", () => {
    document.querySelector("#feedPostVideoInput")?.click();
  });

  const emojiPickerChoices =
    "😀😃😄😁😆😅😂🤣🙂🙃😉😊😇🥰😍😘😗😋😛😜🤪😝🤑🤗🤭🤔🤨😐😑😶🙄😏😴🥳😎🤩🥺😢😭😤😠🤬🥵🥶😱😨😥😓🤯😳🤠🥸👍👎👏🙌🙏💪👋🤝❤️🧡💛💚💙💜🖤🤍💯🔥🎉🎊🥳🎓📸🎥⭐️✨".match(/\p{Emoji}/gu) ||
    [];

  const populateEmojiPicker = () => {
    const picker = document.querySelector("#feedComposerEmojiPicker");
    if (!picker || picker.childElementCount) return;
    picker.innerHTML = emojiPickerChoices.map((emoji) => `<button type="button" data-emoji="${emoji}">${emoji}</button>`).join("");
  };

  document.querySelector("#feedComposerEmojiButton")?.addEventListener("click", (event) => {
    event.stopPropagation();
    populateEmojiPicker();
    document.querySelector("#feedComposerEmojiPicker")?.classList.toggle("is-hidden");
  });

  document.querySelector("#feedComposerEmojiPicker")?.addEventListener("click", (event) => {
    const button = event.target.closest("[data-emoji]");
    if (!button) return;
    const textarea = document.querySelector("#feedPostCaptionInput");
    if (!textarea) return;
    const emoji = button.dataset.emoji;
    const cursor = textarea.selectionStart ?? textarea.value.length;
    textarea.value = `${textarea.value.slice(0, cursor)}${emoji}${textarea.value.slice(cursor)}`;
    textarea.focus();
    textarea.selectionStart = textarea.selectionEnd = cursor + emoji.length;
    updateFeedSubmitState();
  });

  document.addEventListener("click", (event) => {
    if (event.target.closest("#feedComposerEmojiButton, #feedComposerEmojiPicker")) return;
    document.querySelector("#feedComposerEmojiPicker")?.classList.add("is-hidden");
  });

  // Celebrate an occasion / Add a document / More mirror LinkedIn's composer toolbar
  // visually - not wired to real features here yet. Schedule (below) is real.
  ["#feedComposerCalendarButton", "#feedComposerCertificateButton", "#feedComposerMoreButton"].forEach((selector) => {
    document.querySelector(selector)?.addEventListener("click", () => {
      const feedback = document.querySelector("#feedPostFeedback");
      if (feedback) {
        feedback.textContent = "Coming soon.";
        feedback.classList.remove("success");
      }
    });
  });

  // Schedule post - a real feature: the chosen date/time is stored as scheduledAt on the
  // memory, and both the feed and per-album views hide a post until that time has passed
  // (except from its own author, who sees it marked "Scheduled").
  const formatScheduleSummary = (date) =>
    date.toLocaleString("en-US", { weekday: "short", month: "short", day: "numeric", hour: "numeric", minute: "2-digit" });

  const openScheduleModal = () => {
    document.querySelector("#feedComposerModalOverlay")?.classList.add("is-hidden");
    document.querySelector("#feedScheduleModalOverlay")?.classList.remove("is-hidden");
    document.querySelector("#feedScheduleList")?.classList.add("is-hidden");
    const dateInput = document.querySelector("#feedScheduleDateInput");
    const timeInput = document.querySelector("#feedScheduleTimeInput");
    if (composerScheduledAt) {
      const draft = new Date(composerScheduledAt);
      if (dateInput) dateInput.value = draft.toISOString().slice(0, 10);
      if (timeInput) timeInput.value = draft.toTimeString().slice(0, 5);
    }
    updateScheduleSummary();
  };

  const closeScheduleModal = () => {
    document.querySelector("#feedScheduleModalOverlay")?.classList.add("is-hidden");
    document.querySelector("#feedComposerModalOverlay")?.classList.remove("is-hidden");
  };

  const updateScheduleSummary = () => {
    const dateInput = document.querySelector("#feedScheduleDateInput");
    const timeInput = document.querySelector("#feedScheduleTimeInput");
    const summary = document.querySelector("#feedScheduleSummary");
    const nextButton = document.querySelector("#feedScheduleNextButton");
    const hasBoth = Boolean(dateInput?.value) && Boolean(timeInput?.value);
    if (nextButton) nextButton.disabled = !hasBoth;
    if (!summary) return;
    if (!hasBoth) {
      summary.textContent = "Pick a date and time to schedule this post.";
      return;
    }
    const combined = new Date(`${dateInput.value}T${timeInput.value}`);
    summary.textContent = `${formatScheduleSummary(combined)}, based on your location`;
  };

  document.querySelector("#feedComposerScheduleButton")?.addEventListener("click", openScheduleModal);
  document.querySelector("#feedScheduleCloseButton")?.addEventListener("click", closeScheduleModal);
  document.querySelector("#feedScheduleBackButton")?.addEventListener("click", closeScheduleModal);
  document.querySelector("#feedScheduleModalOverlay")?.addEventListener("click", (event) => {
    if (event.target.id === "feedScheduleModalOverlay") closeScheduleModal();
  });
  document.querySelector("#feedScheduleDateInput")?.addEventListener("change", updateScheduleSummary);
  document.querySelector("#feedScheduleTimeInput")?.addEventListener("change", updateScheduleSummary);

  document.querySelector("#feedScheduleClearButton")?.addEventListener("click", () => {
    if (document.querySelector("#feedScheduleDateInput")) document.querySelector("#feedScheduleDateInput").value = "";
    if (document.querySelector("#feedScheduleTimeInput")) document.querySelector("#feedScheduleTimeInput").value = "";
    composerScheduledAt = null;
    document.querySelector("#feedComposerScheduledNote")?.classList.add("is-hidden");
    if (document.querySelector("#feedPostSubmitButton")) document.querySelector("#feedPostSubmitButton").textContent = "Post";
    updateScheduleSummary();
  });

  document.querySelector("#feedScheduleNextButton")?.addEventListener("click", () => {
    const dateInput = document.querySelector("#feedScheduleDateInput");
    const timeInput = document.querySelector("#feedScheduleTimeInput");
    if (!dateInput?.value || !timeInput?.value) return;
    composerScheduledAt = new Date(`${dateInput.value}T${timeInput.value}`).getTime();
    const note = document.querySelector("#feedComposerScheduledNote");
    if (note) {
      note.textContent = `Scheduled for ${formatScheduleSummary(new Date(composerScheduledAt))}`;
      note.classList.remove("is-hidden");
    }
    const submitButton = document.querySelector("#feedPostSubmitButton");
    if (submitButton) submitButton.textContent = "Schedule";
    updateFeedSubmitState();
    closeScheduleModal();
  });

  const renderScheduledPostsList = () => {
    const list = document.querySelector("#feedScheduleList");
    if (!list) return;
    const scheduled = getAlumniMemories()
      .filter((memory) => memory.authorEmail === currentEmail && memory.scheduledAt && memory.scheduledAt > Date.now())
      .sort((a, b) => a.scheduledAt - b.scheduledAt);
    list.innerHTML = scheduled.length
      ? scheduled
          .map(
            (memory) => `
              <div class="feed-schedule-list-item" data-scheduled-memory="${memory.id}">
                <span>${memory.caption || "(no caption)"} - ${formatScheduleSummary(new Date(memory.scheduledAt))}</span>
                <span style="display:flex;gap:6px;">
                  <button type="button" data-post-now="${memory.id}">Post now</button>
                  <button type="button" data-cancel-schedule="${memory.id}">Delete</button>
                </span>
              </div>
            `
          )
          .join("")
      : `<p class="portal-note">No scheduled posts.</p>`;
  };

  document.querySelector("#feedScheduleViewAllLink")?.addEventListener("click", (event) => {
    event.preventDefault();
    renderScheduledPostsList();
    document.querySelector("#feedScheduleList")?.classList.toggle("is-hidden");
  });

  document.querySelector("#feedScheduleList")?.addEventListener("click", (event) => {
    const postNowButton = event.target.closest("[data-post-now]");
    const cancelButton = event.target.closest("[data-cancel-schedule]");
    if (postNowButton) {
      const memories = getAlumniMemories();
      const memory = memories.find((item) => item.id === postNowButton.dataset.postNow);
      if (memory) {
        delete memory.scheduledAt;
        saveAlumniMemories(memories);
        renderScheduledPostsList();
        renderAlbumList();
        renderMemories();
      }
    } else if (cancelButton) {
      saveAlumniMemories(getAlumniMemories().filter((item) => item.id !== cancelButton.dataset.cancelSchedule));
      renderScheduledPostsList();
      renderAlbumList();
      renderMemories();
    }
  });

  document.querySelector("#feedPostPhotoStaging")?.addEventListener("click", (event) => {
    if (event.target.closest("[data-staging-add]")) {
      document.querySelector("#feedPostPhotoInput")?.click();
      return;
    }
    const removeButton = event.target.closest("[data-staging-remove]");
    if (removeButton) {
      feedPostStagedPhotoFiles.splice(Number(removeButton.dataset.stagingRemove), 1);
      renderFeedPhotoStaging();
    }
  });

  document.querySelector("#feedPostPhotoInput")?.addEventListener("change", (event) => {
    feedPostStagedPhotoFiles.push(...Array.from(event.target.files || []));
    event.target.value = "";
    renderFeedPhotoStaging();
  });

  document.querySelector("#feedPostVideoStaging")?.addEventListener("click", (event) => {
    if (event.target.closest("[data-staging-add]")) {
      document.querySelector("#feedPostVideoInput")?.click();
      return;
    }
    const removeButton = event.target.closest("[data-staging-remove]");
    if (removeButton) {
      feedPostStagedVideoFiles.splice(Number(removeButton.dataset.stagingRemove), 1);
      renderFeedVideoStaging();
    }
  });

  document.querySelector("#feedPostVideoInput")?.addEventListener("change", (event) => {
    feedPostStagedVideoFiles.push(...Array.from(event.target.files || []));
    event.target.value = "";
    renderFeedVideoStaging();
  });

  // Posts made from this composer aren't sorted into a user-chosen album - they all land in
  // one auto-created "General Posts" album per author, so Photo & Video Albums still has
  // somewhere to keep them without asking the user to pick one every time.
  const getOrCreateGeneralAlbum = () => {
    const albums = getAlumniAlbums();
    let album = albums.find((item) => item.createdBy === currentEmail && item.name === "General Posts");
    if (!album) {
      album = { id: `album-${Date.now()}`, name: "General Posts", description: "Posts shared from the feed", createdBy: currentEmail, createdAt: Date.now() };
      albums.push(album);
      saveAlumniAlbums(albums);
    }
    return album.id;
  };

  document.querySelector("#feedPostSubmitButton")?.addEventListener("click", async () => {
    const feedback = document.querySelector("#feedPostFeedback");
    const setFeedback = (text, success) => {
      if (!feedback) return;
      feedback.textContent = text;
      feedback.classList.toggle("success", Boolean(success));
    };

    const caption = document.querySelector("#feedPostCaptionInput")?.value.trim();
    if (!caption && !feedPostStagedPhotoFiles.length && !feedPostStagedVideoFiles.length) {
      setFeedback("Write something or add a photo/video.");
      return;
    }

    const albumId = getOrCreateGeneralAlbum();
    const visibility = document.querySelector("#feedPostVisibilitySelect")?.value || "all";
    const { account } = getCurrentAlumniAccountRecord(currentEmail);
    const authorName = account.profile.basic?.name || account.name || currentEmail.split("@")[0];
    const memories = getAlumniMemories();
    const makePost = (extra) => ({
      id: `memory-${Date.now()}-${Math.random().toString(36).slice(2, 7)}`,
      albumId,
      caption,
      visibility,
      author: authorName,
      authorEmail: currentEmail,
      createdAt: Date.now(),
      likes: [],
      comments: [],
      ...(composerScheduledAt ? { scheduledAt: composerScheduledAt } : {}),
      ...extra
    });

    if (feedPostStagedPhotoFiles.length) {
      const mediaDataUrls = [];
      for (const file of feedPostStagedPhotoFiles) {
        const uploaded = await readFileAsDataUrl(file, "alumni/feed");
        mediaDataUrls.push(uploaded.dataUrl);
      }
      memories.push(makePost({ type: "photo", mediaDataUrls }));
    }
    if (feedPostStagedVideoFiles.length) {
      const mediaDataUrls = [];
      for (const file of feedPostStagedVideoFiles) {
        const uploaded = await readFileAsDataUrl(file, "alumni/feed");
        mediaDataUrls.push(uploaded.dataUrl);
      }
      memories.push(makePost({ type: "videofile", mediaDataUrls }));
    }
    if (!feedPostStagedPhotoFiles.length && !feedPostStagedVideoFiles.length) {
      memories.push(makePost({ type: "text" }));
    }

    saveAlumniMemories(memories);
    feedPostStagedPhotoFiles.length = 0;
    feedPostStagedVideoFiles.length = 0;
    renderFeedPhotoStaging();
    renderFeedVideoStaging();
    if (document.querySelector("#feedPostCaptionInput")) document.querySelector("#feedPostCaptionInput").value = "";
    const wasScheduled = Boolean(composerScheduledAt);
    composerScheduledAt = null;
    document.querySelector("#feedComposerScheduledNote")?.classList.add("is-hidden");
    if (document.querySelector("#feedPostSubmitButton")) document.querySelector("#feedPostSubmitButton").textContent = "Post";
    renderAlbumList();
    renderMemories();
    setFeedback(wasScheduled ? "Post scheduled!" : "Posted!", true);
  });

  renderFeedPhotoStaging();
  renderFeedVideoStaging();
  renderFeedComposerAvatar();

  renderAlbumList();
  renderMemories();
};

const alumniDashboardName = document.querySelector("#alumniDashboardName");
if (alumniDashboardName) {
  const alumniEmail = localStorage.getItem("gprecAlumniEmail") || "preview.alumni@gprec.ac.in";
  const alumniBatch = localStorage.getItem("gprecAlumniBatch") || "2026";
  const alumniGoogleName = localStorage.getItem("gprecAlumniName") || "Preview Alumni";

  if (!localStorage.getItem("gprecAlumniEmail")) {
    localStorage.setItem("gprecAlumniEmail", alumniEmail);
    localStorage.setItem("gprecAlumniName", alumniGoogleName);
    localStorage.setItem("gprecAlumniBatch", alumniBatch);
  }

  {
    const setText = (selector, value) => {
      const node = document.querySelector(selector);
      if (node) node.textContent = value;
    };
    const displayName =
      alumniGoogleName ||
      alumniEmail
        .split("@")[0]
        .replace(/[._]/g, " ")
        .replace(/\b\w/g, (letter) => letter.toUpperCase());
    const initials = displayName
      .split(/\s+/)
      .map((part) => part[0])
      .join("")
      .slice(0, 2)
      .toUpperCase();

    setText("#alumniInitials", initials || "AL");
    setText("#alumniDashboardName", displayName || "Alumni");
    setText("#dashboardGreeting", getTimeBasedGreeting(getFirstName(displayName, "Alumni")));
    applyGprecianBotGreeting(getFirstName(displayName, "Alumni"));
    setText("#alumniDashboardBatch", alumniBatch ? `Batch ${alumniBatch}` : "Batch -");
    setText("#alumniProfileName", displayName || "-");
    setText("#alumniProfileEmail", alumniEmail);
    setText("#alumniProfileBatch", alumniBatch || "-");
    initAlumniProfileEditor(alumniEmail);
    renderAlumniDirectory(alumniEmail);
    initAlumniGallery(alumniEmail);
    initAlumniEvents(alumniEmail);
    renderFundingCampaigns();
    renderFundingContributors();
    renderFeedSidebar(alumniEmail);

    if (document.querySelector("#notificationList")) {
      renderNotificationList([]);
    }

    document.querySelector("#fundingContributeButton")?.addEventListener("click", async () => {
      const campaignId = document.querySelector("#fundingCampaignSelect")?.value;
      const amount = Number(document.querySelector("#fundingAmountInput")?.value);
      const feedback = document.querySelector("#fundingFeedback");
      if (!campaignId || !amount || amount <= 0) {
        if (feedback) {
          feedback.textContent = "Choose a campaign and enter a valid amount.";
          feedback.classList.remove("success");
        }
        return;
      }

      const { account } = getCurrentAlumniAccountRecord(alumniEmail);
      const contributorName = account.profile.basic?.name || account.name || alumniEmail.split("@")[0];
      const campaign = getFundingCampaigns().find((item) => item.id === campaignId);

      const payuPaymentLink = await resolvePayuPaymentLink();
      if (!payuPaymentLink) {
        if (feedback) {
          feedback.textContent = "Payment gateway is not linked yet.";
          feedback.classList.remove("success");
        }
        return;
      }

      openPayuCheckoutAndRecord(payuPaymentLink, amount, (paymentId) => {
        recordFundingContribution({
          campaignId,
          name: contributorName,
          email: alumniEmail,
          amount,
          paymentId
        });
        renderFundingCampaigns();
        renderFundingContributors();
        const amountInput = document.querySelector("#fundingAmountInput");
        if (amountInput) amountInput.value = "";
        if (feedback) {
          feedback.textContent = `Thank you! Payment received (ID: ${paymentId}).`;
          feedback.classList.add("success");
        }
      });
    });
  }
}

const facultyDashboardName = document.querySelector("#facultyDashboardName");
if (facultyDashboardName) {
  const facultyEmail = localStorage.getItem("gprecFacultyEmail") || "";
  const facultyRecord = lookupFacultyRecordByEmail(facultyEmail);

  if (!facultyRecord) {
    window.location.href = gprecPageUrl("faculty-login.html");
  } else {
    const setText = (selector, value) => {
      const node = document.querySelector(selector);
      if (node) node.textContent = value;
    };
    applyGprecianBotGreeting(getFirstName(facultyRecord.name, "Faculty"));
    const facultyPhotoUrl = normalizeProfilePhotoUrl(facultyRecord.photoUrl);
    const facultyAvatarEl = document.querySelector("#facultyInitials");
    if (facultyPhotoUrl && facultyAvatarEl) {
      const img = document.createElement("img");
      img.src = facultyPhotoUrl;
      img.alt = `${facultyRecord.name} photo`;
      img.className = facultyAvatarEl.className;
      facultyAvatarEl.replaceWith(img);
    } else {
      setText("#facultyInitials", getInitialsFromName(facultyRecord.name) || "FA");
    }
    setText("#facultyDashboardName", facultyRecord.name);
    setText("#facultyDashboardDesignation", facultyRecord.designation);
    const renderFacultyProfileFields = (record) => {
      const photoUrl = normalizeProfilePhotoUrl(record.photoUrl);
      const facultyProfilePhoto = document.querySelector("#facultyProfilePhoto");
      if (facultyProfilePhoto) facultyProfilePhoto.src = photoUrl || getFallbackInitialsSvg(record.name);
      setText("#facultyProfileName", record.name);
      setText("#facultyProfileDesignation", `Designation: ${record.designation}`);
      setText("#facultyProfileDepartment", `Department: ${record.department}`);
      setText("#facultyProfileSubject", `Subject: ${resolveFacultySubject(record) || "Not assigned yet"}`);
      setText("#facultyProfileEmail", record.email);
      setText("#facultyProfileQualifications", record.qualifications || "-");
      setText("#facultyProfileApaarId", record.apaarId || "-");
      const facultyGoogleScholarEl = document.querySelector("#facultyProfileGoogleScholar");
      if (facultyGoogleScholarEl) facultyGoogleScholarEl.innerHTML = facultyLinkOrDash(record.googleScholar);
      const facultyVidwanProfileEl = document.querySelector("#facultyProfileVidwanProfile");
      if (facultyVidwanProfileEl) facultyVidwanProfileEl.innerHTML = facultyLinkOrDash(record.vidwanProfile);
    };
    renderFacultyProfileFields(facultyRecord);

    const facultyEditProfileForm = document.querySelector("#facultyProfileEditForm");
    const facultyEditProfileFeedback = document.querySelector("#facultyEditProfileFeedback");
    if (facultyEditProfileForm) {
      document.querySelector("#facultyEditQualifications").value = facultyRecord.qualifications || "";
      document.querySelector("#facultyEditGoogleScholar").value = facultyRecord.googleScholar || "";
      document.querySelector("#facultyEditVidwanProfile").value = facultyRecord.vidwanProfile || "";
    }
    facultyEditProfileForm?.addEventListener("submit", (event) => {
      event.preventDefault();
      const qualifications = document.querySelector("#facultyEditQualifications")?.value.trim() || "";
      const googleScholar = document.querySelector("#facultyEditGoogleScholar")?.value.trim() || "";
      const vidwanProfile = document.querySelector("#facultyEditVidwanProfile")?.value.trim() || "";
      const result = gprecDbPost("/faculty/profile-links", { email: facultyRecord.email, qualifications, googleScholar, vidwanProfile });
      if (!result?.ok) {
        if (facultyEditProfileFeedback) {
          facultyEditProfileFeedback.textContent = "Could not reach the portal API to save your profile.";
          facultyEditProfileFeedback.classList.remove("is-hidden", "success");
        }
        return;
      }
      facultyRecord.qualifications = qualifications;
      facultyRecord.googleScholar = googleScholar;
      facultyRecord.vidwanProfile = vidwanProfile;
      renderFacultyProfileFields(facultyRecord);
      rebuildDepartmentFacultyFromDatabase();
      if (facultyEditProfileFeedback) {
        facultyEditProfileFeedback.textContent = "Profile updated.";
        facultyEditProfileFeedback.classList.remove("is-hidden");
        facultyEditProfileFeedback.classList.add("success");
      }
    });

    renderFacultyInvigilationDuties(facultyRecord.email);

    setText("#payslipFacultyName", facultyRecord.name);
    setText("#payslipFacultyDesignation", facultyRecord.designation);
    setText("#payslipFacultyDepartment", facultyRecord.department);

    const payslipMonthSelect = document.querySelector("#payslipMonthSelect");
    if (payslipMonthSelect) {
      const now = new Date();
      const months = Array.from({ length: 12 }, (_, index) =>
        new Date(now.getFullYear(), now.getMonth() - index, 1).toLocaleDateString("en-IN", { month: "long", year: "numeric" })
      );
      payslipMonthSelect.innerHTML = months.map((month) => `<option>${month}</option>`).join("");
    }

    document.querySelector("#payslipForm")?.addEventListener("submit", async (event) => {
      event.preventDefault();
      const month = payslipMonthSelect.value;
      const basic = 45000;
      const da = 4500;
      const hra = 9000;
      const pf = 5400;
      const professionalTax = 200;
      const bankKey = `faculty-${facultyRecord.email}`;
      const bankDetails = getBankDetailsFor(bankKey, null);
      const bankLineParts = buildPaySlipBankLineParts(bankDetails);
      const pdf = await buildPaySlipImage({
        slipNo: makeShortPassId("PS", [facultyRecord.email, month]),
        employeeName: facultyRecord.name,
        employeeId: makeShortPassId("EMP", [facultyRecord.email]),
        designation: facultyRecord.designation,
        department: facultyRecord.department,
        month,
        earnings: [["Basic Pay", basic], ["Dearness Allowance", da], ["House Rent Allowance", hra]],
        deductions: [["Provident Fund", pf], ["Professional Tax", professionalTax]],
        bankLineParts
      });
      const link = document.createElement("a");
      link.href = URL.createObjectURL(pdf);
      link.download = `payslip-${month.replace(/\s+/g, "-")}.pdf`;
      link.click();
    });

    const bankDetailsForm = document.querySelector("#bankDetailsForm");
    if (bankDetailsForm) {
      const bankKey = `faculty-${facultyRecord.email}`;
      const savedBankDetails = getBankDetailsFor(bankKey, {
        accountHolder: facultyRecord.name,
        bankName: "",
        accountNumber: "",
        ifsc: "",
        branch: ""
      });
      document.querySelector("#bankAccountHolder").value = savedBankDetails.accountHolder;
      document.querySelector("#bankName").value = savedBankDetails.bankName;
      const getFacultyBankAccountNumber = wireMaskedAccountNumberInput(document.querySelector("#bankAccountNumber"), savedBankDetails.accountNumber);
      document.querySelector("#bankIfsc").value = savedBankDetails.ifsc;
      document.querySelector("#bankBranch").value = savedBankDetails.branch;

      bankDetailsForm.addEventListener("submit", (event) => {
        event.preventDefault();
        saveBankDetailsFor(bankKey, {
          accountHolder: document.querySelector("#bankAccountHolder").value.trim(),
          bankName: document.querySelector("#bankName").value.trim(),
          accountNumber: getFacultyBankAccountNumber(),
          ifsc: document.querySelector("#bankIfsc").value.trim(),
          branch: document.querySelector("#bankBranch").value.trim()
        });
        const feedback = document.querySelector("#bankDetailsFeedback");
        if (feedback) {
          feedback.textContent = "Bank details saved successfully.";
          feedback.classList.remove("is-hidden");
          feedback.classList.add("success");
        }
      });
    }

    const form16YearSelect = document.querySelector("#form16YearSelect");
    if (form16YearSelect) {
      const now = new Date();
      const startYear = now.getMonth() >= 3 ? now.getFullYear() : now.getFullYear() - 1;
      const years = Array.from({ length: 3 }, (_, index) => {
        const fyStart = startYear - index;
        return `${fyStart}-${String(fyStart + 1).slice(-2)}`;
      });
      form16YearSelect.innerHTML = years.map((year) => `<option>${year}</option>`).join("");
    }

    document.querySelector("#form16Form")?.addEventListener("submit", async (event) => {
      event.preventDefault();
      const financialYear = form16YearSelect.value;
      const monthlyGross = 58500;
      const monthlyDeductions = 5600;
      const annualGross = monthlyGross * 12;
      const annualDeductions = monthlyDeductions * 12;
      const annualNet = annualGross - annualDeductions;
      const estimatedTax = Math.round(annualGross * 0.05);

      const pdf = await buildForm16Image({
        certNo: makeShortPassId("FRM16", [facultyRecord.email, financialYear]),
        employeeName: facultyRecord.name,
        employeeId: makeShortPassId("EMP", [facultyRecord.email]),
        designation: facultyRecord.designation,
        department: facultyRecord.department,
        financialYear,
        annualGross,
        annualDeductions,
        annualNet,
        estimatedTax
      });
      const link = document.createElement("a");
      link.href = URL.createObjectURL(pdf);
      link.download = `form16-${financialYear}.pdf`;
      link.click();
    });

    const facultySubjectCodeMap = {
      "Database Management Systems": "DBMS",
      "Operating Systems": "OS",
      "Computer Networks": "CN",
      "Software Engineering": "SE"
    };
    const facultySubjectCode = facultySubjectCodeMap[resolveFacultySubject(facultyRecord)] || "";
    const facultyTimetableBody = document.querySelector("#facultyTimetableBody");
    const facultyTimetableEmpty = document.querySelector("#facultyTimetableEmpty");
    // Prefer the department admin's uploaded Timetable CSV (matched by this faculty's own
    // email) - falls back to the old subject-code match against the hardcoded schedule
    // for faculty whose department hasn't uploaded a timetable yet.
    const uploadedDeptTimetable = getDepartmentTimetable()[facultyRecord.department] || [];
    const uploadedFacultySlots = uploadedDeptTimetable.filter(
      (slot) => slot.facultyEmail && slot.facultyEmail.toLowerCase() === facultyEmail.toLowerCase()
    );
    const facultyTimetableSlots = uploadedFacultySlots.length > 0
      ? uploadedFacultySlots
      : facultySubjectCode
        ? defaultClassTimetable.filter((slot) => slot.code === facultySubjectCode)
        : [];

    // Today's Schedule - just re-filters the same facultyTimetableSlots already computed above
    // for the weekly timetable, no separate data source or endpoint needed.
    const todayScheduleBody = document.querySelector("#todayScheduleBody");
    const todayScheduleEmpty = document.querySelector("#todayScheduleEmpty");
    const todayScheduleDate = document.querySelector("#todayScheduleDate");
    if (todayScheduleBody) {
      const now = new Date();
      const todayName = new Intl.DateTimeFormat("en-US", { weekday: "long" }).format(now);
      const nowMinutes = now.getHours() * 60 + now.getMinutes();
      if (todayScheduleDate) todayScheduleDate.textContent = currentDayLabel(now);
      const todaySlots = facultyTimetableSlots.filter((slot) => slot.day === todayName && !classHasEnded(slot.time, nowMinutes));
      todayScheduleEmpty?.classList.toggle("is-hidden", todaySlots.length > 0);
      // Reuses the exact .today-slider markup/classes the student dashboard's Current Day
      // Timetable already established (dashboards/student-dashboard.html #academics), rather
      // than a new component, so both roles' "today" views look and behave identically.
      todayScheduleBody.innerHTML = todaySlots
        .map(
          (slot) => `
            <article>
              <span>${slot.time}</span>
              <strong>${slot.code || slot.subject}</strong>
              <small>${slot.subject}${slot.section ? ` | ${slot.section}` : ""}</small>
            </article>
          `
        )
        .join("");
    }

    const cancelledClassBody = document.querySelector("#cancelledClassBody");
    const cancelledClassEmpty = document.querySelector("#cancelledClassEmpty");

    const renderCancelledClasses = () => {
      if (!cancelledClassBody) return;
      const cancellations = getClassCancellations().filter((item) => item.facultyEmail === facultyRecord.email);
      cancelledClassEmpty?.classList.toggle("is-hidden", cancellations.length > 0);
      cancelledClassBody.innerHTML = cancellations
        .map(
          (item) => `
            <tr>
              <td>${item.subject}</td>
              <td>${formatExamDate(item.date)}</td>
              <td>${item.reason}</td>
              <td><button type="button" class="icon-btn-delete" data-remove-cancellation="${item.id}" aria-label="Remove" title="Remove">${deleteIconSvg}</button></td>
            </tr>
          `
        )
        .join("");

      cancelledClassBody.querySelectorAll("[data-remove-cancellation]").forEach((button) => {
        button.addEventListener("click", () => {
          removeClassCancellation(button.dataset.removeCancellation);
          renderCancelledClasses();
        });
      });
    };
    renderCancelledClasses();

    const classScheduleChangesNotices = document.querySelector("#classScheduleChangesNotices");
    const classScheduleChangesEmpty = document.querySelector("#classScheduleChangesEmpty");
    if (classScheduleChangesNotices && facultySubjectCode) {
      const today = new Date(new Date().toDateString());
      const otherCancellations = getClassCancellations()
        .filter((item) => item.facultyEmail !== facultyRecord.email && new Date(item.date) >= today)
        .sort((a, b) => new Date(a.date) - new Date(b.date))
        .map((item) => `<div class="fee-notice"><span>Class Cancelled: <strong>${item.subject}</strong> on ${formatExamDate(item.date)} - ${item.reason}</span></div>`);

      const otherAdhocClasses = getAdhocClassRequests()
        .filter((item) => item.facultyEmail !== facultyRecord.email && item.status === "Approved" && new Date(item.date) >= today)
        .sort((a, b) => new Date(a.date) - new Date(b.date))
        .map((item) => `<div class="fee-notice"><span>Adhoc Class Added: <strong>${item.subject}</strong> on ${formatExamDate(item.date)}, ${item.time}</span></div>`);

      const combined = [...otherAdhocClasses, ...otherCancellations];
      classScheduleChangesEmpty?.classList.toggle("is-hidden", combined.length > 0);
      classScheduleChangesNotices.innerHTML = combined.join("");
    }

    if (facultyTimetableBody) {
      if (facultyTimetableSlots.length === 0) {
        facultyTimetableEmpty?.classList.remove("is-hidden");
      } else {
        facultyTimetableBody.innerHTML = facultyTimetableSlots
          .map(
            (slot) => `
              <tr>
                <td>${slot.day}</td>
                <td>${slot.subject} | ${slot.section || "CSE III-A"}</td>
                <td>${slot.time}</td>
                <td><button type="button" class="btn-reject" data-cancel-day="${slot.day}" data-cancel-subject="${slot.subject}">Cancel Class</button></td>
              </tr>
            `
          )
          .join("");

        facultyTimetableBody.querySelectorAll("[data-cancel-day]").forEach((button) => {
          button.addEventListener("click", () => {
            const cancelClassModalOverlay = document.querySelector("#cancelClassModalOverlay");
            const cancelClassModalSubjectLine = document.querySelector("#cancelClassModalSubjectLine");
            const cancelClassModalDate = document.querySelector("#cancelClassModalDate");
            const cancelClassModalReason = document.querySelector("#cancelClassModalReason");
            if (cancelClassModalSubjectLine) {
              cancelClassModalSubjectLine.textContent = `${button.dataset.cancelSubject} - ${button.dataset.cancelDay}`;
            }
            if (cancelClassModalDate) cancelClassModalDate.value = nextDateForWeekday(button.dataset.cancelDay);
            if (cancelClassModalReason) cancelClassModalReason.value = "";
            cancelClassModalOverlay?.dataset && (cancelClassModalOverlay.dataset.cancelSubject = button.dataset.cancelSubject);
            cancelClassModalOverlay?.classList.remove("is-hidden");
          });
        });
      }
    }

    // Real studentDirectory/sectionAssignments-backed roster for a given section, replacing the
    // old hardcoded 6-name sample roster (facultyRoster/rosterBySection) - same pattern Internal
    // Marks already uses (see buildInternalMarksRoster further down).
    const buildDepartmentSectionRoster = (section) => {
      const bootstrap = getGprecDbBootstrap();
      const directory = bootstrap?.studentDirectory || [];
      const sectionAssignments = bootstrap?.sectionAssignments || {};
      const profiles = bootstrap?.studentProfiles || {};
      const targetSection = normalizeSectionLabel(section);
      return directory
        .filter((student) => student.branch === facultyRecord.department)
        .filter((student) => normalizeSectionLabel(sectionAssignments[student.studentId] || profiles[student.studentId]?.className) === targetSection)
        .sort((a, b) => a.studentId.localeCompare(b.studentId));
    };

    // Real attendance_records/attendance_entries tables now back this (see save_attendance_record
    // in tools/portal_db_server.py) - previously localStorage-only, and previously seeded with
    // fabricated "last few days" sample records for one hardcoded faculty/student on every load,
    // which no longer happens now that real marked attendance is the source of truth.
    const getFacultyAttendanceRecords = () => getGprecDbBootstrap()?.attendanceRecords || [];

    const saveFacultyAttendanceRecords = (facultyEmail, subject, section, date, entries) =>
      gprecDbPost("/attendance", { facultyEmail, subject, section, date, entries });

    const attendanceMarkingClassSelect = document.querySelector("#attendanceMarkingClassSelect");
    const attendanceMarkingBody = document.querySelector("#attendanceMarkingBody");
    const attendanceMarkingForm = document.querySelector("#attendanceMarkingForm");
    const attendanceMarkingDate = document.querySelector("#attendanceMarkingDate");
    const attendanceMarkingFeedback = document.querySelector("#attendanceMarkingFeedback");
    const todayIsoDate = () => {
      const now = new Date();
      const month = String(now.getMonth() + 1).padStart(2, "0");
      const day = String(now.getDate()).padStart(2, "0");
      return `${now.getFullYear()}-${month}-${day}`;
    };
    const yesterdayIsoDate = () => {
      const d = new Date();
      d.setDate(d.getDate() - 1);
      const month = String(d.getMonth() + 1).padStart(2, "0");
      const day = String(d.getDate()).padStart(2, "0");
      return `${d.getFullYear()}-${month}-${day}`;
    };
    const attendanceMarkingSaveButton = document.querySelector("#attendanceMarkingSaveButton");
    const attendanceMarkingViewNote = document.querySelector("#attendanceMarkingViewNote");
    if (attendanceMarkingDate) {
      attendanceMarkingDate.max = todayIsoDate();
      attendanceMarkingDate.value = todayIsoDate();
    }
    const attendanceHistoryBody = document.querySelector("#attendanceHistoryBody");
    const attendanceHistoryEmpty = document.querySelector("#attendanceHistoryEmpty");
    // Never let this end up empty - downstream code always indexes into facultyClasses[0], and
    // a real DB-sourced faculty member has no subject/class assignment yet (no such column in
    // the database), so fall back to one honest "not assigned" placeholder rather than crashing.
    const resolvedFacultyClasses = resolveFacultyClasses(facultyRecord);
    const facultyClasses = resolvedFacultyClasses.length
      ? resolvedFacultyClasses
      : [{ subject: "", section: "Not assigned" }];

    if (attendanceMarkingClassSelect) {
      attendanceMarkingClassSelect.innerHTML = facultyClasses
        .map((cls, index) => {
          // The "Not assigned" section is the synthetic fallback above (no real class on file at
          // all) - showing it as "No subject assigned - Not assigned" stacks two separate
          // fallback labels into one confusing option, so it gets a single clean label instead.
          const label = cls.section === "Not assigned"
            ? "No class assigned"
            : `${facultySubjectCodeMap[cls.subject] || cls.subject || "No subject assigned"} - ${cls.section}`;
          return `<option value="${index}">${label}</option>`;
        })
        .join("");
    }

    const currentAttendanceClass = () => facultyClasses[Number(attendanceMarkingClassSelect?.value || 0)] || facultyClasses[0];
    const currentAttendanceRoster = () => buildDepartmentSectionRoster(currentAttendanceClass().section);

    // Union of real rosters across every section this faculty teaches - the actual audience for
    // an assignment on facultySubjectCode (assignments aren't scoped to a single section).
    const buildFacultySubjectRoster = () => {
      const sections = [...new Set(facultyClasses.map((cls) => cls.section).filter((section) => section && section !== "Not assigned"))];
      const seen = new Set();
      const roster = [];
      sections.forEach((section) => {
        buildDepartmentSectionRoster(section).forEach((student) => {
          if (seen.has(student.studentId)) return;
          seen.add(student.studentId);
          roster.push(student);
        });
      });
      return roster;
    };

    const renderAttendanceMarkingHead = () => {
      const cls = currentAttendanceClass();
      const code = facultySubjectCodeMap[cls.subject];
      const label = document.querySelector("#attendanceMarkingSubject");
      if (label) {
        label.textContent = code
          ? `Subject: ${code} - ${cls.subject} | ${cls.section}`
          : "No subject mapped for attendance marking in this department.";
      }
    };

    const findAttendanceRecord = (date) => {
      const cls = currentAttendanceClass();
      const code = facultySubjectCodeMap[cls.subject];
      return getFacultyAttendanceRecords().find(
        (record) => record.facultyEmail === facultyRecord.email && record.subject === code && (record.section || "CSE III-A") === cls.section && record.date === date
      );
    };

    const getClassAttendanceRecords = () => {
      const cls = currentAttendanceClass();
      const code = facultySubjectCodeMap[cls.subject];
      return getFacultyAttendanceRecords().filter(
        (record) => record.facultyEmail === facultyRecord.email && record.subject === code && (record.section || "CSE III-A") === cls.section
      );
    };

    const studentAttendancePercent = (studentId) => {
      const records = getClassAttendanceRecords();
      if (!records.length) return null;
      let held = 0;
      let present = 0;
      records.forEach((record) => {
        const entry = record.entries.find((item) => item.studentId === studentId);
        if (!entry) return;
        held += 1;
        if (entry.present) present += 1;
      });
      if (held === 0) return null;
      return Math.round((present / held) * 100);
    };

    const renderAttendanceMarkingRoster = () => {
      if (!attendanceMarkingBody) return;
      const date = attendanceMarkingDate?.value || todayIsoDate();
      const isToday = date === todayIsoDate();
      const isYesterday = date === yesterdayIsoDate();
      const isEditable = isToday || isYesterday;
      const existingRecord = findAttendanceRecord(date);
      const presentLookup = new Map((existingRecord?.entries || []).map((entry) => [entry.studentId, entry.present]));
      const readOnly = !isEditable;

      if (attendanceMarkingViewNote) {
        if (isToday) {
          attendanceMarkingViewNote.classList.add("is-hidden");
        } else if (isYesterday) {
          attendanceMarkingViewNote.textContent = existingRecord
            ? `Editing attendance marked on ${date}. This is the only previous date that can still be corrected.`
            : `Marking attendance for ${date}. This is the only previous date that can still be marked.`;
          attendanceMarkingViewNote.classList.remove("is-hidden");
        } else if (existingRecord) {
          attendanceMarkingViewNote.textContent = `Viewing attendance already marked on ${date} (read-only). Only yesterday's attendance can be edited.`;
          attendanceMarkingViewNote.classList.remove("is-hidden");
        } else {
          attendanceMarkingViewNote.textContent = `No attendance was marked on ${date}. Only yesterday's attendance can be edited.`;
          attendanceMarkingViewNote.classList.remove("is-hidden");
        }
      }
      if (attendanceMarkingSaveButton) attendanceMarkingSaveButton.classList.toggle("is-hidden", readOnly);

      const noRecordForDate = readOnly && !existingRecord;
      attendanceMarkingBody.innerHTML = currentAttendanceRoster()
        .map((student) => {
          const percent = studentAttendancePercent(student.studentId);
          const percentCell = percent === null
            ? "-"
            : percent < 30
              ? `<span class="warn">${percent}% ⚠ Low</span>`
              : `<span class="ok">${percent}%</span>`;
          const presentCell = noRecordForDate
            ? `<span class="not-marked">Not marked</span>`
            : `<label class="toggle-switch"><input type="checkbox" data-attendance-present="${student.studentId}" ${(presentLookup.has(student.studentId) ? presentLookup.get(student.studentId) : !readOnly) ? "checked" : ""} ${readOnly ? "disabled" : ""}><span class="toggle-slider"></span></label>`;
          // Below the site's standard 75% attendance requirement (see the student dashboard's own
          // "below the 75% requirement" messaging) - only those students get a notify action, not
          // every row, since this is a manual per-student nudge, not a bulk blast.
          const notifyCell = percent !== null && percent < 75
            ? `<div class="action-cell"><button type="button" data-notify-attendance="${student.studentId}" data-notify-percent="${percent}">Notify</button></div>`
            : "-";
          return `
            <tr>
              <td>${student.studentId}</td>
              <td>${student.name}</td>
              <td>${percentCell}</td>
              <td>${presentCell}</td>
              <td>${notifyCell}</td>
            </tr>
          `;
        })
        .join("");
    };

    const renderAttendanceHistory = () => {
      if (!attendanceHistoryBody) return;
      const cls = currentAttendanceClass();
      const code = facultySubjectCodeMap[cls.subject];
      const records = getFacultyAttendanceRecords().filter(
        (record) => record.facultyEmail === facultyRecord.email && record.subject === code && (record.section || "CSE III-A") === cls.section
      );
      attendanceHistoryEmpty?.classList.toggle("is-hidden", records.length > 0);
      attendanceHistoryBody.innerHTML = records
        .map((record) => {
          const present = record.entries.filter((entry) => entry.present).length;
          return `
            <tr>
              <td>${record.date}</td>
              <td>${present}</td>
              <td>${record.entries.length - present}</td>
              <td>${record.entries.length}</td>
            </tr>
          `;
        })
        .join("");
    };

    renderAttendanceMarkingHead();
    renderAttendanceMarkingRoster();
    renderAttendanceHistory();

    attendanceMarkingBody?.addEventListener("click", (event) => {
      const button = event.target.closest("[data-notify-attendance]");
      if (!button) return;
      const rollNo = button.dataset.notifyAttendance;
      const percent = button.dataset.notifyPercent;
      const student = currentAttendanceRoster().find((item) => item.studentId === rollNo);
      button.disabled = true;
      button.textContent = "Sending...";
      const message = `your ward ${student?.name || rollNo}'s attendance is currently ${percent}%, below the required 75%. Please ensure regular attendance`;
      const result = gprecDbRequest("/notify/parent", { method: "POST", body: { rollNo, kind: "attendance", message } });
      if (result?.ok) {
        button.textContent = `Sent (${result.channel === "whatsapp" ? "WhatsApp" : "SMS"})`;
      } else if (result?.reason === "no-guardian-mobile") {
        button.textContent = "No parent mobile on file";
      } else {
        button.disabled = false;
        button.textContent = `Failed - Retry`;
      }
    });

    attendanceMarkingClassSelect?.addEventListener("change", () => {
      renderAttendanceMarkingHead();
      renderAttendanceMarkingRoster();
      renderAttendanceHistory();
      if (attendanceMarkingFeedback) attendanceMarkingFeedback.classList.add("is-hidden");
    });

    const attendanceMarkingApplyButton = document.querySelector("#attendanceMarkingApplyButton");
    attendanceMarkingApplyButton?.addEventListener("click", () => {
      if (attendanceMarkingDate.value > todayIsoDate()) {
        if (attendanceMarkingFeedback) {
          attendanceMarkingFeedback.textContent = "You cannot view or mark attendance for a future date.";
          attendanceMarkingFeedback.classList.remove("success", "is-hidden");
        }
        attendanceMarkingDate.value = todayIsoDate();
      } else if (attendanceMarkingFeedback) {
        attendanceMarkingFeedback.classList.add("is-hidden");
      }
      renderAttendanceMarkingRoster();
    });

    attendanceMarkingForm?.addEventListener("submit", (event) => {
      event.preventDefault();
      const date = attendanceMarkingDate.value;
      if (!date) return;
      if (date !== todayIsoDate() && date !== yesterdayIsoDate()) {
        if (attendanceMarkingFeedback) {
          attendanceMarkingFeedback.textContent = "Only today's or yesterday's attendance can be saved. Older dates are view-only.";
          attendanceMarkingFeedback.classList.remove("success", "is-hidden");
        }
        return;
      }
      const cls = currentAttendanceClass();
      const code = facultySubjectCodeMap[cls.subject];
      const roster = currentAttendanceRoster();
      const entries = roster.map((student) => ({
        studentId: student.studentId,
        name: student.name,
        present: document.querySelector(`[data-attendance-present="${student.studentId}"]`).checked
      }));
      const result = saveFacultyAttendanceRecords(facultyRecord.email, code, cls.section, date, entries);
      if (!result?.ok) {
        if (attendanceMarkingFeedback) {
          attendanceMarkingFeedback.textContent = "Could not reach the portal API to save attendance.";
          attendanceMarkingFeedback.classList.remove("success");
          attendanceMarkingFeedback.classList.remove("is-hidden");
        }
        return;
      }

      if (attendanceMarkingFeedback) {
        attendanceMarkingFeedback.textContent = `Attendance saved for ${date} (${cls.section}).`;
        attendanceMarkingFeedback.classList.remove("is-hidden");
        attendanceMarkingFeedback.classList.add("success");
      }
      renderAttendanceMarkingRoster();
      renderAttendanceHistory();
    });

    const internalMarksClassSelect = document.querySelector("#internalMarksClassSelect");
    const internalMarksHead = document.querySelector("#internalMarksHead");
    const internalMarksBody = document.querySelector("#internalMarksBody");
    const internalMarksEmpty = document.querySelector("#internalMarksEmpty");
    const internalMarksSubjectNote = document.querySelector("#internalMarksSubjectNote");
    const internalMarksSaveButton = document.querySelector("#internalMarksSaveButton");
    const internalMarksFeedback = document.querySelector("#internalMarksFeedback");

    if (internalMarksBody && facultyRecord.subjectCode) {
      const now = new Date();
      const academicYearStart = now.getMonth() >= 5 ? now.getFullYear() : now.getFullYear() - 1;
      const internalMarksAcademicYear = `${academicYearStart}-${String(academicYearStart + 1).slice(-2)}`;

      // Real sections this faculty actually teaches this subject in, sourced from the same
      // department-uploaded class_timetable data Today's Schedule/My Timetable already use.
      const internalMarksSections = [...new Set(facultyTimetableSlots.map((slot) => slot.section).filter(Boolean))];
      if (!internalMarksSections.length) internalMarksSections.push("-");
      if (internalMarksClassSelect) {
        internalMarksClassSelect.innerHTML = internalMarksSections.map((section) => `<option value="${section}">${section}</option>`).join("");
      }

      const internalMarksCurriculum = getGprecDbBootstrap()?.curriculum?.[facultyRecord.department] || [];
      const internalMarksTheorySubject =
        internalMarksCurriculum.find((subject) => subject.code === facultyRecord.subjectCode) ||
        { code: facultyRecord.subjectCode, name: facultyRecord.subject };
      const internalMarksLabSubject = findAssociatedLabSubject(internalMarksTheorySubject, internalMarksCurriculum);

      if (internalMarksSubjectNote) {
        internalMarksSubjectNote.textContent =
          `Subject: ${facultyRecord.subjectCode} - ${facultyRecord.subject}. Mid-1 + Mid-2 (avg, /20) + Assignment (/10) = Total /30.` +
          (internalMarksLabSubject ? ` Lab: ${internalMarksLabSubject.code} - ${internalMarksLabSubject.name}.` : "");
      }

      const currentInternalMarksSection = () => internalMarksClassSelect?.value || internalMarksSections[0];

      const buildInternalMarksRoster = (section) => {
        const bootstrap = getGprecDbBootstrap();
        const directory = bootstrap?.studentDirectory || [];
        const sectionAssignments = bootstrap?.sectionAssignments || {};
        const profiles = bootstrap?.studentProfiles || {};
        const targetSection = normalizeSectionLabel(section);
        return directory
          .filter((student) => student.branch === facultyRecord.department)
          .filter((student) => normalizeSectionLabel(sectionAssignments[student.studentId] || profiles[student.studentId]?.className) === targetSection)
          .sort((a, b) => a.studentId.localeCompare(b.studentId));
      };

      const renderInternalMarksRoster = () => {
        const section = currentInternalMarksSection();
        const roster = buildInternalMarksRoster(section);
        internalMarksEmpty?.classList.toggle("is-hidden", roster.length > 0);

        const existing = gprecDbRequest(
          `/internal-marks/by-subject?subjectCode=${encodeURIComponent(facultyRecord.subjectCode)}&section=${encodeURIComponent(section)}&academicYear=${encodeURIComponent(internalMarksAcademicYear)}`
        );
        const existingByRoll = {};
        (existing?.marks || []).forEach((row) => {
          existingByRoll[row.rollNo] = row;
        });

        if (internalMarksHead) {
          internalMarksHead.innerHTML = `
            <tr>
              <th>Roll Number</th><th>Student Name</th><th>Mid-1 /20</th><th>Mid-2 /20</th>
              <th>Assignment /10</th><th>Total /30</th>${internalMarksLabSubject ? "<th>Lab /30</th>" : ""}
            </tr>
          `;
        }

        internalMarksBody.innerHTML = roster
          .map((student) => {
            const marks = existingByRoll[student.studentId] || {};
            const total = computeInternalTotal(marks.mid1, marks.mid2, marks.assignment);
            return `
              <tr data-roll="${student.studentId}">
                <td>${student.studentId}</td>
                <td>${student.name}</td>
                <td><input type="number" min="0" max="20" step="0.5" class="internal-marks-input" data-field="mid1" value="${marks.mid1 ?? ""}"></td>
                <td><input type="number" min="0" max="20" step="0.5" class="internal-marks-input" data-field="mid2" value="${marks.mid2 ?? ""}"></td>
                <td><input type="number" min="0" max="10" step="0.5" class="internal-marks-input" data-field="assignment" value="${marks.assignment ?? ""}"></td>
                <td class="internal-marks-total">${total ?? "-"}</td>
                ${internalMarksLabSubject ? `<td><input type="number" min="0" max="30" step="0.5" class="internal-marks-input" data-field="labMarks" value="${marks.labMarks ?? ""}"></td>` : ""}
              </tr>
            `;
          })
          .join("");

        internalMarksBody.querySelectorAll(".internal-marks-input").forEach((input) => {
          input.addEventListener("input", () => {
            const row = input.closest("tr");
            const totalCell = row?.querySelector(".internal-marks-total");
            if (!totalCell) return;
            const readField = (field) => {
              const value = row.querySelector(`[data-field="${field}"]`)?.value;
              return value === "" || value === undefined ? null : value;
            };
            const total = computeInternalTotal(readField("mid1"), readField("mid2"), readField("assignment"));
            totalCell.textContent = total ?? "-";
          });
        });
      };

      renderInternalMarksRoster();
      internalMarksClassSelect?.addEventListener("change", renderInternalMarksRoster);

      internalMarksSaveButton?.addEventListener("click", () => {
        const section = currentInternalMarksSection();
        const rows = Array.from(internalMarksBody.querySelectorAll("tr[data-roll]")).map((row) => {
          const getValue = (field) => {
            const value = row.querySelector(`[data-field="${field}"]`)?.value;
            return value === "" || value === undefined ? null : value;
          };
          return {
            rollNo: row.dataset.roll,
            mid1: getValue("mid1"),
            mid2: getValue("mid2"),
            assignment: getValue("assignment"),
            labMarks: internalMarksLabSubject ? getValue("labMarks") : null
          };
        });
        if (internalMarksFeedback) {
          internalMarksFeedback.textContent = "Saving...";
          internalMarksFeedback.classList.remove("is-hidden", "success");
        }
        const result = gprecDbRequest("/internal-marks", {
          method: "POST",
          body: { department: facultyRecord.department, subjectCode: facultyRecord.subjectCode, section, academicYear: internalMarksAcademicYear, rows }
        });
        if (internalMarksFeedback) {
          if (result?.ok) {
            internalMarksFeedback.textContent = "Marks saved.";
            internalMarksFeedback.classList.add("success");
          } else {
            internalMarksFeedback.textContent = result?.error || "Could not save marks.";
            internalMarksFeedback.classList.remove("success");
          }
        }
      });
    } else if (internalMarksSubjectNote) {
      internalMarksSubjectNote.textContent = "No subject assigned - internal marks entry is unavailable.";
      internalMarksEmpty?.classList.remove("is-hidden");
    }

    const courseLessonBuilder = document.querySelector("#courseLessonBuilder");
    if (courseLessonBuilder) {
      const addLessonRow = () => {
        const row = document.createElement("div");
        row.className = "course-lesson-row";
        row.innerHTML = `
          <label>Lesson Title<input type="text" data-lesson-title placeholder="e.g. Arrays and Linked Lists"></label>
          <label>Link URL<input type="url" data-lesson-url placeholder="https://..."></label>
          <label>Or Upload a Document<input type="file" data-lesson-file></label>
          <button type="button" class="icon-btn-delete" data-remove-lesson-row aria-label="Remove lesson">${deleteIconSvg}</button>
        `;
        row.querySelector("[data-remove-lesson-row]").addEventListener("click", () => row.remove());
        courseLessonBuilder.appendChild(row);
      };
      document.querySelector("#addCourseLessonButton")?.addEventListener("click", addLessonRow);
      addLessonRow();

      const myCoursesListBody = document.querySelector("#myCoursesListBody");
      const myCoursesEmpty = document.querySelector("#myCoursesEmpty");

      const courseStudentListGroup = (label, students) => {
        const bySection = {};
        (students || []).forEach((student) => {
          const key = student.className || "Unassigned";
          (bySection[key] = bySection[key] || []).push(student);
        });
        const sectionKeys = Object.keys(bySection).sort();
        return `
          <div class="course-student-list-group">
            <h4>${label} (${(students || []).length})</h4>
            ${
              sectionKeys.length
                ? sectionKeys
                    .map(
                      (section) => `
                        <div class="course-student-list-section">
                          <span class="course-student-list-section-label">${section}</span>
                          <ul>
                            ${bySection[section].map((student) => `<li>${student.name} <span>${student.rollNo}</span></li>`).join("")}
                          </ul>
                        </div>
                      `
                    )
                    .join("")
                : `<p class="course-student-list-empty">None</p>`
            }
          </div>
        `;
      };

      const renderMyCourses = () => {
        if (!myCoursesListBody) return;
        const openCourseIds = new Set(
          [...myCoursesListBody.querySelectorAll("details[open]")].map((d) => d.dataset.courseId)
        );
        const courses = gprecDbRequest("/courses/mine/stats", { method: "POST", body: {} })?.courses || [];
        const lessonsById = {};
        courses.forEach((course) => (course.lessons || []).forEach((lesson) => { lessonsById[lesson.id] = lesson; }));
        myCoursesEmpty?.classList.toggle("is-hidden", courses.length > 0);
        myCoursesListBody.innerHTML = `<div class="profile-accordion">${courses
          .map(
            (course) => `
              <details class="profile-accordion-item" data-course-id="${course.courseId}">
                <summary>
                  <span>${course.title}</span>
                  <span class="course-summary-faculty"><span class="course-assigned-by-label">Sections</span> ${(course.sections || []).join(", ") || "All sections"}</span>
                </summary>
                <div class="profile-accordion-body">
                  <div class="course-card-head">
                    <p class="bus-service-stops">${course.description || ""}</p>
                    <button type="button" class="icon-btn-delete" data-remove-course="${course.courseId}" aria-label="Remove course">${deleteIconSvg}</button>
                  </div>
                  <div class="admin-metric-grid">
                    <article><strong>${course.registered}</strong><span>Registered</span></article>
                    <article><strong>${course.inProgress}</strong><span>In Progress</span></article>
                    <article><strong>${course.completed}</strong><span>Completed</span></article>
                  </div>
                  <div class="course-student-lists">
                    ${courseStudentListGroup("Registered", course.registeredStudents)}
                    ${courseStudentListGroup("In Progress", course.inProgressStudents)}
                    ${courseStudentListGroup("Completed", course.completedStudents)}
                    ${courseStudentListGroup("Not Registered", course.notRegisteredStudents)}
                  </div>
                  <div class="course-lesson-list">
                    ${
                      (course.lessons || [])
                        .map(
                          (lesson) => `
                            <div class="course-lesson-display-row">
                              <strong>${lesson.title}</strong>
                              <div class="course-lesson-actions">
                                <a href="${lesson.resourceUrl}" data-open-resource="${lesson.id}">Open resource</a>
                                <button type="button" class="icon-btn-edit" data-edit-lesson="${lesson.id}" aria-label="Edit lesson">${editIconSvg}</button>
                                <button type="button" class="icon-btn-delete" data-remove-lesson="${lesson.id}" aria-label="Remove lesson">${deleteIconSvg}</button>
                              </div>
                            </div>
                          `
                        )
                        .join("") || `<p class="lookup-empty">No lessons yet.</p>`
                    }
                  </div>
                  <div class="course-lesson-form" data-course-form="${course.courseId}">
                    <label>Lesson Title<input type="text" data-new-lesson-title placeholder="e.g. Trees and Graphs"></label>
                    <label>Link URL<input type="url" data-new-lesson-url placeholder="https://..."></label>
                    <div class="course-lesson-file-field">
                      <span class="course-lesson-file-label">Or Upload a Document</span>
                      <div class="course-lesson-file-control">
                        <button type="button" class="course-lesson-file-trigger" data-file-trigger>Choose File</button>
                        <span class="course-lesson-file-name" data-file-name>No file chosen</span>
                        <input type="file" data-new-lesson-file class="course-lesson-file-input-hidden">
                      </div>
                    </div>
                    <button type="button" class="pass-action-button" data-add-lesson-submit="${course.courseId}">+ Add Lesson</button>
                    <button type="button" class="pass-action-button pass-action-button-reject is-hidden" data-cancel-lesson-edit>Cancel</button>
                  </div>
                </div>
              </details>
            `
          )
          .join("")}</div>`;
        myCoursesListBody.querySelectorAll("details").forEach((d) => {
          if (openCourseIds.has(d.dataset.courseId)) d.open = true;
        });
        myCoursesListBody.querySelectorAll("[data-remove-course]").forEach((button) => {
          button.addEventListener("click", () => {
            gprecDbRequest("/courses/remove", { method: "POST", body: { id: button.dataset.removeCourse } });
            renderMyCourses();
          });
        });
        myCoursesListBody.querySelectorAll("[data-remove-lesson]").forEach((button) => {
          button.addEventListener("click", () => {
            gprecDbRequest("/courses/lessons/remove", { method: "POST", body: { lessonId: button.dataset.removeLesson } });
            renderMyCourses();
          });
        });
        const resetLessonForm = (formRow) => {
          delete formRow.dataset.editingLessonId;
          formRow.querySelector("[data-new-lesson-title]").value = "";
          formRow.querySelector("[data-new-lesson-url]").value = "";
          formRow.querySelector("[data-new-lesson-file]").value = "";
          formRow.querySelector("[data-file-name]").textContent = "No file chosen";
          formRow.querySelector("[data-add-lesson-submit]").textContent = "+ Add Lesson";
          formRow.querySelector("[data-cancel-lesson-edit]").classList.add("is-hidden");
        };
        myCoursesListBody.querySelectorAll("[data-open-resource]").forEach((button) => {
          button.addEventListener("click", (event) => {
            event.preventDefault();
            const lesson = lessonsById[button.dataset.openResource];
            if (lesson) openResourceModal(lesson.resourceUrl, lesson.title);
          });
        });
        myCoursesListBody.querySelectorAll("[data-edit-lesson]").forEach((button) => {
          button.addEventListener("click", () => {
            const lesson = lessonsById[button.dataset.editLesson];
            const formRow = button.closest(".profile-accordion-item").querySelector("[data-course-form]");
            if (!lesson || !formRow) return;
            formRow.dataset.editingLessonId = lesson.id;
            formRow.querySelector("[data-new-lesson-title]").value = lesson.title;
            formRow.querySelector("[data-new-lesson-url]").value = lesson.resourceUrl;
            formRow.querySelector("[data-add-lesson-submit]").textContent = "Save Changes";
            formRow.querySelector("[data-cancel-lesson-edit]").classList.remove("is-hidden");
            formRow.scrollIntoView({ behavior: "smooth", block: "nearest" });
          });
        });
        myCoursesListBody.querySelectorAll("[data-cancel-lesson-edit]").forEach((button) => {
          button.addEventListener("click", () => resetLessonForm(button.closest(".course-lesson-form")));
        });
        myCoursesListBody.querySelectorAll("[data-file-trigger]").forEach((button) => {
          button.addEventListener("click", () => {
            button.closest(".course-lesson-file-control").querySelector("[data-new-lesson-file]").click();
          });
        });
        myCoursesListBody.querySelectorAll("[data-new-lesson-file]").forEach((input) => {
          input.addEventListener("change", () => {
            input.closest(".course-lesson-file-control").querySelector("[data-file-name]").textContent =
              input.files?.[0]?.name || "No file chosen";
          });
        });
        myCoursesListBody.querySelectorAll("[data-add-lesson-submit]").forEach((button) => {
          button.addEventListener("click", async () => {
            const row = button.closest(".course-lesson-form");
            const title = row.querySelector("[data-new-lesson-title]")?.value.trim() || "";
            const linkUrl = row.querySelector("[data-new-lesson-url]")?.value.trim() || "";
            const file = row.querySelector("[data-new-lesson-file]")?.files?.[0] || null;
            const editingLessonId = row.dataset.editingLessonId || "";
            button.disabled = true;
            button.textContent = editingLessonId ? "Saving..." : "Adding...";
            let resourceUrl = linkUrl;
            if (file) {
              const uploaded = await readFileAsDataUrl(file, "courses/lessons");
              resourceUrl = uploaded?.dataUrl || linkUrl;
            }
            if (title && resourceUrl) {
              if (editingLessonId) {
                gprecDbRequest("/courses/lessons/update", { method: "POST", body: { lessonId: editingLessonId, title, resourceUrl } });
              } else {
                gprecDbRequest("/courses/lessons/add", {
                  method: "POST",
                  body: { courseId: button.dataset.addLessonSubmit, title, resourceUrl }
                });
              }
              renderMyCourses();
            } else {
              button.disabled = false;
              button.textContent = editingLessonId ? "Save Changes" : "+ Add Lesson";
            }
          });
        });
      };

      const courseSectionChecklist = document.querySelector("#courseSectionChecklist");
      if (courseSectionChecklist) {
        const sections = gprecDbRequest("/courses/sections", { method: "POST", body: {} })?.sections || [];
        courseSectionChecklist.innerHTML = sections
          .map((section) => `<label><input type="checkbox" data-course-section value="${section}">${section}</label>`)
          .join("");
      }

      document.querySelector("#createCourseButton")?.addEventListener("click", async () => {
        const title = document.querySelector("#courseTitleInput")?.value.trim() || "";
        const description = document.querySelector("#courseDescriptionInput")?.value.trim() || "";
        const sections = [...(courseSectionChecklist?.querySelectorAll("[data-course-section]:checked") || [])].map(
          (checkbox) => checkbox.value
        );
        const feedback = document.querySelector("#createCourseFeedback");
        const createButton = document.querySelector("#createCourseButton");

        createButton.disabled = true;
        createButton.textContent = "Creating...";
        const lessons = [];
        for (const row of courseLessonBuilder.querySelectorAll(".course-lesson-row")) {
          const lessonTitle = row.querySelector("[data-lesson-title]")?.value.trim() || "";
          const linkUrl = row.querySelector("[data-lesson-url]")?.value.trim() || "";
          const file = row.querySelector("[data-lesson-file]")?.files?.[0] || null;
          let resourceUrl = linkUrl;
          if (file) {
            const uploaded = await readFileAsDataUrl(file, "courses/lessons");
            resourceUrl = uploaded?.dataUrl || linkUrl;
          }
          if (lessonTitle && resourceUrl) lessons.push({ title: lessonTitle, resourceUrl });
        }
        createButton.disabled = false;
        createButton.textContent = "Create Course";

        if (feedback) feedback.classList.remove("success");
        if (!title || !description || !sections.length || !lessons.length) {
          if (feedback) {
            feedback.textContent = "Enter a title, description, at least one section, and at least one lesson (title + link or document).";
            feedback.classList.remove("is-hidden");
          }
          return;
        }
        const result = gprecDbRequest("/courses", { method: "POST", body: { title, description, sections, lessons } });
        if (result?.ok) {
          document.querySelector("#courseTitleInput").value = "";
          document.querySelector("#courseDescriptionInput").value = "";
          courseSectionChecklist.querySelectorAll("[data-course-section]").forEach((checkbox) => (checkbox.checked = false));
          courseLessonBuilder.innerHTML = "";
          addLessonRow();
          if (feedback) {
            feedback.textContent = "Course created.";
            feedback.classList.add("success");
            feedback.classList.remove("is-hidden");
          }
          renderMyCourses();
        } else if (feedback) {
          feedback.textContent = result?.error || "Could not create course.";
          feedback.classList.remove("is-hidden");
        }
      });

      renderMyCourses();
    }

    const classSectionChecklist = document.querySelector("#classSectionChecklist");
    if (classSectionChecklist) {
      const sections = gprecDbRequest("/courses/sections", { method: "POST", body: {} })?.sections || [];
      classSectionChecklist.innerHTML = sections
        .map((section) => `<label><input type="checkbox" data-class-section value="${section}">${section}</label>`)
        .join("");

      const myOnlineClassesListBody = document.querySelector("#myOnlineClassesListBody");
      const myOnlineClassesEmpty = document.querySelector("#myOnlineClassesEmpty");
      let myClassesById = {};

      const renderMyOnlineClasses = () => {
        const classes = gprecDbRequest("/online-classes/all", { method: "POST", body: {} })?.classes || [];
        myClassesById = {};
        classes.forEach((item) => { myClassesById[item.id] = item; });
        myOnlineClassesEmpty?.classList.toggle("is-hidden", classes.length > 0);
        myOnlineClassesListBody.innerHTML = classes
          .map(
            (item) => `
              <article class="bus-service-card">
                <div class="bus-service-card-head">
                  <strong>${item.title}</strong>
                  <span class="webinar-card-meta"><span>${item.scheduledAt}</span>${getLiveStatusBadge(item)}</span>
                </div>
                ${
                  item.watchingCount > 0
                    ? `<div class="webinar-watching-row">${renderWebinarWatchingRow(item)}</div>`
                    : ""
                }
                <p class="bus-service-stops">${item.description}</p>
                <p class="course-summary-faculty"><span class="course-assigned-by-label">Sections</span> ${(item.sections || []).join(", ")}</p>
                <div class="course-card-footer">
                  <a href="${item.liveLink}" class="pass-action-button" data-open-class="${item.id}">Join Class</a>
                  <button type="button" class="icon-btn-delete" data-remove-class="${item.id}" aria-label="Remove class">${deleteIconSvg}</button>
                </div>
              </article>
            `
          )
          .join("");
        myOnlineClassesListBody.querySelectorAll("[data-open-class]").forEach((link) => {
          link.addEventListener("click", (event) => {
            event.preventDefault();
            const item = myClassesById[link.dataset.openClass];
            if (!item) return;
            openResourceModal(item.liveLink, item.title, () => {
              gprecDbRequest("/online-classes/view-ping", { method: "POST", body: { classId: item.id } });
              const fresh = (gprecDbRequest("/online-classes/all", { method: "POST", body: {} })?.classes || []).find(
                (c) => c.id === item.id
              );
              return renderWebinarWatchingRow(fresh);
            });
          });
        });
        myOnlineClassesListBody.querySelectorAll("[data-remove-class]").forEach((button) => {
          button.addEventListener("click", () => {
            gprecDbRequest("/online-classes/remove", { method: "POST", body: { id: button.dataset.removeClass } });
            renderMyOnlineClasses();
          });
        });
      };
      renderMyOnlineClasses();

      document.querySelector("#scheduleClassButton")?.addEventListener("click", () => {
        const title = document.querySelector("#classTitleInput")?.value.trim() || "";
        const description = document.querySelector("#classDescriptionInput")?.value.trim() || "";
        const scheduledAt = document.querySelector("#classScheduledInput")?.value || "";
        const liveLink = document.querySelector("#classLiveLinkInput")?.value.trim() || "";
        const sectionsChecked = [...classSectionChecklist.querySelectorAll("[data-class-section]:checked")].map(
          (checkbox) => checkbox.value
        );
        const feedback = document.querySelector("#scheduleClassFeedback");
        if (feedback) feedback.classList.remove("success");
        if (!title || !description || !scheduledAt || !liveLink || !sectionsChecked.length) {
          if (feedback) {
            feedback.textContent = "Enter a title, description, scheduled time, live link, and at least one section.";
            feedback.classList.remove("is-hidden");
          }
          return;
        }
        const result = gprecDbRequest("/online-classes", {
          method: "POST",
          body: { title, description, liveLink, scheduledAt, sections: sectionsChecked }
        });
        if (result?.ok) {
          document.querySelector("#classTitleInput").value = "";
          document.querySelector("#classDescriptionInput").value = "";
          document.querySelector("#classScheduledInput").value = "";
          document.querySelector("#classLiveLinkInput").value = "";
          classSectionChecklist.querySelectorAll("[data-class-section]").forEach((checkbox) => (checkbox.checked = false));
          if (feedback) {
            feedback.textContent = "Online class scheduled.";
            feedback.classList.add("success");
            feedback.classList.remove("is-hidden");
          }
          renderMyOnlineClasses();
        } else if (feedback) {
          feedback.textContent = result?.error || "Could not schedule class.";
          feedback.classList.remove("is-hidden");
        }
      });
    }

    const assignmentsSubjectLabel = document.querySelector("#assignmentsSubjectLabel");
    if (assignmentsSubjectLabel) {
      assignmentsSubjectLabel.textContent = facultySubjectCode
        ? `Subject: ${facultySubjectCode} - ${facultyRecord.subject}`
        : "No subject mapped for assignments in this department.";
    }
    const materialsSubjectLabel = document.querySelector("#materialsSubjectLabel");
    if (materialsSubjectLabel) {
      materialsSubjectLabel.textContent = facultySubjectCode
        ? `Subject: ${facultySubjectCode} - ${facultyRecord.subject}`
        : "No subject mapped for course materials in this department.";
    }

    const assignmentListBody = document.querySelector("#assignmentListBody");
    const assignmentListEmpty = document.querySelector("#assignmentListEmpty");
    const submissionsListBody = document.querySelector("#submissionsListBody");
    const submissionsListEmpty = document.querySelector("#submissionsListEmpty");
    const submissionsPanelTitle = document.querySelector("#submissionsPanelTitle");
    const createAssignmentForm = document.querySelector("#createAssignmentForm");
    const assignmentCreateFeedback = document.querySelector("#assignmentCreateFeedback");

    document.querySelector("#commentModalClose")?.addEventListener("click", () => {
      document.querySelector("#commentModalOverlay")?.classList.add("is-hidden");
    });
    document.querySelector("#commentModalOverlay")?.addEventListener("click", (event) => {
      if (event.target.id === "commentModalOverlay") event.target.classList.add("is-hidden");
    });

    document.querySelector("#cancelClassModalClose")?.addEventListener("click", () => {
      document.querySelector("#cancelClassModalOverlay")?.classList.add("is-hidden");
    });
    document.querySelector("#cancelClassModalOverlay")?.addEventListener("click", (event) => {
      if (event.target.id === "cancelClassModalOverlay") event.target.classList.add("is-hidden");
    });
    document.querySelector("#cancelClassModalForm")?.addEventListener("submit", (event) => {
      event.preventDefault();
      const cancelClassModalOverlay = document.querySelector("#cancelClassModalOverlay");
      const subject = cancelClassModalOverlay?.dataset.cancelSubject || "";
      const date = document.querySelector("#cancelClassModalDate").value;
      const reason = document.querySelector("#cancelClassModalReason").value.trim();

      createClassCancellation({
        facultyEmail: facultyRecord.email,
        subjectCode: facultySubjectCode,
        subject,
        date,
        reason
      });
      cancelClassModalOverlay?.classList.add("is-hidden");
      renderCancelledClasses();
    });

    const renderSubmissionsFor = (assignment) => {
      if (!submissionsListBody) return;
      if (!assignment) {
        submissionsListBody.innerHTML = "";
        if (submissionsListEmpty) {
          submissionsListEmpty.textContent = "Select an assignment above to view submissions.";
          submissionsListEmpty.classList.remove("is-hidden");
        }
        if (submissionsPanelTitle) submissionsPanelTitle.textContent = "Submissions";
        return;
      }
      if (submissionsPanelTitle) submissionsPanelTitle.textContent = `Submissions - ${assignment.title}`;
      const submissions = getAssignmentSubmissions().filter((submission) => submission.assignmentId === assignment.id);
      const submittedIds = new Set(submissions.map((submission) => submission.studentId));
      const pendingStudents = buildFacultySubjectRoster().filter((student) => !submittedIds.has(student.studentId));

      const submittedRows = submissions
        .map(
          (submission) => `
            <tr>
              <td>${resolveStudentDisplayName(submission.studentId, submission.studentName)} (${submission.studentId})</td>
              <td><span class="ok">Submitted</span></td>
              <td>${submission.submittedAt}</td>
              <td>${
                submission.files?.length
                  ? submission.files
                      .map(
                        (file, index) =>
                          `<button type="button" class="notice-download" title="${file.name}" data-download-file="${submission.id}:${index}">View Document</button>`
                      )
                      .join(" ")
                  : "-"
              }</td>
              <td>${
                submission.comment
                  ? `<button type="button" class="notice-download" data-comment-show="${submission.id}">View Comment</button>`
                  : "-"
              }</td>
              <td>${
                getPlagiarismCheck("assignment", submission.id)
                  ? plagiarismBadgeHtml("assignment", submission.id)
                  : submission.files?.length
                    ? `<span data-plagiarism-result="${submission.id}"><button type="button" class="notice-download" data-plagiarism-check-assignment="${submission.id}">Check Plagiarism</button></span>`
                    : "-"
              }</td>
            </tr>
          `
        )
        .join("");

      const pendingRows = pendingStudents
        .map(
          (student) => `
            <tr>
              <td>${student.name} (${student.studentId})</td>
              <td><span class="warn">Not submitted</span></td>
              <td>-</td>
              <td>-</td>
              <td>-</td>
              <td>-</td>
            </tr>
          `
        )
        .join("");

      submissionsListBody.innerHTML = submittedRows + pendingRows;
      submissionsListEmpty?.classList.add("is-hidden");

      submissionsListBody.querySelectorAll("[data-comment-show]").forEach((button) => {
        button.addEventListener("click", () => {
          const target = submissions.find((item) => item.id === button.dataset.commentShow);
          if (!target) return;
          const commentModalOverlay = document.querySelector("#commentModalOverlay");
          const commentModalText = document.querySelector("#commentModalText");
          if (commentModalText) commentModalText.textContent = target.comment;
          commentModalOverlay?.classList.remove("is-hidden");
        });
      });

      submissionsListBody.querySelectorAll("[data-download-file]").forEach((button) => {
        button.addEventListener("click", () => {
          const [submissionId, fileIndex] = button.dataset.downloadFile.split(":");
          const submission = submissions.find((item) => item.id === submissionId);
          const file = submission?.files?.[Number(fileIndex)];
          if (!file) return;
          window.open(file.dataUrl, "_blank");
        });
      });

      submissionsListBody.querySelectorAll("[data-plagiarism-check-assignment]").forEach((button) => {
        button.addEventListener("click", () => {
          const submissionId = button.dataset.plagiarismCheckAssignment;
          const submission = submissions.find((item) => item.id === submissionId);
          const resultEl = button.closest("[data-plagiarism-result]");
          if (!submission) return;
          button.disabled = true;
          button.textContent = "Reading file...";
          const extracted = gprecDbRequest("/plagiarism/extract-text", { method: "POST", body: { submissionId } });
          if (!extracted?.ok) {
            button.disabled = false;
            button.textContent = "Check Plagiarism";
            if (resultEl) resultEl.insertAdjacentHTML("beforeend", ` <span class="portal-note">Only PDF/Word files can be read - no readable text found.</span>`);
            return;
          }
          runPlagiarismCheck({
            type: "assignment",
            referenceId: submissionId,
            rollNo: submission.studentId,
            text: extracted.text,
            button,
            resultEl
          });
        });
      });
    };

    const renderAssignmentList = () => {
      if (!assignmentListBody) return;
      const assignments = getAssignments().filter((assignment) => assignment.subjectCode === facultySubjectCode);
      assignmentListEmpty?.classList.toggle("is-hidden", assignments.length > 0);
      const submissions = getAssignmentSubmissions();
      const subjectRosterSize = buildFacultySubjectRoster().length;

      assignmentListBody.innerHTML = assignments
        .map((assignment) => {
          const submissionCount = submissions.filter((submission) => submission.assignmentId === assignment.id).length;
          return `
            <tr>
              <td>${assignment.title}</td>
              <td>${formatOutingDateTime(assignment.dueDate)}</td>
              <td>${
                assignment.document
                  ? `<button type="button" class="notice-download" title="${assignment.document.name}" data-download-assignment-doc="${assignment.id}">View Document</button>`
                  : "-"
              }</td>
              <td>${submissionCount} / ${subjectRosterSize}</td>
              <td>
                <div class="action-cell">
                  <button type="button" class="uniform-btn" data-view-submissions="${assignment.id}">View Submissions</button>
                  <button type="button" class="icon-btn-delete" data-remove-assignment="${assignment.id}" aria-label="Remove" title="Remove">${deleteIconSvg}</button>
                </div>
              </td>
            </tr>
          `;
        })
        .join("");

      assignmentListBody.querySelectorAll("[data-view-submissions]").forEach((button) => {
        button.addEventListener("click", () => {
          const assignment = assignments.find((item) => item.id === button.dataset.viewSubmissions);
          renderSubmissionsFor(assignment);
        });
      });

      assignmentListBody.querySelectorAll("[data-download-assignment-doc]").forEach((button) => {
        button.addEventListener("click", () => {
          const assignment = assignments.find((item) => item.id === button.dataset.downloadAssignmentDoc);
          if (!assignment?.document) return;
          window.open(assignment.document.dataUrl, "_blank");
        });
      });

      assignmentListBody.querySelectorAll("[data-remove-assignment]").forEach((button) => {
        button.addEventListener("click", () => {
          removeAssignment(button.dataset.removeAssignment);
          renderAssignmentList();
          renderSubmissionsFor(null);
        });
      });
    };

    createAssignmentForm?.addEventListener("submit", async (event) => {
      event.preventDefault();
      if (!facultySubjectCode) {
        if (assignmentCreateFeedback) {
          assignmentCreateFeedback.textContent = "Assignments are not supported for this department.";
          assignmentCreateFeedback.classList.remove("is-hidden", "success");
        }
        return;
      }
      const title = document.querySelector("#assignmentTitleInput").value.trim();
      const description = document.querySelector("#assignmentDescriptionInput").value.trim();
      const dueDate = document.querySelector("#assignmentDueDateInput").value;
      const documentFile = document.querySelector("#assignmentDocumentInput")?.files?.[0] || null;

      let attachedDocument = null;
      if (documentFile) {
        try {
          attachedDocument = await readFileAsDataUrl(documentFile, `assignments/materials/${facultyRecord.department || "unassigned"}`);
        } catch {
          if (assignmentCreateFeedback) {
            assignmentCreateFeedback.textContent = "Could not read the attached document. Please try again.";
            assignmentCreateFeedback.classList.remove("is-hidden", "success");
          }
          return;
        }
      }

      const result = createAssignment({
        department: facultyRecord.department,
        subjectCode: facultySubjectCode,
        title,
        description,
        dueDate,
        document: attachedDocument,
        createdBy: facultyRecord.name
      });
      if (!result?.ok) {
        if (assignmentCreateFeedback) {
          assignmentCreateFeedback.textContent = "Could not reach the portal API to save the assignment.";
          assignmentCreateFeedback.classList.remove("is-hidden", "success");
        }
        return;
      }

      if (assignmentCreateFeedback) {
        assignmentCreateFeedback.textContent = `${title} created. Students of ${facultySubjectCode} will see it in their subject page.`;
        assignmentCreateFeedback.classList.remove("is-hidden");
        assignmentCreateFeedback.classList.add("success");
      }
      createAssignmentForm.reset();
      renderAssignmentList();
    });

    renderAssignmentList();
    renderSubmissionsFor(null);

    const materialListBody = document.querySelector("#materialListBody");
    const materialListEmpty = document.querySelector("#materialListEmpty");
    const uploadMaterialForm = document.querySelector("#uploadMaterialForm");
    const materialUploadFeedback = document.querySelector("#materialUploadFeedback");

    const renderMaterialList = () => {
      if (!materialListBody) return;
      const materials = getCourseMaterials().filter((material) => material.subjectCode === facultySubjectCode);
      materialListEmpty?.classList.toggle("is-hidden", materials.length > 0);
      materialListBody.innerHTML = materials
        .map(
          (material) => `
            <tr>
              <td>${material.title}</td>
              <td>${material.description}</td>
              <td>${material.fileName}</td>
              <td>${material.uploadedAt}</td>
              <td><button type="button" class="icon-btn-delete" data-remove-material="${material.id}" aria-label="Remove" title="Remove">${deleteIconSvg}</button></td>
            </tr>
          `
        )
        .join("");

      materialListBody.querySelectorAll("[data-remove-material]").forEach((button) => {
        button.addEventListener("click", () => {
          removeCourseMaterial(button.dataset.removeMaterial);
          renderMaterialList();
        });
      });
    };

    uploadMaterialForm?.addEventListener("submit", (event) => {
      event.preventDefault();
      if (!facultySubjectCode) {
        if (materialUploadFeedback) {
          materialUploadFeedback.textContent = "Course materials are not supported for this department.";
          materialUploadFeedback.classList.remove("is-hidden", "success");
        }
        return;
      }
      const title = document.querySelector("#materialTitleInput").value.trim();
      const description = document.querySelector("#materialDescriptionInput").value.trim();
      const fileInput = document.querySelector("#materialFileInput");
      const fileName = fileInput.files?.[0]?.name || "Untitled file";

      createCourseMaterial({
        subjectCode: facultySubjectCode,
        title,
        description,
        fileName
      });

      if (materialUploadFeedback) {
        materialUploadFeedback.textContent = `${title} uploaded. Students of ${facultySubjectCode} will see it in their subject page.`;
        materialUploadFeedback.classList.remove("is-hidden");
        materialUploadFeedback.classList.add("success");
      }
      uploadMaterialForm.reset();
      renderMaterialList();
    });

    renderMaterialList();

    const leaveApproverName = facultyRecord.isHod
      ? "Principal Office (admin@gprec.ac.in)"
      : `${defaultDepartmentFacultyByDept[facultyRecord.department]?.hod.name || "your HOD"} (${defaultDepartmentFacultyByDept[facultyRecord.department]?.hod.email || "-"})`;

    const leaveApprovalRouteNote = document.querySelector("#leaveApprovalRouteNote");
    if (leaveApprovalRouteNote) {
      leaveApprovalRouteNote.textContent = `Your leave request will be sent to ${leaveApproverName} for approval.`;
    }

    const myLeaveRequestsBody = document.querySelector("#myLeaveRequestsBody");
    const myLeaveRequestsEmpty = document.querySelector("#myLeaveRequestsEmpty");
    const renderMyLeaveRequests = () => {
      if (!myLeaveRequestsBody) return;
      const requests = getLeaveRequests().filter((item) => item.facultyEmail === facultyRecord.email);
      myLeaveRequestsEmpty?.classList.toggle("is-hidden", requests.length > 0);
      myLeaveRequestsBody.innerHTML = requests
        .map(
          (item) => `
            <tr>
              <td>${item.leaveType}</td>
              <td>${formatExamDate(item.fromDate)}</td>
              <td>${formatExamDate(item.toDate)}</td>
              <td>${item.reason}</td>
              <td><span class="${requestStatusClass(item.status)}">${item.status}</span></td>
              <td>${
                item.status === "Approved" || item.status === "Pending"
                  ? `<button type="button" class="icon-btn-delete" data-leave-cancel="${item.id}" aria-label="Cancel Request" title="Cancel Request">${deleteIconSvg}</button>`
                  : "-"
              }</td>
            </tr>
          `
        )
        .join("");

      myLeaveRequestsBody.querySelectorAll("[data-leave-cancel]").forEach((button) => {
        button.addEventListener("click", () => {
          removeLeaveRequest(button.dataset.leaveCancel);
          renderMyLeaveRequests();
        });
      });
    };
    renderMyLeaveRequests();

    const leaveBalanceResult = getLeaveBalance();
    if (leaveBalanceResult) {
      const setBalanceText = (selector, entry) => {
        const el = document.querySelector(selector);
        if (el && entry) el.textContent = `${entry.remaining} / ${entry.quota} days remaining`;
      };
      setBalanceText("#leaveBalanceCasual", leaveBalanceResult.casual);
      setBalanceText("#leaveBalanceSick", leaveBalanceResult.sick);
      setBalanceText("#leaveBalanceEarned", leaveBalanceResult.earned);
    }

    document.querySelector("#leaveApplicationForm")?.addEventListener("submit", (event) => {
      event.preventDefault();
      const leaveType = document.querySelector("#leaveTypeSelect").value;
      const fromDate = document.querySelector("#leaveFromDate").value;
      const toDate = document.querySelector("#leaveToDate").value;
      const reason = document.querySelector("#leaveReason").value.trim();

      createLeaveRequest({
        facultyEmail: facultyRecord.email,
        facultyName: facultyRecord.name,
        designation: facultyRecord.designation,
        department: facultyRecord.department,
        isHod: facultyRecord.isHod,
        leaveType,
        fromDate,
        toDate,
        reason
      });

      const feedback = document.querySelector("#leaveApplicationFeedback");
      if (feedback) {
        feedback.textContent = `Leave request submitted. It has been sent to ${leaveApproverName} for approval.`;
        feedback.classList.remove("is-hidden");
        feedback.classList.add("success");
      }
      document.querySelector("#leaveApplicationForm").reset();
      renderMyLeaveRequests();
    });

    const myAdhocClassBody = document.querySelector("#myAdhocClassBody");
    const myAdhocClassEmpty = document.querySelector("#myAdhocClassEmpty");
    const renderMyAdhocClassRequests = () => {
      if (!myAdhocClassBody) return;
      const requests = getAdhocClassRequests().filter((item) => item.facultyEmail === facultyRecord.email);
      myAdhocClassEmpty?.classList.toggle("is-hidden", requests.length > 0);
      myAdhocClassBody.innerHTML = requests
        .map(
          (item) => `
            <tr>
              <td>${item.subject}</td>
              <td>${formatExamDate(item.date)}</td>
              <td>${item.time}</td>
              <td>${item.reason}</td>
              <td><span class="${requestStatusClass(item.status)}">${item.status}</span></td>
              <td><button type="button" class="icon-btn-delete" data-remove-adhoc-request="${item.id}" aria-label="Remove" title="Remove">${deleteIconSvg}</button></td>
            </tr>
          `
        )
        .join("");

      myAdhocClassBody.querySelectorAll("[data-remove-adhoc-request]").forEach((button) => {
        button.addEventListener("click", () => {
          removeAdhocClassRequest(button.dataset.removeAdhocRequest);
          renderMyAdhocClassRequests();
        });
      });
    };
    renderMyAdhocClassRequests();

    document.querySelector("#adhocClassForm")?.addEventListener("submit", (event) => {
      event.preventDefault();
      const date = document.querySelector("#adhocClassDate").value;
      const time = document.querySelector("#adhocClassTime").value.trim();
      const reason = document.querySelector("#adhocClassReason").value.trim();

      createAdhocClassRequest({
        facultyEmail: facultyRecord.email,
        facultyName: facultyRecord.name,
        department: facultyRecord.department,
        isHod: facultyRecord.isHod,
        subject: resolveFacultySubject(facultyRecord),
        subjectCode: facultySubjectCode || "",
        date,
        time,
        reason
      });

      const feedback = document.querySelector("#adhocClassFeedback");
      if (feedback) {
        feedback.textContent = facultyRecord.isHod
          ? "Adhoc class scheduled. Students will see it on their class timetable."
          : "Adhoc class request submitted. It has been sent to your HOD for approval.";
        feedback.classList.remove("is-hidden");
        feedback.classList.add("success");
      }
      document.querySelector("#adhocClassForm").reset();
      renderMyAdhocClassRequests();
    });

    const classMessageSubjectLabel = document.querySelector("#classMessageSubjectLabel");
    if (classMessageSubjectLabel) {
      classMessageSubjectLabel.textContent = facultySubjectCode
        ? `Send a message to CSE III-A students of ${facultySubjectCode} - ${facultyRecord.subject}`
        : resolveFacultySubject(facultyRecord)
          ? `Send a message to your ${facultyRecord.subject} students`
          : "No subject assigned yet - contact your department admin.";
    }

    const sentClassMessagesBody = document.querySelector("#sentClassMessagesBody");
    const sentClassMessagesEmpty = document.querySelector("#sentClassMessagesEmpty");
    const renderSentClassMessages = () => {
      if (!sentClassMessagesBody) return;
      const messages = getClassMessages().filter((item) => item.facultyEmail === facultyRecord.email);
      sentClassMessagesEmpty?.classList.toggle("is-hidden", messages.length > 0);
      sentClassMessagesBody.innerHTML = messages
        .map(
          (item) => `
            <tr>
              <td>${item.title}</td>
              <td>${item.message}</td>
              <td>${item.sentOn}</td>
              <td><button type="button" class="icon-btn-delete" data-remove-class-message="${item.id}" aria-label="Remove" title="Remove">${deleteIconSvg}</button></td>
            </tr>
          `
        )
        .join("");

      sentClassMessagesBody.querySelectorAll("[data-remove-class-message]").forEach((button) => {
        button.addEventListener("click", () => {
          removeClassMessage(button.dataset.removeClassMessage);
          renderSentClassMessages();
        });
      });
    };
    renderSentClassMessages();

    document.querySelector("#classMessageForm")?.addEventListener("submit", (event) => {
      event.preventDefault();
      const feedback = document.querySelector("#classMessageFeedback");
      const title = document.querySelector("#classMessageTitle").value.trim();
      const message = document.querySelector("#classMessageBody").value.trim();

      createClassMessage({
        facultyEmail: facultyRecord.email,
        facultyName: facultyRecord.name,
        subjectCode: facultySubjectCode || "",
        subject: resolveFacultySubject(facultyRecord),
        department: facultyRecord.department,
        title,
        message
      });

      if (feedback) {
        feedback.textContent = "Message sent to your class.";
        feedback.classList.remove("is-hidden");
        feedback.classList.add("success");
      }
      document.querySelector("#classMessageForm").reset();
      renderSentClassMessages();
    });

    const departmentProjectsList = document.querySelector("#departmentProjectsList");
    const departmentProjectsEmpty = document.querySelector("#departmentProjectsEmpty");
    // Flow: Pending idea -> Approve/Reject (with optional feedback) -> once Approved, the
    // guide adds milestones (title + due date) here; the student then uploads a deliverable
    // against each milestone from their own Projects page.
    const renderDepartmentProjects = () => {
      if (!departmentProjectsList) return;
      const projects = getProjects()
        .filter((item) => item.department === facultyRecord.department)
        .sort((a, b) => b.submittedAt - a.submittedAt);
      departmentProjectsEmpty?.classList.toggle("is-hidden", projects.length > 0);

      departmentProjectsList.innerHTML = projects
        .map((item) => {
          const milestones = item.milestones || [];
          const reviewActionsHtml =
            item.status === "Pending"
              ? `<div class="project-review-actions">
                  <input type="text" class="project-feedback-input" placeholder="Feedback (optional)" data-project-feedback-input="${item.id}">
                  <button type="button" class="ai-assist-button" data-ai-improve-sibling title="Improve with AI">✨</button>
                  <button type="button" data-project-approve="${item.id}">Approve</button>
                  <button type="button" class="btn-reject" data-project-reject="${item.id}">Reject</button>
                </div>`
              : "";
          const milestonesHtml =
            item.status === "Approved"
              ? `
                <div class="project-milestones">
                  <h4>Timeline</h4>
                  ${renderTimelineProgress(milestones)}
                  ${
                    milestones.length
                      ? milestones
                          .map((milestone) => {
                            const submissionStatus = milestone.fileDataUrl ? milestone.submissionStatus || "In Review" : "";
                            const milestoneReviewHtml =
                              milestone.fileDataUrl && submissionStatus === "In Review"
                                ? `<div class="project-review-actions">
                                    <input type="text" class="project-feedback-input" placeholder="Feedback (optional)" data-milestone-feedback-input="${milestone.id}">
                                    <button type="button" class="ai-assist-button" data-ai-improve-sibling title="Improve with AI">✨</button>
                                    <button type="button" data-milestone-approve="${item.id}:${milestone.id}">Approve</button>
                                    <button type="button" class="btn-reject" data-milestone-reject="${item.id}:${milestone.id}">Reject</button>
                                  </div>`
                                : "";
                            return `
                              <div class="milestone-row">
                                <div class="milestone-info">
                                  <strong>${milestone.title}</strong>
                                  <span>Due ${formatExamDate(milestone.dueDate)}</span>
                                  ${submissionStatus ? `<span class="${requestStatusClass(submissionStatus)}">${submissionStatus}</span>` : ""}
                                  ${milestone.submissionFeedback ? `<span class="portal-note">Your feedback: ${milestone.submissionFeedback}</span>` : ""}
                                </div>
                                <div class="milestone-upload">
                                  ${
                                    milestone.fileDataUrl
                                      ? `<a class="milestone-download-button" href="${milestone.fileDataUrl}" download="${milestone.fileName}">${downloadIconSvg} Download Submission</a>`
                                      : `<span class="portal-note">Not submitted yet</span>`
                                  }
                                </div>
                                ${milestoneReviewHtml}
                              </div>
                            `;
                          })
                          .join("")
                      : `<p class="portal-note">No timeline set yet.</p>`
                  }
                  <div class="add-milestone-form">
                    <input type="text" placeholder="Milestone title, e.g. Literature Review" data-milestone-title="${item.id}">
                    <input type="date" data-milestone-date="${item.id}">
                    <button type="button" data-add-milestone="${item.id}">Add Milestone</button>
                  </div>
                </div>
              `
              : "";
          return `
            <details class="project-card">
              <summary class="project-card-head">
                <div class="project-card-head-text">
                  <strong>${item.title}</strong>
                  <span class="project-card-submitter">${resolveStudentDisplayName(item.studentId, item.studentName)}${item.teamMembers?.find((member) => member.studentId === item.studentId)?.isLead ? " (Lead)" : ""} (${item.studentId})${item.studentSection ? ` - ${item.studentSection}` : ""}</span>
                </div>
                ${item.status === "Approved" ? timelineSummaryBadge(milestones) : ""}
                <span class="${requestStatusClass(item.status)}">${item.status}</span>
              </summary>
              <div class="project-card-body">
                <p class="project-card-meta">${resolveStudentDisplayName(item.studentId, item.studentName)} (${item.studentId}) | ${item.category} | Guide: ${item.guideName}${formatProjectTeam(item.teamMembers)}</p>
                <p class="project-card-idea">${item.description}</p>
                ${item.feedback ? `<p class="portal-note">Your feedback: ${item.feedback}</p>` : ""}
                ${
                  getPlagiarismCheck("project", item.id)
                    ? plagiarismBadgeHtml("project", item.id)
                    : `<p class="portal-note" data-plagiarism-result="${item.id}"><button type="button" data-plagiarism-check-project="${item.id}">Check Plagiarism</button></p>`
                }
                ${reviewActionsHtml}
                ${milestonesHtml}
              </div>
            </details>
          `;
        })
        .join("");

      departmentProjectsList.querySelectorAll("[data-plagiarism-check-project]").forEach((button) => {
        button.addEventListener("click", () => {
          const item = projects.find((project) => project.id === button.dataset.plagiarismCheckProject);
          if (!item) return;
          runPlagiarismCheck({
            type: "project",
            referenceId: item.id,
            rollNo: item.studentId,
            text: `${item.title}\n\n${item.description}`,
            button,
            resultEl: button.closest("[data-plagiarism-result]")
          });
        });
      });

      const applyDecision = (projectId, status) => {
        const currentProjects = getProjects();
        const item = currentProjects.find((project) => project.id === projectId);
        if (!item) return;
        const feedbackInput = departmentProjectsList.querySelector(`[data-project-feedback-input="${projectId}"]`);
        item.status = status;
        item.feedback = feedbackInput?.value.trim() || item.feedback;
        saveProjects(currentProjects);
        renderDepartmentProjects();
      };

      departmentProjectsList.querySelectorAll("[data-project-approve]").forEach((button) => {
        button.addEventListener("click", () => applyDecision(button.dataset.projectApprove, "Approved"));
      });
      departmentProjectsList.querySelectorAll("[data-project-reject]").forEach((button) => {
        button.addEventListener("click", () => applyDecision(button.dataset.projectReject, "Rejected"));
      });

      const applyMilestoneDecision = (projectId, milestoneId, status) => {
        const currentProjects = getProjects();
        const item = currentProjects.find((project) => project.id === projectId);
        const milestone = item?.milestones?.find((entry) => entry.id === milestoneId);
        if (!milestone) return;
        const feedbackInput = departmentProjectsList.querySelector(`[data-milestone-feedback-input="${milestoneId}"]`);
        milestone.submissionStatus = status;
        milestone.submissionFeedback = feedbackInput?.value.trim() || milestone.submissionFeedback || "";
        saveProjects(currentProjects);
        renderDepartmentProjects();
      };

      departmentProjectsList.querySelectorAll("[data-milestone-approve]").forEach((button) => {
        button.addEventListener("click", () => {
          const [projectId, milestoneId] = button.dataset.milestoneApprove.split(":");
          applyMilestoneDecision(projectId, milestoneId, "Approved");
        });
      });
      departmentProjectsList.querySelectorAll("[data-milestone-reject]").forEach((button) => {
        button.addEventListener("click", () => {
          const [projectId, milestoneId] = button.dataset.milestoneReject.split(":");
          applyMilestoneDecision(projectId, milestoneId, "Rejected");
        });
      });

      departmentProjectsList.querySelectorAll("[data-add-milestone]").forEach((button) => {
        button.addEventListener("click", () => {
          const projectId = button.dataset.addMilestone;
          const titleInput = departmentProjectsList.querySelector(`[data-milestone-title="${projectId}"]`);
          const dateInput = departmentProjectsList.querySelector(`[data-milestone-date="${projectId}"]`);
          const title = titleInput?.value.trim();
          const dueDate = dateInput?.value;
          if (!title || !dueDate) return;
          const currentProjects = getProjects();
          const item = currentProjects.find((project) => project.id === projectId);
          if (!item) return;
          item.milestones = item.milestones || [];
          item.milestones.push({ id: `milestone-${Date.now()}`, title, dueDate });
          saveProjects(currentProjects);
          renderDepartmentProjects();
        });
      });
    };
    renderDepartmentProjects();

    const departmentResearchList = document.querySelector("#departmentResearchList");
    const departmentResearchEmpty = document.querySelector("#departmentResearchEmpty");
    const renderDepartmentResearch = () => {
      if (!departmentResearchList) return;
      const research = getResearch()
        .filter((item) => item.department === facultyRecord.department)
        .sort((a, b) => b.submittedAt - a.submittedAt);
      departmentResearchEmpty?.classList.toggle("is-hidden", research.length > 0);

      departmentResearchList.innerHTML = research
        .map((item) => {
          const milestones = item.milestones || [];
          const reviewActionsHtml =
            item.status === "Pending"
              ? `<div class="project-review-actions">
                  <input type="text" class="project-feedback-input" placeholder="Feedback (optional)" data-research-feedback-input="${item.id}">
                  <button type="button" class="ai-assist-button" data-ai-improve-sibling title="Improve with AI">✨</button>
                  <button type="button" data-research-approve="${item.id}">Approve</button>
                  <button type="button" class="btn-reject" data-research-reject="${item.id}">Reject</button>
                </div>`
              : "";
          const milestonesHtml =
            item.status === "Approved"
              ? `
                <div class="project-milestones">
                  <h4>Research Timeline</h4>
                  ${renderTimelineProgress(milestones)}
                  ${
                    milestones.length
                      ? milestones
                          .map((milestone) => {
                            const submissionStatus = milestone.fileDataUrl ? milestone.submissionStatus || "In Review" : "";
                            const milestoneReviewHtml =
                              milestone.fileDataUrl && submissionStatus === "In Review"
                                ? `<div class="project-review-actions">
                                    <input type="text" class="project-feedback-input" placeholder="Feedback (optional)" data-research-milestone-feedback-input="${milestone.id}">
                                    <button type="button" class="ai-assist-button" data-ai-improve-sibling title="Improve with AI">✨</button>
                                    <button type="button" data-research-milestone-approve="${item.id}:${milestone.id}">Approve</button>
                                    <button type="button" class="btn-reject" data-research-milestone-reject="${item.id}:${milestone.id}">Reject</button>
                                  </div>`
                                : "";
                            return `
                              <div class="milestone-row">
                                <div class="milestone-info">
                                  <strong>${milestone.title}</strong>
                                  <span>Due ${formatExamDate(milestone.dueDate)}</span>
                                  ${submissionStatus ? `<span class="${requestStatusClass(submissionStatus)}">${submissionStatus}</span>` : ""}
                                  ${milestone.submissionFeedback ? `<span class="portal-note">Your feedback: ${milestone.submissionFeedback}</span>` : ""}
                                </div>
                                <div class="milestone-upload">
                                  ${
                                    milestone.fileDataUrl
                                      ? `<a class="milestone-download-button" href="${milestone.fileDataUrl}" download="${milestone.fileName}">${downloadIconSvg} Download Submission</a>`
                                      : `<span class="portal-note">Not submitted yet</span>`
                                  }
                                </div>
                                ${milestoneReviewHtml}
                              </div>
                            `;
                          })
                          .join("")
                      : `<p class="portal-note">No timeline set yet.</p>`
                  }
                  <div class="add-milestone-form">
                    <input type="text" placeholder="Milestone title, e.g. Literature Review" data-research-milestone-title="${item.id}">
                    <input type="date" data-research-milestone-date="${item.id}">
                    <button type="button" data-add-research-milestone="${item.id}">Add Milestone</button>
                  </div>
                </div>
              `
              : "";
          return `
            <details class="project-card">
              <summary class="project-card-head">
                <div class="project-card-head-text">
                  <strong>${item.title}</strong>
                  <span class="project-card-submitter">${resolveStudentDisplayName(item.studentId, item.studentName)} (${item.studentId})${item.studentSection ? ` - ${item.studentSection}` : ""}</span>
                </div>
                ${item.status === "Approved" ? timelineSummaryBadge(milestones) : ""}
                <span class="${requestStatusClass(item.status)}">${item.status}</span>
              </summary>
              <div class="project-card-body">
                <p class="project-card-meta">${item.category} | Supervisor: ${item.guideName}</p>
                <p class="project-card-idea">${item.description}</p>
                ${item.feedback ? `<p class="portal-note">Your feedback: ${item.feedback}</p>` : ""}
                ${
                  getPlagiarismCheck("research", item.id)
                    ? plagiarismBadgeHtml("research", item.id)
                    : `<p class="portal-note" data-plagiarism-result="${item.id}"><button type="button" data-plagiarism-check-research="${item.id}">Check Plagiarism</button></p>`
                }
                ${reviewActionsHtml}
                ${milestonesHtml}
              </div>
            </details>
          `;
        })
        .join("");

      departmentResearchList.querySelectorAll("[data-plagiarism-check-research]").forEach((button) => {
        button.addEventListener("click", () => {
          const item = research.find((entry) => entry.id === button.dataset.plagiarismCheckResearch);
          if (!item) return;
          runPlagiarismCheck({
            type: "research",
            referenceId: item.id,
            rollNo: item.studentId,
            text: `${item.title}\n\n${item.description}`,
            button,
            resultEl: button.closest("[data-plagiarism-result]")
          });
        });
      });

      const applyResearchDecision = (itemId, status) => {
        const currentResearch = getResearch();
        const item = currentResearch.find((entry) => entry.id === itemId);
        if (!item) return;
        const feedbackInput = departmentResearchList.querySelector(`[data-research-feedback-input="${itemId}"]`);
        item.status = status;
        item.feedback = feedbackInput?.value.trim() || item.feedback;
        saveResearch(currentResearch);
        renderDepartmentResearch();
      };

      departmentResearchList.querySelectorAll("[data-research-approve]").forEach((button) => {
        button.addEventListener("click", () => applyResearchDecision(button.dataset.researchApprove, "Approved"));
      });
      departmentResearchList.querySelectorAll("[data-research-reject]").forEach((button) => {
        button.addEventListener("click", () => applyResearchDecision(button.dataset.researchReject, "Rejected"));
      });

      const applyResearchMilestoneDecision = (itemId, milestoneId, status) => {
        const currentResearch = getResearch();
        const item = currentResearch.find((entry) => entry.id === itemId);
        const milestone = item?.milestones?.find((entry) => entry.id === milestoneId);
        if (!milestone) return;
        const feedbackInput = departmentResearchList.querySelector(`[data-research-milestone-feedback-input="${milestoneId}"]`);
        milestone.submissionStatus = status;
        milestone.submissionFeedback = feedbackInput?.value.trim() || milestone.submissionFeedback || "";
        saveResearch(currentResearch);
        renderDepartmentResearch();
      };

      departmentResearchList.querySelectorAll("[data-research-milestone-approve]").forEach((button) => {
        button.addEventListener("click", () => {
          const [itemId, milestoneId] = button.dataset.researchMilestoneApprove.split(":");
          applyResearchMilestoneDecision(itemId, milestoneId, "Approved");
        });
      });
      departmentResearchList.querySelectorAll("[data-research-milestone-reject]").forEach((button) => {
        button.addEventListener("click", () => {
          const [itemId, milestoneId] = button.dataset.researchMilestoneReject.split(":");
          applyResearchMilestoneDecision(itemId, milestoneId, "Rejected");
        });
      });

      departmentResearchList.querySelectorAll("[data-add-research-milestone]").forEach((button) => {
        button.addEventListener("click", () => {
          const itemId = button.dataset.addResearchMilestone;
          const titleInput = departmentResearchList.querySelector(`[data-research-milestone-title="${itemId}"]`);
          const dateInput = departmentResearchList.querySelector(`[data-research-milestone-date="${itemId}"]`);
          const title = titleInput?.value.trim();
          const dueDate = dateInput?.value;
          if (!title || !dueDate) return;
          const currentResearch = getResearch();
          const item = currentResearch.find((entry) => entry.id === itemId);
          if (!item) return;
          item.milestones = item.milestones || [];
          item.milestones.push({ id: `milestone-${Date.now()}`, title, dueDate });
          saveResearch(currentResearch);
          renderDepartmentResearch();
        });
      });
    };
    renderDepartmentResearch();

    if (facultyRecord.isHod) {
      document.querySelectorAll(".hod-only-nav").forEach((element) => element.classList.remove("is-hidden"));

      const leaveApprovalsBody = document.querySelector("#leaveApprovalsBody");
      const leaveApprovalsEmpty = document.querySelector("#leaveApprovalsEmpty");
      const renderLeaveApprovals = () => {
        if (!leaveApprovalsBody) return;
        const requests = getLeaveRequests().filter((item) => item.department === facultyRecord.department && !item.isHod);
        leaveApprovalsEmpty?.classList.toggle("is-hidden", requests.length > 0);
        leaveApprovalsBody.innerHTML = requests
          .map((item) => {
            const actionCell =
              item.status === "Pending"
                ? `<div class="action-cell"><button type="button" data-leave-approve="${item.id}">Yes</button><button type="button" class="btn-reject" data-leave-reject="${item.id}">No</button></div>`
                : "-";
            return `
              <tr>
                <td>${item.facultyName}</td>
                <td>${item.leaveType}</td>
                <td>${formatExamDate(item.fromDate)}</td>
                <td>${formatExamDate(item.toDate)}</td>
                <td>${item.reason}</td>
                <td><span class="${requestStatusClass(item.status)}">${item.status}</span></td>
                <td>${actionCell}</td>
              </tr>
            `;
          })
          .join("");

        leaveApprovalsBody.querySelectorAll("[data-leave-approve]").forEach((button) => {
          button.addEventListener("click", () => {
            decideLeaveRequest(button.dataset.leaveApprove, "Approved");
            renderLeaveApprovals();
          });
        });
        leaveApprovalsBody.querySelectorAll("[data-leave-reject]").forEach((button) => {
          button.addEventListener("click", () => {
            decideLeaveRequest(button.dataset.leaveReject, "Rejected");
            renderLeaveApprovals();
          });
        });
      };
      renderLeaveApprovals();

      const adhocClassApprovalsBody = document.querySelector("#adhocClassApprovalsBody");
      const adhocClassApprovalsEmpty = document.querySelector("#adhocClassApprovalsEmpty");
      const renderAdhocClassApprovals = () => {
        if (!adhocClassApprovalsBody) return;
        const requests = getAdhocClassRequests().filter((item) => item.department === facultyRecord.department && !item.isHod);
        adhocClassApprovalsEmpty?.classList.toggle("is-hidden", requests.length > 0);
        adhocClassApprovalsBody.innerHTML = requests
          .map((item) => {
            const actionCell =
              item.status === "Pending"
                ? `<div class="action-cell"><button type="button" data-adhoc-approve="${item.id}">Yes</button><button type="button" class="btn-reject" data-adhoc-reject="${item.id}">No</button></div>`
                : "-";
            return `
              <tr>
                <td>${item.facultyName}</td>
                <td>${item.subject}</td>
                <td>${formatExamDate(item.date)}</td>
                <td>${item.time}</td>
                <td>${item.reason}</td>
                <td><span class="${requestStatusClass(item.status)}">${item.status}</span></td>
                <td>${actionCell}</td>
              </tr>
            `;
          })
          .join("");

        adhocClassApprovalsBody.querySelectorAll("[data-adhoc-approve]").forEach((button) => {
          button.addEventListener("click", () => {
            decideAdhocClassRequest(button.dataset.adhocApprove, "Approved");
            renderAdhocClassApprovals();
          });
        });
        adhocClassApprovalsBody.querySelectorAll("[data-adhoc-reject]").forEach((button) => {
          button.addEventListener("click", () => {
            decideAdhocClassRequest(button.dataset.adhocReject, "Rejected");
            renderAdhocClassApprovals();
          });
        });
      };
      renderAdhocClassApprovals();

      const hodComplaintsBody = document.querySelector("#hodComplaintsBody");
      const hodComplaintsEmpty = document.querySelector("#hodComplaintsEmpty");
      const renderHodComplaints = () => {
        if (!hodComplaintsBody) return;
        const complaints = getComplaints().filter(
          (item) => item.category === "Academic" && item.department === facultyRecord.department
        );
        hodComplaintsEmpty?.classList.toggle("is-hidden", complaints.length > 0);
        hodComplaintsBody.innerHTML = complaints
          .map(
            (item) => `
              <tr>
                <td>${resolveStudentDisplayName(item.studentId, item.studentName)} (${item.studentId})</td>
                <td>${item.subject}</td>
                <td>${item.description}</td>
                <td><span class="${complaintStatusClass(item.status)}">${item.status}</span></td>
                <td>${
                  item.status === "Pending"
                    ? `<button type="button" data-complaint-resolve="${item.id}">Mark Resolved</button>`
                    : "-"
                }</td>
              </tr>
            `
          )
          .join("");

        hodComplaintsBody.querySelectorAll("[data-complaint-resolve]").forEach((button) => {
          button.addEventListener("click", () => {
            const complaints = getComplaints();
            const item = complaints.find((entry) => entry.id === button.dataset.complaintResolve);
            if (!item) return;
            item.status = "Resolved";
            saveComplaints(complaints);
            renderHodComplaints();
          });
        });
      };
      renderHodComplaints();
    }

    if (document.querySelector("#notificationList")) {
      const leaveNotifications = getLeaveRequests()
        .filter((item) => item.facultyEmail === facultyRecord.email && item.status !== "Pending")
        .map((item) => `Your ${item.leaveType} leave request has been ${item.status.toLowerCase()}.`);
      const adhocNotifications = getAdhocClassRequests()
        .filter((item) => item.facultyEmail === facultyRecord.email && item.status !== "Pending" && !item.isHod)
        .map((item) => `Your adhoc class request for ${formatExamDate(item.date)} has been ${item.status.toLowerCase()}.`);
      const approvalNotifications = facultyRecord.isHod
        ? [
            ...getLeaveRequests()
              .filter((item) => item.department === facultyRecord.department && !item.isHod && item.status === "Pending")
              .map((item) => `${item.facultyName} has a pending ${item.leaveType} request awaiting your approval.`),
            ...getAdhocClassRequests()
              .filter((item) => item.department === facultyRecord.department && !item.isHod && item.status === "Pending")
              .map((item) => `${item.facultyName} has a pending adhoc class request awaiting your approval.`)
          ]
        : [];
      renderNotificationList([...approvalNotifications, ...leaveNotifications, ...adhocNotifications]);
    }
  }
}

// Faculty "My Events": events where this faculty member is the assigned Event Head (see
// facultyHeadEmail on the campus event, set by admin at event-creation time). Independent block
// (not nested inside the huge #facultyDashboardName block above) so it degrades gracefully if
// that block's own facultyRecord lookup already redirected away.
const myEventsBody = document.querySelector("#myEventsBody");
if (myEventsBody) {
  const facultyEmail = (localStorage.getItem("gprecFacultyEmail") || "").toLowerCase();
  const facultyRecord = lookupFacultyRecordByEmail(facultyEmail);
  const myEventsEmpty = document.querySelector("#myEventsEmpty");
  const myEventEditCard = document.querySelector("#myEventEditCard");
  const myEventTitleInput = document.querySelector("#myEventTitleInput");
  const myEventDateInput = document.querySelector("#myEventDateInput");
  const myEventVenueInput = document.querySelector("#myEventVenueInput");
  const myEventFeeInput = document.querySelector("#myEventFeeInput");
  const myEventCapacityInput = document.querySelector("#myEventCapacityInput");
  const myEventDescriptionInput = document.querySelector("#myEventDescriptionInput");
  const myEventSaveButton = document.querySelector("#myEventSaveButton");
  const myEventExportButton = document.querySelector("#myEventExportButton");
  const myEventFeedback = document.querySelector("#myEventFeedback");
  const myEventRegistrantsBody = document.querySelector("#myEventRegistrantsBody");
  const myEventRegistrantsEmpty = document.querySelector("#myEventRegistrantsEmpty");

  let editingEventId = null;

  const myAssignedEvents = () =>
    facultyRecord ? getCampusEvents().filter((event) => (event.facultyHeadEmail || "").toLowerCase() === facultyEmail) : [];

  const renderRegistrantsFor = (eventId) => {
    const registrations = getCampusEventRegistrations().filter((item) => item.eventId === eventId);
    myEventRegistrantsEmpty?.classList.toggle("is-hidden", registrations.length > 0);
    myEventRegistrantsBody.innerHTML = registrations
      .map(
        (item) => `
        <tr>
          <td>${campusEventParticipantType(item)}</td>
          <td>${escapeHtml(item.participantName)}</td>
          <td>${escapeHtml(item.rollNumber || item.email || "-")}</td>
          <td>${escapeHtml(item.paymentStatus || "-")}</td>
          <td>${item.checkIn ? `Yes (${formatOutingDateTime(item.checkIn.scannedAt)})` : "No"}</td>
        </tr>
      `
      )
      .join("");
  };

  const loadEventIntoForm = (event) => {
    editingEventId = event.id;
    myEventEditCard?.classList.remove("is-hidden");
    if (myEventTitleInput) myEventTitleInput.value = event.title || "";
    if (myEventDateInput) myEventDateInput.value = event.date || "";
    if (myEventVenueInput) myEventVenueInput.value = event.venue || "";
    if (myEventFeeInput) myEventFeeInput.value = event.fee || 0;
    if (myEventCapacityInput) myEventCapacityInput.value = event.capacity ?? "";
    if (myEventDescriptionInput) myEventDescriptionInput.value = event.description || "";
    renderRegistrantsFor(event.id);
  };

  const renderMyEvents = () => {
    const events = myAssignedEvents();
    document.querySelectorAll(".event-head-only-nav").forEach((el) => el.classList.toggle("is-hidden", events.length === 0));
    myEventsEmpty?.classList.toggle("is-hidden", events.length > 0);
    const registrations = getCampusEventRegistrations();
    myEventsBody.innerHTML = events
      .map((event) => {
        const count = registrations.filter((item) => item.eventId === event.id).length;
        const fee = Number(event.fee) || 0;
        return `
          <tr>
            <td>${formatCampusEventDate(event.date)}</td>
            <td>${escapeHtml(event.title)}</td>
            <td>${fee ? `₹${fee.toLocaleString("en-IN")}` : "Free"}</td>
            <td>${event.capacity ? `${count} / ${event.capacity}` : count}</td>
            <td><button type="button" class="payment-open-button" data-my-event-manage="${escapeHtml(event.id)}">Manage</button></td>
          </tr>
        `;
      })
      .join("");
    myEventsBody.querySelectorAll("[data-my-event-manage]").forEach((button) => {
      button.addEventListener("click", () => {
        const event = events.find((item) => item.id === button.dataset.myEventManage);
        if (event) loadEventIntoForm(event);
      });
    });
  };
  renderMyEvents();

  myEventSaveButton?.addEventListener("click", () => {
    if (!editingEventId) return;
    const fields = {
      title: myEventTitleInput?.value.trim() || "",
      date: myEventDateInput?.value || "",
      venue: myEventVenueInput?.value.trim() || "",
      fee: Math.max(0, Number(myEventFeeInput?.value) || 0),
      capacity: myEventCapacityInput?.value ? Math.max(0, Number(myEventCapacityInput.value)) : null,
      description: myEventDescriptionInput?.value.trim() || ""
    };
    const result = updateCampusEventAsHead(editingEventId, fields);
    if (result?.ok) {
      renderMyEvents();
      if (myEventFeedback) {
        myEventFeedback.textContent = "Event updated.";
        myEventFeedback.classList.add("success");
      }
    } else if (myEventFeedback) {
      myEventFeedback.textContent = (result && result.error) || "Could not save changes.";
      myEventFeedback.classList.remove("success");
    }
  });

  myEventExportButton?.addEventListener("click", () => {
    if (editingEventId) exportCampusEventParticipants(editingEventId);
  });
}

const parentDashboardName = document.querySelector("#parentDashboardName");
if (parentDashboardName) {
  const parentStudentId = localStorage.getItem("gprecParentStudentId") || "";
  // Base profile covers every student (day scholars included); hostel-only extras (room, block,
  // warden, mess) are layered on top when the student also has a hostel allocation.
  const baseProfile = defaultStudentProfiles[parentStudentId];
  const childRecord = baseProfile
    ? { parent: baseProfile.father, ...baseProfile, ...hostelStudentData[parentStudentId] }
    : hostelStudentData[parentStudentId];

  if (!childRecord) {
    window.location.href = gprecPageUrl("parent-login.html");
  } else {
    const setText = (selector, value) => {
      const node = document.querySelector(selector);
      if (node) node.textContent = value;
    };
    const initials = childRecord.name
      .split(/\s+/)
      .map((part) => part[0])
      .join("")
      .slice(0, 2)
      .toUpperCase();

    setText("#parentInitials", initials || "PA");
    setText("#parentDashboardName", `${childRecord.parent} (Parent)`);
    setText("#parentDashboardChildId", `${childRecord.name} | ${parentStudentId}`);
    renderStudentProfileInto(document.querySelector("#parentChildProfileView"), parentStudentId);
    setText("#dashboardGreeting", getTimeBasedGreeting(getFirstName(childRecord.parent, "Parent")));
    applyGprecianBotGreeting(getFirstName(childRecord.parent, "Parent"));

    const parentAttendanceBody = document.querySelector("#parentAttendanceBody");
    const parentAttendanceOverall = document.querySelector("#parentAttendanceOverall");

    if (parentAttendanceBody) {
      const semesterStart = new Date("2026-01-01");
      const semesterEnd = new Date("2026-06-30");
      let totalHeld = 0;
      let totalAttended = 0;
      parentAttendanceBody.innerHTML = defaultAttendanceSubjects
        .map((subject) => {
          const { held, attended } = computeAttendanceForRange(subject, semesterStart, semesterEnd);
          totalHeld += held;
          totalAttended += attended;
          const percent = held > 0 ? Math.round((attended / held) * 100) : 0;
          return `<tr><td>${subject.code} - ${subject.name}</td><td>${held}</td><td>${attended}</td><td>${percent}%</td></tr>`;
        })
        .join("");
      const overallPercent = totalHeld > 0 ? Math.round((totalAttended / totalHeld) * 100) : 0;
      if (parentAttendanceOverall) {
        parentAttendanceOverall.textContent = `${overallPercent}% (${totalAttended} / ${totalHeld} classes)`;
      }
    }

    const parentGradesBody = document.querySelector("#parentGradesBody");
    const parentGradesSummary = document.querySelector("#parentGradesSummary");

    if (parentGradesBody) {
      const grades = getGprecDbBootstrap()?.studentGrades?.[parentStudentId] || [];
      const parentGradesLastUpdated = document.querySelector("#parentGradesLastUpdated");
      if (!grades.length) {
        if (parentGradesSummary) parentGradesSummary.textContent = "No results on file yet";
        parentGradesBody.innerHTML = "";
        if (parentGradesLastUpdated) parentGradesLastUpdated.textContent = "";
      } else {
        const latestTerm = grades[grades.length - 1];
        const cgpa = (grades.reduce((sum, row) => sum + Number(row.gpa || 0), 0) / grades.length).toFixed(2);
        if (parentGradesSummary) parentGradesSummary.textContent = `Latest SGPA ${latestTerm.gpa} | CGPA ${cgpa}`;
        parentGradesBody.innerHTML = grades
          .map((row) => `<tr><td>${row.term}</td><td>${row.gpa}</td><td>${row.backlogs}</td></tr>`)
          .join("");
        if (parentGradesLastUpdated) {
          const latestUpdate = grades.reduce((max, row) => Math.max(max, Number(row.updatedAt) || 0), 0);
          parentGradesLastUpdated.textContent = latestUpdate
            ? `Last updated: ${new Date(latestUpdate).toLocaleDateString("en-IN", { day: "2-digit", month: "short", year: "numeric" })}`
            : "";
        }
      }
    }


    const parentOutingBody = document.querySelector("#parentOutingBody");
    const parentOutingEmpty = document.querySelector("#parentOutingEmpty");
    const renderParentOutingTable = () => {
      renderOutingRequestsTable(parentOutingBody, parentOutingEmpty, parentStudentId, renderParentOutingTable);
    };
    renderParentOutingTable();

    initOutingRequestForm({
      studentId: parentStudentId,
      requestedBy: "Parent",
      parentMobileValue: childRecord.parentMobile,
      onSaved: renderParentOutingTable
    });

    const parentVisitingBody = document.querySelector("#parentVisitingBody");
    const parentVisitingEmpty = document.querySelector("#parentVisitingEmpty");
    const renderParentVisitingTable = () => {
      if (!parentVisitingBody) return;
      const visitingRequests = getVisitingRequests().filter((request) => request.studentId === parentStudentId);
      parentVisitingEmpty?.classList.toggle("is-hidden", visitingRequests.length > 0);
      parentVisitingBody.innerHTML = visitingRequests
        .map((request) => {
          let actionCell = "-";
          if (request.status === "Pending") {
            actionCell = `<button type="button" class="icon-btn-delete" data-visiting-cancel="${request.id}" aria-label="Cancel Request" title="Cancel Request">${deleteIconSvg}</button>`;
          } else if (request.status === "Approved") {
            actionCell = `<button type="button" class="icon-btn-download" data-visiting-pass="${request.id}" aria-label="Download Pass" title="Download Pass">${downloadIconSvg}</button>`;
          }
          return `
            <tr>
              <td>${request.visitorName}</td>
              <td>${request.relationship}</td>
              <td>${request.purpose}</td>
              <td>${formatOutingDateTime(request.visitDateTime)}</td>
              <td><span class="${visitingStatusClass(request.status)}">${request.status}</span></td>
              <td>${actionCell}</td>
            </tr>
          `;
        })
        .join("");

      parentVisitingBody.querySelectorAll("[data-visiting-cancel]").forEach((button) => {
        button.addEventListener("click", () => {
          const remaining = getVisitingRequests().filter((item) => item.id !== button.dataset.visitingCancel);
          saveVisitingRequests(remaining);
          renderParentVisitingTable();
        });
      });

      parentVisitingBody.querySelectorAll("[data-visiting-pass]").forEach((button) => {
        button.addEventListener("click", () => {
          const request = visitingRequests.find((item) => item.id === button.dataset.visitingPass);
          if (request) downloadVisitPass(request);
        });
      });
    };
    renderParentVisitingTable();

    document.querySelector("#parentVisitingForm")?.addEventListener("submit", (event) => {
      event.preventDefault();
      const visitorName = document.querySelector("#visitingVisitorName").value.trim();
      const relationship = document.querySelector("#visitingRelationship").value;
      const purpose = document.querySelector("#visitingPurpose").value.trim();
      const visitorMobile = document.querySelector("#visitingMobile").value.trim();
      const visitDateTime = document.querySelector("#visitingDateTime").value;

      const visitingRequests = getVisitingRequests();
      visitingRequests.unshift({
        id: `visit-${Date.now()}`,
        studentId: parentStudentId,
        studentName: childRecord.name,
        room: childRecord.room,
        hostel: childRecord.hostel,
        visitorName,
        relationship,
        purpose,
        visitorMobile,
        visitDateTime,
        requestedBy: "Parent",
        status: "Pending"
      });
      saveVisitingRequests(visitingRequests);

      const visitingFeedback = document.querySelector("#visitingFeedback");
      if (visitingFeedback) {
        visitingFeedback.textContent = "Visit request submitted. You will see the status here once the warden responds.";
        visitingFeedback.classList.remove("is-hidden");
        visitingFeedback.classList.add("success");
      }
      document.querySelector("#parentVisitingForm").reset();
      renderParentVisitingTable();
    });

    if (document.querySelector("#notificationList")) {
      const outingNotifications = getOutingRequests()
        .filter((request) => request.studentId === parentStudentId && request.status !== "Pending")
        .map((request) => `Your ${request.outingType || "outing"} request has been ${request.status.toLowerCase()}.`);
      const visitingNotifications = getVisitingRequests()
        .filter((request) => request.studentId === parentStudentId && request.status !== "Pending")
        .map((request) => `Your visit request for ${request.visitorName} has been ${request.status.toLowerCase()}.`);
      renderNotificationList([...outingNotifications, ...visitingNotifications]);
    }
  }
}

