const publicNoticeAudiences = ["Public Announcement"];
const noticeBoardList = document.querySelector("#noticeBoardList");

const noticeBellIconSvg = '<svg viewBox="0 0 24 24" aria-hidden="true"><path d="M18 8a6 6 0 0 0-12 0c0 7-3 7-3 9h18c0-2-3-2-3-9ZM10 21h4"/></svg>';

const renderPublicNoticeBoard = () => {
  if (!noticeBoardList) return;
  const notices = getNotices()
    .filter((notice) => publicNoticeAudiences.includes(notice.audience))
    .reverse();
  const noticeCardsHtml = notices
    .map(
      (notice, index) => `
        <article>
          <span class="notice-board-icon">${noticeBellIconSvg}</span>
          <div class="notice-board-body">
            <h3>${notice.title}${index === 0 ? '<span class="notice-board-new">New</span>' : ""}</h3>
            <p class="notice-board-meta">
              <span class="notice-board-audience">${notice.audience}</span>
              ${notice.createdAt ? `<span class="notice-board-date">${new Date(notice.createdAt).toLocaleDateString("en-IN", { day: "numeric", month: "short", year: "numeric" })}</span>` : ""}
            </p>
            <p class="notice-board-message">${notice.message}</p>
            ${notice.attachment ? `<a class="notice-attachment" href="${notice.attachment.dataUrl}" download="${notice.attachment.name}">Download Attachment</a>` : ""}
          </div>
        </article>
      `
    )
    .join("");

  // Events an admin opened to outside colleges (event.isPublic) get their own notice-board card
  // linking straight to the event visitor dashboard, ahead of the regular notices - this is one
  // place a visitor with no GPREC account can discover public event registration.
  const publicEventCardsHtml = getCampusEvents()
    .filter((event) => event.isPublic)
    .map(
      (event) => `
        <article>
          <span class="notice-board-icon">${noticeBellIconSvg}</span>
          <div class="notice-board-body">
            <h3>${escapeHtml(event.title)}<span class="notice-board-new">Open for Registration</span></h3>
            <p class="notice-board-meta">
              <span class="notice-board-audience">Public - Outside Colleges Welcome</span>
              <span class="notice-board-date">${formatCampusEventDate(event.date)}</span>
            </p>
            <p class="notice-board-message">${escapeHtml(event.description || "")}</p>
            <p class="notice-board-message"><strong>Students from other colleges are welcome to attend - register below, no GPREC login needed.</strong></p>
            <a class="notice-attachment" href="${gprecPageUrl("event-visitor-dashboard.html")}?eventId=${encodeURIComponent(event.id)}&view=signup">Register Now</a>
          </div>
        </article>
      `
    )
    .join("");

  noticeBoardList.innerHTML = publicEventCardsHtml || noticeCardsHtml
    ? publicEventCardsHtml + noticeCardsHtml
    : `<div class="notice-board-empty">No notices posted yet. Check back soon.</div>`;
};

renderPublicNoticeBoard();

// Fan the same admin-published notices out to the Student, Faculty, and Parent dashboard
// spotlight widgets, filtered by audience, alongside their existing static notice items.
const renderAdminNoticesInto = (container, audiences, departmentFilter) => {
  if (!container) return;
  container.querySelectorAll("[data-admin-notice]").forEach((article) => article.remove());
  const items = getNotices()
    .filter((notice) => audiences.includes(notice.audience) && (!notice.department || notice.department === departmentFilter))
    .reverse();
  const articles = items.map((notice, index) => {
    const article = document.createElement("article");
    article.className = "spotlight-card spotlight-card-notice";
    article.setAttribute("data-admin-notice", notice.id);
    const downloadHtml = notice.attachment
      ? `<a class="notice-download" href="${notice.attachment.dataUrl}" download="${notice.attachment.name}">Download</a>`
      : "";
    article.innerHTML = `
      <span class="notice-board-icon">${noticeBellIconSvg}</span>
      <div class="notice-board-body">
        <h3>${notice.title}${index === 0 ? '<span class="notice-board-new">New</span>' : ""}</h3>
        <p class="notice-board-meta">
          <span class="notice-board-audience">${notice.audience}</span>
          ${notice.createdAt ? `<span class="notice-board-date">${new Date(notice.createdAt).toLocaleDateString("en-IN", { day: "numeric", month: "short", year: "numeric" })}</span>` : ""}
        </p>
        <p class="notice-board-message">${notice.message}</p>
        ${downloadHtml}
      </div>
    `;
    return article;
  });
  if (articles.length) container.prepend(...articles);
};

