const markFirstNoticeAsNew = (container) => {
  if (!container) return;
  const normalizeNewBadge = (strong) => {
    const badges = [...strong.querySelectorAll("em, .notice-board-new")];
    badges.forEach((badge, index) => {
      if (index > 0) badge.remove();
    });
    return badges[0] || null;
  };
  Array.from(container.children).forEach((article, index) => {
    const strong = article.querySelector(".notice-board-body h3") || article.querySelector("strong");
    if (!strong) return;
    const existingEm = normalizeNewBadge(strong);
    if (index === 0) {
      article.classList.add("is-new");
      if (!existingEm) {
        const em = document.createElement("em");
        em.textContent = "New";
        strong.appendChild(em);
      }
    } else {
      article.classList.remove("is-new");
      existingEm?.remove();
    }
  });
};

