const persistIntegrationSettings = async (feedbackEl, successText, isPositive = true) => {
  try {
    const response = await fetch(GPREC_CONFIG_SAVE_ENDPOINT, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(getCurrentIntegrationConfig())
    });
    if (!response.ok) throw new Error(`HTTP ${response.status}`);
    Object.assign(defaultAdminConfig, await response.json());
    if (feedbackEl) {
      feedbackEl.textContent = successText || "Saved.";
      feedbackEl.classList.toggle("success", isPositive);
    }
  } catch {
    if (feedbackEl) {
      feedbackEl.textContent = "Saved in this browser only. Start the local settings server to save this permanently.";
      feedbackEl.classList.remove("success");
    }
  }
};

