const aiOllamaConnectionField = document.querySelector("#aiOllamaConnectionField");
const checkOllamaConnectionButton = document.querySelector("#checkOllamaConnectionButton");
const ollamaConnectionStatus = document.querySelector("#ollamaConnectionStatus");
const saveAiSettingsButton = document.querySelector("#saveAiSettingsButton");
const aiSettingsFeedback = document.querySelector("#aiSettingsFeedback");
const aiSettingsStatus = document.querySelector("#aiSettingsStatus");

const getAiSettingsValidation = (settings) => {
  if (!settings.provider) return { ok: false, message: "select a provider" };
  if (settings.provider === "ollama") {
    return settings.model
      ? { ok: true, message: "Ollama model configured" }
      : { ok: false, message: "enter an Ollama model name" };
  }
  if (!settings.apiKey) return { ok: false, message: "enter an API key" };
  if (!settings.model) return { ok: false, message: "enter a model name" };
  const model = settings.model.toLowerCase();
  const modelLooksRight =
    (settings.provider === "gemini" && model.startsWith("gemini-")) ||
    (settings.provider === "openai" && (/^(gpt-|o\d|chatgpt-)/.test(model))) ||
    (settings.provider === "claude" && model.startsWith("claude-"));
  if (!modelLooksRight) {
    const expected = {
      gemini: "a Gemini model, e.g. gemini-2.5-flash",
      openai: "an OpenAI model, e.g. gpt-4o-mini",
      claude: "a Claude model, e.g. claude-sonnet-4-5"
    }[settings.provider] || "a model for the selected provider";
    return { ok: false, message: `model name should be ${expected}` };
  }
  return { ok: true, message: "settings saved, not verified yet" };
};

const isAiSettingsConfigured = (settings) => getAiSettingsValidation(settings).ok;

const showOllamaFields = (isOllama) => {
  aiBaseUrlField?.classList.toggle("is-hidden", !isOllama);
  aiOllamaHint?.classList.toggle("is-hidden", !isOllama);
  aiOllamaConnectionField?.classList.toggle("is-hidden", !isOllama);
};

const renderAiSettingsStatus = () => {
  if (!aiSettingsStatus) return;
  const settings = getAiSettings();
  const validation = getAiSettingsValidation(settings);
  aiSettingsStatus.innerHTML = validation.ok
    ? `<span class="warn">Verifying</span> - checking ${settings.provider || "provider"} connection...`
    : `<span class="warn">Not connected</span> - ${validation.message}; GPRECian Bot uses built-in answers only`;
};

const aiModelNameMatches = (installedName, requestedName) =>
  installedName === requestedName || installedName === `${requestedName}:latest` || installedName.split(":")[0] === requestedName;

let aiVerificationKey = "";
let aiVerificationPromise = null;

const verifyAiSettingsConnection = async (settings, feedbackEl = aiSettingsFeedback) => {
  const validation = getAiSettingsValidation(settings);
  const verificationKey = JSON.stringify({
    provider: settings.provider,
    model: settings.model,
    apiKey: settings.apiKey ? "set" : "",
    baseUrl: settings.baseUrl
  });
  if (aiVerificationPromise && aiVerificationKey === verificationKey) return aiVerificationPromise;
  aiVerificationKey = verificationKey;
  if (!validation.ok) {
    if (aiSettingsStatus) {
      aiSettingsStatus.innerHTML = `<span class="warn">Not connected</span> - ${validation.message}; GPRECian Bot uses built-in answers only`;
    }
    return false;
  }
  aiVerificationPromise = (async () => {
    if (aiSettingsStatus) {
      aiSettingsStatus.innerHTML = `<span class="warn">Verifying</span> - checking ${settings.provider} connection...`;
    }
    if (settings.provider === "ollama") {
      const baseUrl = (settings.baseUrl || "http://localhost:11434").replace(/\/$/, "");
      const controller = new AbortController();
      const timeoutId = setTimeout(() => controller.abort(), 5000);
      try {
        const response = await fetch(`${baseUrl}/api/tags`, { signal: controller.signal });
        if (!response.ok) throw new Error(`HTTP ${response.status}`);
        const data = await response.json();
        const modelNames = (data?.models || []).map((model) => model.name);
        if (!modelNames.some((name) => aiModelNameMatches(name, settings.model))) {
          throw new Error(`model "${settings.model}" is not installed`);
        }
      } finally {
        clearTimeout(timeoutId);
      }
    } else {
      const reply = await fetchAiReply(
        settings,
        "Reply with exactly OK.",
        "You are only testing whether this AI provider configuration works. Reply with exactly OK."
      );
      if (!reply) throw new Error("empty response");
    }
    if (aiSettingsStatus) {
      aiSettingsStatus.innerHTML = `<span class="ok">Connected</span> - ${settings.provider} verified with ${settings.model}`;
    }
    if (feedbackEl) {
      feedbackEl.textContent = `AI settings saved and verified. ${settings.provider} responded successfully.`;
      feedbackEl.classList.add("success");
    }
    return true;
  })()
    .catch((error) => {
      const message = error?.name === "AbortError" ? "connection timed out" : error?.message || "connection failed";
      if (aiSettingsStatus) {
        aiSettingsStatus.innerHTML = `<span class="warn">Not connected</span> - ${message}`;
      }
      if (feedbackEl) {
        feedbackEl.textContent = `AI settings saved, but verification failed: ${message}`;
        feedbackEl.classList.remove("success");
      }
      return false;
    })
    .finally(() => {
      aiVerificationPromise = null;
    });
  return aiVerificationPromise;
};

if (aiProviderInput) {
  const populateAiSettingsForm = () => {
    const settings = getAiSettings();
    if (settings.provider) aiProviderInput.value = settings.provider;
    if (aiModelInput) aiModelInput.value = settings.model;
    if (aiApiKeyInput) aiApiKeyInput.value = settings.apiKey;
    if (aiBaseUrlInput) aiBaseUrlInput.value = settings.baseUrl;
    showOllamaFields(settings.provider === "ollama");
    renderAiSettingsStatus();
    if (getAiSettingsValidation(settings).ok) {
      verifyAiSettingsConnection(settings, null);
    }
  };
  populateAiSettingsForm();
  onAdminConfigLoaded(populateAiSettingsForm);
}

aiProviderInput?.addEventListener("change", () => showOllamaFields(aiProviderInput.value === "ollama"));

saveAiSettingsButton?.addEventListener("click", async () => {
  const settings = {
    provider: aiProviderInput?.value || "",
    model: aiModelInput?.value.trim() || "",
    apiKey: aiApiKeyInput?.value.trim() || "",
    baseUrl: aiBaseUrlInput?.value.trim() || ""
  };
  saveAiSettings(settings);
  renderAiSettingsStatus();
  const validation = getAiSettingsValidation(settings);
  if (aiSettingsFeedback) {
    const provider = aiProviderInput?.value || "";
    const scopeNote = "This applies on the public website and inside every dashboard - though role-specific real-data lookups (attendance, notices, records, etc.) always answer first, so the live AI only steps in for general questions those don't already cover.";
    if (!validation.ok) {
      aiSettingsFeedback.textContent = `Saved, but not connected: ${validation.message}. ${scopeNote}`;
      aiSettingsFeedback.classList.remove("success");
    } else {
      aiSettingsFeedback.textContent =
        provider === "ollama" || provider === "gemini"
          ? `AI settings saved. Status is configured until a live request succeeds. ${scopeNote}`
          : `AI settings saved. Status is configured until a live request succeeds. Note: OpenAI and Anthropic (Claude) usually block direct browser calls without a backend. ${scopeNote}`;
      aiSettingsFeedback.classList.add("success");
    }
  }
  await persistIntegrationSettings(
    aiSettingsFeedback,
    validation.ok ? "AI settings saved. Status is configured until a live request succeeds." : `AI settings saved, but not connected: ${validation.message}.`,
    validation.ok
  );
  if (validation.ok) {
    await verifyAiSettingsConnection(settings, aiSettingsFeedback);
  }
});

const ollamaModelsTableCard = document.querySelector("#ollamaModelsTableCard");
const ollamaModelsBody = document.querySelector("#ollamaModelsBody");

checkOllamaConnectionButton?.addEventListener("click", async () => {
  if (!ollamaConnectionStatus) return;
  const baseUrl = (aiBaseUrlInput?.value.trim() || "http://localhost:11434").replace(/\/$/, "");
  ollamaConnectionStatus.innerHTML = `<span class="warn">Checking...</span>`;
  ollamaModelsTableCard?.classList.add("is-hidden");
  const controller = new AbortController();
  const timeoutId = setTimeout(() => controller.abort(), 5000);
  try {
    const response = await fetch(`${baseUrl}/api/tags`, { signal: controller.signal });
    if (!response.ok) throw new Error(`HTTP ${response.status}`);
    const data = await response.json();
    const models = data?.models || [];
    if (!models.length) {
      ollamaConnectionStatus.innerHTML = `<span class="warn">Connected, but no models installed</span> - run <code>ollama pull llama3.2</code>`;
      return;
    }
    const modelNames = models.map((model) => model.name);
    const enteredModel = aiModelInput?.value.trim() || "llama3.2";
    const modelMatches = modelNames.some((name) => aiModelNameMatches(name, enteredModel));
    ollamaConnectionStatus.innerHTML = modelMatches
      ? `<span class="ok">Connected</span> - ${models.length} model(s) available, including "${escapeHtml(enteredModel)}" (the one in the Model field above)`
      : `<span class="warn">Connected, but "${escapeHtml(enteredModel)}" is not one of the installed models</span> - update the Model field above to one of: ${modelNames.map(escapeHtml).join(", ")}`;
    if (ollamaModelsBody) {
      ollamaModelsBody.innerHTML = models
        .map((model) => {
          const sizeGb = model.size ? `${(model.size / 1e9).toFixed(1)} GB` : "-";
          return `<tr><td>${escapeHtml(model.name)}</td><td>${sizeGb}</td><td>${escapeHtml(model.details?.family || "-")}</td><td>${escapeHtml(model.details?.parameter_size || "-")}</td></tr>`;
        })
        .join("");
      ollamaModelsTableCard?.classList.remove("is-hidden");
    }
  } catch (error) {
    ollamaConnectionStatus.innerHTML = `<span class="warn">Not reachable</span> - make sure "ollama serve" is running and OLLAMA_ORIGINS allows this site's address (${error?.name === "AbortError" ? "timed out" : "connection failed"})`;
  } finally {
    clearTimeout(timeoutId);
  }
});

const aiStatusBadge = (status) => {
  const labels = { success: "Success", failure: "Failed", rateLimited: "Rate-limited", blocked: "Blocked", offTopic: "Off-topic" };
  const cssClass = status === "success" ? "ok" : status === "failure" ? "warn" : "warn";
  return `<span class="${cssClass}">${labels[status] || status}</span>`;
};

const renderAiRequestLog = () => {
  const log = getAiRequestLog();
  const body = document.querySelector("#aiRequestLogBody");
  const empty = document.querySelector("#aiRequestLogEmpty");
  if (!body) return;
  body.innerHTML = log
    .map(
      (entry) => `
        <tr>
          <td>${new Date(entry.timestamp).toLocaleTimeString("en-IN")}</td>
          <td>${escapeHtml(entry.provider || "-")}</td>
          <td>${escapeHtml(entry.model || "-")}</td>
          <td>${aiStatusBadge(entry.status)}</td>
          <td>${entry.latencyMs ? `${entry.latencyMs} ms` : "-"}</td>
          <td>${entry.error ? escapeHtml(entry.error) : "-"}</td>
        </tr>`
    )
    .join("");
  empty?.classList.toggle("is-hidden", log.length > 0);
};

const renderAiUsageStats = () => {
  const stats = getAiUsageStats();
  const log = getAiRequestLog();
  const logCounts = log.reduce(
    (counts, entry) => {
      const status = entry.status || "";
      if (status === "success" || status === "failure") counts.attempts += 1;
      if (status === "success") counts.successes += 1;
      if (status === "failure") counts.failures += 1;
      if (status === "rateLimited") counts.rateLimited += 1;
      if (status === "blocked") counts.blocked += 1;
      if (status === "offTopic") counts.offTopic += 1;
      return counts;
    },
    { attempts: 0, successes: 0, failures: 0, rateLimited: 0, blocked: 0, offTopic: 0 }
  );
  const displayStats = {
    attempts: Math.max(Number(stats.attempts) || 0, logCounts.attempts),
    successes: Math.max(Number(stats.successes) || 0, logCounts.successes),
    failures: Math.max(Number(stats.failures) || 0, logCounts.failures),
    rateLimited: Math.max(Number(stats.rateLimited) || 0, logCounts.rateLimited),
    blocked: Math.max(Number(stats.blocked) || 0, logCounts.blocked),
    offTopic: Math.max(Number(stats.offTopic) || 0, logCounts.offTopic)
  };
  const setStat = (id, value) => { const el = document.querySelector(id); if (el) el.textContent = value; };
  setStat("#aiUsageAttempts", displayStats.attempts);
  setStat("#aiUsageSuccesses", displayStats.successes);
  setStat("#aiUsageFailures", displayStats.failures);
  setStat("#aiUsageRateLimited", displayStats.rateLimited);
  setStat("#aiUsageBlocked", displayStats.blocked);
  setStat("#aiUsageOffTopic", displayStats.offTopic);

  // Success rate and average latency are computed straight from the recent request log (not the
  // running counters above), so they reflect what actually happened, not just tallies.
  const completed = log.filter((entry) => entry.status === "success" || entry.status === "failure");
  const successRate = completed.length ? Math.round((completed.filter((entry) => entry.status === "success").length / completed.length) * 100) : null;
  setStat("#aiUsageSuccessRate", successRate === null ? "-" : `${successRate}%`);
  const timedEntries = log.filter((entry) => entry.latencyMs);
  const avgLatency = timedEntries.length ? Math.round(timedEntries.reduce((sum, entry) => sum + entry.latencyMs, 0) / timedEntries.length) : null;
  setStat("#aiUsageAvgLatency", avgLatency === null ? "-" : `${avgLatency} ms`);

  const lastActivity = document.querySelector("#aiUsageLastActivity");
  if (lastActivity) {
    const latestLogEntry = log[0];
    const lastUsedAt = stats.lastUsedAt || latestLogEntry?.timestamp || 0;
    const lastProvider = stats.lastProvider || latestLogEntry?.provider || "-";
    const lastError = stats.lastError || latestLogEntry?.error || "";
    if (lastUsedAt) {
      lastActivity.textContent = `Last used: ${new Date(lastUsedAt).toLocaleString("en-IN")} via ${lastProvider || "-"}${lastError ? ` - last error: ${lastError}` : ""}`;
    } else if (latestLogEntry) {
      lastActivity.textContent = `Last recorded request: ${aiStatusBadge(latestLogEntry.status).replace(/<[^>]+>/g, "")} via ${lastProvider || "-"}${lastError ? ` - last error: ${lastError}` : ""}`;
    } else {
      lastActivity.textContent = "No AI requests recorded yet.";
    }
  }
  renderAiRequestLog();
};
if (document.querySelector("#aiUsageAttempts")) renderAiUsageStats();

document.querySelector("#resetAiUsageStatsButton")?.addEventListener("click", () => {
  localStorage.removeItem("gprecAiCallTimestamps");
  const result = gprecDbPost("/ai-usage/reset", {});
  showFeedToast(result?.ok ? "AI usage stats and log reset." : "Could not reset AI usage stats. Restart the portal API and make sure you are signed in as admin.");
  renderAiUsageStats();
});

const renderKnowledgeBaseStatus = (syncMessage = "") => {
  const statusEl = document.querySelector("#knowledgeBaseStatus");
  if (!statusEl) return;
  const kb = getGprecianKnowledgeBase();
  statusEl.innerHTML =
    `<span class="ok">${kb.chunks.length} items indexed</span> - last refreshed ${new Date(kb.builtAt).toLocaleString("en-IN")}` +
    (syncMessage ? `<br>${syncMessage}` : "");
};
// Deferred: buildGprecianKnowledgeBase() (called transitively via renderKnowledgeBaseStatus) reads
// getAdmissionsContent/getFeeStructureContent/getScholarshipsContent/getDepartmentsList, which are
// all declared much later in this file - calling it synchronously here would throw a
// "before initialization" TDZ error. setTimeout(0) waits until the whole script has finished
// running (those consts are defined by then) before this ever executes.
if (document.querySelector("#knowledgeBaseStatus")) window.setTimeout(renderKnowledgeBaseStatus, 0);

document.querySelector("#refreshKnowledgeBaseButton")?.addEventListener("click", (event) => {
  refreshGprecDbBootstrap();
  const kb = refreshGprecianKnowledgeBase();
  renderKnowledgeBaseStatus();
  if (!document.querySelector("#knowledgeBaseTableCard")?.classList.contains("is-hidden")) renderKnowledgeBaseTable();

  // Also (re)embeds every chunk into knowledge_base_chunks so the bot's live-AI path can do real
  // semantic search (see retrieveRelevantChunksSemantic) instead of local keyword overlap - this
  // is the slower step (one embedding call per chunk against the local Ollama model), so the
  // button is disabled and the loader shown for its duration.
  const button = event.currentTarget;
  const originalLabel = button.textContent;
  button.disabled = true;
  button.textContent = "Syncing for semantic search...";
  showGprecLoader();
  const result = gprecDbRequest("/knowledge-base/refresh", { method: "POST", body: { chunks: kb.chunks } });
  hideGprecLoader();
  button.disabled = false;
  button.textContent = originalLabel;
  renderKnowledgeBaseStatus(
    result?.ok
      ? `<span class="ok">${result.count} chunks embedded for semantic search.</span>`
      : `<span class="warn">Semantic search sync failed (embedding model unreachable) - the bot will fall back to keyword matching until this succeeds.</span>`
  );
});

const renderKnowledgeBaseTable = () => {
  const body = document.querySelector("#knowledgeBaseTableBody");
  if (!body) return;
  const kb = getGprecianKnowledgeBase();
  body.innerHTML = kb.chunks
    .map(
      (chunk) => `
        <tr>
          <td>${escapeHtml(chunk.id)}</td>
          <td>${escapeHtml(chunk.text)}</td>
          <td>${chunk.link ? `<a href="${escapeHtml(chunk.link.url)}" target="_blank" rel="noreferrer">${escapeHtml(chunk.link.label)}</a>` : "-"}</td>
        </tr>`
    )
    .join("");
};

document.querySelector("#viewKnowledgeBaseButton")?.addEventListener("click", (event) => {
  const card = document.querySelector("#knowledgeBaseTableCard");
  if (!card) return;
  const willShow = card.classList.contains("is-hidden");
  card.classList.toggle("is-hidden", !willShow);
  event.target.textContent = willShow ? "Hide Knowledge Base Contents" : "View Knowledge Base Contents";
  if (willShow) renderKnowledgeBaseTable();
});

// The bot's actual feedback/"learning" loop - see bot_feedback in portal_db_server.py. Only
// Pending items are shown (Approved/Dismissed ones have already been acted on and would just be
// clutter here); approving calls /bot-feedback/resolve, which both marks the row Approved AND
// embeds the correction into knowledge_base_chunks in the same call, so it's searchable
// immediately - no separate "now refresh the knowledge base" step needed.
const renderBotFeedback = () => {
  const body = document.querySelector("#botFeedbackBody");
  if (!body) return;
  const result = gprecDbRequest("/bot-feedback/list", { method: "POST", body: { status: "Pending" } });
  const items = result?.ok ? result.items : [];
  document.querySelector("#botFeedbackEmpty")?.classList.toggle("is-hidden", items.length > 0);
  body.innerHTML = items
    .map(
      (item) => `
        <article class="bot-feedback-item" data-feedback-id="${escapeHtml(item.id)}">
          <div class="bot-feedback-header">
            <div class="bot-feedback-question">
              <span>Question</span>
              <strong>${escapeHtml(item.question)}</strong>
            </div>
            <div class="bot-feedback-meta">
              <span>Reported</span>
              <strong>${escapeHtml(item.createdAt)}</strong>
            </div>
          </div>
          <div class="bot-feedback-answer">
            <span>Bot's Answer</span>
            <p>${escapeHtml(item.botAnswer)}</p>
          </div>
          <div class="bot-feedback-review">
            <label class="bot-feedback-correction">
              <span>Correction</span>
              <textarea rows="3" placeholder="Write the correct answer..." data-correction-input></textarea>
            </label>
            <div class="bot-feedback-actions">
              <button type="button" data-approve-feedback>Approve &amp; Teach</button>
              <button type="button" class="btn-reject" data-dismiss-feedback>Dismiss</button>
            </div>
          </div>
        </article>
      `
    )
    .join("");
};
if (document.querySelector("#botFeedbackBody")) renderBotFeedback();

document.querySelector("#botFeedbackBody")?.addEventListener("click", (event) => {
  const row = event.target.closest("[data-feedback-id]");
  if (!row) return;
  const feedbackId = row.dataset.feedbackId;
  if (event.target.matches("[data-approve-feedback]")) {
    const correction = row.querySelector("[data-correction-input]")?.value.trim();
    if (!correction) {
      showFeedToast("Write the correct answer before approving.");
      return;
    }
    const result = gprecDbRequest("/bot-feedback/resolve", { method: "POST", body: { id: feedbackId, correction } });
    showFeedToast(result?.ok ? "Correction taught to the bot." : "Could not save this correction - try again.");
    if (result?.ok) renderBotFeedback();
  } else if (event.target.matches("[data-dismiss-feedback]")) {
    gprecDbRequest("/bot-feedback/dismiss", { method: "POST", body: { id: feedbackId } });
    renderBotFeedback();
  }
});

// Feature Ideas: lets an admin describe a feature in plain English and get a drafted approach
// + starter code snippet back from AI. This never touches the live site's files - it only shows
// the suggestion as text for a developer to review and add in by hand.
const featureIdeaSystemPrompt =
  "You are a coding assistant for the GPREC college website, a static HTML/CSS/JS site with no build tools, " +
  "the configured portal data sources, and every page shares " +
  "one script.js file plus one shared styles.css file. Pages live in index.html (root), or one level deep under " +
  "pages/ or dashboards/. Match this site's existing design system in every suggestion: CSS " +
  "variables --navy (#04284a, primary brand color), --orange (#ff8702, accent), --white, --ink, --muted, --line, " +
  "--paper, --green, --red defined in :root; buttons and toggles use var(--navy) as their active/on color, never " +
  "introduce new colors; cards use the .admin-card / .admin-form-card classes with an <h3> title; on/off settings " +
  "use the .toggle-switch component (input + <span class=\"toggle-slider\">), not plain checkboxes; per-row " +
  "settings go in an .admin-table-card table; free-text fields are a <label> wrapping a fixed-size (resize: none) " +
  "textarea or input; status messages use <p class=\"portal-feedback\"> (add class \"success\" on success); data " +
  "is read/written with a getX()/saveX() pair backed by localStorage.getItem/setItem + JSON, matching functions " +
  "like getMaintenanceMode/saveMaintenanceMode already in script.js. When the admin describes a feature they " +
  "want, reply in exactly this structure: (1) Approach - 2-4 sentences on how it would work, using the " +
  "conventions above. (2) Where to add it - if this fits an existing page, name the exact file(s) (e.g. " +
  "dashboards/student-dashboard.html, script.js, styles.css) and roughly where in that file (e.g. \"inside the " +
  "Profile section\", \"near the other admin-card blocks\", \"appended to the end of styles.css\"). If it needs " +
  "a brand-new page instead, say so explicitly, give the new file its path following this site's convention " +
  "(pages/ for public pages or login/detail-style pages, dashboards/ for a new dashboard or drill-down detail page - e.g. pages/blog.html), " +
  "note that it should start from the structure in pages/page-template.html, and note that the new filename must " +
  "be added to the GPREC_PAGE_FOLDERS map near the top of script.js (mapping it to its folder) or links to it via " +
  "gprecPageUrl() will break, plus where a nav link to it should be added. (3) Code - one small fenced code block " +
  "per file with the snippet to add, each block preceded by a line naming its file. (4) How to wire it in - 1-3 sentences " +
  "on any final step (e.g. an id to hook up, a function to call). Keep snippets short and focused only on the " +
  "new feature. This is a draft for a developer to review and adapt - do not claim the feature has already been " +
  "added.";
const featureIdeaInput = document.querySelector("#featureIdeaInput");
const featureIdeaAskButton = document.querySelector("#featureIdeaAskButton");
const featureIdeaFeedback = document.querySelector("#featureIdeaFeedback");
const featureIdeaResult = document.querySelector("#featureIdeaResult");
const featureIdeaOutput = document.querySelector("#featureIdeaOutput");
const renderFeatureIdeaOutput = (text) => {
  if (!featureIdeaOutput) return;
  const parts = text.split(/```[a-zA-Z]*\n?/);
  const html = parts
    .map((part, index) => {
      const trimmed = part.trim();
      if (!trimmed) return "";
      return index % 2 === 1
        ? `<pre><code>${escapeHtml(trimmed)}</code></pre>`
        : `<p>${escapeHtml(trimmed).replace(/\n/g, "<br>")}</p>`;
    })
    .join("");
  featureIdeaOutput.innerHTML = html || `<p>${escapeHtml(text)}</p>`;
};
featureIdeaAskButton?.addEventListener("click", async () => {
  const description = featureIdeaInput?.value.trim() || "";
  if (!featureIdeaFeedback) return;
  featureIdeaFeedback.classList.remove("success");
  if (!description) {
    featureIdeaFeedback.textContent = "Describe the feature you want first.";
    return;
  }
  const aiSettings = getAiSettings();
  if (!isAiSettingsConfigured(aiSettings)) {
    featureIdeaFeedback.textContent = "Set up an AI provider in Data Integrations first.";
    return;
  }
  const originalLabel = featureIdeaAskButton.textContent;
  featureIdeaAskButton.disabled = true;
  featureIdeaAskButton.textContent = "Thinking...";
  featureIdeaFeedback.textContent = "";
  featureIdeaResult?.classList.add("is-hidden");
  try {
    const reply = await fetchAiReply(aiSettings, description, featureIdeaSystemPrompt);
    renderFeatureIdeaOutput(reply || "No suggestion returned.");
    featureIdeaResult?.classList.remove("is-hidden");
  } catch (error) {
    featureIdeaFeedback.textContent = error?.message || "The AI request failed. Check the provider setup in Data Integrations.";
  } finally {
    featureIdeaAskButton.disabled = false;
    featureIdeaAskButton.textContent = originalLabel;
  }
});

// Calendar & Reminders: one shared month-view calendar reused on the student, faculty, admin,
// and department dashboards. Reminders added on the admin/department/faculty dashboards are
// "shared" (everyone sees them, only staff can delete them). Reminders added on the student
// dashboard are "personal" (scope: "personal" + owner: the student's own id), filtered with
// gprecStudentId. Exam dates, placement drives, and alumni events are also merged in live and
// shown read-only, so the calendar reflects current data without needing manual syncing.
const getCalendarReminders = () => getGprecDbBootstrap()?.calendarReminders || [];
const saveCalendarReminders = (reminders) => gprecDbPost("/calendar-reminders", reminders);

// Drops any manually-added reminder dated before the start of the current month, so past
// reminders don't pile up forever - called once per page load.
const pruneCalendarReminders = () => {
  const startOfMonth = new Date();
  startOfMonth.setDate(1);
  const cutoff = startOfMonth.toISOString().slice(0, 10);
  const reminders = getCalendarReminders();
  const kept = reminders.filter((reminder) => reminder.date >= cutoff);
  if (kept.length !== reminders.length) saveCalendarReminders(kept);
};

// Indian national holidays are fetched live from Google's public "Holidays in India" calendar
// using the API key saved in the "Google Calendar API" card under Data Integrations. Only
// "Public holiday" events are kept (Google's feed also has minor "Observance" entries that
// aren't actual holidays). Results are cached per year in localStorage since a given year's
// holidays never change. Without a key saved, no national holidays show on the calendar - see
// that admin card for setup steps.
const getGoogleCalendarApiKey = () =>
  adminConfigFieldsLoaded.googleCalendarApiKey ? defaultAdminConfig.googleCalendarApiKey || "" : localStorage.getItem("gprecGoogleCalendarApiKey") || "";
const liveIndianHolidayCache = {};
const liveIndianHolidayFetchesInFlight = new Set();
const calendarRerenderListeners = [];
const notifyCalendarRerender = () => calendarRerenderListeners.forEach((listener) => listener());

// getLibraryRecords() is async (it may call a real library API if one is configured), but
// getAutoCalendarEntries() below is synchronous, so the student's currently-issued books are
// fetched once, cached in memory, and the calendar is asked to re-render once they're ready -
// same fetch-then-notify pattern as the Google Calendar holiday lookup above.
let cachedMyLibraryDue = null;
let libraryDueFetchInFlight = false;
const refreshMyLibraryDue = (studentId) => {
  if (libraryDueFetchInFlight) return;
  libraryDueFetchInFlight = true;
  getLibraryRecords()
    .then((records) => {
      cachedMyLibraryDue = records.filter((record) => record.rollNumber === studentId && record.status !== "Returned");
      notifyCalendarRerender();
    })
    .catch(() => {
      cachedMyLibraryDue = cachedMyLibraryDue || [];
    })
    .finally(() => {
      libraryDueFetchInFlight = false;
    });
};

const getCachedLiveIndianHolidays = (year) => {
  if (liveIndianHolidayCache[year]) return liveIndianHolidayCache[year];
  try {
    const stored = JSON.parse(localStorage.getItem(`gprecLiveIndianHolidays_${year}`) || "null");
    if (Array.isArray(stored)) {
      liveIndianHolidayCache[year] = stored;
      return stored;
    }
  } catch {
    // fall through to null below
  }
  return null;
};

const fetchLiveIndianHolidays = (year, apiKey) => {
  const cacheKey = `${year}`;
  if (getCachedLiveIndianHolidays(year) || liveIndianHolidayFetchesInFlight.has(cacheKey)) return;
  liveIndianHolidayFetchesInFlight.add(cacheKey);
  const calendarId = encodeURIComponent("en.indian#holiday@group.v.calendar.google.com");
  const url =
    `https://www.googleapis.com/calendar/v3/calendars/${calendarId}/events` +
    `?key=${encodeURIComponent(apiKey)}&timeMin=${year}-01-01T00:00:00Z&timeMax=${year}-12-31T23:59:59Z` +
    `&singleEvents=true&orderBy=startTime`;
  fetch(url)
    .then((response) => (response.ok ? response.json() : Promise.reject(new Error("Request failed"))))
    .then((data) => {
      const holidays = (data.items || [])
        .filter((event) => (event.description || "").startsWith("Public holiday") && event.start?.date)
        .map((event) => ({ date: event.start.date, title: event.summary }));
      liveIndianHolidayCache[year] = holidays;
      localStorage.setItem(`gprecLiveIndianHolidays_${year}`, JSON.stringify(holidays));
      notifyCalendarRerender();
    })
    .catch(() => {
      // Invalid key, quota hit, or offline - this year just shows no national holidays.
    })
    .finally(() => {
      liveIndianHolidayFetchesInFlight.delete(cacheKey);
    });
};

const getAutoCalendarEntries = (centerYear = new Date().getFullYear()) => {
  const entries = [];
  const apiKey = getGoogleCalendarApiKey();
  if (apiKey) {
    [centerYear - 1, centerYear, centerYear + 1].forEach((year) => {
      fetchLiveIndianHolidays(year, apiKey);
      (getCachedLiveIndianHolidays(year) || []).forEach((holiday) => {
        entries.push({
          id: `auto-holiday-${holiday.date}`,
          title: `Holiday: ${holiday.title}`,
          date: holiday.date,
          description: "National holiday",
          scope: "shared",
          kind: "holiday-national",
          auto: true
        });
      });
    });
  }
  const examRows = getAllExamCellData();
  const seenExams = new Set();
  Object.keys(examRows).forEach((branch) => {
    examRows[branch].forEach((row) => {
      const key = `${branch}-${row.code}-${row.date}`;
      if (seenExams.has(key) || !row.date) return;
      seenExams.add(key);
      entries.push({
        id: `auto-exam-${key}`,
        title: `Exam: ${row.subject} (${branch})`,
        date: row.date,
        description: row.time || "",
        scope: "shared",
        kind: "exam",
        auto: true
      });
    });
  });
  getPlacementDrives().forEach((drive) => {
    if (!drive.date) return;
    entries.push({
      id: `auto-placement-${drive.id}`,
      title: `Placement: ${drive.company}`,
      date: drive.date,
      description: `${drive.role} - ${drive.ctc}`,
      scope: "shared",
      kind: "placement",
      auto: true
    });
  });
  getAlumniEvents().forEach((event) => {
    if (!event.date) return;
    entries.push({
      id: `auto-event-${event.id}`,
      title: `Event: ${event.title}`,
      date: event.date,
      description: event.location || "",
      scope: "shared",
      kind: "event",
      auto: true
    });
  });

  // Fee due dates, approved faculty leave, and class cancellations are personal to whoever is
  // looking at their own dashboard - each block below only runs on that specific dashboard page,
  // so a student never sees another student's fee dates and a faculty member never sees another
  // faculty's leave/cancellations.
  const currentFile = window.location.pathname.split("/").pop() || "";
  const toIso = (d) => `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, "0")}-${String(d.getDate()).padStart(2, "0")}`;
  const pushMilestoneEntries = (items) => {
    items.forEach((item) => {
      (item.milestones || []).forEach((milestone, index) => {
        if (!milestone.dueDate) return;
        entries.push({
          id: `auto-milestone-${item.id}-${index}`,
          title: `${item.category || "Project"} Milestone: ${milestone.title}`,
          date: milestone.dueDate,
          description: milestone.submissionStatus || "",
          scope: "shared",
          kind: "milestone",
          auto: true
        });
      });
    });
  };

  if (currentFile === "student-dashboard.html") {
    const studentId = localStorage.getItem("gprecStudentId") || "";
    const myFees = getStudentPendingFeeOverrides()[studentId] || [];
    myFees.forEach((fee, index) => {
      if (!fee.dueDate || Number(fee.amount) <= 0) return;
      entries.push({
        id: `auto-fee-${studentId}-${index}`,
        title: `Fee Due: ${fee.feeType}`,
        date: fee.dueDate,
        description: `Rs. ${Number(fee.amount).toLocaleString("en-IN")} pending`,
        scope: "shared",
        kind: "fee-due",
        auto: true
      });
    });

    pushMilestoneEntries(
      [...getProjects(), ...getResearch()].filter(
        (item) => item.status === "Approved" && (item.studentId === studentId || (item.teamMembers || []).some((member) => member.studentId === studentId))
      )
    );

    if (cachedMyLibraryDue === null) refreshMyLibraryDue(studentId);
    (cachedMyLibraryDue || []).forEach((record) => {
      if (!record.dueDate) return;
      entries.push({
        id: `auto-library-${studentId}-${record.bookTitle}-${record.dueDate}`,
        title: `Return Book: ${record.bookTitle}`,
        date: record.dueDate,
        description: record.author ? `by ${record.author}` : "",
        scope: "shared",
        kind: "library-due",
        auto: true
      });
    });
  }

  if (currentFile === "faculty-dashboard.html") {
    const facultyEmail = (localStorage.getItem("gprecFacultyEmail") || "").toLowerCase();
    getLeaveRequests()
      .filter((request) => request.status === "Approved" && (request.facultyEmail || "").toLowerCase() === facultyEmail)
      .forEach((request) => {
        if (!request.fromDate || !request.toDate) return;
        const from = new Date(`${request.fromDate}T00:00:00`);
        const to = new Date(`${request.toDate}T00:00:00`);
        for (let day = new Date(from); day <= to; day.setDate(day.getDate() + 1)) {
          const iso = toIso(day);
          entries.push({
            id: `auto-leave-${request.id}-${iso}`,
            title: `Leave: ${request.leaveType}`,
            date: iso,
            description: request.reason || "",
            scope: "shared",
            kind: "leave",
            auto: true
          });
        }
      });

    getClassCancellations()
      .filter((item) => (item.facultyEmail || "").toLowerCase() === facultyEmail)
      .forEach((item) => {
        if (!item.date) return;
        entries.push({
          id: `auto-cancel-${item.id}`,
          title: `Class Cancelled: ${item.subject}`,
          date: item.date,
          description: item.reason || "",
          scope: "shared",
          kind: "cancelled-class",
          auto: true
        });
      });

    pushMilestoneEntries(
      [...getProjects(), ...getResearch()].filter(
        (item) => item.status === "Approved" && (item.guideEmail || "").toLowerCase() === facultyEmail
      )
    );
  }

  if (currentFile === "non-teaching-dashboard.html") {
    const staffEmail = (localStorage.getItem("gprecNonTeachingEmail") || "").toLowerCase();
    getLeaveRequests()
      .filter((request) => request.isNonTeaching && request.status === "Approved" && (request.staffEmail || "").toLowerCase() === staffEmail)
      .forEach((request) => {
        if (!request.fromDate || !request.toDate) return;
        const from = new Date(`${request.fromDate}T00:00:00`);
        const to = new Date(`${request.toDate}T00:00:00`);
        for (let day = new Date(from); day <= to; day.setDate(day.getDate() + 1)) {
          const iso = toIso(day);
          entries.push({
            id: `auto-leave-${request.id}-${iso}`,
            title: `Leave: ${request.leaveType}`,
            date: iso,
            description: request.reason || "",
            scope: "shared",
            kind: "leave",
            auto: true
          });
        }
      });
  }

  return entries;
};

(() => {
  const grid = document.querySelector("#calendarGrid");
  if (!grid) return;
  pruneCalendarReminders();
  const monthLabel = document.querySelector("#calendarMonthLabel");
  const prevButton = document.querySelector("#calendarPrevMonth");
  const nextButton = document.querySelector("#calendarNextMonth");
  const todayButton = document.querySelector("#calendarTodayButton");
  const weekdaysRow = document.querySelector(".calendar-weekdays");
  const staticWeekdaysHtml = weekdaysRow?.innerHTML || "";
  const titleInput = document.querySelector("#calendarReminderTitle");
  const dateInput = document.querySelector("#calendarReminderDate");
  const timeInput = document.querySelector("#calendarReminderTime");
  const descriptionInput = document.querySelector("#calendarReminderDescription");
  const kindSelect = document.querySelector("#calendarReminderKind");
  const addButton = document.querySelector("#calendarAddReminderButton");
  const feedback = document.querySelector("#calendarReminderFeedback");
  const canAdd = Boolean(addButton);
  const currentFile = window.location.pathname.split("/").pop() || "";
  const isStudentPage = currentFile === "student-dashboard.html";
  const isNonTeachingPage = currentFile === "non-teaching-dashboard.html";
  const isPersonalScope = isStudentPage || isNonTeachingPage;
  const studentId = localStorage.getItem("gprecStudentId") || "";
  const personalOwnerId = isNonTeachingPage ? localStorage.getItem("gprecNonTeachingEmail") || "" : studentId;

  const isoFromDate = (d) => `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, "0")}-${String(d.getDate()).padStart(2, "0")}`;
  const addMonths = (date, delta) => {
    const targetMonth = date.getMonth() + delta;
    const targetYear = date.getFullYear() + Math.floor(targetMonth / 12);
    const normalizedMonth = ((targetMonth % 12) + 12) % 12;
    const daysInTarget = new Date(targetYear, normalizedMonth + 1, 0).getDate();
    return new Date(targetYear, normalizedMonth, Math.min(date.getDate(), daysInTarget));
  };
  const startOfWeek = (date) => {
    const copy = new Date(date);
    copy.setDate(copy.getDate() - copy.getDay());
    return copy;
  };

  const minDate = new Date();
  minDate.setHours(0, 0, 0, 0);
  let viewDate = new Date(minDate);
  const supportedViews = ["day", "week", "month", "year", "schedule"];
  // Remembers the last view picked on this page (Month/Week/Day/...) so it doesn't reset back to
  // Month every time the page loads - stays until the user picks a different one.
  const calendarViewStorageKey = `gprecCalendarView_${window.location.pathname.split("/").pop() || ""}`;
  const storedView = localStorage.getItem(calendarViewStorageKey);
  let currentView = supportedViews.includes(storedView) ? storedView : "month";
  let selectedDate = null;
  const todayIso = () => isoFromDate(new Date());

  // Shared reminders/auto-entries show for everyone; personal ones only show to the student who
  // owns them, and only on their own dashboard. Past dates are included so browsing back to
  // earlier months/years (Prev, or Year view) still shows what was there.
  const visibleEntries = () => [
    ...getAutoCalendarEntries(viewDate.getFullYear()),
    ...getCalendarReminders().filter(
      (reminder) => reminder.scope !== "personal" || (isPersonalScope && reminder.owner === personalOwnerId)
    )
  ];

  const canDeleteEntry = (entry) => {
    if (entry.auto) return false;
    if (entry.scope === "personal") return isPersonalScope && entry.owner === personalOwnerId;
    return canAdd && !isPersonalScope;
  };

  // Older reminders saved before "kind" existed fall back to "personal"/"reminder" by scope.
  const entryKind = (entry) => entry.kind || (entry.scope === "personal" ? "personal" : "reminder");

  const modalOverlay = document.querySelector("#calendarEventModalOverlay");
  const modalDot = document.querySelector("#calendarEventModalDot");
  const modalTitle = document.querySelector("#calendarEventModalTitle");
  const modalDate = document.querySelector("#calendarEventModalDate");
  const modalDescription = document.querySelector("#calendarEventModalDescription");
  const modalDeleteButton = document.querySelector("#calendarEventModalDelete");
  const modalCloseButton = document.querySelector("#calendarEventModalClose");
  let entryById = new Map();

  const closeEventModal = () => modalOverlay?.classList.add("is-hidden");

  const openEventModal = (entry) => {
    if (!modalOverlay) return;
    if (modalDot) modalDot.className = `calendar-event-modal-dot kind-${entryKind(entry)}`;
    if (modalTitle) modalTitle.textContent = entry.title;
    if (modalDate) {
      const dateLabel = new Date(entry.date).toLocaleDateString("en-IN", {
        weekday: "long",
        day: "numeric",
        month: "long",
        year: "numeric"
      });
      const timeLabel = entry.time ? ` · ${formatMinutesAsTime(getStartMinutes(entry))}` : "";
      modalDate.textContent = dateLabel + timeLabel;
    }
    if (modalDescription) {
      modalDescription.textContent = entry.description || "";
      modalDescription.classList.toggle("is-hidden", !entry.description);
    }
    if (modalDeleteButton) {
      const deletable = canDeleteEntry(entry);
      modalDeleteButton.classList.toggle("is-hidden", !deletable);
      modalDeleteButton.dataset.deleteReminder = deletable ? entry.id : "";
    }
    modalOverlay.classList.remove("is-hidden");
  };

  modalCloseButton?.addEventListener("click", closeEventModal);
  modalOverlay?.addEventListener("click", (event) => {
    if (event.target === modalOverlay) closeEventModal();
  });
  modalDeleteButton?.addEventListener("click", () => {
    const id = modalDeleteButton.dataset.deleteReminder;
    if (!id) return;
    saveCalendarReminders(getCalendarReminders().filter((reminder) => reminder.id !== id));
    closeEventModal();
    renderCalendar();
  });

  const entryChipHtml = (entry) =>
    `<button type="button" class="calendar-cell-event kind-${entryKind(entry)}" data-calendar-entry="${entry.id}">${escapeHtml(entry.title)}</button>`;

  // Most entries only have a date (no specific time), so they stay in the all-day section.
  // Reminders can carry their own "HH:MM" time field (set from the Time input); exam entries
  // instead carry a time range in their description (e.g. "10:00 AM - 1:00 PM") - either way, once
  // a start time is known the entry shows as a positioned block on the hourly timeline instead.
  const parseStartMinutes = (description) => {
    const match = /(\d{1,2}):(\d{2})\s*(AM|PM)/i.exec(description || "");
    if (!match) return null;
    let hours = parseInt(match[1], 10);
    const minutes = parseInt(match[2], 10);
    const meridiem = match[3].toUpperCase();
    if (meridiem === "PM" && hours !== 12) hours += 12;
    if (meridiem === "AM" && hours === 12) hours = 0;
    return hours * 60 + minutes;
  };

  const getStartMinutes = (entry) => {
    if (entry.time) {
      const [hours, minutes] = entry.time.split(":").map(Number);
      if (!Number.isNaN(hours) && !Number.isNaN(minutes)) return hours * 60 + minutes;
    }
    return parseStartMinutes(entry.description);
  };

  const formatMinutesAsTime = (totalMinutes) => {
    const hours24 = Math.floor(totalMinutes / 60);
    const minutes = totalMinutes % 60;
    const period = hours24 >= 12 ? "PM" : "AM";
    const hours12 = hours24 % 12 === 0 ? 12 : hours24 % 12;
    return `${hours12}:${String(minutes).padStart(2, "0")} ${period}`;
  };

  const timedEntryHtml = (entry) =>
    `<button type="button" class="calendar-day-timed-event kind-${entryKind(entry)}" style="top:${entry.startMinutes}px" data-calendar-entry="${entry.id}">${formatMinutesAsTime(entry.startMinutes)} - ${escapeHtml(entry.title)}</button>`;

  const dayCellHtml = (dateObj, dayEntries, maxVisible) => {
    const iso = isoFromDate(dateObj);
    const isToday = iso === isoFromDate(minDate);
    const isSelected = iso === selectedDate;
    const visible = dayEntries.slice(0, maxVisible);
    const extra = dayEntries.length - visible.length;
    return (
      `<div class="calendar-cell${isToday ? " is-today" : ""}${isSelected ? " is-selected" : ""}" data-calendar-date="${iso}">` +
      `<button type="button" class="calendar-cell-daynum" data-calendar-date="${iso}">${dateObj.getDate()}</button>` +
      visible.map(entryChipHtml).join("") +
      (extra > 0 ? `<span class="calendar-cell-more">+${extra} more</span>` : "") +
      `</div>`
    );
  };

  const renderMonthView = (entries) => {
    const year = viewDate.getFullYear();
    const month = viewDate.getMonth();
    const firstOfMonth = new Date(year, month, 1);
    const startDay = firstOfMonth.getDay();
    const daysInMonth = new Date(year, month + 1, 0).getDate();
    if (monthLabel) monthLabel.textContent = firstOfMonth.toLocaleDateString("en-IN", { month: "long", year: "numeric" });
    if (weekdaysRow) weekdaysRow.innerHTML = staticWeekdaysHtml;
    grid.className = "calendar-grid";
    const cells = [];
    for (let i = 0; i < startDay; i++) cells.push(`<div class="calendar-cell is-empty"></div>`);
    for (let day = 1; day <= daysInMonth; day++) {
      const dateObj = new Date(year, month, day);
      const dayEntries = entries.filter((entry) => entry.date === isoFromDate(dateObj));
      cells.push(dayCellHtml(dateObj, dayEntries, 2));
    }
    grid.innerHTML = cells.join("");
  };

  const renderWeekView = (entries) => {
    const start = startOfWeek(viewDate);
    const days = Array.from({ length: 7 }, (_, i) => {
      const d = new Date(start);
      d.setDate(start.getDate() + i);
      return d;
    });
    const first = days[0];
    const last = days[6];
    if (monthLabel) {
      monthLabel.textContent =
        first.getMonth() === last.getMonth()
          ? `${first.toLocaleDateString("en-IN", { month: "long" })} ${first.getDate()}-${last.getDate()}, ${first.getFullYear()}`
          : `${first.toLocaleDateString("en-IN", { month: "short", day: "numeric" })} - ${last.toLocaleDateString("en-IN", { month: "short", day: "numeric" })}, ${last.getFullYear()}`;
    }
    if (weekdaysRow) {
      weekdaysRow.innerHTML = days.map((d) => `<span>${d.toLocaleDateString("en-IN", { weekday: "short" })} ${d.getDate()}</span>`).join("");
    }
    grid.className = "calendar-grid view-week";
    grid.innerHTML = days
      .map((d) => dayCellHtml(d, entries.filter((entry) => entry.date === isoFromDate(d)), 6))
      .join("");
  };

  const renderDayView = (entries) => {
    const iso = isoFromDate(viewDate);
    const dayEntries = entries.filter((entry) => entry.date === iso);
    const isToday = iso === isoFromDate(minDate);
    if (monthLabel) {
      monthLabel.textContent = viewDate.toLocaleDateString("en-IN", { weekday: "long", day: "numeric", month: "long", year: "numeric" });
    }
    if (weekdaysRow) weekdaysRow.innerHTML = "";
    grid.className = "calendar-grid view-day";
    selectedDate = iso;
    if (dateInput) dateInput.value = iso;

    const weekdayShort = viewDate.toLocaleDateString("en-IN", { weekday: "short" }).toUpperCase();
    const tzOffsetMinutes = -new Date().getTimezoneOffset();
    const tzSign = tzOffsetMinutes >= 0 ? "+" : "-";
    const tzAbsMinutes = Math.abs(tzOffsetMinutes);
    const tzHours = String(Math.floor(tzAbsMinutes / 60)).padStart(2, "0");
    const tzMinutes = tzAbsMinutes % 60;
    // Include minutes when non-zero so half-hour zones like India (UTC+5:30) show correctly
    // instead of being truncated to "GMT+05".
    const tzLabel = `GMT${tzSign}${tzHours}${tzMinutes ? `:${String(tzMinutes).padStart(2, "0")}` : ""}`;
    const hourRows = Array.from({ length: 24 }, (_, hour) => {
      const label = hour === 0 ? "12 AM" : hour < 12 ? `${hour} AM` : hour === 12 ? "12 PM" : `${hour - 12} PM`;
      return `<div class="calendar-day-hour-row"><span class="calendar-day-hour-label"><span class="calendar-day-hour-label-text">${label}</span></span></div>`;
    }).join("");
    const now = new Date();
    const nowLineHtml = isToday
      ? `<div class="calendar-day-now-line" style="top:${now.getHours() * 60 + now.getMinutes()}px"><span class="calendar-day-now-dot"></span></div>`
      : "";

    const timedEntries = [];
    const allDayEntries = [];
    dayEntries.forEach((entry) => {
      const startMinutes = getStartMinutes(entry);
      if (startMinutes !== null && startMinutes !== undefined) timedEntries.push({ ...entry, startMinutes });
      else allDayEntries.push(entry);
    });
    const allDayHtml = allDayEntries.length ? allDayEntries.map(entryChipHtml).join("") : "";
    const timedEventsHtml = timedEntries.map(timedEntryHtml).join("");

    grid.innerHTML =
      `<div class="calendar-day-top">` +
      `<div class="calendar-day-head"><span class="calendar-day-head-weekday">${weekdayShort}</span><span class="calendar-day-head-num${isToday ? " is-today" : ""}">${viewDate.getDate()}</span></div>` +
      `<div class="calendar-day-allday${allDayHtml ? "" : " is-empty"}" data-calendar-date="${iso}">${allDayHtml}</div>` +
      `</div>` +
      `<div class="calendar-day-timeline"><span class="calendar-day-tz">${tzLabel}</span>${hourRows}${timedEventsHtml}${nowLineHtml}</div>`;

    const timeline = grid.querySelector(".calendar-day-timeline");
    if (timeline) {
      const scrollTarget = isToday ? now.getHours() * 60 + now.getMinutes() : 8 * 60;
      timeline.scrollTop = Math.max(0, scrollTarget - 120);
    }
  };

  // When a day has entries of more than one kind, pick the most notable one to color its dot -
  // fixed calendar dates (holidays, exams, placements) take priority over softer reminders.
  const kindPriority = [
    "holiday-national",
    "holiday-college",
    "exam",
    "leave",
    "cancelled-class",
    "milestone",
    "fee-due",
    "library-due",
    "placement",
    "event",
    "personal",
    "reminder"
  ];
  const dominantKind = (dayEntries) => {
    const kinds = dayEntries.map(entryKind);
    return kindPriority.find((kind) => kinds.includes(kind)) || kinds[0];
  };

  const renderYearView = (entries) => {
    const year = viewDate.getFullYear();
    if (monthLabel) monthLabel.textContent = String(year);
    if (weekdaysRow) weekdaysRow.innerHTML = "";
    grid.className = "calendar-grid view-year";
    const months = Array.from({ length: 12 }, (_, monthIndex) => {
      const firstOfMonth = new Date(year, monthIndex, 1);
      const startDay = firstOfMonth.getDay();
      const daysInMonth = new Date(year, monthIndex + 1, 0).getDate();
      const dayCells = [];
      for (let i = 0; i < startDay; i++) dayCells.push(`<span class="calendar-mini-day is-empty"></span>`);
      for (let day = 1; day <= daysInMonth; day++) {
        const iso = isoFromDate(new Date(year, monthIndex, day));
        const dayEntries = entries.filter((entry) => entry.date === iso);
        const isToday = iso === isoFromDate(minDate);
        const kindClass = dayEntries.length ? ` kind-${dominantKind(dayEntries)}` : "";
        dayCells.push(
          `<button type="button" class="calendar-mini-day${isToday ? " is-today" : ""}${kindClass}" data-calendar-date="${iso}">${day}</button>`
        );
      }
      return `<div class="calendar-mini-month"><strong>${firstOfMonth.toLocaleDateString("en-IN", { month: "long" })}</strong><div class="calendar-mini-grid">${dayCells.join("")}</div></div>`;
    });
    grid.innerHTML = months.join("");
  };

  const renderScheduleView = (entries) => {
    if (monthLabel) monthLabel.textContent = "Schedule";
    if (weekdaysRow) weekdaysRow.innerHTML = "";
    grid.className = "calendar-grid view-schedule";
    const upcoming = entries.filter((entry) => entry.date >= isoFromDate(minDate)).sort((a, b) => a.date.localeCompare(b.date));
    if (!upcoming.length) {
      grid.innerHTML = `<p class="portal-note">No upcoming events.</p>`;
      return;
    }
    let lastDate = "";
    grid.innerHTML = upcoming
      .map((entry) => {
        const showDateHeader = entry.date !== lastDate;
        lastDate = entry.date;
        const dateLabel = new Date(`${entry.date}T00:00:00`).toLocaleDateString("en-IN", { weekday: "long", day: "numeric", month: "long" });
        return (
          (showDateHeader ? `<div class="calendar-schedule-date">${dateLabel}</div>` : "") +
          `<button type="button" class="calendar-schedule-item" data-calendar-entry="${entry.id}">` +
          `<span class="calendar-schedule-dot kind-${entryKind(entry)}"></span>` +
          `<span class="calendar-schedule-title">${escapeHtml(entry.title)}</span>` +
          `</button>`
        );
      })
      .join("");
  };

  // Schedule is an "upcoming from today" agenda, not a navigable date range, so it has no
  // Prev/Next. Every other view can freely browse into the past or future.
  const isAtMinBoundary = () => currentView === "schedule";

  const renderCalendar = () => {
    const entries = visibleEntries();
    entryById = new Map(entries.map((entry) => [entry.id, entry]));
    if (currentView === "week") renderWeekView(entries);
    else if (currentView === "day") renderDayView(entries);
    else if (currentView === "year") renderYearView(entries);
    else if (currentView === "schedule") renderScheduleView(entries);
    else renderMonthView(entries);
    if (prevButton) prevButton.disabled = isAtMinBoundary();
    if (nextButton) nextButton.disabled = currentView === "schedule";
  };
  calendarRerenderListeners.push(renderCalendar);

  const goToToday = () => {
    viewDate = new Date(minDate);
    renderCalendar();
  };

  todayButton?.addEventListener("click", goToToday);

  // View switcher: Day/Week/Month/Year/Schedule actually change the layout, Google
  // Calendar-style, and the choice is remembered per page (see calendarViewStorageKey above) so
  // it stays put across reloads until the user picks a different one.
  const viewToggle = document.querySelector("#calendarViewToggle");
  const viewLabel = document.querySelector("#calendarViewLabel");
  const viewMenu = document.querySelector("#calendarViewMenu");
  const setActiveViewOption = (view) => {
    viewMenu?.querySelectorAll("button").forEach((button) => button.classList.toggle("active", button.dataset.calendarView === view));
    const activeOption = viewMenu?.querySelector(`[data-calendar-view="${view}"]`);
    if (viewLabel && activeOption) viewLabel.textContent = activeOption.textContent.trim().replace(/[A-Z]$/, "").trim();
  };
  if (currentView !== "month") setActiveViewOption(currentView);
  viewToggle?.addEventListener("click", (event) => {
    event.stopPropagation();
    const willOpen = viewMenu?.classList.contains("is-hidden");
    viewMenu?.classList.toggle("is-hidden", !willOpen);
    viewToggle.setAttribute("aria-expanded", String(Boolean(willOpen)));
  });
  viewMenu?.addEventListener("click", (event) => {
    const option = event.target.closest("[data-calendar-view]");
    if (option) {
      const requestedView = option.dataset.calendarView;
      if (supportedViews.includes(requestedView)) {
        currentView = requestedView;
        localStorage.setItem(calendarViewStorageKey, currentView);
        setActiveViewOption(currentView);
        renderCalendar();
      }
    }
    viewMenu.classList.add("is-hidden");
    viewToggle?.setAttribute("aria-expanded", "false");
  });
  document.addEventListener("click", (event) => {
    if (!viewMenu || viewMenu.classList.contains("is-hidden")) return;
    if (!event.target.closest(".calendar-view-select")) {
      viewMenu.classList.add("is-hidden");
      viewToggle?.setAttribute("aria-expanded", "false");
    }
  });

  prevButton?.addEventListener("click", () => {
    if (isAtMinBoundary()) return;
    if (currentView === "month") viewDate = addMonths(viewDate, -1);
    else if (currentView === "week") viewDate.setDate(viewDate.getDate() - 7);
    else if (currentView === "year") viewDate.setFullYear(viewDate.getFullYear() - 1);
    else viewDate.setDate(viewDate.getDate() - 1);
    renderCalendar();
  });
  nextButton?.addEventListener("click", () => {
    if (currentView === "schedule") return;
    if (currentView === "month") viewDate = addMonths(viewDate, 1);
    else if (currentView === "week") viewDate.setDate(viewDate.getDate() + 7);
    else if (currentView === "year") viewDate.setFullYear(viewDate.getFullYear() + 1);
    else viewDate.setDate(viewDate.getDate() + 1);
    renderCalendar();
  });
  grid.addEventListener("click", (event) => {
    const entryButton = event.target.closest("[data-calendar-entry]");
    if (entryButton) {
      const entry = entryById.get(entryButton.dataset.calendarEntry);
      if (entry) openEventModal(entry);
      return;
    }
    const dateTarget = event.target.closest("[data-calendar-date]");
    if (!dateTarget) return;
    selectedDate = dateTarget.dataset.calendarDate;
    if (dateInput) dateInput.value = selectedDate;
    if (currentView === "year") {
      viewDate = new Date(`${selectedDate}T00:00:00`);
      currentView = "day";
      localStorage.setItem(calendarViewStorageKey, currentView);
      setActiveViewOption(currentView);
    }
    renderCalendar();
  });

  if (canAdd) {
    addButton.addEventListener("click", () => {
      const title = titleInput?.value.trim() || "";
      const date = dateInput?.value || "";
      if (feedback) feedback.classList.remove("success");
      if (!title || !date) {
        if (feedback) feedback.textContent = "Enter a title and date.";
        return;
      }
      if (date < todayIso().slice(0, 8) + "01") {
        if (feedback) feedback.textContent = "Pick a date in the current month or later.";
        return;
      }
      const reminders = getCalendarReminders();
      reminders.push({
        id: `reminder-${Date.now()}`,
        title,
        date,
        time: timeInput?.value || "",
        description: descriptionInput?.value.trim() || "",
        scope: isPersonalScope ? "personal" : "shared",
        owner: isPersonalScope ? personalOwnerId : "",
        kind: isPersonalScope ? "personal" : kindSelect?.value === "holiday-college" ? "holiday-college" : "reminder"
      });
      saveCalendarReminders(reminders);
      if (titleInput) titleInput.value = "";
      if (timeInput) timeInput.value = "";
      if (descriptionInput) descriptionInput.value = "";
      renderCalendar();
      if (feedback) {
        feedback.textContent = `Reminder "${title}" added${isPersonalScope ? " - only visible to you." : "."}`;
        feedback.classList.add("success");
      }
    });
  }

  renderCalendar();
})();

// Admin-panel setting for the Alumni Google Sign-In Client ID. admin-config.json wins when
// present; localStorage is only a fallback for browsers that cannot write the config file.
const googleClientIdInput = document.querySelector("#googleClientIdInput");
const saveGoogleClientIdButton = document.querySelector("#saveGoogleClientIdButton");
const googleClientIdFeedback = document.querySelector("#googleClientIdFeedback");
const googleClientIdStatus = document.querySelector("#googleClientIdStatus");
let googleConfigJsonValid = false;

const renderGoogleClientIdStatus = () => {
  if (!googleClientIdStatus) return;
  const configured = adminConfigFieldsLoaded.googleClientId && defaultAdminConfig.googleClientId && !defaultAdminConfig.googleClientId.includes("YOUR_GOOGLE_CLIENT_ID");
  const override = adminConfigFieldsLoaded.googleClientId ? "" : localStorage.getItem("gprecGoogleClientIdOverride") || "";
  googleClientIdStatus.innerHTML = (configured || override || googleConfigJsonValid)
    ? `<span class="ok">Connected</span> - ${configured ? "saved on the server" : "using this device's fallback"}`
    : `<span class="warn">Not connected</span> - Google Sign-In button won't work until a real Client ID is set`;
};

if (googleClientIdInput) {
  const populateGoogleClientIdForm = () => {
    googleClientIdInput.value = adminConfigFieldsLoaded.googleClientId
      ? defaultAdminConfig.googleClientId || ""
      : localStorage.getItem("gprecGoogleClientIdOverride") || "";
    renderGoogleClientIdStatus();
  };
  populateGoogleClientIdForm();
  onAdminConfigLoaded(populateGoogleClientIdForm);
  renderGoogleClientIdStatus();
  // Show what's actually active from admin-config.json as a placeholder when there's no
  // override, so editing the JSON file directly is visible here too, not just the override.
  fetch(gprecRootPrefix + "admin-config.json")
    .then((response) => response.json())
    .then((config) => {
      if (config.googleClientId && !config.googleClientId.includes("YOUR_GOOGLE_CLIENT_ID")) {
        googleClientIdInput.placeholder = `Currently set on the server: ${config.googleClientId}`;
        googleConfigJsonValid = true;
        renderGoogleClientIdStatus();
      }
    })
    .catch(() => {
      // admin-config.json unreachable (e.g. opened via file://) - placeholder stays default.
    });
}

saveGoogleClientIdButton?.addEventListener("click", () => {
  const value = googleClientIdInput?.value.trim() || "";
  defaultAdminConfig.googleClientId = value;
  adminConfigFieldsLoaded.googleClientId = true;
  if (value) localStorage.setItem("gprecGoogleClientIdOverride", value);
  else localStorage.removeItem("gprecGoogleClientIdOverride");
  renderGoogleClientIdStatus();
  persistIntegrationSettings(
    googleClientIdFeedback,
    value ? "Google Client ID saved." : "Google Client ID cleared."
  );
});

