const renderPlainList = (items) => `<ul class="disclosure-list">${items.map((item) => `<li>${escapeHtml(item)}</li>`).join("")}</ul>`;
const renderNumberedList = (items) =>
  `<ol style="margin:0;padding-left:20px;color:#344054;font-size:0.88rem;line-height:1.7;">${items.map((item) => `<li style="margin-bottom:6px;">${escapeHtml(item)}</li>`).join("")}</ol>`;

const buildDepartmentCategories = (department) => {
  const categories = [];
  const staticContent = {};

  const aboutParts = [`<p class="about-justify" style="margin:0 0 12px;">${escapeHtml(department.about || "")}</p>`];
  if (department.vision) {
    aboutParts.push(`<h4>Vision</h4><p style="margin:0 0 12px;color:#344054;font-size:0.88rem;line-height:1.6;">${escapeHtml(department.vision)}</p>`);
  }
  if (department.mission?.length) aboutParts.push(`<h4>Mission</h4>${renderPlainList(department.mission)}`);
  if (department.peos?.length) aboutParts.push(`<h4>Programme Educational Objectives</h4>${renderNumberedList(department.peos)}`);
  if (department.pos?.length) aboutParts.push(`<h4>Programme Outcomes</h4>${renderPlainList(department.pos)}`);
  if (department.psos?.length) aboutParts.push(`<h4>Program Specific Outcomes</h4>${renderNumberedList(department.psos)}`);
  categories.push({ id: "about", label: "Department" });
  staticContent.about = aboutParts.join("");

  if (department.programs?.length) {
    categories.push({ id: "programs", label: "Programs Offered" });
    staticContent.programs = `
      <div class="disclosure-table-wrap">
        <table class="disclosure-table">
          <thead><tr><th>Programme</th><th>Intake</th></tr></thead>
          <tbody>${department.programs.map((p) => `<tr><td>${escapeHtml(p.name)}</td><td>${escapeHtml(p.intake)}</td></tr>`).join("")}</tbody>
        </table>
      </div>`;
  }

  if (department.boardOfStudies?.length) {
    categories.push({ id: "bos", label: "Board of Studies" });
    staticContent.bos = `
      <div class="disclosure-table-wrap">
        <table class="disclosure-table">
          <thead><tr><th>Position</th><th>Name</th><th>Affiliation</th></tr></thead>
          <tbody>${department.boardOfStudies.map((m) => `<tr><td>${escapeHtml(m.position)}</td><td>${escapeHtml(m.name)}</td><td>${escapeHtml(m.affiliation)}</td></tr>`).join("")}</tbody>
        </table>
      </div>`;
  }

  if (department.studentActivities?.length) {
    categories.push({ id: "activities", label: "Student Activities" });
    staticContent.activities = renderPlainList(department.studentActivities);
  }

  if (department.facilities?.length || department.library?.length) {
    categories.push({ id: "infrastructure", label: "Infrastructure" });
    const parts = [];
    if (department.facilities?.length) parts.push(`<h4>Laboratories</h4>${renderPlainList(department.facilities)}`);
    if (department.library?.length) {
      parts.push(`
        <h4>Department Library</h4>
        <div class="disclosure-table-wrap">
          <table class="disclosure-table">
            <thead><tr><th>Item</th><th>Quantity</th></tr></thead>
            <tbody>${department.library.map((row) => `<tr><td>${escapeHtml(row.item)}</td><td>${escapeHtml(row.quantity)}</td></tr>`).join("")}</tbody>
          </table>
        </div>`);
    }
    staticContent.infrastructure = parts.join("");
  }

  if (department.departmentAchievements?.length || department.ltScholarship?.length) {
    categories.push({ id: "achievements", label: "Achievements" });
    const parts = [];
    if (department.departmentAchievements?.length) {
      parts.push(`
        <h4>Department Achievements</h4>
        <div class="disclosure-table-wrap">
          <table class="disclosure-table">
            <thead><tr><th>Event</th><th>Dates</th></tr></thead>
            <tbody>${department.departmentAchievements.map((row) => `<tr><td>${escapeHtml(row.event)}</td><td>${escapeHtml(row.dates)}</td></tr>`).join("")}</tbody>
          </table>
        </div>`);
    }
    if (department.studentAchievementsNote) {
      parts.push(`<h4>Student Achievements</h4><p style="margin:0 0 12px;color:#344054;font-size:0.88rem;line-height:1.6;">${escapeHtml(department.studentAchievementsNote)}</p>`);
    }
    if (department.ltScholarship?.length) {
      parts.push(`
        <div class="disclosure-table-wrap">
          <table class="disclosure-table">
            <thead><tr><th>Year</th><th>Roll No.</th><th>Student</th><th>Institution</th></tr></thead>
            <tbody>${department.ltScholarship.map((row) => `<tr><td>${escapeHtml(row.year)}</td><td>${escapeHtml(row.roll)}</td><td>${escapeHtml(row.name)}</td><td>${escapeHtml(row.institution)}</td></tr>`).join("")}</tbody>
          </table>
        </div>`);
    }
    staticContent.achievements = parts.join("");
  }

  if (department.gallery?.length) {
    categories.push({ id: "gallery", label: "Gallery" });
    staticContent.gallery = `
      <div class="department-gallery">
        ${department.gallery.map((photo) => `<figure><img src="${escapeHtml(photo.url)}" alt="${escapeHtml(photo.caption || department.name)}" loading="lazy"><figcaption>${escapeHtml(photo.caption || "")}</figcaption></figure>`).join("")}
      </div>`;
  }

  return { categories, staticContent };
};

const departmentNameEl = document.querySelector("#departmentName");
if (departmentNameEl) {
  const deptCode = document.body.dataset.deptCode || new URLSearchParams(window.location.search).get("dept");
  const department = getDepartmentsList().find((dept) => dept.code === deptCode) || getDepartmentsList()[0];
  if (department) {
    document.title = `${department.name} | GPREC`;
    const departmentCodeEl = document.querySelector("#departmentCode");
    if (departmentCodeEl) departmentCodeEl.textContent = department.code || "Department";
    departmentNameEl.textContent = department.name;

    const departmentTabsContainer = document.querySelector("#departmentTabsContainer");
    const departmentPanelsContainer = document.querySelector("#departmentPanelsContainer");
    if (departmentTabsContainer && departmentPanelsContainer) {
      const { categories, staticContent } = buildDepartmentCategories(department);
      renderCategoryTabsAndPanels(departmentTabsContainer, departmentPanelsContainer, categories, { staticContent });
    }
  }
}

