// Fee Structure/Scholarships above. Falls back to the page's real, already-published content
// (unlike those, which rely on a pre-seeded site_content row) so the page still shows real text
// even before an admin ever opens this editor.
const IDEA_LAB_CONTENT_DEFAULTS = {
  about: "The AICTE Idea Lab is a cutting-edge facility at GPREC that fosters innovation, where student ideas are transformed into significant solutions. It bridges the gap between classroom theory and practical application by giving students hands-on access to prototyping tools and equipment.",
  equipment: "The lab is equipped with 3D printers, laser cutters, IoT kits, and advanced design software, and is built to encourage multidisciplinary collaboration and the entrepreneurial spirit that turns a rough idea into a working prototype.",
  slogan: "“Create, Innovate, Transform” - the Idea Lab's guiding philosophy, focused on developing industry-ready engineers.",
  vision: "To develop a culture of creativity and experiential learning that produces future innovators and entrepreneurs, through practical experimentation and design thinking.",
  mission: [
    "Foster a culture of creation through experiential, hands-on learning.",
    "Facilitate skill cultivation through access to state-of-the-art equipment.",
    "Stimulate novel ideas and entrepreneurial ventures among students.",
    "Foster collaborative, interdisciplinary endeavours across departments.",
    "Support the national “Atmanirbhar Bharat” (self-reliant India) initiative."
  ],
  benefits: [
    "Enhanced practical understanding of classroom concepts.",
    "Development of an entrepreneurial mindset.",
    "A culture of multidisciplinary teamwork.",
    "Improved employability through hands-on project experience.",
    "Strong emphasis on project-based learning."
  ],
  infrastructure: "The Idea Lab draws on GPREC's existing network of well-equipped laboratories, workshops, and centres of excellence, which together support internships, skill development, and prototype creation across every engineering department.",
  tenderUrl: "https://www.gprec.ac.in/collegepdf/AICTE-IDEA-Tender-Document.pdf"
};
const getIdeaLabContent = () => {
  const saved = getSiteContent("ideaLabContent", null);
  return saved && typeof saved === "object" ? { ...IDEA_LAB_CONTENT_DEFAULTS, ...saved } : IDEA_LAB_CONTENT_DEFAULTS;
};
const saveIdeaLabContent = (content) => saveSiteContent("ideaLabContent", content);

const IDEA_LAB_TEAM_DEFAULTS = [
  { role: "Chief Mentor", details: "Dr. B. Sreenivasa Reddy, Principal" },
  { role: "Coordinator", details: "Dr. T. Bramhananda Reddy, Professor, EEE" },
  { role: "Co-Coordinator", details: "Sri A. Pradeep Kumar Yadav, Assistant Professor, EEE" },
  { role: "Tech Gurus", details: "Dr. D. R. Srinivas, Associate Professor, ECE\nDr. M. Madhusudhana Reddy, Assistant Professor, ECE\nDr. D. Mohana Krishnudu, Assistant Professor, ME\nDr. G. Venkatesh, Assistant Professor, ME" },
  { role: "Student Ambassadors", details: "Ms. M. Navya, UG Student, EEE\nMs. K. Meghana, UG Student, EEE\nMr. Saginala Praneeth, UG Student, ME" },
  { role: "Technical Support", details: "Sri O. Sandeep Krishna, Technician\nSri M. Sreenivasulu, Technician" }
];
const getIdeaLabTeam = () => {
  const saved = getSiteContent("ideaLabTeam", null);
  return Array.isArray(saved) && saved.length ? saved : IDEA_LAB_TEAM_DEFAULTS;
};
const saveIdeaLabTeam = (team) => saveSiteContent("ideaLabTeam", team);

const ideaLabAboutEl = document.querySelector("#ideaLabAbout");
if (ideaLabAboutEl) {
  const ideaLabContent = getIdeaLabContent();
  ideaLabAboutEl.textContent = ideaLabContent.about;
  const ideaLabEquipmentEl = document.querySelector("#ideaLabEquipment");
  if (ideaLabEquipmentEl) ideaLabEquipmentEl.textContent = ideaLabContent.equipment;
  const ideaLabSloganEl = document.querySelector("#ideaLabSlogan");
  if (ideaLabSloganEl) ideaLabSloganEl.textContent = ideaLabContent.slogan;
  const ideaLabVisionEl = document.querySelector("#ideaLabVision");
  if (ideaLabVisionEl) ideaLabVisionEl.textContent = ideaLabContent.vision;
  const ideaLabInfrastructureEl = document.querySelector("#ideaLabInfrastructure");
  if (ideaLabInfrastructureEl) ideaLabInfrastructureEl.textContent = ideaLabContent.infrastructure;
  const ideaLabTenderLink = document.querySelector("#ideaLabTenderLink");
  if (ideaLabTenderLink && ideaLabContent.tenderUrl) ideaLabTenderLink.href = ideaLabContent.tenderUrl;
  const ideaLabMissionList = document.querySelector("#ideaLabMissionList");
  if (ideaLabMissionList) {
    ideaLabMissionList.innerHTML = (ideaLabContent.mission || []).map((item) => `<li>${escapeHtml(item)}</li>`).join("");
  }
  const ideaLabBenefitsList = document.querySelector("#ideaLabBenefitsList");
  if (ideaLabBenefitsList) {
    ideaLabBenefitsList.innerHTML = (ideaLabContent.benefits || []).map((item) => `<li>${escapeHtml(item)}</li>`).join("");
  }
  const ideaLabTeamBody = document.querySelector("#ideaLabTeamBody");
  if (ideaLabTeamBody) {
    ideaLabTeamBody.innerHTML = getIdeaLabTeam()
      .map((member) => `<tr><td>${escapeHtml(member.role)}</td><td>${escapeHtml(member.details).replace(/\n/g, "<br>")}</td></tr>`)
      .join("");
  }
}

