  return `
    <h4>R&D Committee</h4>
    <p style="margin:0 0 12px;color:#344054;font-size:0.88rem;line-height:1.6;">${escapeHtml(content.committee).replace(/\n/g, "<br>")}</p>
    <h4>Objectives</h4>
    <p style="margin:0 0 12px;color:#344054;font-size:0.88rem;line-height:1.6;">${escapeHtml(content.objectives).replace(/\n/g, "<br>")}</p>
    <h4>Faculty &amp; Student Incentives</h4>
    <p style="margin:0 0 12px;color:#344054;font-size:0.88rem;line-height:1.6;">${escapeHtml(content.incentives).replace(/\n/g, "<br>")}</p>
    <h4>In-House Project Scheme</h4>
    <p style="margin:0;color:#344054;font-size:0.88rem;line-height:1.6;">${escapeHtml(content.inHouseScheme).replace(/\n/g, "<br>")}</p>`;
