const buildFundedProjectsHtml = () => {
  const rows = getFundedProjectsRows();
  const totalNonRecurring = rows.reduce((sum, row) => sum + parseIndianNumber(row.nonRecurring), 0);
  const totalRecurring = rows.reduce((sum, row) => sum + parseIndianNumber(row.recurring), 0);
  const ongoing = getOngoingProjectsRows();
  return `
    <h4>Externally Funded Projects</h4>
    <div class="disclosure-table-wrap">
      <table class="disclosure-table">
        <thead><tr><th>Year</th><th>Scheme</th><th>Coordinator</th><th>Dept.</th><th>Non-Recurring (Rs.)</th><th>Recurring (Rs.)</th></tr></thead>
        <tbody>
          ${rows.map((row) => `<tr><td>${escapeHtml(row.year)}</td><td>${escapeHtml(row.scheme)}</td><td>${escapeHtml(row.coordinator)}</td><td>${escapeHtml(row.dept)}</td><td>${escapeHtml(row.nonRecurring)}</td><td>${escapeHtml(row.recurring)}</td></tr>`).join("")}
          <tr style="font-weight:900;"><td></td><td></td><td>Total Amount</td><td></td><td>${formatIndianNumber(totalNonRecurring)}</td><td>${formatIndianNumber(totalRecurring)}</td></tr>
        </tbody>
      </table>
    </div>
    <h4>Ongoing In-House Projects</h4>
    <div class="disclosure-table-wrap">
      <table class="disclosure-table">
        <thead><tr><th>#</th><th>Principal Investigator</th><th>Dept.</th><th>Project Title</th><th>Financial Assistance (Rs.)</th><th>Status</th></tr></thead>
        <tbody>
          ${ongoing.map((row, index) => `<tr><td>${index + 1}</td><td>${escapeHtml(row.pi)}</td><td>${escapeHtml(row.dept)}</td><td>${escapeHtml(row.title)}</td><td>${escapeHtml(row.amount)}</td><td>${escapeHtml(row.status)}</td></tr>`).join("")}
        </tbody>
      </table>
    </div>`;
};

