const getExamCellContent = () => getSiteContent("examCellContent", {});
const saveExamCellContent = (content) => saveSiteContent("examCellContent", content);

const examCellTabsContainer = document.querySelector("#examCellTabsContainer");
if (examCellTabsContainer) {
  const examCell = getExamCellContent();
  const categories = [{ id: "about", label: "About" }];
  const staticContent = {
    about: `<p class="about-justify" style="margin:0 0 12px;">${escapeHtml(examCell.about || "")}</p>`
  };
  if (examCell.functions?.length) {
    categories.push({ id: "functions", label: "Functions & Responsibilities" });
    staticContent.functions = `
      ${renderPlainList(examCell.functions)}
      ${examCell.infrastructure ? `<h4>Infrastructure &amp; Systems</h4><p style="margin:0;color:#344054;font-size:0.88rem;line-height:1.6;">${escapeHtml(examCell.infrastructure)}</p>` : ""}`;
  }
  if (examCell.generalRules?.length || examCell.malpracticeOffenses?.length) {
    categories.push({ id: "rules", label: "Rules & Regulations" });
    const parts = [];
    if (examCell.generalRules?.length) parts.push(`<h4>General Examination Rules</h4>${renderPlainList(examCell.generalRules)}`);
    if (examCell.malpracticeOffenses?.length) {
      parts.push(`
        <h4>Malpractice Offenses &amp; Punishments</h4>
        <div class="disclosure-table-wrap">
          <table class="disclosure-table">
            <thead><tr><th>Offense</th><th>Punishment</th></tr></thead>
            <tbody>${examCell.malpracticeOffenses.map((row) => `<tr><td>${escapeHtml(row.offense)}</td><td>${escapeHtml(row.punishment)}</td></tr>`).join("")}</tbody>
          </table>
        </div>`);
    }
    if (examCell.malpracticeNote) {
      parts.push(`<p style="margin:12px 0 0;color:#344054;font-size:0.88rem;line-height:1.6;">${escapeHtml(examCell.malpracticeNote)}</p>`);
    }
    staticContent.rules = parts.join("");
  }
  if (examCell.courseCompletionNotice) {
    categories.push({ id: "completion", label: "Course Completion Policy" });
    // A paragraph wrapped in **...** mirrors the bold-underlined-italic emphasis line in the
    // original scanned notice ("Completing the course of study means not merely...") - highlighted
    // the same way here instead of reading as plain text like the rest of the notice.
    staticContent.completion = examCell.courseCompletionNotice
      .split("\n\n")
      .map((paragraph) => {
        const isEmphasized = paragraph.startsWith("**") && paragraph.endsWith("**");
        const text = isEmphasized ? paragraph.slice(2, -2) : paragraph;
        const style = isEmphasized
          ? "margin:0 0 12px;padding:10px 12px;border-left:3px solid var(--orange);background:#fff8ef;color:var(--navy);font-weight:900;text-decoration:underline;font-size:0.88rem;line-height:1.6;"
          : "margin:0 0 12px;color:#344054;font-size:0.88rem;line-height:1.6;";
        return `<p style="${style}">${escapeHtml(text)}</p>`;
      })
      .join("");
  }
  if (examCell.importantLinks?.length) {
    categories.push({ id: "links", label: "Important Links" });
    staticContent.links = `
      <div class="disclosure-table-wrap">
        <table class="disclosure-table">
          <thead><tr><th>Link</th><th>Details</th></tr></thead>
          <tbody>${examCell.importantLinks.map((link) => `<tr><td>${escapeHtml(link.title)}</td><td>${escapeHtml(link.note || "")}</td></tr>`).join("")}</tbody>
        </table>
      </div>`;
  }
  if (examCell.downloadApplications?.length) {
    categories.push({ id: "downloads", label: "Download Applications" });
    staticContent.downloads = `
      <div class="disclosure-table-wrap">
        <table class="disclosure-table">
          <thead><tr><th>Application</th><th></th></tr></thead>
          <tbody>${examCell.downloadApplications
            .map(
              (item) => `
                <tr>
                  <td>${escapeHtml(item.title)}</td>
                  <td><a class="notice-download" href="${escapeHtml(item.url)}" target="_blank" rel="noreferrer">${escapeHtml(item.label || "Download")}</a></td>
                </tr>`
            )
            .join("")}</tbody>
        </table>
      </div>`;
  }
  renderCategoryTabsAndPanels(examCellTabsContainer, document.querySelector("#examCellPanelsContainer"), categories, { staticContent });
}

const examCellAboutInput = document.querySelector("#examCellAboutInput");
if (examCellAboutInput) {
  const examCellFunctionsInput = document.querySelector("#examCellFunctionsInput");
  const examCellInfrastructureInput = document.querySelector("#examCellInfrastructureInput");
  const examCellGeneralRulesInput = document.querySelector("#examCellGeneralRulesInput");
  const examCellMalpracticeOffensesInput = document.querySelector("#examCellMalpracticeOffensesInput");
  const examCellMalpracticeNoteInput = document.querySelector("#examCellMalpracticeNoteInput");
  const examCellCourseCompletionInput = document.querySelector("#examCellCourseCompletionInput");
  const examCellImportantLinksInput = document.querySelector("#examCellImportantLinksInput");
  const examCellDownloadApplicationsInput = document.querySelector("#examCellDownloadApplicationsInput");
  const examCellSaveButton = document.querySelector("#examCellSaveButton");
  const examCellFeedback = document.querySelector("#examCellFeedback");

  const examCellLinesToList = (value) => (value || "").split("\n").map((line) => line.trim()).filter(Boolean);
  const examCellListToLines = (list) => (list || []).join("\n");
  const examCellLinesToRows = (value, keys) =>
    examCellLinesToList(value).map((line) => {
      const parts = line.split("|").map((part) => part.trim());
      const row = {};
      keys.forEach((key, index) => { row[key] = parts[index] || ""; });
      return row;
    });
  const examCellRowsToLines = (rows, keys) => (rows || []).map((row) => keys.map((key) => row[key] || "").join(" | ")).join("\n");

  const examCell = getExamCellContent();
  examCellAboutInput.value = examCell.about || "";
  examCellFunctionsInput.value = examCellListToLines(examCell.functions);
  examCellInfrastructureInput.value = examCell.infrastructure || "";
  examCellGeneralRulesInput.value = examCellListToLines(examCell.generalRules);
  examCellMalpracticeOffensesInput.value = examCellRowsToLines(examCell.malpracticeOffenses, ["offense", "punishment"]);
  examCellMalpracticeNoteInput.value = examCell.malpracticeNote || "";
  examCellCourseCompletionInput.value = examCell.courseCompletionNotice || "";
  examCellImportantLinksInput.value = examCellRowsToLines(examCell.importantLinks, ["title", "note"]);
  examCellDownloadApplicationsInput.value = examCellRowsToLines(examCell.downloadApplications, ["title", "url", "label"]);

  examCellSaveButton?.addEventListener("click", () => {
    saveExamCellContent({
      about: examCellAboutInput.value.trim(),
      functions: examCellLinesToList(examCellFunctionsInput.value),
      infrastructure: examCellInfrastructureInput.value.trim(),
      generalRules: examCellLinesToList(examCellGeneralRulesInput.value),
      malpracticeOffenses: examCellLinesToRows(examCellMalpracticeOffensesInput.value, ["offense", "punishment"]),
      malpracticeNote: examCellMalpracticeNoteInput.value.trim(),
      courseCompletionNotice: examCellCourseCompletionInput.value.trim(),
      importantLinks: examCellLinesToRows(examCellImportantLinksInput.value, ["title", "note"]),
      downloadApplications: examCellLinesToRows(examCellDownloadApplicationsInput.value, ["title", "url", "label"])
    });
    if (examCellFeedback) {
      examCellFeedback.textContent = "Exam Cell content saved. Refresh the Exam Cell page to see it live.";
      examCellFeedback.classList.add("success");
    }
  });
}

