    if (!button || !editingDepartmentId) return;
    const index = Number(button.dataset.removeDepartmentGallery);
    const list = getDepartmentsList();
    const dept = list.find((item) => item.id === editingDepartmentId);
    if (!dept) return;
    dept.gallery = (dept.gallery || []).filter((_, i) => i !== index);
    saveDepartmentsList(list);
    renderDepartmentGalleryAdmin();
