    if (contactInfoEmail1) contactInfoEmail1.value = info.email1 || "";
    if (contactInfoEmail2) contactInfoEmail2.value = info.email2 || "";
    if (contactInfoHowToReach) contactInfoHowToReach.value = info.howToReach || "";
