      saveIdeaLabTeam([...getIdeaLabTeam(), { role, details }]);
      renderIdeaLabTeamAdmin();
      if (ideaLabTeamRoleInput) ideaLabTeamRoleInput.value = "";
      if (ideaLabTeamDetailsInput) ideaLabTeamDetailsInput.value = "";
