  // Patents and Call for Research Proposals are just categories in getResearchDevCategories(),
  // same as everything the "Categories & Documents" editor above handles - but since they're
  // permanent, well-known tabs on the public page (not admin-created), they get their own
  // dedicated subtab here instead of requiring the category dropdown to find them.
  const wireFixedCategoryItemsEditor = ({ categoryId, itemsBodyId, itemsEmptyId, titleInputId, urlInputId, sectionInputId, addButtonId, addFeedbackId }) => {
    const itemsBody = document.querySelector(itemsBodyId);
    if (!itemsBody) return;
    const itemsEmpty = document.querySelector(itemsEmptyId);
    const titleInput = document.querySelector(titleInputId);
    const urlInput = document.querySelector(urlInputId);
    const sectionInput = sectionInputId ? document.querySelector(sectionInputId) : null;
    const addFeedback = document.querySelector(addFeedbackId);

    const renderItems = () => {
      const categories = getResearchDevCategories();
      const category = categories.find((cat) => cat.id === categoryId);
      const items = category?.items || [];
      itemsBody.innerHTML = items
        .map(
          (item, index) => `
            <tr>
              <td>${escapeHtml(item.title)}</td>
              <td><a href="${escapeHtml(item.url)}" target="_blank" rel="noreferrer">${escapeHtml(item.url)}</a></td>
              ${sectionInputId ? `<td>${escapeHtml(item.section || "")}</td>` : ""}
              <td><button type="button" class="icon-btn-delete" data-remove-index="${index}" aria-label="Remove" title="Remove">${deleteIconSvg}</button></td>
            </tr>`
        )
        .join("");
      if (itemsEmpty) itemsEmpty.classList.toggle("is-hidden", items.length > 0);
    };
    renderItems();

    document.querySelector(addButtonId)?.addEventListener("click", () => {
      const title = titleInput?.value.trim() || "";
      const url = urlInput?.value.trim() || "";
      if (!title || !url) {
        if (addFeedback) { addFeedback.textContent = "Enter both a title and a URL."; addFeedback.classList.remove("success"); }
        return;
      }
      const section = sectionInput?.value.trim() || "";
      const categories = getResearchDevCategories();
      const category = categories.find((cat) => cat.id === categoryId);
      if (category) category.items = [...(category.items || []), { title, url, ...(section ? { section } : {}) }];
      saveResearchDevCategories(categories);
      renderItems();
      if (titleInput) titleInput.value = "";
      if (urlInput) urlInput.value = "";
      if (sectionInput) sectionInput.value = "";
      if (addFeedback) { addFeedback.textContent = "Added."; addFeedback.classList.add("success"); }
    });

    itemsBody.addEventListener("click", (event) => {
      const button = event.target.closest("[data-remove-index]");
      if (!button) return;
      const index = Number(button.dataset.removeIndex);
      const categories = getResearchDevCategories();
      const category = categories.find((cat) => cat.id === categoryId);
      if (category) category.items = (category.items || []).filter((_, i) => i !== index);
      saveResearchDevCategories(categories);
      renderItems();
      showFeedToast("Removed.");
    });
  };

