  // Generic row-editor for the R&D data tables (Funded Projects, Ongoing Projects, Research
  // Scholars, Consultancy, Publications) - each table has its own columns/inputs, but the same
  // add/remove/re-render shape, so `fields` maps input elements to row property names.
  const wireTableRowEditor = ({ getRows, saveRows, bodyId, emptyId, fields, buildRow, renderRow, addButtonId, addFeedbackId }) => {
    const body = document.querySelector(bodyId);
    const empty = document.querySelector(emptyId);
    const addButton = document.querySelector(addButtonId);
    const addFeedback = document.querySelector(addFeedbackId);
    if (!body) return;

    const render = () => {
      const rows = getRows();
      body.innerHTML = rows
        .map(
          (row, index) => `
            <tr>
              ${renderRow(row, index)}
              <td><button type="button" class="icon-btn-delete" data-remove-row="${index}" aria-label="Remove" title="Remove">${deleteIconSvg}</button></td>
            </tr>`
        )
        .join("");
      if (empty) empty.classList.toggle("is-hidden", rows.length > 0);
    };
    render();

    body.addEventListener("click", (event) => {
      const button = event.target.closest("[data-remove-row]");
      if (!button) return;
      const index = Number(button.dataset.removeRow);
      saveRows(getRows().filter((_, i) => i !== index));
      render();
      showFeedToast("Row removed.");
    });

    addButton?.addEventListener("click", () => {
      const row = buildRow();
      if (!row) {
        if (addFeedback) { addFeedback.textContent = "Fill in the required fields."; addFeedback.classList.remove("success"); }
        return;
      }
      saveRows([...getRows(), row]);
      render();
      fields.forEach((selector) => {
        const field = document.querySelector(selector);
        if (field) field.value = "";
      });
      if (addFeedback) { addFeedback.textContent = "Added."; addFeedback.classList.add("success"); }
    });
  };

  wireTableRowEditor({
    getRows: getFundedProjectsRows,
    saveRows: saveFundedProjectsRows,
    bodyId: "#fundedProjectAdminBody",
    emptyId: "#fundedProjectAdminEmpty",
    addButtonId: "#fundedProjectAddButton",
    addFeedbackId: "#fundedProjectAddFeedback",
    fields: ["#fundedProjectYearInput", "#fundedProjectSchemeInput", "#fundedProjectCoordinatorInput", "#fundedProjectDeptInput", "#fundedProjectNonRecurringInput", "#fundedProjectRecurringInput"],
    renderRow: (row) => `<td>${escapeHtml(row.year)}</td><td>${escapeHtml(row.scheme)}</td><td>${escapeHtml(row.coordinator)}</td><td>${escapeHtml(row.dept)}</td><td>${escapeHtml(row.nonRecurring)}</td><td>${escapeHtml(row.recurring)}</td>`,
    buildRow: () => {
      const year = document.querySelector("#fundedProjectYearInput")?.value.trim() || "";
      const scheme = document.querySelector("#fundedProjectSchemeInput")?.value.trim() || "";
      if (!year || !scheme) return null;
      return {
        year,
        scheme,
        coordinator: document.querySelector("#fundedProjectCoordinatorInput")?.value.trim() || "",
        dept: document.querySelector("#fundedProjectDeptInput")?.value.trim() || "",
        nonRecurring: document.querySelector("#fundedProjectNonRecurringInput")?.value.trim() || "",
        recurring: document.querySelector("#fundedProjectRecurringInput")?.value.trim() || ""
      };
    }
  });

